-- =============================================================================
-- BASELINE SNAPSHOT — production schema as of 2026-04-27
-- =============================================================================
-- This file is a frozen capture of the live `vhzipqarkmmfuqadefep` Supabase
-- project's `public` schema produced by `supabase db dump --linked`. It is
-- NOT intended to be replayed against a fresh database — it is documentation
-- of the production state at a known point in time, used as the reference
-- baseline against which future drift will be detected.
--
-- Why this exists:
--   Between 2026-04-23 and 2026-04-27 the live database accumulated ~172
--   migrations that never landed in this repo's source control (most likely
--   applied via a sibling fork — see project memory project_lovable_migration).
--   On 2026-04-27 we reconciled by:
--     (a) capturing this snapshot
--     (b) calling `supabase migration repair --status applied` on every
--         remote-only migration so the registry stops complaining about
--         them
--     (c) writing forward-going migrations on top of this baseline
--
-- This snapshot itself is repaired-as-applied alongside the other 172 — the
-- supabase CLI never executes its body. To regenerate the snapshot at any
-- future point: `supabase db dump --linked --schema public > <new-snapshot>`.
--
-- Drift detection going forward: `supabase db diff --linked --schema public`
-- against HEAD of source control should produce an empty diff. Any
-- divergence means an out-of-band apply happened and needs reconciling.
-- =============================================================================



SET statement_timeout = 0;
SET lock_timeout = 0;
SET idle_in_transaction_session_timeout = 0;
SET client_encoding = 'UTF8';
SET standard_conforming_strings = on;
SELECT pg_catalog.set_config('search_path', '', false);
SET check_function_bodies = false;
SET xmloption = content;
SET client_min_messages = warning;
SET row_security = off;


CREATE SCHEMA IF NOT EXISTS "public";


ALTER SCHEMA "public" OWNER TO "pg_database_owner";


COMMENT ON SCHEMA "public" IS 'SourceCo schema. Soft-delete convention for NEW tables: deleted_at TIMESTAMPTZ NULL (NULL = live). Existing tables may use archived BOOLEAN; both are currently valid. See docs/DATA_MODEL_MIGRATION.md.';



