CREATE OR REPLACE FUNCTION "public"."archive_listing"("p_listing_id" "uuid", "p_reason" "text" DEFAULT NULL::"text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NOT public.is_admin(auth.uid()) THEN
    RAISE EXCEPTION 'Only admins can archive listings';
  END IF;

  UPDATE public.listings
  SET
    remarketing_status = 'archived',
    archive_reason = p_reason,
    updated_at = now()
  WHERE id = p_listing_id
    AND deleted_at IS NULL;

  RETURN FOUND;
END;
$$;


ALTER FUNCTION "public"."archive_listing"("p_listing_id" "uuid", "p_reason" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."archive_listing"("p_listing_id" "uuid", "p_reason" "text") IS 'Archive a single listing by setting remarketing_status=''archived'' and archive_reason. Admin-only. SECURITY DEFINER so it bypasses any RLS on listings and reliably runs the audit trigger regardless of session role.';



CREATE OR REPLACE FUNCTION "public"."archive_listings_bulk"("p_listing_ids" "uuid"[], "p_reason" "text" DEFAULT NULL::"text") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_count integer;
BEGIN
  IF NOT public.is_admin(auth.uid()) THEN
    RAISE EXCEPTION 'Only admins can archive listings';
  END IF;

  IF p_listing_ids IS NULL OR array_length(p_listing_ids, 1) IS NULL THEN
    RETURN 0;
  END IF;

  UPDATE public.listings
  SET
    remarketing_status = 'archived',
    archive_reason = p_reason,
    updated_at = now()
  WHERE id = ANY(p_listing_ids)
    AND deleted_at IS NULL;

  GET DIAGNOSTICS v_count = ROW_COUNT;
  RETURN v_count;
END;
$$;


ALTER FUNCTION "public"."archive_listings_bulk"("p_listing_ids" "uuid"[], "p_reason" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."archive_listings_bulk"("p_listing_ids" "uuid"[], "p_reason" "text") IS 'Bulk-archive listings. Admin-only. Returns number of rows updated.';



CREATE OR REPLACE FUNCTION "public"."assign_connection_request_decider"("p_request_id" "uuid", "p_decision" "text", "p_admin_id" "uuid", "p_decision_at" timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  caller_id uuid;
  caller_is_admin boolean;
BEGIN
  -- Auth check
  caller_id := auth.uid();
  IF caller_id IS NULL THEN
    RAISE EXCEPTION 'User not authenticated';
  END IF;

  -- Admin check
  SELECT is_admin INTO caller_is_admin FROM public.profiles WHERE id = caller_id;
  IF NOT COALESCE(caller_is_admin, false) THEN
    RAISE EXCEPTION 'Only admins can assign decision admins';
  END IF;

  -- Validate decision value
  IF p_decision NOT IN ('approved','rejected','on_hold','pending') THEN
    RAISE EXCEPTION 'Invalid decision value: %', p_decision;
  END IF;

  -- Handle reset to pending (clear all attribution)
  IF p_decision = 'pending' THEN
    UPDATE public.connection_requests
    SET 
      status = 'pending',
      decision_at = NULL,
      approved_by = NULL,
      approved_at = NULL,
      rejected_by = NULL,
      rejected_at = NULL,
      on_hold_by = NULL,
      on_hold_at = NULL,
      updated_at = NOW()
    WHERE id = p_request_id;
    RETURN FOUND;
  END IF;

  -- Assign the decision and admin attribution
  UPDATE public.connection_requests
  SET 
    status = p_decision,
    decision_at = COALESCE(p_decision_at, NOW()),
    approved_by = CASE WHEN p_decision = 'approved' THEN p_admin_id ELSE NULL END,
    approved_at = CASE WHEN p_decision = 'approved' THEN COALESCE(p_decision_at, NOW()) ELSE NULL END,
    rejected_by = CASE WHEN p_decision = 'rejected' THEN p_admin_id ELSE NULL END,
    rejected_at = CASE WHEN p_decision = 'rejected' THEN COALESCE(p_decision_at, NOW()) ELSE NULL END,
    on_hold_by = CASE WHEN p_decision = 'on_hold' THEN p_admin_id ELSE NULL END,
    on_hold_at = CASE WHEN p_decision = 'on_hold' THEN COALESCE(p_decision_at, NOW()) ELSE NULL END,
    updated_at = NOW()
  WHERE id = p_request_id;

  RETURN FOUND;
END;
$$;


ALTER FUNCTION "public"."assign_connection_request_decider"("p_request_id" "uuid", "p_decision" "text", "p_admin_id" "uuid", "p_decision_at" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."assign_role_for_invite"("_user_id" "uuid", "_role" "text", "_granted_by" "uuid", "_reason" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  _old_role app_role;
BEGIN
  IF _role NOT IN ('owner', 'admin', 'moderator', 'viewer') THEN
    RAISE EXCEPTION 'Invalid role: %. Must be owner, admin, moderator, or viewer.', _role;
  END IF;

  SELECT role INTO _old_role FROM public.user_roles WHERE user_id = _user_id;

  INSERT INTO public.user_roles (user_id, role, granted_by, reason)
  VALUES (_user_id, _role::app_role, _granted_by, _reason)
  ON CONFLICT (user_id)
  DO UPDATE SET
    role    = _role::app_role,
    granted_by = _granted_by,
    granted_at = now(),
    reason  = _reason;

  INSERT INTO public.permission_audit_log (target_user_id, changed_by, old_role, new_role, reason)
  VALUES (_user_id, _granted_by, _old_role, _role::app_role, _reason);

  UPDATE public.profiles
  SET
    is_admin = (_role IN ('owner', 'admin', 'moderator')),
    updated_at = NOW()
  WHERE id = _user_id;
END;
$$;


ALTER FUNCTION "public"."assign_role_for_invite"("_user_id" "uuid", "_role" "text", "_granted_by" "uuid", "_reason" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."audit_buyer_changes"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_sensitive_fields TEXT[] := ARRAY['thesis_summary', 'target_geographies', 'target_revenue_min', 'target_revenue_max'];
  v_changed_sensitive BOOLEAN := false;
BEGIN
  -- Check if any sensitive fields changed
  IF TG_OP = 'UPDATE' THEN
    v_changed_sensitive := (
      OLD.thesis_summary IS DISTINCT FROM NEW.thesis_summary OR
      OLD.target_geographies IS DISTINCT FROM NEW.target_geographies OR
      OLD.target_revenue_min IS DISTINCT FROM NEW.target_revenue_min OR
      OLD.target_revenue_max IS DISTINCT FROM NEW.target_revenue_max
    );
  END IF;

  -- Only log if sensitive fields changed or it's a create/delete
  IF TG_OP = 'INSERT' OR TG_OP = 'DELETE' OR v_changed_sensitive THEN
    PERFORM log_audit_event(
      auth.uid(),
      (SELECT email FROM auth.users WHERE id = auth.uid()),
      EXISTS(SELECT 1 FROM profiles WHERE id = auth.uid() AND is_admin = true),
      LOWER(TG_OP),
      'buyer',
      COALESCE(NEW.id, OLD.id),
      CASE WHEN TG_OP != 'INSERT' THEN to_jsonb(OLD) END,
      CASE WHEN TG_OP != 'DELETE' THEN to_jsonb(NEW) END,
      NULL
    );
  END IF;

  RETURN COALESCE(NEW, OLD);
END;
$$;


ALTER FUNCTION "public"."audit_buyer_changes"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."audit_profile_changes"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
BEGIN
  -- Log profile updates to audit table
  IF TG_OP = 'UPDATE' THEN
    INSERT INTO public.audit_logs (
      table_name, 
      operation, 
      old_data, 
      new_data, 
      user_id, 
      admin_id,
      metadata
    ) VALUES (
      TG_TABLE_NAME,
      TG_OP,
      to_jsonb(OLD),
      to_jsonb(NEW),
      NEW.id,
      auth.uid(),
      jsonb_build_object(
        'changed_fields', (
          SELECT jsonb_object_agg(old_row.key, jsonb_build_object('old', old_row.value, 'new', new_row.value))
          FROM jsonb_each(to_jsonb(OLD)) AS old_row(key, value)
          JOIN jsonb_each(to_jsonb(NEW)) AS new_row(key, value) ON old_row.key = new_row.key
          WHERE old_row.value IS DISTINCT FROM new_row.value
        )
      )
    );
  END IF;
  
  RETURN COALESCE(NEW, OLD);
END;
$$;


ALTER FUNCTION "public"."audit_profile_changes"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."auto_assign_deal_from_listing"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NEW.listing_id IS NOT NULL AND NEW.assigned_to IS NULL THEN
    SELECT primary_owner_id INTO NEW.assigned_to
    FROM public.listings
    WHERE id = NEW.listing_id
    AND primary_owner_id IS NOT NULL;

    IF NEW.assigned_to IS NOT NULL THEN
      NEW.owner_assigned_at := now();
    ELSE
      RAISE NOTICE 'auto_assign_deal_from_listing: listing % has no primary_owner_id; deal % inserted unassigned', NEW.listing_id, NEW.id;
    END IF;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."auto_assign_deal_from_listing"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."auto_assign_deal_from_listing"() IS 'Auto-assigns new deals to the admin who handled previous deals for the same listing';



CREATE OR REPLACE FUNCTION "public"."auto_create_contact_from_email"("p_email" "text", "p_source" "text" DEFAULT 'auto_detected'::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
DECLARE
  v_email TEXT;
  v_domain TEXT;
  v_firm_id UUID;
  v_firm_archived BOOLEAN;
  v_existing_id UUID;
  v_existing_archived BOOLEAN;
  v_new_id UUID;
  v_local TEXT;
  v_first_name TEXT;
  v_last_name TEXT;
BEGIN
  IF p_email IS NULL OR trim(p_email) = '' THEN RETURN NULL; END IF;
  v_email := lower(trim(p_email));
  IF position('@' IN v_email) = 0 THEN RETURN NULL; END IF;
  v_domain := split_part(v_email, '@', 2);
  IF v_domain IS NULL OR v_domain = '' THEN RETURN NULL; END IF;
  IF EXISTS (SELECT 1 FROM public.generic_email_domains WHERE domain = v_domain) THEN RETURN NULL; END IF;

  SELECT firm_id INTO v_firm_id FROM public.firm_domain_aliases WHERE domain = v_domain LIMIT 1;
  IF v_firm_id IS NULL THEN RETURN NULL; END IF;

  IF NOT EXISTS (SELECT 1 FROM public.firm_agreements WHERE id = v_firm_id) THEN RETURN NULL; END IF;

  SELECT id, archived INTO v_existing_id, v_existing_archived
  FROM public.contacts
  WHERE lower(email) = v_email
  ORDER BY archived ASC
  LIMIT 1;

  IF v_existing_id IS NOT NULL AND NOT v_existing_archived THEN RETURN v_existing_id; END IF;

  IF v_existing_id IS NOT NULL AND v_existing_archived THEN
    UPDATE public.contacts SET archived = false, source = p_source, updated_at = now()
     WHERE id = v_existing_id;
    RETURN v_existing_id;
  END IF;

  v_local := split_part(v_email, '@', 1);
  IF v_local IS NULL OR v_local = '' OR v_local !~ '[a-z]' THEN
    v_first_name := 'Unknown';
    v_last_name := '';
  ELSE
    v_first_name := initcap(split_part(v_local, '.', 1));
    v_last_name := CASE WHEN v_local LIKE '%.%' THEN initcap(split_part(v_local, '.', 2)) ELSE '' END;
    IF v_first_name !~ '^[A-Za-z]+$' THEN
      v_first_name := 'Unknown';
      v_last_name := '';
    END IF;
  END IF;

  BEGIN
    INSERT INTO public.contacts (first_name, last_name, email, firm_id, contact_type, source)
    VALUES (v_first_name, v_last_name, v_email, v_firm_id, 'buyer', p_source)
    RETURNING id INTO v_new_id;
  EXCEPTION WHEN unique_violation THEN
    SELECT id INTO v_new_id FROM public.contacts WHERE lower(email) = v_email LIMIT 1;
  END;

  RETURN v_new_id;
END;
$_$;


ALTER FUNCTION "public"."auto_create_contact_from_email"("p_email" "text", "p_source" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."auto_create_contact_from_email"("p_email" "text", "p_source" "text") IS 'Phase 3 of domain-based contact tracking. Creates a contact for the given email if its domain matches firm_domain_aliases and is not in generic_email_domains. Returns the contact id (new or existing), or NULL if no firm match / generic / malformed.';



CREATE OR REPLACE FUNCTION "public"."auto_create_deal_from_approved_connection"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_existing_deal_id     uuid;
  v_default_stage_id     uuid;
  v_buyer_contact_id     uuid;
  v_seller_contact_id    uuid;
  v_remarketing_buyer_id uuid;
  v_contact_name         text;
  v_listing_title        text;
  v_deal_title           text;
  v_nda_status           text;
  v_fee_status           text;
  v_source               text;
BEGIN
  IF NEW.status <> 'approved' OR COALESCE(OLD.status, '') = 'approved' THEN
    RETURN NEW;
  END IF;

  SELECT id
    INTO v_existing_deal_id
    FROM public.deal_pipeline
   WHERE connection_request_id = NEW.id
     AND deleted_at IS NULL
   LIMIT 1;

  IF v_existing_deal_id IS NOT NULL THEN
    RETURN NEW;
  END IF;

  SELECT id
    INTO v_default_stage_id
    FROM public.deal_stages
   WHERE is_active = true AND is_default = true
   LIMIT 1;

  IF v_default_stage_id IS NULL THEN
    SELECT id
      INTO v_default_stage_id
      FROM public.deal_stages
     WHERE is_active = true
     ORDER BY position ASC
     LIMIT 1;
  END IF;

  IF v_default_stage_id IS NULL THEN
    RAISE EXCEPTION
      'auto_create_deal_from_approved_connection: no active deal_stages found';
  END IF;

  -- First try: authenticated marketplace user.
  IF NEW.user_id IS NOT NULL THEN
    SELECT c.id, c.remarketing_buyer_id
      INTO v_buyer_contact_id, v_remarketing_buyer_id
      FROM public.contacts c
     WHERE c.profile_id = NEW.user_id
       AND c.contact_type = 'buyer'
       AND c.archived = false
     LIMIT 1;
  END IF;

  -- Fallback: match the lead email against the auto-created contact row
  -- (idx_contacts_buyer_email_unique guarantees at most one).
  IF v_buyer_contact_id IS NULL AND NEW.lead_email IS NOT NULL THEN
    SELECT c.id, c.remarketing_buyer_id
      INTO v_buyer_contact_id, v_remarketing_buyer_id
      FROM public.contacts c
     WHERE c.contact_type = 'buyer'
       AND c.archived = false
       AND c.email IS NOT NULL
       AND lower(c.email) = lower(NEW.lead_email)
     LIMIT 1;
  END IF;

  IF NEW.listing_id IS NOT NULL THEN
    SELECT c.id
      INTO v_seller_contact_id
      FROM public.contacts c
     WHERE c.listing_id = NEW.listing_id
       AND c.contact_type = 'seller'
       AND c.is_primary_seller_contact = true
       AND c.archived = false
     LIMIT 1;
  END IF;

  IF NEW.user_id IS NOT NULL THEN
    SELECT COALESCE(
             NULLIF(TRIM(COALESCE(p.first_name, '') || ' ' || COALESCE(p.last_name, '')), ''),
             p.email
           )
      INTO v_contact_name
      FROM public.profiles p
     WHERE p.id = NEW.user_id;
  END IF;

  v_contact_name := COALESCE(v_contact_name, NEW.lead_name, NEW.lead_email, 'Unknown');

  SELECT l.title
    INTO v_listing_title
    FROM public.listings l
   WHERE l.id = NEW.listing_id;

  v_deal_title := v_contact_name || ' - ' || COALESCE(v_listing_title, 'Unknown Listing');

  v_nda_status := CASE
    WHEN COALESCE(NEW.lead_nda_signed,     false) THEN 'signed'
    WHEN COALESCE(NEW.lead_nda_email_sent, false) THEN 'sent'
    ELSE 'not_sent'
  END;

  v_fee_status := CASE
    WHEN COALESCE(NEW.lead_fee_agreement_signed,     false) THEN 'signed'
    WHEN COALESCE(NEW.lead_fee_agreement_email_sent, false) THEN 'sent'
    ELSE 'not_sent'
  END;

  v_source := COALESCE(NEW.source, 'marketplace');

  INSERT INTO public.deal_pipeline (
    listing_id,
    stage_id,
    connection_request_id,
    buyer_contact_id,
    seller_contact_id,
    remarketing_buyer_id,
    value,
    probability,
    assigned_to,
    stage_entered_at,
    source,
    nda_status,
    fee_agreement_status,
    title,
    description,
    priority
  )
  VALUES (
    NEW.listing_id,
    v_default_stage_id,
    NEW.id,
    v_buyer_contact_id,
    v_seller_contact_id,
    v_remarketing_buyer_id,
    0,
    10,
    NEW.approved_by,
    now(),
    v_source,
    v_nda_status,
    v_fee_status,
    v_deal_title,
    COALESCE(NEW.user_message, 'Deal created from approved connection request'),
    'medium'
  );

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."auto_create_deal_from_approved_connection"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."auto_create_deal_from_approved_connection"() IS 'CANONICAL deal creation path for marketplace connection requests. Wraps the trigger body in log_trigger_error + re-raise so repeat regressions (schema drift, null approved_by, etc.) leave a durable audit trail in trigger_error_log. Rewritten 20260721, observability added 20260726.';



CREATE OR REPLACE FUNCTION "public"."auto_create_deal_from_connection_request"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  new_inquiry_stage_id uuid;
  deal_source_value text;
  contact_name_value text;
  buyer_priority_value integer;
BEGIN
  SELECT id INTO new_inquiry_stage_id
  FROM public.deal_stages
  WHERE name = 'New Inquiry'
  LIMIT 1;

  deal_source_value := CASE
    WHEN NEW.source IN ('website', 'marketplace', 'webflow', 'manual') THEN NEW.source
    ELSE 'marketplace'
  END;

  IF NEW.user_id IS NOT NULL THEN
    SELECT
      COALESCE(p.first_name || ' ' || p.last_name, p.email),
      COALESCE(calculate_buyer_priority_score(p.buyer_type), 0)
    INTO
      contact_name_value,
      buyer_priority_value
    FROM public.profiles p
    WHERE p.id = NEW.user_id;
  ELSE
    contact_name_value := NEW.lead_name;
    buyer_priority_value := COALESCE(NEW.buyer_priority_score, 0);
  END IF;

  INSERT INTO public.deal_pipeline (
    listing_id,
    stage_id,
    connection_request_id,
    value,
    probability,
    source,
    title,
    buyer_priority_score,
    nda_status,
    fee_agreement_status,
    created_at,
    stage_entered_at
  ) VALUES (
    NEW.listing_id,
    new_inquiry_stage_id,
    NEW.id,
    0,
    5,
    deal_source_value,
    COALESCE(
      contact_name_value || ' - ' || (SELECT title FROM public.listings WHERE id = NEW.listing_id),
      'New Deal'
    ),
    buyer_priority_value,
    CASE
      WHEN NEW.lead_nda_signed THEN 'signed'
      WHEN NEW.lead_nda_email_sent THEN 'sent'
      ELSE 'not_sent'
    END,
    CASE
      WHEN NEW.lead_fee_agreement_signed THEN 'signed'
      WHEN NEW.lead_fee_agreement_email_sent THEN 'sent'
      ELSE 'not_sent'
    END,
    NEW.created_at,
    NEW.created_at
  );

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."auto_create_deal_from_connection_request"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."auto_create_firm_member_for_lead"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Only process if firm_id and email exist
  IF NEW.firm_id IS NOT NULL AND NEW.email IS NOT NULL THEN
    -- Insert or update firm_member entry for this lead
    INSERT INTO public.firm_members (
      firm_id,
      member_type,
      lead_email,
      lead_name,
      lead_company,
      inbound_lead_id,
      added_at
    )
    VALUES (
      NEW.firm_id,
      'lead',
      NEW.email,
      NEW.name,
      NEW.company_name,
      NEW.id,
      NOW()
    )
    ON CONFLICT (firm_id, lead_email) 
    WHERE member_type = 'lead'
    DO UPDATE SET
      lead_name = EXCLUDED.lead_name,
      lead_company = EXCLUDED.lead_company,
      inbound_lead_id = EXCLUDED.inbound_lead_id,
      updated_at = NOW();
  END IF;
  
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."auto_create_firm_member_for_lead"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."auto_create_stage_tasks"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_template record;
  v_task jsonb;
  v_stage_name text;
  v_assignee_id uuid;
BEGIN
  IF OLD.stage_id IS NOT DISTINCT FROM NEW.stage_id THEN
    RETURN NEW;
  END IF;

  SELECT name INTO v_stage_name FROM public.deal_stages WHERE id = NEW.stage_id;
  IF v_stage_name IS NULL THEN
    RETURN NEW;
  END IF;

  v_assignee_id := NEW.assigned_to;

  FOR v_template IN
    SELECT * FROM public.task_templates
    WHERE is_active = true AND stage_trigger = v_stage_name
  LOOP
    FOR v_task IN SELECT * FROM jsonb_array_elements(v_template.tasks)
    LOOP
      INSERT INTO public.daily_standup_tasks (
        title, description, assignee_id, task_type, priority,
        status, due_date, entity_type, entity_id,
        deal_id, auto_generated, generation_source, template_id,
        source, created_at
      ) VALUES (
        v_task->>'title',
        v_task->>'description',
        v_assignee_id,
        COALESCE(v_task->>'task_type', 'other'),
        COALESCE(v_task->>'priority', 'medium'),
        'pending',
        CURRENT_DATE + (COALESCE((v_task->>'due_offset_days')::int, 3)),
        'deal',
        NEW.listing_id,   -- use listing_id so entity_id matches URL param
        NEW.id,           -- deal_id keeps deal_pipeline.id (guard_task_approval uses it)
        true,
        'stage_entry',
        v_template.id,
        'template',
        now()
      );
    END LOOP;

    PERFORM public.log_deal_activity(
      NEW.listing_id,   -- was NEW.id (deal_pipeline.id) — now correct listing UUID
      'task_created',
      format('Auto-created tasks from template: %s', v_template.name),
      format('Stage changed to %s — created %s tasks', v_stage_name, jsonb_array_length(v_template.tasks)),
      v_assignee_id,
      jsonb_build_object('template_id', v_template.id, 'stage', v_stage_name)
    );
  END LOOP;

  PERFORM public.log_deal_activity(
    NEW.listing_id,   -- was NEW.id (deal_pipeline.id)
    'stage_change',
    format('Stage changed to %s', v_stage_name),
    NULL,
    v_assignee_id,
    jsonb_build_object(
      'old_stage_id', OLD.stage_id,
      'new_stage_id', NEW.stage_id,
      'stage_name', v_stage_name
    )
  );

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."auto_create_stage_tasks"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."auto_generate_deal_identifier"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  attempts INTEGER := 0;
  max_attempts INTEGER := 10;
  candidate TEXT;
BEGIN
  IF NEW.deal_identifier IS NOT NULL AND NEW.deal_identifier != '' THEN
    RETURN NEW;
  END IF;

  LOOP
    attempts := attempts + 1;
    IF attempts > max_attempts THEN
      RAISE EXCEPTION 'Failed to generate unique deal_identifier after % attempts', max_attempts;
    END IF;

    candidate := public.generate_deal_identifier();

    IF NOT EXISTS (SELECT 1 FROM listings WHERE deal_identifier = candidate) THEN
      NEW.deal_identifier := candidate;
      RETURN NEW;
    END IF;
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."auto_generate_deal_identifier"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."auto_link_lead_to_firm"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_firm_id UUID;
  v_email_domain TEXT;
  v_normalized_company TEXT;
  v_generic_domains TEXT[] := ARRAY['gmail.com', 'yahoo.com', 'hotmail.com', 'outlook.com', 'icloud.com', 'aol.com', 'mail.com', 'protonmail.com'];
BEGIN
  -- Extract domain from lead email
  IF NEW.email IS NOT NULL THEN
    v_email_domain := extract_domain(NEW.email);
  END IF;

  -- Normalize company name
  IF NEW.company_name IS NOT NULL THEN
    v_normalized_company := normalize_company_name(NEW.company_name);
  END IF;

  -- Try to find existing firm (avoid generic email domains)
  IF v_normalized_company IS NOT NULL OR (v_email_domain IS NOT NULL AND v_email_domain <> ALL(v_generic_domains)) THEN
    SELECT id INTO v_firm_id
    FROM firm_agreements
    WHERE 
      (normalized_company_name = v_normalized_company AND v_normalized_company IS NOT NULL)
      OR (email_domain = v_email_domain AND v_email_domain IS NOT NULL AND v_email_domain <> ALL(v_generic_domains))
      OR (website_domain = v_email_domain AND v_email_domain IS NOT NULL AND v_email_domain <> ALL(v_generic_domains))
    LIMIT 1;
    
    -- If no firm found, create one
    IF v_firm_id IS NULL AND (NEW.company_name IS NOT NULL OR v_email_domain IS NOT NULL) THEN
      INSERT INTO firm_agreements (
        primary_company_name,
        normalized_company_name,
        email_domain,
        member_count,
        created_at,
        updated_at
      ) VALUES (
        COALESCE(NEW.company_name, v_email_domain),
        COALESCE(v_normalized_company, v_email_domain),
        CASE WHEN v_email_domain <> ALL(v_generic_domains) THEN v_email_domain ELSE NULL END,
        0,
        NOW(),
        NOW()
      )
      RETURNING id INTO v_firm_id;
    END IF;
    
    NEW.firm_id := v_firm_id;
  END IF;
  
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."auto_link_lead_to_firm"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."auto_link_user_to_firm"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_firm_id UUID;
  v_email_domain TEXT;
  v_website_domain TEXT;
  v_normalized_company TEXT;
  v_existing_lead_member_id UUID;
  v_generic_domains TEXT[] := ARRAY['gmail.com', 'yahoo.com', 'hotmail.com', 'outlook.com', 'icloud.com', 'aol.com', 'mail.com', 'protonmail.com'];
BEGIN
  BEGIN
    IF NEW.email IS NOT NULL THEN
      v_email_domain := extract_domain(NEW.email);
    END IF;
    
    IF NEW.website IS NOT NULL THEN
      v_website_domain := extract_domain(NEW.website);
    END IF;
    
    IF NEW.company IS NOT NULL AND NEW.company <> '' THEN
      v_normalized_company := normalize_company_name(NEW.company);
    END IF;
    
    IF v_normalized_company IS NOT NULL OR (v_email_domain IS NOT NULL AND v_email_domain <> ALL(v_generic_domains)) OR v_website_domain IS NOT NULL THEN
      SELECT id INTO v_firm_id
      FROM firm_agreements
      WHERE 
        (normalized_company_name = v_normalized_company AND v_normalized_company IS NOT NULL)
        OR (email_domain = v_email_domain AND v_email_domain IS NOT NULL AND v_email_domain <> ALL(v_generic_domains))
        OR (website_domain = v_website_domain AND v_website_domain IS NOT NULL)
      LIMIT 1;
      
      IF v_firm_id IS NULL THEN
        IF v_normalized_company IS NOT NULL THEN
          INSERT INTO firm_agreements (
            primary_company_name, normalized_company_name, email_domain, website_domain, member_count, created_at, updated_at
          ) VALUES (
            NEW.company, v_normalized_company,
            CASE WHEN v_email_domain <> ALL(v_generic_domains) THEN v_email_domain ELSE NULL END,
            v_website_domain, 0, NOW(), NOW()
          )
          RETURNING id INTO v_firm_id;
        ELSIF v_email_domain IS NOT NULL AND v_email_domain <> ALL(v_generic_domains) THEN
          INSERT INTO firm_agreements (
            primary_company_name, normalized_company_name, email_domain, website_domain, member_count, created_at, updated_at
          ) VALUES (
            v_email_domain, v_email_domain, v_email_domain, v_website_domain, 0, NOW(), NOW()
          )
          RETURNING id INTO v_firm_id;
        END IF;
      END IF;
      
      IF v_firm_id IS NOT NULL THEN
        SELECT id INTO v_existing_lead_member_id
        FROM firm_members
        WHERE firm_id = v_firm_id AND member_type = 'lead' AND LOWER(lead_email) = LOWER(NEW.email);
        
        IF v_existing_lead_member_id IS NOT NULL THEN
          DELETE FROM firm_members WHERE id = v_existing_lead_member_id;
          INSERT INTO firm_members (firm_id, user_id, member_type, added_at)
          VALUES (v_firm_id, NEW.id, 'marketplace_user', NOW())
          ON CONFLICT (firm_id, user_id) WHERE member_type = 'marketplace_user' DO NOTHING;
        ELSE
          INSERT INTO firm_members (firm_id, user_id, member_type, added_at)
          VALUES (v_firm_id, NEW.id, 'marketplace_user', NOW())
          ON CONFLICT (firm_id, user_id) WHERE member_type = 'marketplace_user' DO NOTHING;
        END IF;
        
        UPDATE firm_agreements
        SET member_count = (SELECT COUNT(*) FROM firm_members WHERE firm_id = v_firm_id), updated_at = NOW()
        WHERE id = v_firm_id;
        
        UPDATE profiles
        SET 
          fee_agreement_signed = CASE WHEN (SELECT fee_agreement_signed FROM firm_agreements WHERE id = v_firm_id) THEN TRUE ELSE fee_agreement_signed END,
          fee_agreement_signed_at = CASE WHEN (SELECT fee_agreement_signed FROM firm_agreements WHERE id = v_firm_id) AND NOT COALESCE(fee_agreement_signed, FALSE) THEN (SELECT fee_agreement_signed_at FROM firm_agreements WHERE id = v_firm_id) ELSE fee_agreement_signed_at END,
          nda_signed = CASE WHEN (SELECT nda_signed FROM firm_agreements WHERE id = v_firm_id) THEN TRUE ELSE nda_signed END,
          nda_signed_at = CASE WHEN (SELECT nda_signed FROM firm_agreements WHERE id = v_firm_id) AND NOT COALESCE(nda_signed, FALSE) THEN (SELECT nda_signed_at FROM firm_agreements WHERE id = v_firm_id) ELSE nda_signed_at END,
          updated_at = NOW()
        WHERE id = NEW.id;
      END IF;
    END IF;
  EXCEPTION WHEN OTHERS THEN
    RAISE NOTICE 'auto_link_user_to_firm failed for profile %: % %', NEW.id, SQLERRM, SQLSTATE;
    BEGIN
      INSERT INTO public.trigger_logs (trigger_name, error_message, user_id, created_at)
      VALUES ('auto_link_user_to_firm', SQLERRM || ' [' || SQLSTATE || ']', NEW.id, NOW());
    EXCEPTION WHEN OTHERS THEN
      NULL;
    END;
  END;
  
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."auto_link_user_to_firm"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."auto_recur_completed_task"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_next_due date;
  v_new_id uuid;
BEGIN
  IF NEW.status != 'completed' OR OLD.status = 'completed' THEN
    RETURN NEW;
  END IF;

  IF NEW.recurrence_rule IS NULL THEN
    RETURN NEW;
  END IF;

  v_next_due := CASE NEW.recurrence_rule
    WHEN 'daily' THEN CURRENT_DATE + 1
    WHEN 'weekly' THEN CURRENT_DATE + 7
    WHEN 'biweekly' THEN CURRENT_DATE + 14
    WHEN 'monthly' THEN CURRENT_DATE + 30
    ELSE CURRENT_DATE + 7
  END;

  INSERT INTO public.daily_standup_tasks (
    title, description, assignee_id, task_type, priority,
    status, due_date, entity_type, entity_id,
    deal_id, recurrence_rule, recurrence_parent_id,
    auto_generated, generation_source, source,
    created_at
  ) VALUES (
    NEW.title, NEW.description, NEW.assignee_id, NEW.task_type, NEW.priority,
    'pending', v_next_due, NEW.entity_type, NEW.entity_id,
    NEW.deal_id, NEW.recurrence_rule, COALESCE(NEW.recurrence_parent_id, NEW.id),
    true, 'recurrence', 'system',
    now()
  )
  RETURNING id INTO v_new_id;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."auto_recur_completed_task"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."auto_set_parent_pe_firm_fields"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  IF NEW.parent_pe_firm_id IS NOT NULL
     AND (OLD.parent_pe_firm_id IS DISTINCT FROM NEW.parent_pe_firm_id) THEN
    -- Set parent_pe_firm_name from the parent record
    SELECT company_name INTO NEW.parent_pe_firm_name
    FROM public.buyers
    WHERE id = NEW.parent_pe_firm_id;

    -- Ensure is_pe_backed is true
    NEW.is_pe_backed := true;
  ELSIF NEW.parent_pe_firm_id IS NULL
        AND OLD.parent_pe_firm_id IS NOT NULL THEN
    -- Clearing the parent link
    NEW.parent_pe_firm_name := NULL;
    NEW.is_pe_backed := false;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."auto_set_parent_pe_firm_fields"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."auto_upgrade_access_on_fee_agreement"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NEW.fee_agreement_status = 'signed'
     AND (OLD.fee_agreement_status IS DISTINCT FROM 'signed') THEN

    UPDATE data_room_access
    SET can_view_full_memo = true,
        can_view_data_room = true
    WHERE marketplace_user_id IN (
      SELECT p.id
      FROM profiles p
      WHERE p.company = NEW.primary_company_name
    )
    AND revoked_at IS NULL;
  END IF;

  RETURN NEW;
END;
$$;


