CREATE OR REPLACE FUNCTION "public"."autowire_buyer_id_from_contact"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
DECLARE
  resolved UUID;
  has_listing_col BOOLEAN;
BEGIN
  IF NEW.remarketing_buyer_id IS NOT NULL THEN RETURN NEW; END IF;
  IF NEW.contact_id IS NULL THEN RETURN NEW; END IF;

  -- Respect contact_activities_anchor_xor: if row is already
  -- listing-anchored, it's a deal-side row and should not get a buyer link.
  BEGIN
    EXECUTE format('SELECT ($1).listing_id IS NOT NULL') INTO has_listing_col USING NEW;
    IF has_listing_col THEN RETURN NEW; END IF;
  EXCEPTION WHEN undefined_column THEN
    -- Tables without listing_id (like smartlead_messages which has it,
    -- but no XOR against buyer) — fall through.
    NULL;
  END;

  BEGIN
    SELECT c.remarketing_buyer_id INTO resolved
    FROM public.contacts c WHERE c.id = NEW.contact_id LIMIT 1;
    IF resolved IS NOT NULL THEN
      NEW.remarketing_buyer_id := resolved;
    END IF;
  EXCEPTION WHEN OTHERS THEN
    RAISE NOTICE 'autowire_buyer_id_from_contact non-fatal: %', SQLERRM;
  END;

  RETURN NEW;
END;
$_$;


ALTER FUNCTION "public"."autowire_buyer_id_from_contact"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."bulk_update_connection_request_status"("request_ids" "uuid"[], "new_status" "text", "admin_notes" "text" DEFAULT NULL::"text") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  updated_count INT;
BEGIN
  UPDATE connection_requests
  SET
    status = new_status,
    decision_notes = COALESCE(admin_notes, decision_notes),
    decision_at = NOW(),
    updated_at = NOW()
  WHERE id = ANY(request_ids);

  GET DIAGNOSTICS updated_count = ROW_COUNT;
  RETURN updated_count;
END;
$$;


ALTER FUNCTION "public"."bulk_update_connection_request_status"("request_ids" "uuid"[], "new_status" "text", "admin_notes" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."calculate_buyer_priority_score"("buyer_type_param" "text") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN CASE 
    WHEN LOWER(buyer_type_param) LIKE '%pe%' OR LOWER(buyer_type_param) LIKE '%private equity%' THEN 5
    WHEN LOWER(buyer_type_param) LIKE '%corporate%' OR LOWER(buyer_type_param) LIKE '%strategic%' THEN 4
    WHEN LOWER(buyer_type_param) LIKE '%independent sponsor%' OR LOWER(buyer_type_param) LIKE '%family office%' THEN 3
    WHEN LOWER(buyer_type_param) LIKE '%search fund%' THEN 2
    WHEN LOWER(buyer_type_param) LIKE '%individual%' THEN 1
    ELSE 0
  END;
END;
$$;


ALTER FUNCTION "public"."calculate_buyer_priority_score"("buyer_type_param" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."calculate_buyer_priority_score"("p_buyer_type" "text", "p_company_name" "text", "p_annual_revenue" "text", "p_business_categories" "text"[], "p_target_locations" "text"[], "p_capital_available" "text", "p_acquisition_timeline" "text", "p_is_registered_user" boolean DEFAULT false) RETURNS integer
    LANGUAGE "plpgsql" IMMUTABLE
    SET "search_path" TO 'public'
    AS $_$
DECLARE
  score integer := 0;
BEGIN
  IF p_buyer_type = 'PE Firm' THEN score := score + 30;
  ELSIF p_buyer_type = 'Family Office' THEN score := score + 25;
  ELSIF p_buyer_type = 'Strategic Acquirer' THEN score := score + 20;
  ELSIF p_buyer_type = 'Search Fund' THEN score := score + 15;
  ELSIF p_buyer_type = 'Independent Sponsor' THEN score := score + 10;
  ELSE score := score + 5;
  END IF;

  IF p_capital_available = '$50M+' THEN score := score + 25;
  ELSIF p_capital_available = '$20M-$50M' THEN score := score + 20;
  ELSIF p_capital_available = '$10M-$20M' THEN score := score + 15;
  ELSIF p_capital_available = '$5M-$10M' THEN score := score + 10;
  ELSE score := score + 5;
  END IF;

  IF p_acquisition_timeline = 'Immediate (0-3 months)' THEN score := score + 20;
  ELSIF p_acquisition_timeline = 'Short-term (3-6 months)' THEN score := score + 15;
  ELSIF p_acquisition_timeline = 'Medium-term (6-12 months)' THEN score := score + 10;
  ELSE score := score + 5;
  END IF;

  IF p_is_registered_user THEN score := score + 10; END IF;
  IF p_company_name IS NOT NULL AND p_company_name != '' THEN score := score + 5; END IF;
  IF p_business_categories IS NOT NULL AND array_length(p_business_categories, 1) > 0 THEN score := score + 5; END IF;
  IF p_target_locations IS NOT NULL AND array_length(p_target_locations, 1) > 0 THEN score := score + 5; END IF;

  RETURN LEAST(score, 100);
END;
$_$;


ALTER FUNCTION "public"."calculate_buyer_priority_score"("p_buyer_type" "text", "p_company_name" "text", "p_annual_revenue" "text", "p_business_categories" "text"[], "p_target_locations" "text"[], "p_capital_available" "text", "p_acquisition_timeline" "text", "p_is_registered_user" boolean) OWNER TO "postgres";

SET default_tablespace = '';

SET default_table_access_method = "heap";


CREATE TABLE IF NOT EXISTS "public"."deal_pipeline" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "listing_id" "uuid",
    "stage_id" "uuid" NOT NULL,
    "connection_request_id" "uuid",
    "inbound_lead_id" "uuid",
    "title" "text" NOT NULL,
    "description" "text",
    "value" numeric DEFAULT 0,
    "priority" "text" DEFAULT 'medium'::"text",
    "probability" integer DEFAULT 50,
    "expected_close_date" "date",
    "assigned_to" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"(),
    "updated_at" timestamp with time zone DEFAULT "now"(),
    "stage_entered_at" timestamp with time zone DEFAULT "now"(),
    "source" "text" DEFAULT 'manual'::"text",
    "nda_status" "text" DEFAULT 'not_sent'::"text",
    "fee_agreement_status" "text" DEFAULT 'not_sent'::"text",
    "followed_up" boolean DEFAULT false,
    "followed_up_at" timestamp with time zone,
    "followed_up_by" "uuid",
    "buyer_priority_score" integer DEFAULT 0,
    "negative_followed_up" boolean DEFAULT false,
    "negative_followed_up_at" timestamp with time zone,
    "negative_followed_up_by" "uuid",
    "deleted_at" timestamp with time zone,
    "owner_assigned_at" timestamp with time zone,
    "owner_assigned_by" "uuid",
    "deal_score" integer,
    "last_enriched_at" timestamp with time zone,
    "remarketing_score_id" "uuid",
    "remarketing_buyer_id" "uuid",
    "meeting_scheduled" boolean DEFAULT false NOT NULL,
    "buyer_contact_id" "uuid",
    "seller_contact_id" "uuid",
    "contact_name" "text",
    "contact_company" "text",
    "contact_email" "text",
    "contact_phone" "text",
    "under_loi" boolean DEFAULT false,
    "first_reviewed_at" timestamp with time zone,
    "review_sla_hours" integer DEFAULT 48,
    "buyer_introduction_id" "uuid",
    "final_price" numeric,
    "closed_at" timestamp with time zone,
    "lost_reason" "text",
    "lost_reason_detail" "text",
    "lost_to_competitor" "text",
    "last_activity_at" timestamp with time zone DEFAULT "now"(),
    "follow_up_cadence_days" integer DEFAULT 7,
    CONSTRAINT "deal_pipeline_lost_reason_check" CHECK ((("lost_reason" IS NULL) OR ("lost_reason" = ANY (ARRAY['price_too_high'::"text", 'price_too_low'::"text", 'no_fit'::"text", 'competitor_won'::"text", 'buyer_walked'::"text", 'seller_walked'::"text", 'financing_failed'::"text", 'diligence_failed'::"text", 'timing'::"text", 'regulatory'::"text", 'other'::"text"])))),
    CONSTRAINT "deals_fee_agreement_status_check" CHECK (("fee_agreement_status" = ANY (ARRAY['not_sent'::"text", 'sent'::"text", 'signed'::"text", 'declined'::"text"]))),
    CONSTRAINT "deals_nda_status_check" CHECK (("nda_status" = ANY (ARRAY['not_sent'::"text", 'sent'::"text", 'signed'::"text", 'declined'::"text"]))),
    CONSTRAINT "deals_priority_check" CHECK (("priority" = ANY (ARRAY['low'::"text", 'medium'::"text", 'high'::"text", 'urgent'::"text"]))),
    CONSTRAINT "deals_probability_check" CHECK ((("probability" >= 0) AND ("probability" <= 100))),
    CONSTRAINT "deals_source_check" CHECK (("source" = ANY (ARRAY['manual'::"text", 'marketplace'::"text", 'webflow'::"text", 'salesforce'::"text", 'valuation_calculator'::"text", 'valuation_lead'::"text", 'smartlead'::"text", 'gp_partners'::"text", 'sourceco'::"text", 'captarget'::"text", 'match_tool'::"text", 'website'::"text", 'referral'::"text", 'salesforce_remarketing'::"text", 'remarketing'::"text", 'portal'::"text"])))
);


ALTER TABLE "public"."deal_pipeline" OWNER TO "postgres";


COMMENT ON COLUMN "public"."deal_pipeline"."stage_id" IS 'Required - every deal must have a stage. Foreign key has ON DELETE RESTRICT to prevent orphaned deals';



COMMENT ON COLUMN "public"."deal_pipeline"."assigned_to" IS 'Admin who owns this buyer relationship (Deal Owner)';



COMMENT ON COLUMN "public"."deal_pipeline"."deleted_at" IS 'Soft delete timestamp - when deal was deleted';



COMMENT ON COLUMN "public"."deal_pipeline"."owner_assigned_at" IS 'When the deal owner was first assigned';



COMMENT ON COLUMN "public"."deal_pipeline"."owner_assigned_by" IS 'Admin who assigned the deal owner (usually themselves)';



COMMENT ON COLUMN "public"."deal_pipeline"."final_price" IS 'Negotiated purchase price captured when the deal is marked Closed Won.';



COMMENT ON COLUMN "public"."deal_pipeline"."closed_at" IS 'Timestamp when the deal first entered a Closed Won or Closed Lost stage.';



COMMENT ON COLUMN "public"."deal_pipeline"."lost_reason" IS 'Categorical reason captured when the deal is marked Closed Lost.';



COMMENT ON COLUMN "public"."deal_pipeline"."lost_reason_detail" IS 'Free-text context about why the deal was lost.';



COMMENT ON COLUMN "public"."deal_pipeline"."lost_to_competitor" IS 'Optional name of the competing broker/buyer that won instead.';



CREATE OR REPLACE FUNCTION "public"."calculate_deal_buyer_priority"("deal_row" "public"."deal_pipeline") RETURNS integer
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  score INTEGER := 0;
  value_score INTEGER := 0;
  probability_score INTEGER := 0;
  urgency_score INTEGER := 0;
BEGIN
  CASE 
    WHEN deal_row.value >= 10000000 THEN value_score := 40;
    WHEN deal_row.value >= 5000000 THEN value_score := 30;
    WHEN deal_row.value >= 1000000 THEN value_score := 20;
    WHEN deal_row.value >= 500000 THEN value_score := 10;
    ELSE value_score := 5;
  END CASE;

  probability_score := LEAST(30, deal_row.probability * 30 / 100);

  CASE deal_row.priority
    WHEN 'urgent' THEN urgency_score := 30;
    WHEN 'high' THEN urgency_score := 20;
    WHEN 'medium' THEN urgency_score := 10;
    ELSE urgency_score := 5;
  END CASE;

  score := value_score + probability_score + urgency_score;

  IF deal_row.nda_status = 'signed' THEN score := score + 5; END IF;
  IF deal_row.fee_agreement_status = 'signed' THEN score := score + 5; END IF;

  RETURN score;
END;
$$;


ALTER FUNCTION "public"."calculate_deal_buyer_priority"("deal_row" "public"."deal_pipeline") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."calculate_engagement_score"("p_listings_viewed" integer, "p_listings_saved" integer, "p_connections_requested" integer, "p_total_session_time" integer) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  score INTEGER;
BEGIN
  -- Calculate weighted score (0-100)
  score := LEAST(p_listings_viewed / 10 * 30, 30) +
           LEAST(p_listings_saved / 5 * 30, 30) +
           LEAST(p_connections_requested * 10, 20) +
           LEAST(p_total_session_time / 3600 * 20, 20);
           
  RETURN GREATEST(LEAST(score, 100), 0);
END;
$$;


ALTER FUNCTION "public"."calculate_engagement_score"("p_listings_viewed" integer, "p_listings_saved" integer, "p_connections_requested" integer, "p_total_session_time" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."canonical_autowire_buyers"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  resolved_id UUID;
  nn TEXT;
  dn TEXT;
BEGIN
  -- Only act if company_id is null and we have a company_name to work with
  IF NEW.company_id IS NOT NULL OR NEW.company_name IS NULL THEN
    RETURN NEW;
  END IF;

  nn := public.normalize_name(NEW.company_name);
  IF nn IS NULL THEN RETURN NEW; END IF;

  BEGIN
    -- Try to find existing canonical row
    SELECT id INTO resolved_id FROM public.companies
    WHERE normalized_name = nn AND deleted_at IS NULL
    LIMIT 1;

    IF resolved_id IS NULL THEN
      -- Create new canonical row
      dn := NULLIF(REGEXP_REPLACE(
        LOWER(COALESCE(NULLIF(NEW.company_website,''), NULLIF(NEW.platform_website,''), NULLIF(NEW.pe_firm_website,''))),
        '^https?://(www\.)?', '', 'i'
      ), '');
      INSERT INTO public.companies (name, domain)
      VALUES (NEW.company_name, dn)
      ON CONFLICT DO NOTHING
      RETURNING id INTO resolved_id;

      -- Re-read in case another concurrent insert won the race
      IF resolved_id IS NULL THEN
        SELECT id INTO resolved_id FROM public.companies
        WHERE normalized_name = nn AND deleted_at IS NULL
        LIMIT 1;
      END IF;
    END IF;

    NEW.company_id := resolved_id;
  EXCEPTION WHEN OTHERS THEN
    RAISE NOTICE 'canonical_autowire_buyers failed for buyer %: %', NEW.id, SQLERRM;
  END;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."canonical_autowire_buyers"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."canonical_autowire_by_company_name"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  resolved_id UUID;
  norm TEXT;
BEGIN
  IF NEW.company_id IS NOT NULL THEN
    RETURN NEW;
  END IF;
  IF NEW.company_name IS NULL OR TRIM(NEW.company_name) = '' THEN
    RETURN NEW;
  END IF;

  BEGIN
    norm := public.normalize_name(NEW.company_name);
    IF norm IS NULL OR norm = '' THEN
      RETURN NEW;
    END IF;

    SELECT id INTO resolved_id
    FROM public.companies
    WHERE normalized_name = norm
      AND deleted_at IS NULL
    LIMIT 1;

    IF resolved_id IS NOT NULL THEN
      NEW.company_id := resolved_id;
    END IF;
  EXCEPTION WHEN OTHERS THEN
    RAISE NOTICE 'canonical_autowire_by_company_name: non-fatal error: %', SQLERRM;
  END;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."canonical_autowire_by_company_name"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."canonical_autowire_contacts"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  resolved_id UUID;
  ne TEXT;
  full_name_computed TEXT;
  resolved_company_id UUID;
BEGIN
  IF NEW.buyer_identity_id IS NOT NULL OR NEW.email IS NULL THEN
    RETURN NEW;
  END IF;

  ne := public.normalize_email(NEW.email);
  IF ne IS NULL THEN RETURN NEW; END IF;

  full_name_computed := NULLIF(TRIM(CONCAT(COALESCE(NEW.first_name,''), ' ', COALESCE(NEW.last_name,''))), '');

  BEGIN
    -- Resolve company_id via buyers if the contact has remarketing_buyer_id set
    IF NEW.remarketing_buyer_id IS NOT NULL THEN
      SELECT b.company_id INTO resolved_company_id
      FROM public.buyers b WHERE b.id = NEW.remarketing_buyer_id;
    END IF;

    -- Try to find existing buyer_identity by normalized email
    SELECT id INTO resolved_id FROM public.buyer_identities
    WHERE normalized_email = ne AND deleted_at IS NULL
    LIMIT 1;

    IF resolved_id IS NULL THEN
      INSERT INTO public.buyer_identities
        (full_name, primary_email, primary_contact_id, company_id)
      VALUES (full_name_computed, NEW.email, NEW.id, resolved_company_id)
      ON CONFLICT DO NOTHING
      RETURNING id INTO resolved_id;

      IF resolved_id IS NULL THEN
        SELECT id INTO resolved_id FROM public.buyer_identities
        WHERE normalized_email = ne AND deleted_at IS NULL
        LIMIT 1;
      END IF;
    ELSE
      -- Existing identity — best-effort merge: set primary_contact_id + company_id if not already set
      UPDATE public.buyer_identities
      SET primary_contact_id = COALESCE(primary_contact_id, NEW.id),
          company_id         = COALESCE(company_id, resolved_company_id),
          updated_at         = now()
      WHERE id = resolved_id;
    END IF;

    NEW.buyer_identity_id := resolved_id;
  EXCEPTION WHEN OTHERS THEN
    RAISE NOTICE 'canonical_autowire_contacts failed for contact %: %', NEW.id, SQLERRM;
  END;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."canonical_autowire_contacts"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."canonical_autowire_listings"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  resolved_id UUID;
  nn TEXT;
  dn TEXT;
BEGIN
  IF NEW.owner_company_id IS NOT NULL OR NEW.internal_company_name IS NULL THEN
    RETURN NEW;
  END IF;

  nn := public.normalize_name(NEW.internal_company_name);
  IF nn IS NULL THEN RETURN NEW; END IF;

  BEGIN
    SELECT id INTO resolved_id FROM public.companies
    WHERE normalized_name = nn AND deleted_at IS NULL
    LIMIT 1;

    IF resolved_id IS NULL THEN
      dn := NULLIF(REGEXP_REPLACE(LOWER(NULLIF(NEW.website,'')), '^https?://(www\.)?', '', 'i'), '');
      INSERT INTO public.companies (name, domain)
      VALUES (NEW.internal_company_name, dn)
      ON CONFLICT DO NOTHING
      RETURNING id INTO resolved_id;

      IF resolved_id IS NULL THEN
        SELECT id INTO resolved_id FROM public.companies
        WHERE normalized_name = nn AND deleted_at IS NULL
        LIMIT 1;
      END IF;
    END IF;

    NEW.owner_company_id := resolved_id;
  EXCEPTION WHEN OTHERS THEN
    RAISE NOTICE 'canonical_autowire_listings failed for listing %: %', NEW.id, SQLERRM;
  END;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."canonical_autowire_listings"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."canonical_autowire_profiles"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  resolved_id UUID;
  ne TEXT;
  full_name_computed TEXT;
  resolved_company_id UUID;
  co_name TEXT;
BEGIN
  IF NEW.buyer_identity_id IS NOT NULL OR NEW.email IS NULL THEN
    RETURN NEW;
  END IF;

  ne := public.normalize_email(NEW.email);
  IF ne IS NULL THEN RETURN NEW; END IF;

  full_name_computed := NULLIF(TRIM(CONCAT(COALESCE(NEW.first_name,''), ' ', COALESCE(NEW.last_name,''))), '');
  co_name := COALESCE(NULLIF(NEW.company_name,''), NULLIF(NEW.company,''));

  BEGIN
    -- Resolve company_id by company_name if present
    IF co_name IS NOT NULL THEN
      SELECT id INTO resolved_company_id FROM public.companies
      WHERE normalized_name = public.normalize_name(co_name) AND deleted_at IS NULL
      LIMIT 1;
    END IF;

    SELECT id INTO resolved_id FROM public.buyer_identities
    WHERE normalized_email = ne AND deleted_at IS NULL
    LIMIT 1;

    IF resolved_id IS NULL THEN
      INSERT INTO public.buyer_identities
        (full_name, primary_email, profile_id, company_id)
      VALUES (full_name_computed, NEW.email, NEW.id, resolved_company_id)
      ON CONFLICT DO NOTHING
      RETURNING id INTO resolved_id;

      IF resolved_id IS NULL THEN
        SELECT id INTO resolved_id FROM public.buyer_identities
        WHERE normalized_email = ne AND deleted_at IS NULL
        LIMIT 1;
      END IF;
    ELSE
      UPDATE public.buyer_identities
      SET profile_id = COALESCE(profile_id, NEW.id),
          company_id = COALESCE(company_id, resolved_company_id),
          updated_at = now()
      WHERE id = resolved_id;
    END IF;

    NEW.buyer_identity_id := resolved_id;
  EXCEPTION WHEN OTHERS THEN
    RAISE NOTICE 'canonical_autowire_profiles failed for profile %: %', NEW.id, SQLERRM;
  END;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."canonical_autowire_profiles"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."cascade_pe_firm_name_change"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  IF NEW.company_name IS DISTINCT FROM OLD.company_name
     AND NEW.buyer_type = 'private_equity' THEN
    UPDATE public.buyers
    SET parent_pe_firm_name = NEW.company_name
    WHERE parent_pe_firm_id = NEW.id;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."cascade_pe_firm_name_change"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."cascade_soft_delete_listing"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF OLD.deleted_at IS NULL AND NEW.deleted_at IS NOT NULL THEN
    UPDATE public.deal_pipeline SET deleted_at = NEW.deleted_at WHERE listing_id = NEW.id AND deleted_at IS NULL;
  END IF;
  IF OLD.deleted_at IS NOT NULL AND NEW.deleted_at IS NULL THEN
    UPDATE public.deal_pipeline SET deleted_at = NULL WHERE listing_id = NEW.id AND deleted_at = OLD.deleted_at;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."cascade_soft_delete_listing"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."change_user_role"("_target_user_id" "uuid", "_new_role" "text", "_reason" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  _caller_role text;
BEGIN
  IF _new_role NOT IN ('owner', 'admin', 'moderator', 'viewer') THEN
    RAISE EXCEPTION 'Invalid role: %. Must be owner, admin, moderator, or viewer.', _new_role;
  END IF;

  SELECT role INTO _caller_role
  FROM public.user_roles
  WHERE user_id = auth.uid();

  IF _caller_role IS DISTINCT FROM 'owner' THEN
    RAISE EXCEPTION 'Only owners can change user roles';
  END IF;

  INSERT INTO public.user_roles (user_id, role, granted_by, reason)
  VALUES (_target_user_id, _new_role::app_role, auth.uid(), _reason)
  ON CONFLICT (user_id)
  DO UPDATE SET
    role = EXCLUDED.role,
    granted_by = EXCLUDED.granted_by,
    granted_at = now(),
    reason = EXCLUDED.reason;

  INSERT INTO public.permission_audit_log (target_user_id, changed_by, old_role, new_role, reason)
  VALUES (
    _target_user_id,
    auth.uid(),
    (SELECT role FROM public.user_roles WHERE user_id = _target_user_id),
    _new_role::app_role,
    _reason
  );
END;
$$;


ALTER FUNCTION "public"."change_user_role"("_target_user_id" "uuid", "_new_role" "text", "_reason" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."change_user_role"("target_user_id" "uuid", "new_role" "public"."app_role", "change_reason" "text" DEFAULT NULL::"text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  caller_id UUID;
  caller_role public.app_role;
  old_role public.app_role;
  target_email TEXT;
  target_current_role public.app_role;
BEGIN
  caller_id := auth.uid();
  caller_role := public.get_user_role(caller_id);

  IF caller_role NOT IN ('owner', 'admin') THEN
    RAISE EXCEPTION 'Only owners and admins can change user roles';
  END IF;

  IF caller_role = 'admin' THEN
    IF new_role NOT IN ('moderator', 'viewer') THEN
      RAISE EXCEPTION 'Admins can only assign Team Member or Viewer roles';
    END IF;
  END IF;

  target_current_role := public.get_user_role(target_user_id);

  IF target_current_role = 'owner' AND new_role != 'owner' THEN
    IF caller_id = target_user_id THEN
      RAISE EXCEPTION 'Owners cannot demote themselves';
    END IF;
    RAISE EXCEPTION 'Cannot demote an owner. This must be changed at the database level.';
  END IF;

  IF new_role = 'owner' AND caller_role != 'owner' THEN
    RAISE EXCEPTION 'Only owners can promote users to owner';
  END IF;

  IF caller_role = 'admin' AND target_current_role IN ('admin', 'owner') THEN
    RAISE EXCEPTION 'Admins cannot modify other admins or owners';
  END IF;

  SELECT email INTO target_email FROM auth.users WHERE id = target_user_id;
  old_role := target_current_role;

  DELETE FROM public.user_roles WHERE user_id = target_user_id;

  INSERT INTO public.user_roles (user_id, role, granted_by, reason)
  VALUES (target_user_id, new_role, caller_id, change_reason);

  INSERT INTO public.permission_audit_log (
    target_user_id, changed_by, old_role, new_role, reason
  ) VALUES (
    target_user_id, caller_id, old_role, new_role, change_reason
  );

  UPDATE public.profiles
  SET
    is_admin = (new_role IN ('owner', 'admin', 'moderator')),
    updated_at = NOW()
  WHERE id = target_user_id;

  RETURN TRUE;
END;
$$;


ALTER FUNCTION "public"."change_user_role"("target_user_id" "uuid", "new_role" "public"."app_role", "change_reason" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."check_agreement_coverage"("p_email" "text", "p_agreement_type" "text" DEFAULT 'nda'::"text") RETURNS TABLE("is_covered" boolean, "coverage_source" "text", "firm_id" "uuid", "firm_name" "text", "agreement_status" "text", "signed_by_name" "text", "signed_at" timestamp with time zone, "parent_firm_name" "text", "expires_at" timestamp with time zone)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_domain TEXT;
  v_is_generic BOOLEAN := false;
  v_firm_id UUID;
  v_parent_buyer_id UUID;
  v_parent_firm_id UUID;
  v_table_exists BOOLEAN;
BEGIN
  v_domain := lower(split_part(p_email, '@', 2));

  IF v_domain IS NULL OR v_domain = '' THEN
    RETURN QUERY SELECT false, 'not_covered'::TEXT, NULL::UUID, NULL::TEXT,
      'not_started'::TEXT, NULL::TEXT, NULL::TIMESTAMPTZ, NULL::TEXT, NULL::TIMESTAMPTZ;
    RETURN;
  END IF;

  -- Check generic domain blocklist with fallback if table missing
  SELECT EXISTS (
    SELECT 1 FROM information_schema.tables
    WHERE table_schema = 'public' AND table_name = 'generic_email_domains'
  ) INTO v_table_exists;

  IF v_table_exists THEN
    SELECT EXISTS (
      SELECT 1 FROM public.generic_email_domains WHERE generic_email_domains.domain = v_domain
    ) INTO v_is_generic;
  ELSE
    v_is_generic := v_domain = ANY(ARRAY[
      'gmail.com','googlemail.com','yahoo.com','hotmail.com','outlook.com',
      'aol.com','icloud.com','me.com','mac.com','live.com','msn.com',
      'mail.com','zoho.com','yandex.com','gmx.com','gmx.net',
      'protonmail.com','proton.me','pm.me','fastmail.com','tutanota.com','hey.com',
      'comcast.net','att.net','sbcglobal.net','verizon.net','cox.net',
      'charter.net','earthlink.net','bellsouth.net'
    ]);
  END IF;

  -- For NON-generic domains: try direct domain lookup
  IF NOT v_is_generic THEN
    IF p_agreement_type = 'nda' THEN
      RETURN QUERY
      SELECT
        fa.nda_status = 'signed' AND (fa.nda_expires_at IS NULL OR fa.nda_expires_at > now()),
        'direct'::TEXT,
        fa.id,
        fa.primary_company_name,
        fa.nda_status,
        fa.nda_signed_by_name,
        fa.nda_signed_at,
        NULL::TEXT,
        fa.nda_expires_at
      FROM public.firm_agreements fa
      WHERE fa.email_domain = v_domain
         OR fa.website_domain = v_domain
         OR EXISTS (SELECT 1 FROM public.firm_domain_aliases fda WHERE fda.firm_id = fa.id AND fda.domain = v_domain)
      LIMIT 1;
      IF FOUND THEN RETURN; END IF;
    ELSE
      RETURN QUERY
      SELECT
        fa.fee_agreement_status = 'signed' AND (fa.fee_agreement_expires_at IS NULL OR fa.fee_agreement_expires_at > now()),
        'direct'::TEXT,
        fa.id,
        fa.primary_company_name,
        fa.fee_agreement_status,
        fa.fee_agreement_signed_by_name,
        fa.fee_agreement_signed_at,
        NULL::TEXT,
        fa.fee_agreement_expires_at
      FROM public.firm_agreements fa
      WHERE fa.email_domain = v_domain
         OR fa.website_domain = v_domain
         OR EXISTS (SELECT 1 FROM public.firm_domain_aliases fda WHERE fda.firm_id = fa.id AND fda.domain = v_domain)
      LIMIT 1;
      IF FOUND THEN RETURN; END IF;
    END IF;

    -- For NON-generic domains: try PE firm parent lookup
    SELECT rb.pe_firm_id INTO v_parent_buyer_id
    FROM public.remarketing_buyers rb
    WHERE rb.pe_firm_id IS NOT NULL
      AND rb.archived = false
      AND (rb.email_domain = v_domain OR extract_domain(rb.company_website) = v_domain)
    LIMIT 1;

    IF v_parent_buyer_id IS NOT NULL THEN
      IF p_agreement_type = 'nda' THEN
        RETURN QUERY
        SELECT
          fa.nda_status = 'signed' AND (fa.nda_expires_at IS NULL OR fa.nda_expires_at > now()),
          'pe_parent'::TEXT,
          fa.id,
          fa.primary_company_name,
          fa.nda_status,
          fa.nda_signed_by_name,
          fa.nda_signed_at,
          parent_rb.company_name,
          fa.nda_expires_at
        FROM public.remarketing_buyers parent_rb
        LEFT JOIN public.firm_agreements fa ON (
          fa.email_domain = parent_rb.email_domain
          OR fa.website_domain = extract_domain(parent_rb.company_website)
        )
        WHERE parent_rb.id = v_parent_buyer_id
          AND fa.id IS NOT NULL
        LIMIT 1;
        IF FOUND THEN RETURN; END IF;
      ELSE
        RETURN QUERY
        SELECT
          fa.fee_agreement_status = 'signed' AND (fa.fee_agreement_expires_at IS NULL OR fa.fee_agreement_expires_at > now()),
          'pe_parent'::TEXT,
          fa.id,
          fa.primary_company_name,
          fa.fee_agreement_status,
          fa.fee_agreement_signed_by_name,
          fa.fee_agreement_signed_at,
          parent_rb.company_name,
          fa.fee_agreement_expires_at
        FROM public.remarketing_buyers parent_rb
        LEFT JOIN public.firm_agreements fa ON (
          fa.email_domain = parent_rb.email_domain
          OR fa.website_domain = extract_domain(parent_rb.company_website)
        )
        WHERE parent_rb.id = v_parent_buyer_id
          AND fa.id IS NOT NULL
        LIMIT 1;
        IF FOUND THEN RETURN; END IF;
      END IF;
    END IF;
  END IF;

  -- ALWAYS try firm_member lookup (critical for generic domain users like Gmail)
  IF p_agreement_type = 'nda' THEN
    RETURN QUERY
    SELECT
      fa.nda_status = 'signed' AND (fa.nda_expires_at IS NULL OR fa.nda_expires_at > now()),
      'firm_member'::TEXT,
      fa.id,
      fa.primary_company_name,
      fa.nda_status,
      fa.nda_signed_by_name,
      fa.nda_signed_at,
      NULL::TEXT,
      fa.nda_expires_at
    FROM public.firm_members fm
    JOIN public.firm_agreements fa ON fa.id = fm.firm_id
    JOIN public.profiles p ON p.id = fm.user_id
    WHERE p.email = p_email
    LIMIT 1;
    IF FOUND THEN RETURN; END IF;
  ELSE
    RETURN QUERY
    SELECT
      fa.fee_agreement_status = 'signed' AND (fa.fee_agreement_expires_at IS NULL OR fa.fee_agreement_expires_at > now()),
      'firm_member'::TEXT,
      fa.id,
      fa.primary_company_name,
      fa.fee_agreement_status,
      fa.fee_agreement_signed_by_name,
      fa.fee_agreement_signed_at,
      NULL::TEXT,
      fa.fee_agreement_expires_at
    FROM public.firm_members fm
    JOIN public.firm_agreements fa ON fa.id = fm.firm_id
    JOIN public.profiles p ON p.id = fm.user_id
    WHERE p.email = p_email
    LIMIT 1;
    IF FOUND THEN RETURN; END IF;
  END IF;

  -- Not covered
  RETURN QUERY SELECT false, 'not_covered'::TEXT, NULL::UUID, NULL::TEXT,
    'not_started'::TEXT, NULL::TEXT, NULL::TIMESTAMPTZ, NULL::TEXT, NULL::TIMESTAMPTZ;
END;
$$;


ALTER FUNCTION "public"."check_agreement_coverage"("p_email" "text", "p_agreement_type" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."check_data_room_access"("p_deal_id" "uuid", "p_user_id" "uuid", "p_category" "text") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT EXISTS (
    SELECT 1
    FROM data_room_access a
    WHERE a.marketplace_user_id = p_user_id
      AND a.revoked_at IS NULL
      AND (a.expires_at IS NULL OR a.expires_at > now())
      AND (
        a.deal_id = p_deal_id
        OR
        a.deal_id IN (SELECT l.id FROM listings l WHERE l.source_deal_id = p_deal_id)
      )
      AND (
        (p_category = 'anonymous_teaser' AND a.can_view_teaser = true)
        OR (p_category = 'full_memo' AND a.can_view_full_memo = true)
        OR (p_category = 'data_room' AND a.can_view_data_room = true)
      )
  );
$$;


ALTER FUNCTION "public"."check_data_room_access"("p_deal_id" "uuid", "p_user_id" "uuid", "p_category" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."check_linkedin_profile_available"("p_linkedin_url" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_normalized text;
  v_taken      boolean;
BEGIN
  -- Strict: empty/whitespace input is always available
  IF p_linkedin_url IS NULL OR btrim(p_linkedin_url) = '' THEN
    RETURN jsonb_build_object('available', true, 'reason', 'empty_input');
  END IF;

  v_normalized := public.normalize_linkedin_url(p_linkedin_url);

  -- Defensive: normalization yielding empty/null is treated as empty input
  IF v_normalized IS NULL OR btrim(v_normalized) = '' THEN
    RETURN jsonb_build_object('available', true, 'reason', 'empty_input');
  END IF;

  SELECT EXISTS (
    SELECT 1
    FROM public.profiles p
    WHERE public.normalize_linkedin_url(p.linkedin_url) = v_normalized
      AND p.deleted_at IS NULL
      AND p.merged_into_profile_id IS NULL
  ) INTO v_taken;

  IF v_taken THEN
    RETURN jsonb_build_object('available', false, 'reason', 'taken');
  END IF;

  RETURN jsonb_build_object('available', true, 'reason', 'not_taken');
END;
$$;


ALTER FUNCTION "public"."check_linkedin_profile_available"("p_linkedin_url" "text") OWNER TO "postgres";


