CREATE OR REPLACE FUNCTION "public"."check_parent_pe_firm_depth"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  IF NEW.parent_pe_firm_id IS NOT NULL THEN
    -- The referenced parent must not itself have a parent
    IF EXISTS (
      SELECT 1 FROM public.buyers
      WHERE id = NEW.parent_pe_firm_id
        AND parent_pe_firm_id IS NOT NULL
    ) THEN
      RAISE EXCEPTION 'Parent PE firm cannot itself have a parent (max depth = 1)';
    END IF;

    -- Also prevent a PE firm from being set as a child if it has children
    IF EXISTS (
      SELECT 1 FROM public.buyers
      WHERE parent_pe_firm_id = NEW.id
    ) THEN
      RAISE EXCEPTION 'This record has portfolio companies and cannot be made a child of another PE firm';
    END IF;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."check_parent_pe_firm_depth"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."check_portal_push_update"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF is_admin(auth.uid()) THEN
    RETURN NEW;
  END IF;

  IF NEW.push_note IS DISTINCT FROM OLD.push_note
    OR NEW.priority IS DISTINCT FROM OLD.priority
    OR NEW.deal_snapshot IS DISTINCT FROM OLD.deal_snapshot
    OR NEW.pushed_by IS DISTINCT FROM OLD.pushed_by
    OR NEW.listing_id IS DISTINCT FROM OLD.listing_id
    OR NEW.portal_org_id IS DISTINCT FROM OLD.portal_org_id
    OR NEW.response_due_by IS DISTINCT FROM OLD.response_due_by
    OR NEW.reminder_count IS DISTINCT FROM OLD.reminder_count
    OR NEW.last_reminder_at IS DISTINCT FROM OLD.last_reminder_at
    OR NEW.data_room_access_token IS DISTINCT FROM OLD.data_room_access_token
  THEN
    RAISE EXCEPTION 'Portal users can only update status and view tracking fields';
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."check_portal_push_update"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."check_scores_freshness"("p_listing_id" "uuid", "p_max_age_hours" integer DEFAULT 24) RETURNS TABLE("has_scores" boolean, "score_count" integer, "oldest_score_age_hours" numeric, "is_fresh" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    COUNT(*) > 0 AS has_scores,
    COUNT(*)::INTEGER AS score_count,
    COALESCE(
      EXTRACT(EPOCH FROM (now() - MIN(rs.scored_at))) / 3600.0,
      0
    )::NUMERIC AS oldest_score_age_hours,
    CASE
      WHEN COUNT(*) = 0 THEN false
      WHEN MIN(rs.scored_at) IS NULL THEN false
      WHEN MIN(rs.scored_at) > now() - (p_max_age_hours || ' hours')::INTERVAL THEN true
      ELSE false
    END AS is_fresh
  FROM remarketing_scores rs
  WHERE rs.listing_id = p_listing_id
    AND (rs.is_disqualified IS NOT TRUE);
END;
$$;


ALTER FUNCTION "public"."check_scores_freshness"("p_listing_id" "uuid", "p_max_age_hours" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."check_scores_freshness"("p_listing_id" "uuid", "p_max_age_hours" integer) IS 'Returns score freshness info for a listing. Frontend uses this to decide whether to trigger auto-scoring. Prevents redundant scoring runs.';



CREATE OR REPLACE FUNCTION "public"."check_task_auto_completion"() RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_rule       record;
  v_task       record;
  v_match      boolean;
  v_listing_id uuid;
BEGIN
  FOR v_rule IN
    SELECT * FROM public.task_auto_completion_rules WHERE is_active = true
  LOOP
    FOR v_task IN
      SELECT id, deal_id, entity_id, entity_type, title
      FROM public.daily_standup_tasks
      WHERE task_type = v_rule.task_type
        AND status IN ('pending', 'in_progress')
        AND deal_id IS NOT NULL
    LOOP
      BEGIN
        IF v_rule.trigger_value = 'EXISTS' THEN
          EXECUTE format(
            'SELECT EXISTS(SELECT 1 FROM %I WHERE %I IS NOT NULL LIMIT 1)',
            v_rule.watch_table, v_rule.watch_column
          ) INTO v_match;
        ELSIF v_rule.match_via = 'deal_id' THEN
          EXECUTE format(
            'SELECT EXISTS(SELECT 1 FROM %I WHERE %I = %L AND id = %L LIMIT 1)',
            v_rule.watch_table, v_rule.watch_column, v_rule.trigger_value, v_task.deal_id
          ) INTO v_match;
        ELSE
          EXECUTE format(
            'SELECT EXISTS(SELECT 1 FROM %I WHERE %I = %L LIMIT 1)',
            v_rule.watch_table, v_rule.watch_column, v_rule.trigger_value
          ) INTO v_match;
        END IF;
      EXCEPTION WHEN OTHERS THEN
        v_match := false;
      END;

      IF v_match THEN
        UPDATE public.daily_standup_tasks
        SET status          = 'completed',
            completed_at    = now(),
            completion_notes = format('Auto-completed: %s', v_rule.description)
        WHERE id = v_task.id;

        SELECT listing_id INTO v_listing_id
        FROM public.deal_pipeline
        WHERE id = v_task.deal_id;

        IF v_listing_id IS NOT NULL THEN
          PERFORM public.log_deal_activity(
            v_listing_id,
            'task_completed',
            format('Auto-completed: %s', v_task.title),
            v_rule.description,
            NULL,
            jsonb_build_object('auto_completed', true, 'rule_id', v_rule.id)
          );
        END IF;
      END IF;
    END LOOP;
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."check_task_auto_completion"() OWNER TO "postgres";


