CREATE OR REPLACE FUNCTION "public"."claim_events"("p_event_type" "text", "p_processor" "text", "p_batch_size" integer DEFAULT 10) RETURNS SETOF "public"."global_activity_queue"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  WITH claimable AS (
    SELECT id
    FROM public.global_activity_queue
    WHERE event_type = p_event_type
      AND processed_at IS NULL
    ORDER BY created_at ASC
    LIMIT p_batch_size
    FOR UPDATE SKIP LOCKED
  )
  UPDATE public.global_activity_queue AS q
  SET
    processed_at = now(),
    processor    = p_processor
  FROM claimable
  WHERE q.id = claimable.id
  RETURNING q.*;
END;
$$;


