CREATE OR REPLACE FUNCTION "public"."cleanup_phantom_phone"("p_dry_run" boolean DEFAULT true) RETURNS TABLE("action" "text", "contact_id" "uuid", "slot" "text", "old_value" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_is_admin BOOLEAN;
BEGIN
  SELECT public.is_admin(auth.uid()) INTO v_is_admin;
  IF NOT COALESCE(v_is_admin, false) THEN
    RAISE EXCEPTION 'Access denied: admin role required to clean phantom phone'
      USING ERRCODE = '42501';
  END IF;

  RETURN QUERY
  WITH hits AS (
    SELECT
      c.id,
      'phone'::text AS slot,
      c.phone       AS val
    FROM public.contacts c
    WHERE regexp_replace(coalesce(c.phone, ''), '\D', '', 'g') LIKE '%8003918892%'
  ),
  updated AS (
    UPDATE public.contacts c
    SET
      phone      = NULL,
      updated_at = now()
    WHERE NOT p_dry_run
      AND regexp_replace(coalesce(c.phone, ''), '\D', '', 'g') LIKE '%8003918892%'
    RETURNING c.id
  )
  SELECT
    CASE WHEN p_dry_run THEN 'WOULD_CLEAR' ELSE 'CLEARED' END AS action,
    hits.id AS contact_id,
    hits.slot,
    hits.val AS old_value
  FROM hits
  -- Force updated CTE to execute even in dry-run (no-op when p_dry_run=true)
  LEFT JOIN updated u ON u.id = hits.id OR p_dry_run;
END;
$$;


ALTER FUNCTION "public"."cleanup_phantom_phone"("p_dry_run" boolean) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."cleanup_phantom_phone"("p_dry_run" boolean) IS 'Ticket 16 remediation — clears the phantom (800) 391-8892 from contacts.phone. Dry-run by default; pass p_dry_run=false to actually wipe. Admin-gated. Run the diagnostic views first (phantom_phone_contacts, phantom_phone_buyers, phoneburner_phantom_contacts) to identify the source BEFORE wiping — otherwise the phantom will re-populate on the next sync.';



