CREATE OR REPLACE FUNCTION "public"."compute_daily_enrichment_cost_summary"() RETURNS TABLE("total_24h_usd" numeric, "total_7d_usd" numeric, "alert_raised" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
DECLARE
  v_run_at      TIMESTAMPTZ := now();
  v_24h_start   TIMESTAMPTZ := now() - INTERVAL '24 hours';
  v_7d_start    TIMESTAMPTZ := now() - INTERVAL '7 days';
  v_threshold   NUMERIC(10,2);
  v_enabled     BOOLEAN;
  v_notify_sup  BOOLEAN;
  v_total_24h   NUMERIC := 0;
  v_total_7d    NUMERIC := 0;
  v_by_provider JSONB := '{}'::jsonb;
  v_by_function JSONB := '{}'::jsonb;
  v_alert_id    UUID;
  v_breakdown   RECORD;
  v_alerted     BOOLEAN := false;
BEGIN
  -- Read config (single row).
  SELECT daily_threshold_usd, enabled, notify_support_inbox
    INTO v_threshold, v_enabled, v_notify_sup
    FROM public.enrichment_cost_alert_config
   WHERE id = 1;

  IF v_threshold IS NULL THEN
    -- Config row missing — fall back to safe defaults.
    v_threshold := 100.00;
    v_enabled   := true;
    v_notify_sup := false;
  END IF;

  -- ── 24h snapshot rows: provider × function_name ──
  INSERT INTO public.daily_enrichment_cost_summary
    (run_at, window_label, window_start, window_end,
     provider, function_name, call_count, input_tokens, output_tokens, total_usd)
  SELECT
    v_run_at, '24h', v_24h_start, v_run_at,
    COALESCE(provider, 'unknown'),
    COALESCE(function_name, 'unknown'),
    COUNT(*),
    COALESCE(SUM(input_tokens), 0),
    COALESCE(SUM(output_tokens), 0),
    COALESCE(SUM(estimated_cost_usd), 0)
  FROM public.enrichment_cost_log
  WHERE created_at >= v_24h_start
    AND created_at <  v_run_at
  GROUP BY provider, function_name;

  -- ── 7d snapshot rows: provider × function_name ──
  INSERT INTO public.daily_enrichment_cost_summary
    (run_at, window_label, window_start, window_end,
     provider, function_name, call_count, input_tokens, output_tokens, total_usd)
  SELECT
    v_run_at, '7d', v_7d_start, v_run_at,
    COALESCE(provider, 'unknown'),
    COALESCE(function_name, 'unknown'),
    COUNT(*),
    COALESCE(SUM(input_tokens), 0),
    COALESCE(SUM(output_tokens), 0),
    COALESCE(SUM(estimated_cost_usd), 0)
  FROM public.enrichment_cost_log
  WHERE created_at >= v_7d_start
    AND created_at <  v_run_at
  GROUP BY provider, function_name;

  -- ── Roll up totals from the rows we just wrote ──
  SELECT COALESCE(SUM(total_usd), 0) INTO v_total_24h
    FROM public.daily_enrichment_cost_summary
   WHERE run_at = v_run_at AND window_label = '24h';

  SELECT COALESCE(SUM(total_usd), 0) INTO v_total_7d
    FROM public.daily_enrichment_cost_summary
   WHERE run_at = v_run_at AND window_label = '7d';

  -- ── Per-provider breakdown for the alert/log ──
  SELECT COALESCE(jsonb_object_agg(provider, total_usd), '{}'::jsonb)
    INTO v_by_provider
    FROM (
      SELECT provider, SUM(total_usd) AS total_usd
        FROM public.daily_enrichment_cost_summary
       WHERE run_at = v_run_at AND window_label = '24h'
       GROUP BY provider
    ) p;

  SELECT COALESCE(jsonb_object_agg(function_name, total_usd), '{}'::jsonb)
    INTO v_by_function
    FROM (
      SELECT function_name, SUM(total_usd) AS total_usd
        FROM public.daily_enrichment_cost_summary
       WHERE run_at = v_run_at AND window_label = '24h'
       GROUP BY function_name
    ) f;

  RAISE NOTICE
    '[cost-summary] run_at=% 24h_total=$% 7d_total=$% threshold=$% enabled=%',
    v_run_at, v_total_24h, v_total_7d, v_threshold, v_enabled;

  -- ── Per-provider visibility in db push output ──
  FOR v_breakdown IN
    SELECT provider, SUM(total_usd) AS total_usd
      FROM public.daily_enrichment_cost_summary
     WHERE run_at = v_run_at AND window_label = '24h'
     GROUP BY provider
     ORDER BY total_usd DESC
  LOOP
    RAISE NOTICE '[cost-summary]   24h provider=% total=$%',
      v_breakdown.provider, v_breakdown.total_usd;
  END LOOP;

  -- ── Threshold check ──
  IF v_enabled AND v_total_24h > v_threshold THEN
    INSERT INTO public.enrichment_cost_alerts
      (window_label, total_usd, threshold_usd, by_provider, by_function)
    VALUES
      ('24h', v_total_24h, v_threshold, v_by_provider, v_by_function)
    RETURNING id INTO v_alert_id;

    RAISE WARNING
      '[cost-summary] ALERT id=% — 24h spend $% exceeds threshold $%. by_provider=%',
      v_alert_id, v_total_24h, v_threshold, v_by_provider::text;

    -- Optionally fire the support-inbox edge function for human visibility.
    -- Uses the same hardcoded service-role JWT pattern as migration 38.
    --
    -- NOTE: notify-support-inbox today only handles three `type` values
    -- (new_message, document_request, admin_reply). To stay non-invasive
    -- we re-use the `new_message` shape and pack the cost summary into
    -- messagePreview. A follow-up migration (reserved 20260801000113) can
    -- add a dedicated `cost_alert` branch to that edge function and switch
    -- the type string here. Default is OFF — admins opt in by setting
    -- `enrichment_cost_alert_config.notify_support_inbox = true`.
    IF v_notify_sup THEN
      BEGIN
        PERFORM net.http_post(
          url := 'https://vhzipqarkmmfuqadefep.supabase.co/functions/v1/notify-support-inbox',
          headers := jsonb_build_object(
            'Authorization',
            'Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InZoemlwcWFya21tZnVxYWRlZmVwIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc0NjYxNzExMywiZXhwIjoyMDYyMTkzMTEzfQ.VkHWUIHpILCuNZWDwXfB_j2LN2Ki5NT_RN4n-OuFVxM',
            'Content-Type', 'application/json'
          ),
          body := jsonb_build_object(
            'type', 'new_message',
            'buyerName', 'Cost Monitor',
            'buyerEmail', 'noreply@sourcecodeals.com',
            'dealTitle', 'Enrichment cost alert',
            'messagePreview',
              'Daily enrichment spend exceeded threshold. ' ||
              '24h total: $' || v_total_24h::text ||
              ' | Threshold: $' || v_threshold::text ||
              ' | By provider: ' || v_by_provider::text ||
              ' | By function: ' || v_by_function::text ||
              ' | Alert id: ' || v_alert_id::text
          )
        );
      EXCEPTION WHEN OTHERS THEN
        -- Never let notification failure break the cron.
        RAISE NOTICE '[cost-summary] notify-support-inbox POST failed: %', SQLERRM;
      END;
    END IF;

    v_alerted := true;
  END IF;

  RETURN QUERY SELECT v_total_24h, v_total_7d, v_alerted;
END;
$_$;


ALTER FUNCTION "public"."compute_daily_enrichment_cost_summary"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."compute_daily_enrichment_cost_summary"() IS 'Aggregates enrichment_cost_log over the last 24h and 7d into daily_enrichment_cost_summary, RAISE NOTICEs per-provider totals, and inserts a row into enrichment_cost_alerts if 24h spend exceeds the configured threshold. Run by the `daily-enrichment-cost-summary` cron at 09:00 UTC.';



CREATE OR REPLACE FUNCTION "public"."compute_stale_cr_recommendations"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_inserted INTEGER := 0;
BEGIN
  -- Wipe rows for requests that no longer qualify (decided, or now-young).
  DELETE FROM public.connection_request_stale_recommendations r
  WHERE NOT EXISTS (
    SELECT 1 FROM public.connection_requests cr
    WHERE cr.id = r.request_id
      AND cr.status IN ('pending', 'on_hold')
  );

  -- Upsert current recommendations.
  WITH candidates AS (
    SELECT
      cr.id AS request_id,
      EXTRACT(DAY FROM (now() - cr.created_at))::INTEGER AS age_days,
      l.status AS listing_status,
      CASE
        WHEN l.status IS NULL OR l.status <> 'active'
          THEN 'archive'
        WHEN EXTRACT(DAY FROM (now() - cr.created_at)) >= 30
          THEN 'deny'
        WHEN EXTRACT(DAY FROM (now() - cr.created_at)) >= 14
          THEN 'review'
        ELSE NULL
      END AS action,
      CASE
        WHEN l.status IS NULL OR l.status <> 'active'
          THEN 'Underlying listing is ' || COALESCE(l.status, 'missing') ||
               ' — request is tied to a non-active deal.'
        WHEN EXTRACT(DAY FROM (now() - cr.created_at)) >= 30
          THEN 'No admin decision in 30+ days — deny to close the loop for the buyer.'
        WHEN EXTRACT(DAY FROM (now() - cr.created_at)) >= 14
          THEN 'Pending 14+ days — review before it becomes a 30-day deny.'
        ELSE NULL
      END AS reason
    FROM public.connection_requests cr
    LEFT JOIN public.listings l ON l.id = cr.listing_id
    WHERE cr.status IN ('pending', 'on_hold')
  )
  INSERT INTO public.connection_request_stale_recommendations
    (request_id, recommended_action, reason, age_days, listing_status, computed_at)
  SELECT request_id, action, reason, age_days, listing_status, now()
  FROM candidates
  WHERE action IS NOT NULL
  ON CONFLICT (request_id) DO UPDATE
    SET recommended_action = EXCLUDED.recommended_action,
        reason             = EXCLUDED.reason,
        age_days           = EXCLUDED.age_days,
        listing_status     = EXCLUDED.listing_status,
        computed_at        = now();

  GET DIAGNOSTICS v_inserted = ROW_COUNT;

  -- Remove rows whose underlying request no longer qualifies as stale
  DELETE FROM public.connection_request_stale_recommendations r
  WHERE EXISTS (
    SELECT 1 FROM public.connection_requests cr
    LEFT JOIN public.listings l ON l.id = cr.listing_id
    WHERE cr.id = r.request_id
      AND cr.status IN ('pending', 'on_hold')
      AND l.status = 'active'
      AND EXTRACT(DAY FROM (now() - cr.created_at)) < 14
  );

  RETURN v_inserted;
END;
$$;


ALTER FUNCTION "public"."compute_stale_cr_recommendations"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."compute_stale_cr_recommendations"() IS 'Ticket 14b — rebuilds the connection_request_stale_recommendations table. Safe to run idempotently. Invoked by the stale-cr-recs cron 4x/day and available for manual runs from the admin UI.';



CREATE OR REPLACE FUNCTION "public"."contact_activities_seed_transcription"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  IF NEW.activity_type = 'call_completed'
     AND NEW.recording_url IS NOT NULL
     AND (NEW.call_transcript IS NULL OR NEW.call_transcript = '')
     AND (NEW.transcription_status IS NULL OR NEW.transcription_status = 'none')
  THEN
    NEW.transcription_status := 'pending';
  END IF;

  IF NEW.activity_type = 'call_completed'
     AND NEW.call_transcript IS NOT NULL
     AND NEW.call_transcript <> ''
     AND (NEW.transcription_status IS NULL OR NEW.transcription_status = 'none')
  THEN
    NEW.transcription_status := 'not_applicable';
    NEW.transcription_provider := COALESCE(NEW.transcription_provider, 'phoneburner_native');
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."contact_activities_seed_transcription"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."contacts_apply_webhook_flags"("p_contact_id" "uuid", "p_updates" "jsonb") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  -- Whitelist of keys webhooks are allowed to set via this RPC. Any key in
  -- p_updates that isn't in this list causes the call to fail — forces the
  -- caller to use a dedicated RPC for broader updates.
  allowed_keys TEXT[] := ARRAY[
    'do_not_call',
    'phone_number_invalid',
    'updated_at'
  ];
  k TEXT;
  v_do_not_call         BOOLEAN;
  v_phone_number_invalid BOOLEAN;
  v_touch_updated       BOOLEAN := FALSE;
BEGIN
  IF p_contact_id IS NULL THEN
    RAISE EXCEPTION 'contacts_apply_webhook_flags: p_contact_id is required';
  END IF;

  IF p_updates IS NULL OR jsonb_typeof(p_updates) <> 'object' THEN
    RAISE EXCEPTION 'contacts_apply_webhook_flags: p_updates must be a JSON object';
  END IF;

  -- Validate every key up-front so partial writes don't land.
  FOR k IN SELECT * FROM jsonb_object_keys(p_updates) LOOP
    IF NOT (k = ANY(allowed_keys)) THEN
      RAISE EXCEPTION 'contacts_apply_webhook_flags: key % is not in the webhook whitelist', k;
    END IF;
  END LOOP;

  -- Extract allowed values (NULL when key absent).
  IF p_updates ? 'do_not_call' THEN
    v_do_not_call := (p_updates ->> 'do_not_call')::boolean;
  END IF;
  IF p_updates ? 'phone_number_invalid' THEN
    v_phone_number_invalid := (p_updates ->> 'phone_number_invalid')::boolean;
  END IF;
  IF p_updates ? 'updated_at' THEN
    v_touch_updated := TRUE;
  END IF;

  -- Single UPDATE. Using CASE WHEN ... THEN <new> ELSE <col> END so unspecified
  -- keys preserve their current values without needing a separate branch.
  UPDATE contacts
    SET
      do_not_call          = CASE WHEN p_updates ? 'do_not_call'
                                  THEN v_do_not_call
                                  ELSE do_not_call END,
      phone_number_invalid = CASE WHEN p_updates ? 'phone_number_invalid'
                                  THEN v_phone_number_invalid
                                  ELSE phone_number_invalid END,
      updated_at           = CASE WHEN v_touch_updated THEN now() ELSE updated_at END
    WHERE id = p_contact_id;
END;
$$;


ALTER FUNCTION "public"."contacts_apply_webhook_flags"("p_contact_id" "uuid", "p_updates" "jsonb") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."contacts_apply_webhook_flags"("p_contact_id" "uuid", "p_updates" "jsonb") IS 'Webhook-safe narrow updater for contacts flag columns (do_not_call, phone_number_invalid, updated_at). Rejects any JSON key not in the whitelist. Use this from edge-function webhooks instead of a direct UPDATE so the contact consolidation lint stays satisfied and flag-write surface area is tracked in one place.';



CREATE OR REPLACE FUNCTION "public"."contacts_soft_delete"("p_contact_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_is_admin BOOLEAN;
BEGIN
  IF p_contact_id IS NULL THEN
    RAISE EXCEPTION 'contacts_soft_delete: p_contact_id is required';
  END IF;

  -- Admin gate. The direct UI write path was previously authorized by the
  -- `contacts_admin_all` RLS policy — this RPC replaces that authorization
  -- with an explicit is_admin check since SECURITY DEFINER bypasses RLS.
  SELECT public.is_admin(auth.uid()) INTO v_is_admin;
  IF NOT COALESCE(v_is_admin, false) THEN
    RAISE EXCEPTION 'Access denied: admin role required to soft-delete contacts'
      USING ERRCODE = '42501';
  END IF;

  UPDATE public.contacts
  SET
    -- Set BOTH the legacy archived flag and the canonical deleted_at.
    -- Readers filter on archived; unique indexes filter on deleted_at.
    -- Setting both ensures the row disappears from every lookup surface.
    archived   = true,
    deleted_at = COALESCE(deleted_at, now()),
    updated_at = now()
  WHERE id = p_contact_id;

  RETURN p_contact_id;
END;
$$;


ALTER FUNCTION "public"."contacts_soft_delete"("p_contact_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."contacts_soft_delete"("p_contact_id" "uuid") IS 'Soft-deletes a contact by setting archived=true AND deleted_at=now(). Admin-gated. Replaces the UI-side direct UPDATE that broke silently after 20260625000008 revoked authenticated writes.';



CREATE OR REPLACE FUNCTION "public"."contacts_upsert"("p_identity" "jsonb", "p_fields" "jsonb", "p_source" "text" DEFAULT 'manual'::"text", "p_enrichment" "jsonb" DEFAULT NULL::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_contact_id   UUID;
  v_existing     public.contacts%ROWTYPE;
  v_new_row      public.contacts%ROWTYPE;
  v_event_type   TEXT;
  v_is_insert    BOOLEAN;
  v_old_json     JSONB;
  v_new_json     JSONB;
  v_changed      TEXT[];
BEGIN
  v_contact_id := public.resolve_contact_identity(
    (p_identity->>'email')::TEXT,
    (p_identity->>'linkedin_url')::TEXT,
    (p_identity->>'phone')::TEXT,
    NULLIF((p_identity->>'firm_id')::TEXT, '')::UUID
  );

  v_is_insert := v_contact_id IS NULL;

  IF v_is_insert AND (p_fields ? 'email' OR p_fields ? 'linkedin_url') THEN
    v_contact_id := public.resolve_contact_identity(
      (p_fields->>'email')::TEXT,
      (p_fields->>'linkedin_url')::TEXT,
      (p_fields->>'phone')::TEXT,
      NULLIF((p_fields->>'firm_id')::TEXT, '')::UUID
    );
    v_is_insert := v_contact_id IS NULL;
  END IF;

  IF NOT v_is_insert THEN
    SELECT * INTO v_existing FROM public.contacts WHERE id = v_contact_id;
    v_old_json := to_jsonb(v_existing);
  END IF;

  IF v_is_insert THEN
    IF COALESCE(p_fields->>'first_name', '') = '' THEN
      RAISE EXCEPTION 'contacts_upsert: first_name is required for new contacts';
    END IF;

    IF COALESCE(p_fields->>'email', '') = ''
       AND COALESCE(p_fields->>'linkedin_url', '') = '' THEN
      RAISE EXCEPTION 'contacts_upsert: new contacts require at least one of email or linkedin_url';
    END IF;

    INSERT INTO public.contacts (
      first_name, last_name, email, phone, linkedin_url, title,
      contact_type, firm_id, remarketing_buyer_id, profile_id, listing_id,
      is_primary_at_firm, is_primary_seller_contact,
      nda_signed, nda_signed_at, fee_agreement_signed, fee_agreement_signed_at,
      confidence, last_enriched_at, last_enrichment_source,
      role_category, priority_level,
      source, notes
    ) VALUES (
      COALESCE(p_fields->>'first_name', 'Unknown'),
      COALESCE(p_fields->>'last_name', ''),
      NULLIF(lower(trim(p_fields->>'email')), ''),
      NULLIF(trim(p_fields->>'phone'), ''),
      NULLIF(trim(p_fields->>'linkedin_url'), ''),
      NULLIF(trim(p_fields->>'title'), ''),
      COALESCE(p_fields->>'contact_type', 'buyer'),
      NULLIF(p_fields->>'firm_id', '')::UUID,
      NULLIF(p_fields->>'remarketing_buyer_id', '')::UUID,
      NULLIF(p_fields->>'profile_id', '')::UUID,
      NULLIF(p_fields->>'listing_id', '')::UUID,
      COALESCE((p_fields->>'is_primary_at_firm')::BOOLEAN, false),
      COALESCE((p_fields->>'is_primary_seller_contact')::BOOLEAN, false),
      COALESCE((p_fields->>'nda_signed')::BOOLEAN, false),
      (p_fields->>'nda_signed_at')::TIMESTAMPTZ,
      COALESCE((p_fields->>'fee_agreement_signed')::BOOLEAN, false),
      (p_fields->>'fee_agreement_signed_at')::TIMESTAMPTZ,
      CASE
        WHEN p_enrichment IS NOT NULL THEN COALESCE(p_enrichment->>'confidence', 'unverified')
        ELSE COALESCE(p_fields->>'confidence', 'unverified')
      END,
      CASE WHEN p_enrichment IS NOT NULL THEN now() ELSE NULL END,
      CASE WHEN p_enrichment IS NOT NULL THEN p_enrichment->>'provider' ELSE NULL END,
      NULLIF(p_fields->>'role_category', ''),
      NULLIF((p_fields->>'priority_level')::SMALLINT, 0),
      p_source,
      NULLIF(p_fields->>'notes', '')
    )
    RETURNING id INTO v_contact_id;

    v_event_type := CASE WHEN p_enrichment IS NOT NULL THEN 'enrichment' ELSE 'create' END;

  ELSE
    UPDATE public.contacts
    SET
      first_name   = COALESCE(NULLIF(p_fields->>'first_name', ''),   first_name),
      last_name    = COALESCE(NULLIF(p_fields->>'last_name', ''),    last_name),
      email        = COALESCE(NULLIF(lower(trim(p_fields->>'email')), ''), email),
      phone        = COALESCE(NULLIF(trim(p_fields->>'phone'), ''),  phone),
      linkedin_url = COALESCE(NULLIF(trim(p_fields->>'linkedin_url'), ''), linkedin_url),
      title        = COALESCE(NULLIF(trim(p_fields->>'title'), ''),  title),
      firm_id      = COALESCE(NULLIF(p_fields->>'firm_id', '')::UUID, firm_id),
      remarketing_buyer_id = COALESCE(NULLIF(p_fields->>'remarketing_buyer_id', '')::UUID, remarketing_buyer_id),
      profile_id   = COALESCE(NULLIF(p_fields->>'profile_id', '')::UUID, profile_id),
      listing_id   = COALESCE(NULLIF(p_fields->>'listing_id', '')::UUID, listing_id),
      contact_type = COALESCE(NULLIF(p_fields->>'contact_type', ''), contact_type),
      role_category   = COALESCE(NULLIF(p_fields->>'role_category', ''), role_category),
      priority_level  = COALESCE(NULLIF((p_fields->>'priority_level')::SMALLINT, 0), priority_level),
      notes        = COALESCE(NULLIF(p_fields->>'notes', ''), notes),
      confidence   = CASE
        WHEN p_enrichment IS NOT NULL THEN COALESCE(p_enrichment->>'confidence', confidence)
        ELSE confidence
      END,
      last_enriched_at = CASE
        WHEN p_enrichment IS NOT NULL THEN now()
        ELSE last_enriched_at
      END,
      last_enrichment_source = CASE
        WHEN p_enrichment IS NOT NULL THEN p_enrichment->>'provider'
        ELSE last_enrichment_source
      END,
      -- Revive an archived row on explicit re-add. We only land here when
      -- resolve_contact_identity returned a row (post-fix #2 above, that
      -- means archived=false) — but legacy rows with archived=true AND
      -- deleted_at IS NULL could have been resolved BEFORE fix #2
      -- applied, in which case contacts_upsert's caller wants a live
      -- row. Clearing archived here is a no-op for already-live rows
      -- and a repair for the legacy edge case.
      archived     = false,
      updated_at = now()
    WHERE id = v_contact_id;

    v_event_type := CASE WHEN p_enrichment IS NOT NULL THEN 'enrichment' ELSE 'update' END;
  END IF;

  SELECT * INTO v_new_row FROM public.contacts WHERE id = v_contact_id;
  v_new_json := to_jsonb(v_new_row);

  IF v_old_json IS NOT NULL THEN
    SELECT array_agg(key)
    INTO v_changed
    FROM jsonb_object_keys(v_new_json) AS key
    WHERE v_old_json->key IS DISTINCT FROM v_new_json->key;
  END IF;

  INSERT INTO public.contact_events (
    contact_id,
    event_type,
    provider,
    confidence,
    source_query,
    old_values,
    new_values,
    changed_fields,
    performed_by,
    performed_at
  )
  VALUES (
    v_contact_id,
    v_event_type,
    COALESCE(p_enrichment->>'provider', p_source),
    p_enrichment->>'confidence',
    p_enrichment->>'source_query',
    v_old_json,
    v_new_json,
    v_changed,
    auth.uid(),
    now()
  );

  RETURN v_contact_id;
END;
$$;


ALTER FUNCTION "public"."contacts_upsert"("p_identity" "jsonb", "p_fields" "jsonb", "p_source" "text", "p_enrichment" "jsonb") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."contacts_upsert"("p_identity" "jsonb", "p_fields" "jsonb", "p_source" "text", "p_enrichment" "jsonb") IS 'Single write entry point for public.contacts. Resolves identity via resolve_contact_identity(), performs INSERT or UPDATE, and appends a history row to contact_events atomically. Structured phone fields (mobile_phone_1/2/3, office_phone, phone_source) accept explicit empty strings to clear; JSON null or a missing key keeps the existing value.';



CREATE OR REPLACE FUNCTION "public"."convert_inbound_lead_to_request"("p_lead_id" "uuid", "p_listing_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_admin_id uuid;
  v_lead record;
  v_existing_user record;
  v_existing_request_id uuid;
  v_new_request_id uuid;
BEGIN
  v_admin_id := auth.uid();
  IF v_admin_id IS NULL THEN RAISE EXCEPTION 'User not authenticated'; END IF;
  IF NOT is_admin(v_admin_id) THEN RAISE EXCEPTION 'Only admins can convert leads'; END IF;

  SELECT * INTO v_lead FROM public.inbound_leads WHERE id = p_lead_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'Lead not found'; END IF;

  SELECT * INTO v_existing_user FROM public.profiles WHERE email = v_lead.email;

  IF v_existing_user.id IS NOT NULL THEN
    SELECT id INTO v_existing_request_id FROM public.connection_requests
    WHERE user_id = v_existing_user.id AND listing_id = p_listing_id AND status != 'rejected';

    IF v_existing_request_id IS NOT NULL THEN
      -- Link the lead and mark as channel duplicate
      UPDATE public.connection_requests
      SET source_metadata = COALESCE(source_metadata, '{}'::jsonb) ||
        jsonb_build_object(
          'is_channel_duplicate', true,
          'channel_merge', 'marketplace_to_website',
          'linked_lead_id', p_lead_id,
          'merged_at', NOW()
        ),
          updated_at = NOW()
      WHERE id = v_existing_request_id;

      UPDATE public.inbound_leads SET
        status = 'converted',
        converted_to_request_id = v_existing_request_id,
        converted_at = NOW(),
        converted_by = v_admin_id,
        mapped_to_listing_id = p_listing_id,
        mapped_at = NOW(),
        mapped_by = v_admin_id
      WHERE id = p_lead_id;

      RETURN v_existing_request_id;
    END IF;

    INSERT INTO public.connection_requests (
      user_id, listing_id, user_message,
      lead_name, lead_email, lead_company, lead_role, lead_phone,
      source, source_lead_id, converted_by, converted_at, status, source_metadata
    ) VALUES (
      v_existing_user.id,
      p_listing_id,
      v_lead.message,
      v_lead.name,
      v_lead.email,
      v_lead.company_name,
      v_lead.role,
      v_lead.phone_number,
      'website',
      p_lead_id,
      v_admin_id,
      NOW(),
      'pending',
      jsonb_build_object('original_channel','website')
    ) RETURNING id INTO v_new_request_id;
  ELSE
    INSERT INTO public.connection_requests (
      user_id, listing_id, user_message,
      lead_name, lead_email, lead_company, lead_role, lead_phone,
      source, source_lead_id, converted_by, converted_at, status, source_metadata
    ) VALUES (
      NULL,
      p_listing_id,
      v_lead.message,
      v_lead.name,
      v_lead.email,
      v_lead.company_name,
      v_lead.role,
      v_lead.phone_number,
      'website',
      p_lead_id,
      v_admin_id,
      NOW(),
      'pending',
      jsonb_build_object('original_channel','website')
    ) RETURNING id INTO v_new_request_id;
  END IF;

  UPDATE public.inbound_leads SET
    status = 'converted',
    converted_to_request_id = v_new_request_id,
    converted_at = NOW(),
    converted_by = v_admin_id,
    mapped_to_listing_id = p_listing_id,
    mapped_at = NOW(),
    mapped_by = v_admin_id
  WHERE id = p_lead_id;

  RETURN v_new_request_id;
END;
$$;


ALTER FUNCTION "public"."convert_inbound_lead_to_request"("p_lead_id" "uuid", "p_listing_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_deal_from_connection_request"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  default_stage_id UUID;
  deal_title TEXT;
  listing_title TEXT;
  v_buyer_contact_id UUID;
  v_seller_contact_id UUID;
  v_remarketing_buyer_id UUID;
BEGIN
  SELECT id INTO default_stage_id
  FROM public.deal_stages
  WHERE is_default = TRUE
  ORDER BY position
  LIMIT 1;

  SELECT title INTO listing_title
  FROM public.listings
  WHERE id = NEW.listing_id;

  deal_title := COALESCE(NEW.lead_name, 'Unknown') || ' - ' || COALESCE(listing_title, 'Unknown Listing');

  IF NEW.user_id IS NOT NULL THEN
    SELECT c.id, c.remarketing_buyer_id
    INTO v_buyer_contact_id, v_remarketing_buyer_id
    FROM public.contacts c
    WHERE c.profile_id = NEW.user_id
      AND c.contact_type = 'buyer'
      AND c.archived = false
    LIMIT 1;
  END IF;

  IF NEW.listing_id IS NOT NULL THEN
    SELECT c.id INTO v_seller_contact_id
    FROM public.contacts c
    WHERE c.listing_id = NEW.listing_id
      AND c.contact_type = 'seller'
      AND c.is_primary_seller_contact = true
      AND c.archived = false
    LIMIT 1;
  END IF;

  INSERT INTO public.deal_pipeline (
    listing_id,
    stage_id,
    connection_request_id,
    title,
    description,
    source,
    buyer_contact_id,
    seller_contact_id,
    remarketing_buyer_id,
    metadata
  ) VALUES (
    NEW.listing_id,
    default_stage_id,
    NEW.id,
    deal_title,
    NEW.user_message,
    COALESCE(NEW.source, 'marketplace'),
    v_buyer_contact_id,
    v_seller_contact_id,
    v_remarketing_buyer_id,
    jsonb_build_object(
      'auto_created', TRUE,
      'source_type', 'connection_request'
    )
  );

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."create_deal_from_connection_request"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_deal_from_inbound_lead"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  default_stage_id UUID;
  deal_title TEXT;
  listing_title TEXT;
  v_buyer_contact_id UUID;
  v_seller_contact_id UUID;
  v_remarketing_buyer_id UUID;
BEGIN
  IF OLD.status != 'converted' AND NEW.status = 'converted' THEN
    SELECT id INTO default_stage_id
    FROM public.deal_stages
    WHERE is_default = TRUE
    ORDER BY position
    LIMIT 1;

    SELECT title INTO listing_title
    FROM public.listings
    WHERE id = NEW.mapped_to_listing_id;

    deal_title := COALESCE(NEW.name, 'Unknown') || ' - ' || COALESCE(listing_title, 'Unknown Listing');

    IF NEW.email IS NOT NULL THEN
      SELECT c.id, c.remarketing_buyer_id
      INTO v_buyer_contact_id, v_remarketing_buyer_id
      FROM public.contacts c
      WHERE lower(c.email) = lower(NEW.email)
        AND c.contact_type = 'buyer'
        AND c.archived = false
      LIMIT 1;
    END IF;

    IF NEW.mapped_to_listing_id IS NOT NULL THEN
      SELECT c.id INTO v_seller_contact_id
      FROM public.contacts c
      WHERE c.listing_id = NEW.mapped_to_listing_id
        AND c.contact_type = 'seller'
        AND c.is_primary_seller_contact = true
        AND c.archived = false
      LIMIT 1;
    END IF;

    INSERT INTO public.deal_pipeline (
      listing_id,
      stage_id,
      inbound_lead_id,
      title,
      description,
      source,
      buyer_contact_id,
      seller_contact_id,
      remarketing_buyer_id,
      metadata
    ) VALUES (
      NEW.mapped_to_listing_id,
      default_stage_id,
      NEW.id,
      deal_title,
      NEW.message,
      COALESCE(NEW.source, 'webflow'),
      v_buyer_contact_id,
      v_seller_contact_id,
      v_remarketing_buyer_id,
      jsonb_build_object(
        'auto_created', TRUE,
        'source_type', 'inbound_lead'
      )
    );
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."create_deal_from_inbound_lead"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_deal_on_request_approval"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  existing_deal_id uuid;
  qualified_stage_id uuid;
  nda_status text := 'not_sent';
  fee_status text := 'not_sent';
  src text;
  deal_title text;
  new_deal_id uuid;
  v_listing_website text;
BEGIN
  IF TG_OP = 'UPDATE' AND NEW.status = 'approved' AND COALESCE(OLD.status,'') <> 'approved' THEN
    SELECT id INTO existing_deal_id FROM public.deal_pipeline WHERE connection_request_id = NEW.id LIMIT 1;
    IF existing_deal_id IS NOT NULL THEN
      RETURN NEW;
    END IF;

    SELECT website INTO v_listing_website
    FROM public.listings
    WHERE id = NEW.listing_id;

    IF NOT public.is_valid_company_website(v_listing_website) THEN
      RETURN NEW;
    END IF;

    SELECT id INTO qualified_stage_id FROM public.deal_stages
      WHERE is_active = true AND name = 'Qualified'
      ORDER BY position
      LIMIT 1;

    IF qualified_stage_id IS NULL THEN
      SELECT id INTO qualified_stage_id FROM public.deal_stages WHERE is_active = true ORDER BY position LIMIT 1;
    END IF;

    IF COALESCE(NEW.lead_nda_signed, false) THEN
      nda_status := 'signed';
    ELSIF COALESCE(NEW.lead_nda_email_sent, false) THEN
      nda_status := 'sent';
    END IF;

    IF COALESCE(NEW.lead_fee_agreement_signed, false) THEN
      fee_status := 'signed';
    ELSIF COALESCE(NEW.lead_fee_agreement_email_sent, false) THEN
      fee_status := 'sent';
    END IF;

    src := COALESCE(NEW.source, 'marketplace');

    SELECT COALESCE(l.title, 'Unknown') INTO deal_title FROM public.listings l WHERE l.id = NEW.listing_id;

    INSERT INTO public.deal_pipeline (
      listing_id, stage_id, connection_request_id, value, probability, expected_close_date,
      assigned_to, stage_entered_at, source,
      nda_status, fee_agreement_status, title, description, priority
    )
    VALUES (
      NEW.listing_id, qualified_stage_id, NEW.id, 0, 50, NULL,
      NEW.approved_by, now(), src,
      nda_status, fee_status,
      deal_title,
      COALESCE(NEW.user_message, 'Deal created from approved connection request'),
      'medium'
    )
    RETURNING id INTO new_deal_id;

    IF new_deal_id IS NOT NULL THEN
      INSERT INTO public.deal_activities (deal_id, admin_id, activity_type, title, description, metadata)
      VALUES (
        new_deal_id,
        NEW.approved_by,
        'note_added',
        'Created from connection request',
        COALESCE(NEW.user_message, 'Approved connection request and created deal'),
        jsonb_build_object('connection_request_id', NEW.id)
      );
    END IF;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."create_deal_on_request_approval"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_listing_conversation"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NEW.status = 'approved'
     AND OLD.status != 'approved'
     AND NEW.user_id IS NOT NULL THEN
    INSERT INTO listing_conversations (
      listing_id,
      connection_request_id,
      user_id,
      admin_id
    )
    VALUES (
      NEW.listing_id,
      NEW.id,
      NEW.user_id,
      NEW.approved_by
    )
    ON CONFLICT (connection_request_id) DO NOTHING;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."create_listing_conversation"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_pipeline_deal"("p_connection_request_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_cr              RECORD;
  v_source          text;
  v_lead_source     text;
  v_buyer_type      text;
  v_buyer_priority  integer;
  v_stage_id        uuid;
  v_buyer_contact_id uuid;
  v_remarketing_buyer_id uuid;
  v_seller_contact_id uuid;
  v_contact_name    text;
  v_listing_title   text;
  v_deal_title      text;
  v_nda_status      text;
  v_fee_status      text;
  v_new_deal_id     uuid;
  v_existing_deal_id uuid;
BEGIN
  SELECT *
    INTO v_cr
    FROM public.connection_requests
   WHERE id = p_connection_request_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'create_pipeline_deal: connection_request not found: %', p_connection_request_id;
  END IF;

  -- Duplicate guard
  SELECT dp.id INTO v_existing_deal_id
    FROM public.deal_pipeline dp
   WHERE dp.connection_request_id = p_connection_request_id
   LIMIT 1;

  IF v_existing_deal_id IS NOT NULL THEN
    RETURN v_existing_deal_id;
  END IF;

  -- Ensure source
  v_source := v_cr.source;

  IF v_cr.source_lead_id IS NOT NULL
     AND (v_source IS NULL OR v_source = 'marketplace')
  THEN
    SELECT il.source
      INTO v_lead_source
      FROM public.inbound_leads il
     WHERE il.id = v_cr.source_lead_id;

    IF v_lead_source IS NOT NULL THEN
      v_source := v_lead_source;
    END IF;
  END IF;

  v_source := COALESCE(v_source, 'marketplace');

  -- Buyer priority score
  v_buyer_priority := 0;

  IF v_cr.user_id IS NOT NULL THEN
    SELECT p.buyer_type
      INTO v_buyer_type
      FROM public.profiles p
     WHERE p.id = v_cr.user_id;

    v_buyer_priority := COALESCE(
      public.calculate_buyer_priority_score(v_buyer_type),
      0
    );
  ELSE
    v_buyer_priority := COALESCE(v_cr.buyer_priority_score, 0);
  END IF;

  -- Stage lookup (was 'New Inquiry', renamed to 'Approved')
  SELECT ds.id
    INTO v_stage_id
    FROM public.deal_stages ds
   WHERE ds.name IN ('Approved', 'New Inquiry')
   ORDER BY ds.position ASC
   LIMIT 1;

  IF v_stage_id IS NULL THEN
    SELECT ds.id INTO v_stage_id
      FROM public.deal_stages ds
     ORDER BY ds.position ASC
     LIMIT 1;
  END IF;

  IF v_stage_id IS NULL THEN
    RAISE EXCEPTION 'create_pipeline_deal: no deal_stages found';
  END IF;

  -- Resolve buyer_contact_id and remarketing_buyer_id
  IF v_cr.user_id IS NOT NULL THEN
    SELECT c.id, c.remarketing_buyer_id
      INTO v_buyer_contact_id, v_remarketing_buyer_id
      FROM public.contacts c
     WHERE c.profile_id = v_cr.user_id
       AND c.contact_type = 'buyer'
       AND c.archived = false
     LIMIT 1;
  END IF;

  -- Resolve seller_contact_id
  IF v_cr.listing_id IS NOT NULL THEN
    SELECT c.id
      INTO v_seller_contact_id
      FROM public.contacts c
     WHERE c.listing_id = v_cr.listing_id
       AND c.contact_type = 'seller'
       AND c.is_primary_seller_contact = true
       AND c.archived = false
     LIMIT 1;
  END IF;

  -- Build deal title
  IF v_cr.user_id IS NOT NULL THEN
    SELECT COALESCE(p.first_name || ' ' || p.last_name, p.email)
      INTO v_contact_name
      FROM public.profiles p
     WHERE p.id = v_cr.user_id;
  END IF;
  v_contact_name := COALESCE(v_contact_name, v_cr.lead_name, 'Unknown');

  SELECT l.title
    INTO v_listing_title
    FROM public.listings l
   WHERE l.id = v_cr.listing_id;

  v_deal_title := v_contact_name || ' - ' || COALESCE(v_listing_title, 'Unknown Listing');

  -- Derive NDA / fee statuses
  v_nda_status := CASE
    WHEN COALESCE(v_cr.lead_nda_signed, false)     THEN 'signed'
    WHEN COALESCE(v_cr.lead_nda_email_sent, false)  THEN 'sent'
    ELSE 'not_sent'
  END;

  v_fee_status := CASE
    WHEN COALESCE(v_cr.lead_fee_agreement_signed, false)     THEN 'signed'
    WHEN COALESCE(v_cr.lead_fee_agreement_email_sent, false)  THEN 'sent'
    ELSE 'not_sent'
  END;

  -- INSERT into deal_pipeline
  INSERT INTO public.deal_pipeline (
    listing_id,
    stage_id,
    connection_request_id,
    remarketing_buyer_id,
    value,
    probability,
    source,
    title,
    buyer_priority_score,
    nda_status,
    fee_agreement_status,
    created_at,
    stage_entered_at,
    buyer_contact_id,
    seller_contact_id
  ) VALUES (
    v_cr.listing_id,
    v_stage_id,
    v_cr.id,
    v_remarketing_buyer_id,
    0,
    5,
    v_source,
    v_deal_title,
    v_buyer_priority,
    v_nda_status,
    v_fee_status,
    v_cr.created_at,
    v_cr.created_at,
    v_buyer_contact_id,
    v_seller_contact_id
  )
  RETURNING id INTO v_new_deal_id;

  RETURN v_new_deal_id;
END;
$$;


ALTER FUNCTION "public"."create_pipeline_deal"("p_connection_request_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."create_pipeline_deal"("p_connection_request_id" "uuid") IS 'Phase 4 RPC: Replaces the 4-trigger chain that fired on connection_requests INSERT. Creates a deal_pipeline row from a connection_request in a single explicit call.';



CREATE OR REPLACE FUNCTION "public"."decrement_provider_concurrent"("p_provider" "text") RETURNS "void"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
BEGIN
  UPDATE enrichment_rate_limits
  SET concurrent_requests = GREATEST(0, concurrent_requests - 1),
      updated_at = now()
  WHERE provider = p_provider;
END;
$$;


