CREATE OR REPLACE FUNCTION "public"."emit_event"("p_event_type" "text", "p_entity_type" "text" DEFAULT NULL::"text", "p_entity_id" "uuid" DEFAULT NULL::"uuid", "p_actor_id" "uuid" DEFAULT NULL::"uuid", "p_metadata" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_event_id uuid;
BEGIN
  INSERT INTO public.global_activity_queue (
    event_type,
    entity_type,
    entity_id,
    actor_id,
    context_json,
    operation_type,
    status,
    classification
  ) VALUES (
    p_event_type,
    p_entity_type,
    p_entity_id,
    p_actor_id,
    p_metadata,
    COALESCE(p_event_type, 'generic'),
    'queued',
    'minor'
  )
  RETURNING id INTO v_event_id;

  RETURN v_event_id;
END;
$$;


ALTER FUNCTION "public"."emit_event"("p_event_type" "text", "p_entity_type" "text", "p_entity_id" "uuid", "p_actor_id" "uuid", "p_metadata" "jsonb") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."emit_event"("p_event_type" "text", "p_entity_type" "text", "p_entity_id" "uuid", "p_actor_id" "uuid", "p_metadata" "jsonb") IS 'Publishes an event to the global_activity_queue. Returns the new event UUID.';



CREATE OR REPLACE FUNCTION "public"."emit_event_safe"("p_event_type" "text", "p_entity_type" "text" DEFAULT NULL::"text", "p_entity_id" "uuid" DEFAULT NULL::"uuid", "p_actor_id" "uuid" DEFAULT NULL::"uuid", "p_metadata" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_id uuid;
BEGIN
  BEGIN
    v_id := public.emit_event(p_event_type, p_entity_type, p_entity_id, p_actor_id, p_metadata);
    RETURN v_id;
  EXCEPTION WHEN OTHERS THEN
    RAISE WARNING 'emit_event_safe: % for %/%: %', p_event_type, p_entity_type, p_entity_id, SQLERRM;
    RETURN NULL;
  END;
END;
$$;


ALTER FUNCTION "public"."emit_event_safe"("p_event_type" "text", "p_entity_type" "text", "p_entity_id" "uuid", "p_actor_id" "uuid", "p_metadata" "jsonb") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."emit_event_safe"("p_event_type" "text", "p_entity_type" "text", "p_entity_id" "uuid", "p_actor_id" "uuid", "p_metadata" "jsonb") IS 'Wrapper around emit_event() that swallows errors as WARNING. Use from triggers so event emission failures never break the primary write path.';



CREATE OR REPLACE FUNCTION "public"."enhanced_merge_or_create_connection_request"("p_listing_id" "uuid", "p_user_message" "text" DEFAULT NULL::"text", "p_lead_name" "text" DEFAULT NULL::"text", "p_lead_email" "text" DEFAULT NULL::"text", "p_lead_company" "text" DEFAULT NULL::"text", "p_lead_role" "text" DEFAULT NULL::"text", "p_lead_phone" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid;
  v_user_profile record;
  v_existing_request record;
  v_existing_lead_request record;
  v_new_request_id uuid;
  v_result jsonb;
  v_fee_coverage record;
  v_user_email text;
  v_is_internal boolean;
BEGIN
  v_user_id := auth.uid();
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'User not authenticated';
  END IF;

  -- SERVER-SIDE GATE: Block requests against internal/remarketing deals
  SELECT is_internal_deal INTO v_is_internal FROM public.listings WHERE id = p_listing_id;
  IF v_is_internal IS TRUE THEN
    RAISE EXCEPTION 'Cannot request connection to an internal deal';
  END IF;

  -- Get user profile
  SELECT * INTO v_user_profile FROM public.profiles WHERE id = v_user_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'User profile not found';
  END IF;

  -- SERVER-SIDE GATE: Block business owners
  IF v_user_profile.buyer_type IN ('businessOwner', 'business_owner') THEN
    RAISE EXCEPTION 'Business owner accounts cannot request deal connections';
  END IF;

  -- SERVER-SIDE GATE: Fee Agreement is required (NDA alone is not sufficient)
  SELECT email INTO v_user_email FROM auth.users WHERE id = v_user_id;
  IF v_user_email IS NOT NULL THEN
    SELECT * INTO v_fee_coverage FROM public.check_agreement_coverage(v_user_email, 'fee_agreement');
    
    IF NOT COALESCE(v_fee_coverage.is_covered, false) THEN
      RAISE EXCEPTION 'A Fee Agreement must be signed before requesting deal access';
    END IF;
  END IF;

  -- Check for existing marketplace request from this user for this listing
  SELECT * INTO v_existing_request
  FROM public.connection_requests
  WHERE user_id = v_user_id
    AND listing_id = p_listing_id
    AND status != 'rejected'
  ORDER BY created_at DESC
  LIMIT 1;

  IF v_existing_request.id IS NOT NULL THEN
    UPDATE public.connection_requests
    SET
      user_message = p_user_message,
      source_metadata = COALESCE(source_metadata, '{}'::jsonb) ||
        jsonb_build_object(
          'has_duplicate_submission', true,
          'duplicate_submission_count', COALESCE((source_metadata->'duplicate_submission_count')::int, 0) + 1,
          'previous_message', v_existing_request.user_message,
          'latest_message_at', NOW(),
          'needs_admin_review', true,
          'duplicate_reason', 'same_user_same_listing'
        ),
      updated_at = NOW()
    WHERE id = v_existing_request.id;

    RETURN jsonb_build_object(
      'request_id', v_existing_request.id,
      'is_duplicate', true,
      'duplicate_type', 'same_user_same_listing',
      'action_taken', 'updated_existing_request',
      'previous_message', v_existing_request.user_message,
      'previous_status', v_existing_request.status,
      'created_at', v_existing_request.created_at
    );
  END IF;

  IF p_lead_email IS NOT NULL THEN
    SELECT * INTO v_existing_lead_request
    FROM public.connection_requests
    WHERE listing_id = p_listing_id
      AND lead_email = p_lead_email
      AND status != 'rejected'
    ORDER BY created_at DESC
    LIMIT 1;

    IF v_existing_lead_request.id IS NOT NULL THEN
      UPDATE public.connection_requests
      SET
        user_id = v_user_id,
        user_message = COALESCE(p_user_message, v_existing_lead_request.user_message),
        source_metadata = COALESCE(v_existing_lead_request.source_metadata, '{}'::jsonb) ||
          jsonb_build_object(
            'merged_from_lead', true,
            'original_lead_email', p_lead_email,
            'merged_at', NOW()
          ),
        updated_at = NOW()
      WHERE id = v_existing_lead_request.id;

      RETURN jsonb_build_object(
        'request_id', v_existing_lead_request.id,
        'is_duplicate', true,
        'duplicate_type', 'lead_to_user_merge',
        'action_taken', 'merged_lead_request',
        'previous_status', v_existing_lead_request.status
      );
    END IF;
  END IF;

  v_new_request_id := gen_random_uuid();

  INSERT INTO public.connection_requests (
    id, listing_id, user_id, user_message, status,
    lead_name, lead_email, lead_company, lead_role, lead_phone,
    source_metadata, created_at, updated_at
  ) VALUES (
    v_new_request_id, p_listing_id, v_user_id, p_user_message, 'pending',
    p_lead_name, p_lead_email, p_lead_company, p_lead_role, p_lead_phone,
    jsonb_build_object('source', 'marketplace', 'created_via', 'enhanced_rpc'),
    NOW(), NOW()
  );

  RETURN jsonb_build_object(
    'request_id', v_new_request_id,
    'is_duplicate', false,
    'action_taken', 'created_new_request',
    'status', 'pending'
  );
END;
$$;


ALTER FUNCTION "public"."enhanced_merge_or_create_connection_request"("p_listing_id" "uuid", "p_user_message" "text", "p_lead_name" "text", "p_lead_email" "text", "p_lead_company" "text", "p_lead_role" "text", "p_lead_phone" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."enqueue_portal_listings"("p_portal_org_id" "uuid") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_count integer;
BEGIN
  -- Caller must be an admin.
  IF NOT EXISTS (
    SELECT 1 FROM public.profiles
    WHERE id = auth.uid() AND is_admin = true
  ) THEN
    RAISE EXCEPTION 'insufficient_privilege: admin required';
  END IF;

  -- Skip if portal isn't active — no point re-scoring.
  IF NOT EXISTS (
    SELECT 1 FROM public.portal_organizations
    WHERE id = p_portal_org_id AND status = 'active'
  ) THEN
    RAISE EXCEPTION 'portal_not_active: % is not an active portal', p_portal_org_id;
  END IF;

  -- Skip if no active criteria exist for this portal — nothing to match.
  IF NOT EXISTS (
    SELECT 1 FROM public.portal_thesis_criteria
    WHERE portal_org_id = p_portal_org_id AND is_active = true
  ) THEN
    RETURN 0;
  END IF;

  -- Enqueue all matchable listings. ON CONFLICT so re-runs are cheap.
  INSERT INTO public.portal_recommendation_queue (listing_id, queued_at)
  SELECT id, now()
  FROM public.listings
  WHERE deleted_at IS NULL
    AND (not_a_fit IS NULL OR not_a_fit = false)
  ON CONFLICT (listing_id) DO UPDATE
    SET queued_at = EXCLUDED.queued_at;

  GET DIAGNOSTICS v_count = ROW_COUNT;
  RETURN v_count;
END;
$$;


ALTER FUNCTION "public"."enqueue_portal_listings"("p_portal_org_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."ensure_profile_exists"() RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user_id uuid;
  v_email text;
  v_first_name text;
  v_last_name text;
BEGIN
  v_user_id := auth.uid();
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  -- Check if profile already exists (fast path)
  IF EXISTS (SELECT 1 FROM public.profiles WHERE id = v_user_id) THEN
    RETURN;
  END IF;

  -- Read from auth.users
  SELECT
    COALESCE(u.email, ''),
    COALESCE(NULLIF(TRIM(u.raw_user_meta_data->>'first_name'), ''), 'Unknown'),
    COALESCE(NULLIF(TRIM(u.raw_user_meta_data->>'last_name'), ''), 'User')
  INTO v_email, v_first_name, v_last_name
  FROM auth.users u
  WHERE u.id = v_user_id;

  -- Insert minimal profile
  INSERT INTO public.profiles (id, email, first_name, last_name)
  VALUES (v_user_id, v_email, v_first_name, v_last_name)
  ON CONFLICT (id) DO NOTHING;

EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'ensure_profile_exists failed for %: % %', v_user_id, SQLSTATE, SQLERRM;
END;
$$;


ALTER FUNCTION "public"."ensure_profile_exists"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."ensure_source_from_lead"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  lead_source text;
BEGIN
  IF NEW.source_lead_id IS NOT NULL AND (NEW.source IS NULL OR NEW.source = 'marketplace') THEN
    SELECT source INTO lead_source FROM public.inbound_leads WHERE id = NEW.source_lead_id;
    IF lead_source IS NOT NULL THEN
      NEW.source := lead_source;
      NEW.source_metadata := COALESCE(NEW.source_metadata, '{}'::jsonb) || jsonb_build_object('auto_source_from_lead', true);
    END IF;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."ensure_source_from_lead"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."evaluate_smart_list_now"("p_list_id" "uuid") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_list record;
  v_count int := 0;
BEGIN
  IF NOT is_admin(auth.uid()) THEN
    RAISE EXCEPTION 'Only admins can evaluate smart lists';
  END IF;

  SELECT * INTO v_list FROM contact_lists WHERE id = p_list_id AND is_smart_list = TRUE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Smart list not found';
  END IF;

  IF v_list.source_entity = 'listings' THEN
    INSERT INTO smart_list_evaluation_queue (listing_id, queued_at)
    SELECT id, now() FROM listings
    WHERE deleted_at IS NULL
      AND (not_a_fit = false OR not_a_fit IS NULL)
      AND main_contact_email IS NOT NULL
    ON CONFLICT (listing_id) DO UPDATE SET queued_at = now();
    GET DIAGNOSTICS v_count = ROW_COUNT;
  ELSIF v_list.source_entity = 'remarketing_buyers' THEN
    INSERT INTO smart_list_buyer_evaluation_queue (buyer_id, queued_at)
    SELECT id, now() FROM buyers
    WHERE archived = false AND deleted_at IS NULL
    ON CONFLICT (buyer_id) DO UPDATE SET queued_at = now();
    GET DIAGNOSTICS v_count = ROW_COUNT;
  END IF;

  UPDATE contact_lists SET last_evaluated_at = now() WHERE id = p_list_id;
  RETURN v_count;
END;
$$;


ALTER FUNCTION "public"."evaluate_smart_list_now"("p_list_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."expire_stale_scoring_runs"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  expired_count INTEGER;
BEGIN
  UPDATE scoring_runs
  SET
    status = 'timed_out',
    completed_at = now()
  WHERE status = 'running'
    AND started_at < now() - INTERVAL '15 minutes';

  GET DIAGNOSTICS expired_count = ROW_COUNT;
  RETURN expired_count;
END;
$$;


ALTER FUNCTION "public"."expire_stale_scoring_runs"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."extract_domain"("url" "text") RETURNS "text"
    LANGUAGE "plpgsql" IMMUTABLE
    SET "search_path" TO 'public'
    AS $_$
DECLARE
  domain TEXT;
BEGIN
  IF url IS NULL OR url = '' THEN
    RETURN NULL;
  END IF;

  -- Remove protocol
  domain := regexp_replace(url, '^https?://', '', 'i');
  -- Remove www.
  domain := regexp_replace(domain, '^www\.', '', 'i');
  -- Remove path, query string, fragment
  domain := regexp_replace(domain, '[/?#].*$', '');
  -- Remove trailing dot
  domain := regexp_replace(domain, '\.$', '');
  -- Lowercase
  domain := lower(trim(domain));

  IF domain = '' THEN
    RETURN NULL;
  END IF;

  RETURN domain;
END;
$_$;


ALTER FUNCTION "public"."extract_domain"("url" "text") OWNER TO "postgres";


