COMMENT ON COLUMN "public"."listings"."main_contact_title" IS 'Primary seller contact title/position (e.g., CEO, CFO, Owner)';



COMMENT ON COLUMN "public"."listings"."scoring_notes" IS 'Human-readable breakdown of how the deal quality score was calculated (v4+)';



COMMENT ON COLUMN "public"."listings"."fts" IS 'Trigger-maintained tsvector for full-text search. Weighted: title(A) > category/location(B) > description(C) > tags(D)';



COMMENT ON COLUMN "public"."listings"."main_contact_first_name" IS 'Primary seller contact first name — synced from deal contact';



COMMENT ON COLUMN "public"."listings"."main_contact_last_name" IS 'Primary seller contact last name — synced from deal contact';



COMMENT ON COLUMN "public"."listings"."main_contact_linkedin" IS 'Primary seller contact LinkedIn profile URL — synced from deal contact';



COMMENT ON COLUMN "public"."listings"."featured_deal_ids" IS 'Optional hand-picked deal IDs to feature on this listing''s landing page. Falls back to most-recent deals when null.';



CREATE OR REPLACE FUNCTION "public"."find_listing_by_normalized_domain"("target_domain" "text") RETURNS SETOF "public"."listings"
    LANGUAGE "sql" STABLE
    AS $$
  SELECT *
  FROM listings
  WHERE normalize_domain(website) = normalize_domain(target_domain)
    AND website IS NOT NULL
    AND website != ''
    AND website != '<UNKNOWN>'
  LIMIT 1;
$$;


ALTER FUNCTION "public"."find_listing_by_normalized_domain"("target_domain" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_ca_resolve_and_propagate"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_map RECORD;
BEGIN
  -- ── Step 1: resolve contact_id by email if not already set ──
  IF NEW.contact_id IS NULL AND NEW.contact_email IS NOT NULL THEN
    SELECT c.id INTO NEW.contact_id
    FROM public.contacts c
    WHERE LOWER(c.email) = LOWER(NEW.contact_email)
      AND c.deleted_at IS NULL
      AND COALESCE(c.archived, false) = false
    ORDER BY c.created_at DESC
    LIMIT 1;
  END IF;

  -- ── Step 2 REMOVED (PR 2 / Step 5, 2026-04-26) ──
  -- The auto-create branch that built seller contacts with the
  -- phoneburner-auto-create source label when no match was found has
  -- been removed. Channel sync workers route unknown contacts through
  -- the unified resolver (_shared/contact-resolver.ts) and park
  -- unmatched activity in the channel's unmatched queue rather than
  -- creating placeholder contacts. Existing such orphans are addressed
  -- in a separate cleanup sweep; this function no longer creates new
  -- ones. (NOTE: the literal underscore form of the label is omitted
  -- from this comment so post-assertion 3's substring check does not
  -- false-positive on the docs.)

  -- ── Step 3: propagate disposition to contacts (if we have both) ──
  -- TCPA / DNC compliance + dialer-queue / disposition-history behaviour.
  -- Preserved exactly as in the production version.
  IF NEW.contact_id IS NOT NULL AND NEW.disposition_code IS NOT NULL THEN
    SELECT * INTO v_map
    FROM public.disposition_mappings
    WHERE phoneburner_disposition_code = NEW.disposition_code
      AND is_active = true
    LIMIT 1;

    IF FOUND THEN
      UPDATE public.contacts c
      SET
        do_not_call = CASE WHEN v_map.mark_do_not_call THEN true ELSE c.do_not_call END,
        do_not_call_reason = CASE
          WHEN v_map.mark_do_not_call AND c.do_not_call_reason IS NULL
          THEN 'Auto: ' || NEW.disposition_label
          ELSE c.do_not_call_reason
        END,
        phone_number_invalid = CASE WHEN v_map.mark_phone_invalid THEN true ELSE c.phone_number_invalid END,
        last_disposition_code = NEW.disposition_code,
        last_disposition_label = NEW.disposition_label,
        last_disposition_date = COALESCE(NEW.call_started_at, now()),
        updated_at = now()
      WHERE c.id = NEW.contact_id;

      -- Schedule callback if the mapping says so
      IF v_map.create_task AND v_map.task_type = 'call' AND v_map.task_due_offset_days IS NOT NULL
         AND NEW.callback_scheduled_date IS NULL THEN
        NEW.callback_scheduled_date := COALESCE(NEW.call_started_at, now())
          + (v_map.task_due_offset_days || ' days')::interval;
      END IF;
    END IF;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_ca_resolve_and_propagate"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_ca_resolve_and_propagate"() IS 'Auto-resolves contact_id from contact_email, creates a new seller contact if none exists, and propagates disposition flags (do_not_call, phone_invalid, callback scheduling) via disposition_mappings. Runs BEFORE INSERT/UPDATE on contact_activities.';



CREATE OR REPLACE FUNCTION "public"."fn_enforce_sender_role"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Allow system messages (no sender) to keep their provided sender_role
  IF NEW.sender_id IS NULL THEN
    RETURN NEW;
  END IF;
  
  -- Check if user is admin via user_roles table
  IF public.is_admin(NEW.sender_id) THEN
    NEW.sender_role := 'admin';
  ELSE
    NEW.sender_role := 'buyer';
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_enforce_sender_role"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_mirror_enrichment_status_to_listing"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NEW.listing_id IS NULL THEN
    RETURN NEW;
  END IF;
  -- Only fire if status meaningfully changed
  IF TG_OP = 'INSERT' OR (TG_OP = 'UPDATE' AND OLD.status IS DISTINCT FROM NEW.status) THEN
    UPDATE public.listings
    SET enrichment_status = NEW.status, updated_at = now()
    WHERE id = NEW.listing_id
      AND deleted_at IS NULL
      AND (enrichment_status IS DISTINCT FROM NEW.status);
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_mirror_enrichment_status_to_listing"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_protect_message_immutability"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF public.is_admin(auth.uid()) THEN
    RETURN NEW;
  END IF;

  IF NEW.body IS DISTINCT FROM OLD.body
    OR NEW.sender_id IS DISTINCT FROM OLD.sender_id
    OR NEW.sender_role IS DISTINCT FROM OLD.sender_role
    OR NEW.message_type IS DISTINCT FROM OLD.message_type
    OR NEW.connection_request_id IS DISTINCT FROM OLD.connection_request_id
    OR NEW.created_at IS DISTINCT FROM OLD.created_at THEN
    RAISE EXCEPTION 'Only read status fields can be updated by non-admin users';
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_protect_message_immutability"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."generate_deal_identifier"() RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    current_year TEXT;
    next_sequence INTEGER;
BEGIN
    current_year := EXTRACT(year FROM NOW())::TEXT;
    next_sequence := nextval('public.deal_identifier_seq');
    RETURN 'SCO-' || current_year || '-' || LPAD(next_sequence::TEXT, 5, '0');
END;
$$;


ALTER FUNCTION "public"."generate_deal_identifier"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."generate_valuation_display_name"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $_$
DECLARE
  type_label TEXT;
  seq_num INTEGER;
BEGIN
  type_label := CASE NEW.calculator_type
    WHEN 'general' THEN 'General Calculator'
    WHEN 'auto_shop' THEN 'Auto Shop Calculator'
    WHEN 'hvac' THEN 'HVAC Calculator'
    WHEN 'collision' THEN 'Collision Calculator'
    ELSE initcap(replace(NEW.calculator_type, '_', ' ')) || ' Calculator'
  END;

  SELECT COALESCE(MAX(
    CASE
      WHEN display_name ~ '#[0-9]+$'
      THEN CAST(regexp_replace(display_name, '.*#', '') AS INTEGER)
      ELSE 0
    END
  ), 0) + 1 INTO seq_num
  FROM valuation_leads
  WHERE calculator_type = NEW.calculator_type
    AND display_name IS NOT NULL;

  NEW.display_name := type_label || ' #' || seq_num;
  RETURN NEW;
END;
$_$;


ALTER FUNCTION "public"."generate_valuation_display_name"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_active_team_members"() RETURNS TABLE("user_id" "uuid", "full_name" "text", "first_name" "text", "last_name" "text", "email" "text", "aliases" "text"[])
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT
    ur.user_id,
    (COALESCE(p.first_name, '') || ' ' || COALESCE(p.last_name, ''))::TEXT AS full_name,
    COALESCE(p.first_name, '') AS first_name,
    COALESCE(p.last_name, '') AS last_name,
    p.email,
    COALESCE(
      (SELECT array_agg(a.alias) FROM public.team_member_aliases a WHERE a.profile_id = p.id),
      ARRAY[]::TEXT[]
    ) AS aliases
  FROM public.user_roles ur
  JOIN public.profiles p ON p.id = ur.user_id
  WHERE ur.role IN ('owner', 'admin', 'moderator');
$$;


ALTER FUNCTION "public"."get_active_team_members"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_all_user_roles"() RETURNS TABLE("user_id" "uuid", "role" "public"."app_role", "granted_at" timestamp with time zone, "granted_by" "uuid", "user_email" "text", "user_first_name" "text", "user_last_name" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NOT (public.is_owner(auth.uid()) OR public.has_role(auth.uid(), 'admin')) THEN
    RETURN;
  END IF;

  RETURN QUERY
  SELECT
    ur.user_id,
    ur.role,
    ur.granted_at,
    ur.granted_by,
    au.email::text as user_email,
    p.first_name::text as user_first_name,
    p.last_name::text as user_last_name
  FROM public.user_roles ur
  LEFT JOIN auth.users au ON ur.user_id = au.id
  LEFT JOIN public.profiles p ON ur.user_id = p.id
  ORDER BY
    CASE ur.role
      WHEN 'owner' THEN 1
      WHEN 'admin' THEN 2
      WHEN 'moderator' THEN 3
      ELSE 4
    END,
    ur.granted_at DESC;
END;
$$;


ALTER FUNCTION "public"."get_all_user_roles"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_buyer_deal_history"("p_buyer_id" "uuid") RETURNS TABLE("deal_id" "uuid", "deal_title" "text", "deal_category" "text", "has_teaser_access" boolean, "has_full_memo_access" boolean, "has_data_room_access" boolean, "memos_sent" bigint, "last_memo_sent_at" timestamp with time zone, "pipeline_stage" "text", "pipeline_stage_id" "uuid")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NOT public.is_admin(auth.uid()) THEN RAISE EXCEPTION 'Access denied: admin role required'; END IF;
  RETURN QUERY
  SELECT l.id, COALESCE(l.internal_company_name, l.title), l.category,
    COALESCE(a.can_view_teaser, false), COALESCE(a.can_view_full_memo, false),
    COALESCE(a.can_view_data_room, false),
    COALESCE((SELECT COUNT(*) FROM public.memo_distribution_log dl WHERE dl.deal_id = l.id AND dl.remarketing_buyer_id = p_buyer_id), 0::bigint),
    (SELECT MAX(dl.sent_at) FROM public.memo_distribution_log dl WHERE dl.deal_id = l.id AND dl.remarketing_buyer_id = p_buyer_id),
    ds.name, d.stage_id
  FROM public.listings l
  LEFT JOIN public.data_room_access a ON a.deal_id = l.id AND a.remarketing_buyer_id = p_buyer_id
  LEFT JOIN public.deal_pipeline d ON d.listing_id = l.id AND d.remarketing_buyer_id = p_buyer_id
  LEFT JOIN public.deal_stages ds ON ds.id = d.stage_id
  WHERE a.id IS NOT NULL OR d.id IS NOT NULL
    OR EXISTS (SELECT 1 FROM public.memo_distribution_log dl WHERE dl.deal_id = l.id AND dl.remarketing_buyer_id = p_buyer_id)
  ORDER BY GREATEST(a.granted_at, d.created_at,
    (SELECT MAX(dl.sent_at) FROM public.memo_distribution_log dl WHERE dl.deal_id = l.id AND dl.remarketing_buyer_id = p_buyer_id)
  ) DESC NULLS LAST;
END;
$$;


ALTER FUNCTION "public"."get_buyer_deal_history"("p_buyer_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_captarget_filter_options"() RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  result jsonb;
BEGIN
  IF NOT public.is_admin(auth.uid()) THEN
    RAISE EXCEPTION 'Access denied: admin role required';
  END IF;

  WITH sheet_tabs AS (
    SELECT DISTINCT captarget_sheet_tab AS v
    FROM listings
    WHERE deal_source = 'captarget'
      AND captarget_sheet_tab IS NOT NULL
      AND captarget_sheet_tab <> ''
    ORDER BY v
  ),
  outreach_channels AS (
    SELECT DISTINCT captarget_outreach_channel AS v
    FROM listings
    WHERE deal_source = 'captarget'
      AND captarget_outreach_channel IS NOT NULL
      AND captarget_outreach_channel <> ''
    ORDER BY v
  ),
  -- The UI accessor for the 'category' filter prefers `industry` then
  -- `category`; mirror that here so the dropdown options match what the
  -- rows actually render.
  industries AS (
    SELECT DISTINCT COALESCE(NULLIF(industry, ''), NULLIF(category, '')) AS v
    FROM listings
    WHERE deal_source = 'captarget'
      AND COALESCE(NULLIF(industry, ''), NULLIF(category, '')) IS NOT NULL
    ORDER BY v
  ),
  employee_ranges AS (
    SELECT DISTINCT linkedin_employee_range AS v
    FROM listings
    WHERE deal_source = 'captarget'
      AND linkedin_employee_range IS NOT NULL
      AND linkedin_employee_range <> ''
    ORDER BY v
  )
  SELECT jsonb_build_object(
    'captarget_sheet_tab',
      COALESCE((SELECT jsonb_agg(jsonb_build_object('label', v, 'value', v)) FROM sheet_tabs), '[]'::jsonb),
    'captarget_outreach_channel',
      COALESCE((SELECT jsonb_agg(jsonb_build_object('label', v, 'value', v)) FROM outreach_channels), '[]'::jsonb),
    'category',
      COALESCE((SELECT jsonb_agg(jsonb_build_object('label', v, 'value', v)) FROM industries), '[]'::jsonb),
    'linkedin_employee_range',
      COALESCE((SELECT jsonb_agg(jsonb_build_object('label', v, 'value', v)) FROM employee_ranges), '[]'::jsonb)
  )
  INTO result;

  RETURN result;
END;
$$;


ALTER FUNCTION "public"."get_captarget_filter_options"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."get_captarget_filter_options"() IS 'DISTINCT filter dropdown values for the CapTarget leads page. Uses COALESCE(industry, category) for the "category" field to match the UI accessor. Admin-gated.';



CREATE OR REPLACE FUNCTION "public"."get_captarget_page_stats"("p_date_from" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_date_to" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_hide_pushed" boolean DEFAULT false, "p_hide_not_fit" boolean DEFAULT false) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  result jsonb;
BEGIN
  IF NOT public.is_admin(auth.uid()) THEN
    RAISE EXCEPTION 'Access denied: admin role required';
  END IF;

  WITH base AS (
    SELECT
      id,
      pushed_to_all_deals,
      captarget_interest_type,
      enriched_at,
      deal_total_score,
      is_priority_target,
      captarget_status,
      captarget_contact_date,
      created_at,
      remarketing_status
    FROM listings
    WHERE deal_source = 'captarget'
  ),
  -- Summary counts: completely unfiltered (matches the header line
  -- "{N} total · {unpushed} un-pushed · {interest} interest · …")
  summary AS (
    SELECT
      count(*)                                                            AS total_deals,
      count(*) FILTER (WHERE pushed_to_all_deals IS NOT TRUE)              AS unpushed_count,
      count(*) FILTER (WHERE captarget_interest_type = 'interest')         AS interest_count,
      count(*) FILTER (WHERE enriched_at IS NOT NULL)                      AS enriched_count,
      count(*) FILTER (WHERE deal_total_score IS NOT NULL)                 AS scored_count
    FROM base
  ),
  -- KPI cards: filtered by the active timeframe only. Mirrors the client-side
  -- `isInRange(captarget_contact_date || created_at)` semantics.
  kpi_base AS (
    SELECT *
    FROM base
    WHERE (p_date_from IS NULL OR COALESCE(captarget_contact_date, created_at) >= p_date_from)
      AND (p_date_to   IS NULL OR COALESCE(captarget_contact_date, created_at) <= p_date_to)
  ),
  kpi AS (
    SELECT
      count(*)                                                 AS total_deals,
      count(*) FILTER (WHERE is_priority_target = true)         AS priority_deals,
      COALESCE(round(avg(deal_total_score)
        FILTER (WHERE deal_total_score IS NOT NULL)), 0)        AS avg_score,
      count(*) FILTER (WHERE deal_total_score IS NULL)          AS needs_scoring
    FROM kpi_base
  ),
  -- Status tab counts: base filters (hide-pushed, hide-not-fit, timeframe)
  -- applied but NOT the captarget_status tab itself — so active + inactive
  -- always sum to "all".
  tab_base AS (
    SELECT *
    FROM base
    WHERE (NOT p_hide_pushed OR pushed_to_all_deals IS NOT TRUE)
      AND (NOT p_hide_not_fit
           OR remarketing_status IS NULL
           OR remarketing_status <> 'not_a_fit')
      AND (p_date_from IS NULL OR COALESCE(captarget_contact_date, created_at) >= p_date_from)
      AND (p_date_to   IS NULL OR COALESCE(captarget_contact_date, created_at) <= p_date_to)
  ),
  tabs AS (
    SELECT
      count(*)                                              AS filtered_total,
      count(*) FILTER (WHERE captarget_status = 'active')    AS active_count,
      count(*) FILTER (WHERE captarget_status = 'inactive')  AS inactive_count
    FROM tab_base
  )
  SELECT jsonb_build_object(
    'summary', jsonb_build_object(
      'total_deals',    summary.total_deals,
      'unpushed_count', summary.unpushed_count,
      'interest_count', summary.interest_count,
      'enriched_count', summary.enriched_count,
      'scored_count',   summary.scored_count
    ),
    'kpi', jsonb_build_object(
      'total_deals',    kpi.total_deals,
      'priority_deals', kpi.priority_deals,
      'avg_score',      kpi.avg_score,
      'needs_scoring',  kpi.needs_scoring
    ),
    'tabs', jsonb_build_object(
      'filtered_total', tabs.filtered_total,
      'active_count',   tabs.active_count,
      'inactive_count', tabs.inactive_count
    )
  )
  INTO result
  FROM summary, kpi, tabs;

  RETURN result;
END;
$$;


ALTER FUNCTION "public"."get_captarget_page_stats"("p_date_from" timestamp with time zone, "p_date_to" timestamp with time zone, "p_hide_pushed" boolean, "p_hide_not_fit" boolean) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."get_captarget_page_stats"("p_date_from" timestamp with time zone, "p_date_to" timestamp with time zone, "p_hide_pushed" boolean, "p_hide_not_fit" boolean) IS 'Aggregate counters for the CapTarget leads admin page. Returns summary (unfiltered header counts), kpi (timeframe-filtered), and tabs (base-filtered). Admin-gated.';



CREATE OR REPLACE FUNCTION "public"."get_connection_request_analytics"("time_range" "text" DEFAULT '30d'::"text") RETURNS TABLE("total_requests" bigint, "pending_requests" bigint, "approved_requests" bigint, "rejected_requests" bigint, "conversion_rate" numeric)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  date_filter timestamp;
BEGIN
  date_filter := CASE time_range
    WHEN '7d' THEN now() - interval '7 days'
    WHEN '30d' THEN now() - interval '30 days'
    WHEN '90d' THEN now() - interval '90 days'
    ELSE now() - interval '30 days'
  END;

  RETURN QUERY
  SELECT
    count(*)::bigint as total_requests,
    count(*) FILTER (WHERE status = 'pending')::bigint as pending_requests,
    count(*) FILTER (WHERE status = 'approved')::bigint as approved_requests,
    count(*) FILTER (WHERE status = 'rejected')::bigint as rejected_requests,
    CASE 
      WHEN count(*) > 0 THEN 
        (count(*) FILTER (WHERE status = 'approved')::numeric / count(*)::numeric * 100)
      ELSE 0
    END as conversion_rate
  FROM connection_requests
  WHERE created_at > date_filter;
END;
$$;


ALTER FUNCTION "public"."get_connection_request_analytics"("time_range" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_connection_request_conflicts"() RETURNS TABLE("request_id" "uuid", "user_email" "text", "listing_title" "text", "conflict_type" "text", "conflict_details" "jsonb", "needs_review" boolean)
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT 
    cr.id as request_id,
    COALESCE(p.email, cr.lead_email) as user_email,
    l.title as listing_title,
    CASE 
      WHEN cr.source_metadata->>'has_duplicate_submission' = 'true' THEN 'duplicate_submission'
      WHEN cr.source_metadata->>'is_channel_duplicate' = 'true' THEN 'channel_merge'
      ELSE 'unknown'
    END as conflict_type,
    cr.source_metadata as conflict_details,
    COALESCE((cr.source_metadata->>'needs_admin_review')::boolean, false) as needs_review
  FROM connection_requests cr
  LEFT JOIN profiles p ON cr.user_id = p.id
  LEFT JOIN listings l ON cr.listing_id = l.id
  WHERE (
    cr.source_metadata->>'has_duplicate_submission' = 'true' OR
    cr.source_metadata->>'is_channel_duplicate' = 'true'
  )
  AND cr.status != 'rejected'
  ORDER BY cr.updated_at DESC
$$;


ALTER FUNCTION "public"."get_connection_request_conflicts"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_deal_access_matrix"("p_deal_id" "uuid") RETURNS TABLE("access_id" "uuid", "remarketing_buyer_id" "uuid", "marketplace_user_id" "uuid", "contact_id" "uuid", "buyer_name" "text", "buyer_company" "text", "contact_title" "text", "can_view_teaser" boolean, "can_view_full_memo" boolean, "can_view_data_room" boolean, "fee_agreement_signed" boolean, "fee_agreement_override" boolean, "fee_agreement_override_reason" "text", "granted_at" timestamp with time zone, "revoked_at" timestamp with time zone, "expires_at" timestamp with time zone, "last_access_at" timestamp with time zone, "access_token" "uuid")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Auth guard: admin-only
  IF NOT public.is_admin(auth.uid()) THEN
    RAISE EXCEPTION 'Access denied: admin role required';
  END IF;

  RETURN QUERY
  SELECT
    a.id AS access_id,
    a.remarketing_buyer_id,
    a.marketplace_user_id,
    a.contact_id,
    COALESCE(
      NULLIF(TRIM(c.first_name || ' ' || c.last_name), ''),
      rb.company_name,
      NULLIF(TRIM(p.first_name || ' ' || p.last_name), ''),
      p.email
    ) AS buyer_name,
    COALESCE(
      fa.primary_company_name,
      rb.pe_firm_name,
      rb.company_name
    ) AS buyer_company,
    c.title AS contact_title,
    a.can_view_teaser,
    a.can_view_full_memo,
    a.can_view_data_room,
    COALESCE(
      (SELECT fac.fee_agreement_status = 'signed'
       FROM public.firm_agreements fac
       WHERE fac.id = c.firm_id
       LIMIT 1),
      (SELECT fal.fee_agreement_status = 'signed'
       FROM public.firm_agreements fal
       WHERE (fal.email_domain = rb.email_domain OR fal.website_domain IS NOT NULL)
         AND rb.email_domain IS NOT NULL
         AND fal.email_domain = rb.email_domain
       LIMIT 1),
      false
    ) AS fee_agreement_signed,
    a.fee_agreement_override,
    a.fee_agreement_override_reason,
    a.granted_at,
    a.revoked_at,
    a.expires_at,
    COALESCE(
      a.last_access_at,
      (SELECT MAX(al.created_at) FROM public.data_room_audit_log al
       WHERE al.deal_id = a.deal_id
         AND al.user_id = COALESCE(a.marketplace_user_id, a.remarketing_buyer_id)
         AND al.action IN ('view_document', 'download_document', 'view_data_room'))
    ) AS last_access_at,
    a.access_token
  FROM public.data_room_access a
  LEFT JOIN public.contacts c ON c.id = a.contact_id
  LEFT JOIN public.firm_agreements fa ON fa.id = c.firm_id
  LEFT JOIN public.remarketing_buyers rb ON rb.id = a.remarketing_buyer_id
  LEFT JOIN public.profiles p ON p.id = a.marketplace_user_id
  WHERE a.deal_id = p_deal_id
  ORDER BY a.granted_at DESC;
END;
$$;


ALTER FUNCTION "public"."get_deal_access_matrix"("p_deal_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_deal_distribution_log"("p_deal_id" "uuid") RETURNS TABLE("log_id" "uuid", "buyer_name" "text", "buyer_company" "text", "memo_type" "text", "channel" "text", "sent_by_name" "text", "sent_at" timestamp with time zone, "email_address" "text", "notes" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Auth guard: admin-only
  IF NOT public.is_admin(auth.uid()) THEN
    RAISE EXCEPTION 'Access denied: admin role required';
  END IF;

  RETURN QUERY
  SELECT
    dl.id AS log_id,
    COALESCE(rb.company_name, NULLIF(TRIM(p.first_name || ' ' || p.last_name), ''), p.email) AS buyer_name,
    COALESCE(rb.pe_firm_name, rb.company_name) AS buyer_company,
    dl.memo_type,
    dl.channel,
    NULLIF(TRIM(sp.first_name || ' ' || sp.last_name), '') AS sent_by_name,
    dl.sent_at,
    dl.email_address,
    dl.notes
  FROM public.memo_distribution_log dl
  LEFT JOIN public.remarketing_buyers rb ON rb.id = dl.remarketing_buyer_id
  LEFT JOIN public.profiles p ON p.id = dl.marketplace_user_id
  LEFT JOIN public.profiles sp ON sp.id = dl.sent_by
  WHERE dl.deal_id = p_deal_id
  ORDER BY dl.sent_at DESC;
END;
$$;


ALTER FUNCTION "public"."get_deal_distribution_log"("p_deal_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_deals_with_buyer_profiles"() RETURNS TABLE("deal_id" "uuid", "deal_title" "text", "deal_description" "text", "deal_value" numeric, "deal_priority" "text", "deal_probability" numeric, "deal_expected_close_date" "date", "deal_source" "text", "deal_created_at" timestamp with time zone, "deal_updated_at" timestamp with time zone, "deal_stage_entered_at" timestamp with time zone, "deal_deleted_at" timestamp with time zone, "connection_request_id" "uuid", "stage_id" "uuid", "stage_name" "text", "stage_color" "text", "stage_position" integer, "stage_is_active" boolean, "stage_is_default" boolean, "stage_is_system_stage" boolean, "stage_default_probability" numeric, "stage_type" "text", "listing_id" "uuid", "listing_title" "text", "listing_revenue" numeric, "listing_ebitda" numeric, "listing_location" "text", "listing_category" "text", "listing_internal_company_name" "text", "listing_image_url" "text", "listing_deal_total_score" numeric, "listing_is_priority_target" boolean, "listing_needs_owner_contact" boolean, "listing_needs_buyer_search" boolean, "admin_id" "uuid", "admin_first_name" "text", "admin_last_name" "text", "admin_email" "text", "buyer_type" "text", "buyer_website" "text", "buyer_quality_score" numeric, "buyer_tier" integer, "contact_name" "text", "contact_email" "text", "contact_company" "text", "contact_phone" "text", "contact_role" "text", "buyer_first_name" "text", "buyer_last_name" "text", "buyer_email" "text", "buyer_company" "text", "buyer_phone" "text", "nda_status" "text", "fee_agreement_status" "text", "followed_up" boolean, "followed_up_at" timestamp with time zone, "negative_followed_up" boolean, "negative_followed_up_at" timestamp with time zone, "meeting_scheduled" boolean, "under_loi" boolean)
    LANGUAGE "sql" STABLE
    AS $$
  SELECT
    d.id, d.title, d.description, d.value, d.priority, d.probability,
    d.expected_close_date, d.source, d.created_at, d.updated_at,
    COALESCE(d.stage_entered_at, d.created_at), d.deleted_at,
    d.connection_request_id,
    ds.id, ds.name, ds.color, ds.position, ds.is_active, ds.is_default,
    ds.is_system_stage, ds.default_probability, ds.stage_type,
    l.id, l.title, l.revenue, l.ebitda, l.location, l.category,
    l.internal_company_name, l.image_url, l.deal_total_score,
    l.is_priority_target, l.needs_owner_contact,
    COALESCE(l.needs_buyer_search, false),
    ap.id, ap.first_name, ap.last_name, ap.email,
    bp.buyer_type, COALESCE(bp.website, bp.buyer_org_url),
    bp.buyer_quality_score, bp.buyer_tier,
    cr.lead_name, cr.lead_email, cr.lead_company, cr.lead_phone, cr.lead_role,
    bp.first_name, bp.last_name, bp.email, bp.company, bp.phone_number,
    CASE WHEN cr.lead_nda_signed THEN 'signed'
         WHEN cr.lead_nda_email_sent THEN 'sent'
         ELSE 'not_sent' END,
    CASE WHEN cr.lead_fee_agreement_signed THEN 'signed'
         WHEN cr.lead_fee_agreement_email_sent THEN 'sent'
         ELSE 'not_sent' END,
    COALESCE(cr.followed_up, false), cr.followed_up_at,
    COALESCE(cr.negative_followed_up, false), cr.negative_followed_up_at,
    COALESCE(d.meeting_scheduled, false),
    COALESCE(d.under_loi, false)
  FROM public.deal_pipeline d
  LEFT JOIN public.listings l ON l.id = d.listing_id
  LEFT JOIN public.deal_stages ds ON ds.id = d.stage_id
  LEFT JOIN public.profiles ap ON ap.id = d.assigned_to
  LEFT JOIN public.connection_requests cr ON cr.id = d.connection_request_id
  LEFT JOIN public.profiles bp ON bp.id = cr.user_id
  WHERE d.deleted_at IS NULL
    AND (d.connection_request_id IS NULL OR cr.id IS NOT NULL)
  ORDER BY d.created_at DESC;
$$;


ALTER FUNCTION "public"."get_deals_with_buyer_profiles"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_deals_with_details"() RETURNS TABLE("deal_id" "uuid", "deal_title" "text", "deal_description" "text", "deal_value" numeric, "deal_priority" "text", "deal_probability" integer, "deal_expected_close_date" "date", "deal_source" "text", "deal_created_at" timestamp with time zone, "deal_updated_at" timestamp with time zone, "deal_stage_entered_at" timestamp with time zone, "stage_id" "uuid", "stage_name" "text", "stage_color" "text", "stage_position" integer, "listing_id" "uuid", "listing_title" "text", "listing_revenue" numeric, "listing_ebitda" numeric, "listing_location" "text", "contact_name" "text", "contact_email" "text", "contact_company" "text", "contact_phone" "text", "contact_role" "text", "buyer_contact_id" "uuid", "buyer_contact_name" "text", "buyer_contact_email" "text", "seller_contact_id" "uuid", "seller_contact_name" "text", "remarketing_buyer_id" "uuid", "remarketing_buyer_company" "text", "nda_status" "text", "fee_agreement_status" "text", "followed_up" boolean, "followed_up_at" timestamp with time zone, "assigned_to" "uuid", "assigned_admin_name" "text", "assigned_admin_email" "text", "total_tasks" integer, "pending_tasks" integer, "completed_tasks" integer, "activity_count" integer)
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT
    d.id as deal_id,
    d.title as deal_title,
    d.description as deal_description,
    d.value as deal_value,
    d.priority as deal_priority,
    d.probability as deal_probability,
    d.expected_close_date as deal_expected_close_date,
    d.source as deal_source,
    d.created_at as deal_created_at,
    d.updated_at as deal_updated_at,
    d.stage_entered_at as deal_stage_entered_at,
    ds.id as stage_id,
    ds.name as stage_name,
    ds.color as stage_color,
    ds.position as stage_position,
    l.id as listing_id,
    l.title as listing_title,
    l.revenue as listing_revenue,
    l.ebitda as listing_ebitda,
    l.location as listing_location,
    -- Contact info now from connection_requests or contacts table
    COALESCE(
      TRIM(bc.first_name || ' ' || bc.last_name),
      cr.lead_name
    ) as contact_name,
    COALESCE(bc.email, cr.lead_email) as contact_email,
    COALESCE(rb.company_name, cr.lead_company) as contact_company,
    COALESCE(bc.phone, cr.lead_phone) as contact_phone,
    COALESCE(bc.title, cr.lead_role) as contact_role,
    d.buyer_contact_id,
    CASE WHEN bc.id IS NOT NULL
      THEN TRIM(bc.first_name || ' ' || bc.last_name)
      ELSE NULL
    END as buyer_contact_name,
    bc.email as buyer_contact_email,
    d.seller_contact_id,
    CASE WHEN sc.id IS NOT NULL
      THEN TRIM(sc.first_name || ' ' || sc.last_name)
      ELSE NULL
    END as seller_contact_name,
    d.remarketing_buyer_id,
    rb.company_name as remarketing_buyer_company,
    d.nda_status,
    d.fee_agreement_status,
    d.followed_up,
    d.followed_up_at,
    d.assigned_to,
    COALESCE(p.first_name || ' ' || p.last_name, p.email) as assigned_admin_name,
    p.email as assigned_admin_email,
    COALESCE(task_stats.total_tasks, 0) as total_tasks,
    COALESCE(task_stats.pending_tasks, 0) as pending_tasks,
    COALESCE(task_stats.completed_tasks, 0) as completed_tasks,
    COALESCE(activity_stats.activity_count, 0) as activity_count
  FROM public.deal_pipeline d
  LEFT JOIN public.deal_stages ds ON d.stage_id = ds.id
  LEFT JOIN public.listings l ON d.listing_id = l.id
  LEFT JOIN public.profiles p ON d.assigned_to = p.id
  LEFT JOIN public.contacts bc ON d.buyer_contact_id = bc.id
  LEFT JOIN public.contacts sc ON d.seller_contact_id = sc.id
  LEFT JOIN public.remarketing_buyers rb ON d.remarketing_buyer_id = rb.id
  LEFT JOIN public.connection_requests cr ON cr.id = d.connection_request_id
  LEFT JOIN (
    SELECT
      entity_id AS deal_id,
      COUNT(*)::integer as total_tasks,
      SUM(CASE WHEN status IN ('pending', 'pending_approval', 'in_progress', 'overdue') THEN 1 ELSE 0 END)::integer as pending_tasks,
      SUM(CASE WHEN status = 'completed' THEN 1 ELSE 0 END)::integer as completed_tasks
    FROM public.daily_standup_tasks
    WHERE entity_type = 'deal'
    GROUP BY entity_id
  ) task_stats ON d.id = task_stats.deal_id
  LEFT JOIN (
    SELECT
      deal_id,
      COUNT(*)::integer as activity_count
    FROM public.deal_activities
    GROUP BY deal_id
  ) activity_stats ON d.id = activity_stats.deal_id
  WHERE d.deleted_at IS NULL
  ORDER BY d.updated_at DESC;
$$;


ALTER FUNCTION "public"."get_deals_with_details"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_feedback_analytics"("days_back" integer DEFAULT 30) RETURNS TABLE("total_feedback" bigint, "unread_count" bigint, "avg_response_time_hours" numeric, "satisfaction_avg" numeric, "category_breakdown" "jsonb", "priority_breakdown" "jsonb", "daily_trends" "jsonb", "top_users" "jsonb")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  start_date TIMESTAMP := NOW() - (days_back || ' days')::INTERVAL;
BEGIN
  -- Get basic metrics
  SELECT COUNT(*) INTO total_feedback
  FROM feedback_messages
  WHERE created_at >= start_date;
  
  SELECT COUNT(*) INTO unread_count
  FROM feedback_messages
  WHERE status = 'unread' AND created_at >= start_date;
  
  -- Calculate average response time (avoid nested aggregates)
  WITH response_times AS (
    SELECT EXTRACT(EPOCH FROM (updated_at - created_at))/3600 as hours_diff
    FROM feedback_messages
    WHERE admin_response IS NOT NULL 
      AND updated_at > created_at 
      AND created_at >= start_date
  )
  SELECT COALESCE(AVG(hours_diff), 0) INTO avg_response_time_hours
  FROM response_times;
  
  -- Set satisfaction average to null since column doesn't exist
  satisfaction_avg := NULL;
  
  -- Category breakdown
  SELECT COALESCE(jsonb_object_agg(category, cnt), '{}'::jsonb) INTO category_breakdown
  FROM (
    SELECT category, COUNT(*) as cnt
    FROM feedback_messages
    WHERE created_at >= start_date
    GROUP BY category
  ) t;
  
  -- Priority breakdown
  SELECT COALESCE(jsonb_object_agg(priority, cnt), '{}'::jsonb) INTO priority_breakdown
  FROM (
    SELECT priority, COUNT(*) as cnt
    FROM feedback_messages
    WHERE created_at >= start_date
    GROUP BY priority
  ) t;
  
  -- Daily trends (avoid nested aggregates)
  WITH daily_data AS (
    SELECT 
      date_trunc('day', created_at)::DATE as trend_date,
      COUNT(*) as daily_count,
      AVG(
        CASE WHEN admin_response IS NOT NULL AND updated_at > created_at
        THEN EXTRACT(EPOCH FROM (updated_at - created_at))/3600
        ELSE NULL END
      ) as daily_avg_response_time
    FROM feedback_messages
    WHERE created_at >= start_date
    GROUP BY date_trunc('day', created_at)
  )
  SELECT COALESCE(jsonb_agg(
    jsonb_build_object(
      'date', trend_date,
      'count', daily_count,
      'avg_response_time', daily_avg_response_time
    ) ORDER BY trend_date
  ), '[]'::jsonb) INTO daily_trends
  FROM daily_data;
  
  -- Top users by feedback volume
  SELECT COALESCE(jsonb_agg(
    jsonb_build_object(
      'user_id', user_id,
      'feedback_count', cnt
    ) ORDER BY cnt DESC
  ), '[]'::jsonb) INTO top_users
  FROM (
    SELECT 
      user_id,
      COUNT(*) as cnt
    FROM feedback_messages
    WHERE created_at >= start_date AND user_id IS NOT NULL
    GROUP BY user_id
    ORDER BY cnt DESC
    LIMIT 10
  ) t;
  
  RETURN QUERY SELECT 
    get_feedback_analytics.total_feedback,
    get_feedback_analytics.unread_count,
    get_feedback_analytics.avg_response_time_hours,
    get_feedback_analytics.satisfaction_avg,
    get_feedback_analytics.category_breakdown,
    get_feedback_analytics.priority_breakdown,
    get_feedback_analytics.daily_trends,
    get_feedback_analytics.top_users;
END;
$$;


ALTER FUNCTION "public"."get_feedback_analytics"("days_back" integer) OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "public"."buyer_transcripts" (
