    "listing_id" "uuid",
    "phone_number" "text",
    "deal_transcript_id" "uuid",
    "has_content" boolean DEFAULT true
);


ALTER TABLE "public"."buyer_transcripts" OWNER TO "postgres";


COMMENT ON COLUMN "public"."buyer_transcripts"."listing_id" IS 'Optional link to the specific deal this meeting relates to. Set by bulk-sync-all-fireflies when the meeting''s participant emails or title match a listing, or by the backfill in migration 20260801000061. Allowed to be NULL — a buyer can have transcripts before any deal exists.';



COMMENT ON COLUMN "public"."buyer_transcripts"."phone_number" IS 'Dialed phone number for this call. Surfaces the primary matching key on orphan/unlinked surfaces without requiring a join through contact_activities.';



COMMENT ON COLUMN "public"."buyer_transcripts"."deal_transcript_id" IS 'Cross-side link: the deal_transcripts row for the same Fireflies meeting (shared fireflies_transcript_id). NULL when the meeting is buyer-only or sourced from PhoneBurner (no fireflies_id on either side). Populated by trg_link_transcripts_from_buyer trigger on INSERT or UPDATE OF fireflies_transcript_id.';



COMMENT ON COLUMN "public"."buyer_transcripts"."has_content" IS 'true = fetch content from Fireflies API; false = Fireflies has no retrievable content (tried + failed, or meeting was too short / purged). Mirror of deal_transcripts.has_content.';



CREATE TABLE IF NOT EXISTS "public"."contact_activities" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "contact_id" "uuid",
    "remarketing_buyer_id" "uuid",
    "user_id" "uuid",
    "phoneburner_session_id" "uuid",
    "activity_type" "text" NOT NULL,
    "source_system" "text" DEFAULT 'phoneburner'::"text" NOT NULL,
    "call_started_at" timestamp with time zone,
    "call_connected_at" timestamp with time zone,
    "call_ended_at" timestamp with time zone,
    "call_duration_seconds" integer,
    "talk_time_seconds" integer,
    "call_outcome" "text",
    "answered_by" "text",
    "disposition_code" "text",
    "disposition_label" "text",
    "disposition_notes" "text",
    "disposition_set_at" timestamp with time zone,
    "callback_scheduled_date" timestamp with time zone,
    "callback_completed_at" timestamp with time zone,
    "callback_outcome" "text",
    "recording_url" "text",
    "recording_duration_seconds" integer,
    "user_name" "text",
    "user_email" "text",
    "phoneburner_call_id" "text",
    "phoneburner_contact_id" "text",
    "phoneburner_event_id" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "contact_email" "text",
    "call_transcript" "text",
    "call_direction" "text",
    "call_connected" boolean,
    "recording_url_public" "text",
    "phoneburner_status" "text",
    "contact_notes" "text",
    "phoneburner_lead_id" "text",
    "listing_id" "uuid",
    "request_id" "text",
    "recording_storage_path" "text",
    "recording_archived_at" timestamp with time zone,
    "valuation_lead_id" "uuid",
    "ai_summary" "text",
    "extracted_insights" "jsonb",
    "extraction_status" "text",
    "transcription_status" "text" DEFAULT 'none'::"text",
    "transcription_provider" "text",
    "transcription_job_id" "text",
    "transcription_requested_at" timestamp with time zone,
    "transcription_completed_at" timestamp with time zone,
    "transcription_error" "text",
    "transcription_attempts" integer DEFAULT 0 NOT NULL,
    "phone_number" "text",
    "matching_status" "text",
    "previous_contact_id" "uuid",
    "matched_at" timestamp with time zone,
    "unmatched_at" timestamp with time zone,
    "unmatched_reason" "text",
    "resolution_method" "text",
    CONSTRAINT "contact_activities_anchor_xor" CHECK ((NOT (("remarketing_buyer_id" IS NOT NULL) AND ("listing_id" IS NOT NULL)))),
    CONSTRAINT "contact_activities_transcription_status_check" CHECK (("transcription_status" = ANY (ARRAY['none'::"text", 'pending'::"text", 'submitting'::"text", 'polling'::"text", 'completed'::"text", 'failed'::"text", 'not_applicable'::"text"])))
);


ALTER TABLE "public"."contact_activities" OWNER TO "postgres";


COMMENT ON COLUMN "public"."contact_activities"."recording_storage_path" IS 'Path (relative to storage.call-recordings bucket) of the archived MP3 copy of recording_url. NULL until archive-call-recording runs.';



COMMENT ON COLUMN "public"."contact_activities"."recording_archived_at" IS 'When archive-call-recording successfully fetched and uploaded the recording. Lets us distinguish "archive pending" from "archive failed".';



COMMENT ON COLUMN "public"."contact_activities"."extracted_insights" IS 'AI-extracted structured criteria from call_transcript (same shape as buyer_transcripts.extracted_insights). Populated by extract-phoneburner-call edge function.';



COMMENT ON COLUMN "public"."contact_activities"."transcription_status" IS 'Lifecycle of AssemblyAI transcription for this call. See 20260801000058 migration.';



COMMENT ON COLUMN "public"."contact_activities"."phone_number" IS 'Normalized phone number that was dialed / received on this activity. Populated by the PhoneBurner webhook going forward; historical rows backfilled from contacts.phone via contact_id.';



COMMENT ON COLUMN "public"."contact_activities"."matching_status" IS 'Application-set: ''matched'' when contact_id resolves, ''unmatched'' when it does not. Retro-match cron filters on this.';



COMMENT ON COLUMN "public"."contact_activities"."previous_contact_id" IS 'Preserves the prior contact_id when an orphan is archived and contact_id is nulled. Lets us trace back to the archived contact for audit.';



COMMENT ON COLUMN "public"."contact_activities"."matched_at" IS 'When the resolver linked contact_id. Cleared when contact_id is cleared. Never set while contact_id IS NULL.';



COMMENT ON COLUMN "public"."contact_activities"."unmatched_at" IS 'When the row entered (or returned to) unmatched state. Set on initial unmatched insert and on orphan-archival re-decoupling.';



COMMENT ON COLUMN "public"."contact_activities"."unmatched_reason" IS 'Why this row is currently unmatched. Distinct from any historical reason — always reflects current state.';



COMMENT ON COLUMN "public"."contact_activities"."resolution_method" IS 'How matched_at got populated: ''sync'', ''webhook'', ''retro_match'', ''manual_link''.';



COMMENT ON CONSTRAINT "contact_activities_anchor_xor" ON "public"."contact_activities" IS 'Buyer outreach anchors to remarketing_buyer_id; seller outreach anchors to listing_id. A single activity row may carry zero or one of the two, never both.';



CREATE TABLE IF NOT EXISTS "public"."contacts" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
