    "last_name" "text" DEFAULT ''::"text" NOT NULL,
    "email" "text",
    "phone" "text",
    "linkedin_url" "text",
    "title" "text",
    "contact_type" "text" DEFAULT 'buyer'::"text" NOT NULL,
    "firm_id" "uuid",
    "remarketing_buyer_id" "uuid",
    "is_primary_at_firm" boolean DEFAULT false,
    "profile_id" "uuid",
    "listing_id" "uuid",
    "is_primary_seller_contact" boolean DEFAULT false,
    "nda_signed" boolean DEFAULT false,
    "nda_signed_at" timestamp with time zone,
    "fee_agreement_signed" boolean DEFAULT false,
    "fee_agreement_signed_at" timestamp with time zone,
    "source" "text" DEFAULT 'manual'::"text",
    "notes" "text",
    "archived" boolean DEFAULT false,
    "created_at" timestamp with time zone DEFAULT "now"(),
    "updated_at" timestamp with time zone DEFAULT "now"(),
    "last_call_attempt_at" timestamp with time zone,
    "last_call_connected_at" timestamp with time zone,
    "total_call_attempts" integer DEFAULT 0,
    "total_calls_connected" integer DEFAULT 0,
    "total_call_duration_seconds" integer DEFAULT 0,
    "phoneburner_contact_id" "text",
    "phoneburner_last_sync_at" timestamp with time zone,
    "do_not_call" boolean DEFAULT false,
    "do_not_call_reason" "text",
    "phone_number_invalid" boolean DEFAULT false,
    "next_action_type" "text",
    "next_action_date" "date",
    "next_action_notes" "text",
    "last_disposition_code" "text",
    "last_disposition_label" "text",
    "last_disposition_date" timestamp with time zone,
    "company_name" "text",
    "created_by" "uuid",
    "email_domain" "text",
    "confidence" "text" DEFAULT 'unverified'::"text",
    "last_enriched_at" timestamp with time zone,
    "last_enrichment_source" "text",
    "merged_into_id" "uuid",
    "deleted_at" timestamp with time zone,
    "role_category" "text",
    "priority_level" smallint,
    "email_verified_at" timestamp with time zone,
    "buyer_identity_id" "uuid",
    "last_interaction_summary" "text",
    "last_interaction_summary_generated_at" timestamp with time zone,
    "last_interaction_summary_stale" boolean DEFAULT true NOT NULL,
    "last_contacted_at" timestamp with time zone,
    "archive_reason" "text",
    "mobile_phone_1" "text",
    "mobile_phone_2" "text",
    "mobile_phone_3" "text",
    "office_phone" "text",
    "phone_source" "text",
    "phone_normalized" "text" GENERATED ALWAYS AS ("regexp_replace"("phone", '[^0-9]'::"text", ''::"text", 'g'::"text")) STORED,
    "mobile_phone_1_normalized" "text" GENERATED ALWAYS AS ("regexp_replace"("mobile_phone_1", '[^0-9]'::"text", ''::"text", 'g'::"text")) STORED,
    "mobile_phone_2_normalized" "text" GENERATED ALWAYS AS ("regexp_replace"("mobile_phone_2", '[^0-9]'::"text", ''::"text", 'g'::"text")) STORED,
    "mobile_phone_3_normalized" "text" GENERATED ALWAYS AS ("regexp_replace"("mobile_phone_3", '[^0-9]'::"text", ''::"text", 'g'::"text")) STORED,
    "office_phone_normalized" "text" GENERATED ALWAYS AS ("regexp_replace"("office_phone", '[^0-9]'::"text", ''::"text", 'g'::"text")) STORED,
    CONSTRAINT "contacts_confidence_check" CHECK (("confidence" = ANY (ARRAY['verified'::"text", 'likely'::"text", 'guessed'::"text", 'unverified'::"text"]))),
    CONSTRAINT "contacts_contact_type_check" CHECK (("contact_type" = ANY (ARRAY['buyer'::"text", 'seller'::"text", 'advisor'::"text", 'internal'::"text", 'portal_user'::"text"]))),
    CONSTRAINT "contacts_priority_level_check" CHECK ((("priority_level" IS NULL) OR (("priority_level" >= 1) AND ("priority_level" <= 5))))
);


ALTER TABLE "public"."contacts" OWNER TO "postgres";


COMMENT ON TABLE "public"."contacts" IS 'Unified contact identity for all people across the platform.';



COMMENT ON COLUMN "public"."contacts"."company_name" IS 'Company the contact works at. May differ from the linked firm name.';



COMMENT ON COLUMN "public"."contacts"."email_domain" IS 'Lowercased domain extracted from email, or NULL if the domain is a generic/free provider (gmail, yahoo, etc.). Auto-populated by set_contact_email_domain trigger. Used for firm-level activity matching via firm_domain_aliases.';



COMMENT ON COLUMN "public"."contacts"."last_interaction_summary" IS 'AI-generated rollup of this contact''s recent interactions. Scoped to this specific person (not the whole firm). Regenerated when any of their source events change.';



COMMENT ON COLUMN "public"."contacts"."archive_reason" IS 'Audit string set when archived=true. PR 2 orphan cleanup uses ''orphan_auto_created''. Future archival paths (merges, manual archives) should populate this too.';



COMMENT ON COLUMN "public"."contacts"."mobile_phone_1" IS 'Primary mobile/cell number. Preferred dial number for PhoneBurner.';



COMMENT ON COLUMN "public"."contacts"."mobile_phone_2" IS 'Secondary mobile number.';



COMMENT ON COLUMN "public"."contacts"."mobile_phone_3" IS 'Tertiary mobile number.';



COMMENT ON COLUMN "public"."contacts"."office_phone" IS 'Office/main line/switchboard. Usually not dialable for direct outreach.';



COMMENT ON COLUMN "public"."contacts"."phone_source" IS 'Origin of the phone data: blitz, clay, prospeo, apollo_import, manual, backfill, etc.';



