COMMENT ON COLUMN "public"."profiles"."is_admin" IS 'Legacy flag, auto-synced from user_roles table via trigger. Do not update directly. Use change_user_role() function to modify roles.';



COMMENT ON COLUMN "public"."profiles"."investment_size" IS 'Array of investment size ranges selected by the user (jsonb array of text)';



COMMENT ON COLUMN "public"."profiles"."referral_source" IS 'How the user heard about SourceCo (e.g., google, linkedin, ai, etc.)';



COMMENT ON COLUMN "public"."profiles"."referral_source_detail" IS 'Follow-up detail about the referral source (e.g., which AI, what search term, etc.)';



COMMENT ON COLUMN "public"."profiles"."deal_sourcing_methods" IS 'How the user typically sources acquisition targets (multi-select)';



COMMENT ON COLUMN "public"."profiles"."target_acquisition_volume" IS 'Number of acquisitions targeting in next 12 months';



COMMENT ON COLUMN "public"."profiles"."first_external_referrer" IS 'Original external referrer from cross-domain tracking (e.g., www.google.com)';



COMMENT ON COLUMN "public"."profiles"."first_blog_landing" IS 'First blog page visited from cross-domain tracking (e.g., /blog/best-m-a-news)';



COMMENT ON COLUMN "public"."profiles"."first_seen_at" IS 'Timestamp of first discovery from user_journeys';



COMMENT ON COLUMN "public"."profiles"."first_utm_source" IS 'First-touch UTM source for campaign attribution';



COMMENT ON COLUMN "public"."profiles"."buyer_identity_id" IS 'Reciprocal pointer to buyer_identities(id) for reverse lookups. Nullable during soft migration. FK constraint deferred until backfill audit shows zero gap.';



COMMENT ON COLUMN "public"."profiles"."signup_metadata" IS 'Arbitrary signup-time context: from_deal_id, first_deal_viewed, is_landing_page_referral, UTM params. JSONB so shape can evolve without migrations.';



COMMENT ON COLUMN "public"."profiles"."merged_into_profile_id" IS 'Tombstone pointer for duplicate profiles merged into a canonical row. When a profile is deduplicated the loser keeps its id (and its auth.users link) so historical FKs continue to resolve, and points merged_into_profile_id at the canonical winner. Reads should either filter WHERE merged_into_profile_id IS NULL or use resolve_canonical_profile_id().';



