CREATE OR REPLACE FUNCTION "public"."get_or_create_firm"("p_company_name" "text", "p_website" "text" DEFAULT NULL::"text", "p_email" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_firm_id UUID;
  v_normalized_name TEXT;
  v_website_domain TEXT;
  v_email_domain TEXT;
  v_variations JSONB;
BEGIN
  -- Normalize inputs
  v_normalized_name := normalize_company_name(p_company_name);
  v_website_domain := extract_domain(p_website);
  v_email_domain := extract_domain(p_email);
  
  IF v_normalized_name IS NULL THEN
    RETURN NULL;
  END IF;
  
  -- Strategy 1: Exact normalized name match
  SELECT id INTO v_firm_id
  FROM public.firm_agreements
  WHERE normalized_company_name = v_normalized_name
  LIMIT 1;
  
  IF v_firm_id IS NOT NULL THEN
    -- Update domains if not set
    UPDATE public.firm_agreements
    SET 
      website_domain = COALESCE(website_domain, v_website_domain),
      email_domain = COALESCE(email_domain, v_email_domain),
      company_name_variations = CASE
        WHEN NOT (company_name_variations @> to_jsonb(p_company_name))
        THEN company_name_variations || to_jsonb(p_company_name)
        ELSE company_name_variations
      END,
      updated_at = NOW()
    WHERE id = v_firm_id;
    
    RETURN v_firm_id;
  END IF;
  
  -- Strategy 2: Match by website domain (if provided and not generic)
  IF v_website_domain IS NOT NULL 
     AND v_website_domain NOT IN ('gmail.com', 'yahoo.com', 'hotmail.com', 'outlook.com', 'icloud.com') THEN
    SELECT id INTO v_firm_id
    FROM public.firm_agreements
    WHERE website_domain = v_website_domain
    LIMIT 1;
    
    IF v_firm_id IS NOT NULL THEN
      RETURN v_firm_id;
    END IF;
  END IF;
  
  -- Strategy 3: Match by email domain (if provided and not generic)
  IF v_email_domain IS NOT NULL 
     AND v_email_domain NOT IN ('gmail.com', 'yahoo.com', 'hotmail.com', 'outlook.com', 'icloud.com') THEN
    SELECT id INTO v_firm_id
    FROM public.firm_agreements
    WHERE email_domain = v_email_domain
    LIMIT 1;
    
    IF v_firm_id IS NOT NULL THEN
      RETURN v_firm_id;
    END IF;
  END IF;
  
  -- No match found, create new firm
  v_variations := to_jsonb(ARRAY[p_company_name]);
  
  INSERT INTO public.firm_agreements (
    normalized_company_name,
    primary_company_name,
    website_domain,
    email_domain,
    company_name_variations
  ) VALUES (
    v_normalized_name,
    p_company_name,
    v_website_domain,
    v_email_domain,
    v_variations
  )
  RETURNING id INTO v_firm_id;
  
  RETURN v_firm_id;
END;
$$;


ALTER FUNCTION "public"."get_or_create_firm"("p_company_name" "text", "p_website" "text", "p_email" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_permission_audit_log"("filter_user_id" "uuid" DEFAULT NULL::"uuid", "limit_count" integer DEFAULT 100) RETURNS TABLE("id" "uuid", "target_user_id" "uuid", "target_email" "text", "target_name" "text", "changed_by" "uuid", "changer_email" "text", "changer_name" "text", "old_role" "public"."app_role", "new_role" "public"."app_role", "reason" "text", "created_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Only owners can view audit logs
  IF NOT public.is_owner(auth.uid()) THEN
    RAISE EXCEPTION 'Only owners can view permission audit logs';
  END IF;
  
  RETURN QUERY
  SELECT 
    pal.id,
    pal.target_user_id,
    tu.email::text AS target_email,
    COALESCE(tp.first_name || ' ' || tp.last_name, tu.email::text) AS target_name,
    pal.changed_by,
    cu.email::text AS changer_email,
    COALESCE(cp.first_name || ' ' || cp.last_name, cu.email::text) AS changer_name,
    pal.old_role,
    pal.new_role,
    pal.reason,
    pal.created_at
  FROM public.permission_audit_log pal
  LEFT JOIN auth.users tu ON pal.target_user_id = tu.id
  LEFT JOIN public.profiles tp ON pal.target_user_id = tp.id
  LEFT JOIN auth.users cu ON pal.changed_by = cu.id
  LEFT JOIN public.profiles cp ON pal.changed_by = cp.id
  WHERE (filter_user_id IS NULL OR pal.target_user_id = filter_user_id)
  ORDER BY pal.created_at DESC
  LIMIT limit_count;
END;
$$;


ALTER FUNCTION "public"."get_permission_audit_log"("filter_user_id" "uuid", "limit_count" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_phoneburner_connected_users"() RETURNS TABLE("token_id" "uuid", "user_id" "uuid", "display_name" "text", "phoneburner_user_email" "text", "expires_at" timestamp with time zone, "updated_at" timestamp with time zone, "profile_first_name" "text", "profile_last_name" "text", "profile_email" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
  SELECT
    t.id AS token_id,
    t.user_id,
    t.display_name,
    t.phoneburner_user_email,
    t.expires_at::timestamptz,
    t.updated_at::timestamptz,
    p.first_name AS profile_first_name,
    p.last_name AS profile_last_name,
    p.email AS profile_email
  FROM phoneburner_oauth_tokens t
  LEFT JOIN profiles p ON p.id = t.user_id
  ORDER BY t.display_name NULLS LAST, p.first_name;
$$;


