CREATE OR REPLACE FUNCTION "public"."guard_task_approval"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_is_admin boolean;
  v_is_owner boolean;
  v_deal_id uuid;
BEGIN
  IF OLD.status IS DISTINCT FROM 'pending_approval' OR NEW.status IS DISTINCT FROM 'pending' THEN
    RETURN NEW;
  END IF;

  IF auth.role() = 'service_role' THEN
    RETURN NEW;
  END IF;

  SELECT COALESCE(is_admin, false) INTO v_is_admin
    FROM public.profiles
    WHERE id = auth.uid();

  IF v_is_admin THEN
    RETURN NEW;
  END IF;

  v_deal_id := COALESCE(
    NEW.deal_id,
    CASE WHEN NEW.entity_type = 'deal' THEN NEW.entity_id ELSE NULL END
  );

  IF v_deal_id IS NULL THEN
    RAISE EXCEPTION 'Only the deal owner or an admin can approve this task (no deal linked)'
      USING ERRCODE = '42501';
  END IF;

  SELECT EXISTS (
    SELECT 1 FROM public.deal_pipeline
    WHERE id = v_deal_id
      AND (assigned_to = auth.uid() OR primary_owner_id = auth.uid())
  ) INTO v_is_owner;

  IF NOT v_is_owner THEN
    RAISE EXCEPTION 'Only the deal owner or an admin can approve this task'
      USING ERRCODE = '42501';
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."guard_task_approval"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."guard_task_approval"() IS 'Enforces deal-owner-or-admin authorization for approving AI-extracted tasks.';



CREATE OR REPLACE FUNCTION "public"."handle_buyer_universe_archive"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  -- archived -> true: snooze open tasks for 30 days (mirror listing 'inactive')
  IF NEW.archived = true AND OLD.archived = false THEN
    UPDATE public.daily_standup_tasks
       SET status = 'snoozed',
           snoozed_until = CURRENT_DATE + INTERVAL '30 days',
           updated_at = now()
     WHERE entity_type = 'buyer_universe'
       AND entity_id = NEW.id
       AND status IN ('pending','pending_approval','in_progress','overdue');
  END IF;

  -- archived -> false: wake snoozed tasks (mirror listing re-activation)
  IF NEW.archived = false AND OLD.archived = true THEN
    UPDATE public.daily_standup_tasks
       SET status = 'pending',
           snoozed_until = NULL,
           updated_at = now()
     WHERE entity_type = 'buyer_universe'
       AND entity_id = NEW.id
       AND status = 'snoozed';
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."handle_buyer_universe_archive"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."handle_buyer_universe_delete"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  -- Cancel any still-open tasks linked to this universe. We keep these rows
  -- (with a stale entity_id) for audit; the soft-FK trigger only validates
  -- writes that touch entity_type/entity_id, so status updates on these rows
  -- continue to work.
  UPDATE public.daily_standup_tasks
     SET status = 'cancelled',
         updated_at = now()
   WHERE entity_type = 'buyer_universe'
     AND entity_id = OLD.id
     AND status IN ('pending','pending_approval','in_progress','overdue','snoozed');

  RETURN OLD;
END;
$$;


ALTER FUNCTION "public"."handle_buyer_universe_delete"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."handle_deal_close"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  stage_record RECORD;
BEGIN
  -- Only fire when stage_id changes
  IF NEW.stage_id IS DISTINCT FROM OLD.stage_id THEN
    SELECT name, stage_type INTO stage_record
    FROM public.deal_stages
    WHERE id = NEW.stage_id;

    -- Check if this is a terminal stage
    IF stage_record.stage_type IN ('closed_won', 'closed_lost') THEN
      -- Mark listing as inactive if deal is closed and listing exists
      IF NEW.listing_id IS NOT NULL THEN
        UPDATE public.listings
        SET status = 'inactive', updated_at = NOW()
        WHERE id = NEW.listing_id
        AND status = 'active'
        AND is_internal_deal = false;
      END IF;

      -- Update buyer introductions to reflect deal closure.
      -- buyer_introductions links via listing_id, not deal_id.
      UPDATE public.buyer_introductions
      SET introduction_status = CASE
        WHEN stage_record.stage_type = 'closed_won' THEN 'fit_and_interested'
        ELSE 'not_a_fit'
      END,
      updated_at = NOW()
      WHERE listing_id = NEW.listing_id
      AND introduction_status NOT IN ('not_a_fit', 'fit_and_interested');
    END IF;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."handle_deal_close"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."handle_deal_stage_change"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE new_stage_name text;
BEGIN
  SELECT name INTO new_stage_name FROM public.deal_stages WHERE id = NEW.stage_id;
  IF new_stage_name = 'Closed Won' THEN
    UPDATE public.daily_standup_tasks SET status = 'completed',
      completion_notes = 'Deal closed won — auto-completed', completed_at = now(), updated_at = now()
    WHERE entity_type = 'deal' AND entity_id = NEW.id AND status IN ('pending','pending_approval','in_progress','overdue');
  END IF;
  IF new_stage_name = 'Closed Lost' THEN
    UPDATE public.daily_standup_tasks SET status = 'cancelled', updated_at = now()
    WHERE entity_type = 'deal' AND entity_id = NEW.id AND status IN ('pending','pending_approval','in_progress','overdue');
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."handle_deal_stage_change"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."handle_listing_status_change"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  IF NEW.status = 'sold' AND OLD.status != 'sold' THEN
    UPDATE public.daily_standup_tasks SET status = 'listing_closed', updated_at = now()
    WHERE entity_type = 'listing' AND entity_id = NEW.id AND status IN ('pending','pending_approval','in_progress','overdue');
    UPDATE public.daily_standup_tasks SET status = 'listing_closed', updated_at = now()
    WHERE entity_type = 'deal' AND entity_id IN (SELECT id FROM public.deal_pipeline WHERE listing_id = NEW.id)
    AND status IN ('pending','pending_approval','in_progress','overdue');
  END IF;
  IF NEW.status = 'inactive' AND OLD.status = 'active' THEN
    UPDATE public.daily_standup_tasks SET status = 'snoozed', snoozed_until = CURRENT_DATE + INTERVAL '30 days', updated_at = now()
    WHERE entity_type = 'listing' AND entity_id = NEW.id AND status IN ('pending','pending_approval','in_progress','overdue');
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."handle_listing_status_change"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."handle_new_user"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid;
  v_email text;
  v_meta jsonb;
  v_first_name text;
  v_last_name text;
  v_company text;
  v_buyer_type text;
  v_website text;
  v_linkedin text;
  v_phone text;
  v_job_title text;
  v_referral_source text;
  v_referral_source_detail text;
  v_visitor_id text;
BEGIN
  v_user_id := NEW.id;
  v_email := COALESCE(NEW.email, '');
  v_meta := COALESCE(NEW.raw_user_meta_data, '{}'::jsonb);

  -- Extract fields from metadata
  v_first_name := COALESCE(NULLIF(TRIM(v_meta->>'first_name'), ''), 'Unknown');
  v_last_name := COALESCE(NULLIF(TRIM(v_meta->>'last_name'), ''), 'User');
  v_company := COALESCE(v_meta->>'company', '');
  v_buyer_type := COALESCE(NULLIF(v_meta->>'buyer_type', ''), 'individual');
  v_website := COALESCE(v_meta->>'website', '');
  v_linkedin := COALESCE(v_meta->>'linkedin_profile', '');
  v_phone := COALESCE(v_meta->>'phone_number', '');
  v_job_title := COALESCE(v_meta->>'job_title', '');
  v_referral_source := COALESCE(v_meta->>'referral_source', '');
  v_referral_source_detail := COALESCE(v_meta->>'referral_source_detail', '');
  v_visitor_id := v_meta->>'visitor_id';

  -- ===== STAGE 1: Insert profile with ALL core fields =====
  BEGIN
    INSERT INTO public.profiles (
      id, email, first_name, last_name,
      company, buyer_type, website, linkedin_profile,
      phone_number, job_title, referral_source, referral_source_detail,
      role, approval_status, email_verified
    ) VALUES (
      v_user_id, v_email, v_first_name, v_last_name,
      v_company, v_buyer_type, v_website, v_linkedin,
      v_phone, v_job_title, v_referral_source, v_referral_source_detail,
      'buyer', 'pending', false
    );
  EXCEPTION WHEN unique_violation THEN
    BEGIN
      UPDATE public.profiles SET
        first_name = COALESCE(NULLIF(v_first_name, 'Unknown'), first_name),
        last_name = COALESCE(NULLIF(v_last_name, 'User'), last_name),
        company = COALESCE(NULLIF(v_company, ''), company),
        buyer_type = COALESCE(NULLIF(v_buyer_type, 'individual'), buyer_type),
        website = COALESCE(NULLIF(v_website, ''), website),
        linkedin_profile = COALESCE(NULLIF(v_linkedin, ''), linkedin_profile),
        phone_number = COALESCE(NULLIF(v_phone, ''), phone_number),
        job_title = COALESCE(NULLIF(v_job_title, ''), job_title),
        referral_source = COALESCE(NULLIF(v_referral_source, ''), referral_source),
        referral_source_detail = COALESCE(NULLIF(v_referral_source_detail, ''), referral_source_detail)
      WHERE id = v_user_id;
    EXCEPTION WHEN OTHERS THEN
      BEGIN
        INSERT INTO public.trigger_logs (trigger_name, user_id, user_email, status, error_message, metadata)
        VALUES ('handle_new_user', v_user_id, v_email, 'warning',
          'update_existing_failed: ' || SQLERRM,
          jsonb_build_object('sqlstate', SQLSTATE));
      EXCEPTION WHEN OTHERS THEN NULL;
      END;
    END;
  WHEN OTHERS THEN
    -- Full insert failed — log and try minimal
    BEGIN
      INSERT INTO public.trigger_logs (trigger_name, user_id, user_email, status, error_message, metadata)
      VALUES ('handle_new_user', v_user_id, v_email, 'warning',
        'full_insert_failed: ' || SQLERRM,
        jsonb_build_object('sqlstate', SQLSTATE));
    EXCEPTION WHEN OTHERS THEN NULL;
    END;

    BEGIN
      INSERT INTO public.profiles (id, email, first_name, last_name)
      VALUES (v_user_id, v_email, v_first_name, v_last_name)
      ON CONFLICT (id) DO NOTHING;
    EXCEPTION WHEN OTHERS THEN
      BEGIN
        INSERT INTO public.trigger_logs (trigger_name, user_id, user_email, status, error_message, metadata)
        VALUES ('handle_new_user', v_user_id, v_email, 'error',
          'minimal_insert_failed: ' || SQLERRM,
          jsonb_build_object('sqlstate', SQLSTATE));
      EXCEPTION WHEN OTHERS THEN NULL;
      END;
    END;
  END;

  -- ===== STAGE 2: Link visitor journey (best-effort) =====
  IF v_visitor_id IS NOT NULL AND v_visitor_id != '' THEN
    BEGIN
      UPDATE public.user_journeys
      SET user_id = v_user_id
      WHERE visitor_id = v_visitor_id
        AND user_id IS NULL;
    EXCEPTION WHEN OTHERS THEN
      BEGIN
        INSERT INTO public.trigger_logs (trigger_name, user_id, user_email, status, error_message, metadata)
        VALUES ('handle_new_user', v_user_id, v_email, 'warning',
          'journey_link_failed: ' || SQLERRM,
          jsonb_build_object('visitor_id', v_visitor_id));
      EXCEPTION WHEN OTHERS THEN NULL;
      END;
    END;
  END IF;

  -- ===== STAGE 3: Marketplace buyer sync (best-effort) =====
  BEGIN
    PERFORM public.sync_marketplace_buyer(v_user_id);
  EXCEPTION WHEN OTHERS THEN
    BEGIN
      INSERT INTO public.trigger_logs (trigger_name, user_id, user_email, status, error_message, metadata)
      VALUES ('handle_new_user', v_user_id, v_email, 'warning',
        'marketplace_sync_failed: ' || SQLERRM,
        jsonb_build_object('sqlstate', SQLSTATE));
    EXCEPTION WHEN OTHERS THEN NULL;
    END;
  END;

  -- ===== STAGE 4: Link existing leads (best-effort) =====
  BEGIN
    UPDATE public.connection_requests
    SET profile_id = v_user_id
    WHERE LOWER(TRIM(email)) = LOWER(TRIM(v_email))
      AND profile_id IS NULL;
  EXCEPTION WHEN OTHERS THEN
    BEGIN
      INSERT INTO public.trigger_logs (trigger_name, user_id, user_email, status, error_message, metadata)
      VALUES ('handle_new_user', v_user_id, v_email, 'warning',
        'lead_link_failed: ' || SQLERRM, NULL);
    EXCEPTION WHEN OTHERS THEN NULL;
    END;
  END;

  -- ===== Success log =====
  BEGIN
    INSERT INTO public.trigger_logs (trigger_name, user_id, user_email, status, success, metadata)
    VALUES ('handle_new_user', v_user_id, v_email, 'success', true,
      jsonb_build_object('company', v_company, 'buyer_type', v_buyer_type));
  EXCEPTION WHEN OTHERS THEN NULL;
  END;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."handle_new_user"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."has_role"("_user_id" "uuid", "_role" "public"."app_role") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT EXISTS (
    SELECT 1
    FROM public.user_roles
    WHERE user_id = _user_id
      AND role = _role
  )
$$;


ALTER FUNCTION "public"."has_role"("_user_id" "uuid", "_role" "public"."app_role") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."haversine_miles"("lat1" double precision, "lng1" double precision, "lat2" double precision, "lng2" double precision) RETURNS double precision
    LANGUAGE "sql" IMMUTABLE PARALLEL SAFE
    AS $$
  SELECT 3959.0 * 2 * asin(
    sqrt(
      sin(radians(lat2 - lat1) / 2) ^ 2 +
      cos(radians(lat1)) * cos(radians(lat2)) *
      sin(radians(lng2 - lng1) / 2) ^ 2
    )
  );
$$;


ALTER FUNCTION "public"."haversine_miles"("lat1" double precision, "lng1" double precision, "lat2" double precision, "lng2" double precision) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."hydrate_profile_from_metadata"("p_user_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_meta jsonb;
  v_email text;
BEGIN
  -- Read metadata from auth.users
  SELECT raw_user_meta_data, email
  INTO v_meta, v_email
  FROM auth.users
  WHERE id = p_user_id;

  IF v_meta IS NULL THEN
    RETURN; -- No metadata to hydrate from
  END IF;

  -- Update the profile with ALL fields from metadata
  -- Only updates non-null/non-empty metadata values, preserves existing data
  UPDATE public.profiles SET
    first_name = COALESCE(NULLIF(v_meta->>'first_name', ''), first_name),
    last_name = COALESCE(NULLIF(v_meta->>'last_name', ''), last_name),
    company = COALESCE(NULLIF(v_meta->>'company', ''), company),
    buyer_type = COALESCE(NULLIF(v_meta->>'buyer_type', ''), buyer_type),
    website = COALESCE(NULLIF(v_meta->>'website', ''), website),
    linkedin_profile = COALESCE(NULLIF(v_meta->>'linkedin_profile', ''), linkedin_profile),
    phone_number = COALESCE(NULLIF(v_meta->>'phone_number', ''), phone_number),
    job_title = COALESCE(NULLIF(v_meta->>'job_title', ''), job_title),
    referral_source = COALESCE(NULLIF(v_meta->>'referral_source', ''), referral_source),
    referral_source_detail = COALESCE(NULLIF(v_meta->>'referral_source_detail', ''), referral_source_detail)
  WHERE id = p_user_id;

EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'hydrate_profile_from_metadata failed for %: % %', p_user_id, SQLSTATE, SQLERRM;
END;
$$;


ALTER FUNCTION "public"."hydrate_profile_from_metadata"("p_user_id" "uuid") OWNER TO "postgres";


