CREATE OR REPLACE FUNCTION "public"."increment_global_queue_progress"("p_operation_type" "text", "p_completed_delta" integer DEFAULT 0, "p_failed_delta" integer DEFAULT 0) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  UPDATE global_activity_queue
  SET
    completed_items = COALESCE(completed_items, 0) + p_completed_delta,
    failed_items = COALESCE(failed_items, 0) + p_failed_delta
  WHERE operation_type = p_operation_type
    AND status = 'running';
END;
$$;


