CREATE OR REPLACE FUNCTION "public"."increment_journey_sessions"("p_visitor_id" "text", "p_session_id" "text", "p_page_path" "text" DEFAULT '/'::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  UPDATE public.user_journeys
  SET 
    total_sessions = total_sessions + 1,
    last_seen_at = NOW(),
    last_session_id = p_session_id,
    last_page_path = p_page_path,
    updated_at = NOW()
  WHERE visitor_id = p_visitor_id
    AND last_session_id != p_session_id; -- Only increment if it's actually a new session
END;
$$;


