CREATE OR REPLACE FUNCTION "public"."increment_link_open_count"("p_link_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_first_open BOOLEAN;
  v_result jsonb;
BEGIN
  -- Atomically increment and set timestamps
  UPDATE document_tracked_links
  SET
    open_count = open_count + 1,
    last_opened_at = now(),
    first_opened_at = COALESCE(first_opened_at, now())
  WHERE id = p_link_id
  RETURNING (first_opened_at = now()) INTO v_first_open;

  -- Also update the release log if this is the first open
  IF v_first_open THEN
    UPDATE document_release_log
    SET first_opened_at = now()
    WHERE tracked_link_id = p_link_id
      AND first_opened_at IS NULL;
  END IF;

  v_result := jsonb_build_object('first_open', v_first_open);
  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."increment_link_open_count"("p_link_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."increment_provider_concurrent"("p_provider" "text") RETURNS "void"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
BEGIN
  INSERT INTO enrichment_rate_limits (provider, concurrent_requests, updated_at)
  VALUES (p_provider, 1, now())
  ON CONFLICT (provider) DO UPDATE
  SET concurrent_requests = enrichment_rate_limits.concurrent_requests + 1,
      updated_at = now();
END;
$$;


ALTER FUNCTION "public"."increment_provider_concurrent"("p_provider" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."increment_scoring_run_progress"("p_listing_id" "uuid", "p_scored_delta" integer DEFAULT 0, "p_failed_delta" integer DEFAULT 0) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  UPDATE scoring_runs
  SET
    scored_count = scored_count + p_scored_delta,
    failed_count = failed_count + p_failed_delta,
    -- Auto-complete when all buyers are accounted for
    status = CASE
      WHEN (scored_count + p_scored_delta + failed_count + p_failed_delta) >= total_buyers
        THEN 'completed'
      ELSE status
    END,
    completed_at = CASE
      WHEN (scored_count + p_scored_delta + failed_count + p_failed_delta) >= total_buyers
        THEN now()
      ELSE completed_at
    END
  WHERE listing_id = p_listing_id
    AND status = 'running';
END;
$$;


ALTER FUNCTION "public"."increment_scoring_run_progress"("p_listing_id" "uuid", "p_scored_delta" integer, "p_failed_delta" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."increment_scoring_run_progress"("p_listing_id" "uuid", "p_scored_delta" integer, "p_failed_delta" integer) IS 'Atomically increments scored/failed counts on the active scoring run for a listing. Called by score-buyer-deal after each batch.';



CREATE OR REPLACE FUNCTION "public"."intersect_lists"("p_list_ids" "uuid"[], "p_new_name" "text", "p_list_type" "text" DEFAULT 'mixed'::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_new_list_id uuid;
  v_count int;
  v_list_count int;
BEGIN
  IF NOT is_admin(auth.uid()) THEN
    RAISE EXCEPTION 'Only admins can intersect lists';
  END IF;

  v_list_count := array_length(p_list_ids, 1);

  INSERT INTO contact_lists (name, list_type, created_by, contact_count)
  VALUES (p_new_name, p_list_type, auth.uid(), 0)
  RETURNING id INTO v_new_list_id;

  WITH common_emails AS (
    SELECT contact_email
    FROM contact_list_members
    WHERE list_id = ANY(p_list_ids) AND removed_at IS NULL
    GROUP BY contact_email
    HAVING count(DISTINCT list_id) = v_list_count
  ),
  source_data AS (
    SELECT DISTINCT ON (m.contact_email)
      m.contact_email, m.contact_name, m.contact_phone, m.contact_company,
      m.contact_role, m.entity_type, m.entity_id
    FROM contact_list_members m
    JOIN common_emails ce ON m.contact_email = ce.contact_email
    WHERE m.list_id = p_list_ids[1] AND m.removed_at IS NULL
    ORDER BY m.contact_email
  )
  INSERT INTO contact_list_members (list_id, contact_email, contact_name, contact_phone,
    contact_company, contact_role, entity_type, entity_id, added_by)
  SELECT v_new_list_id, contact_email, contact_name, contact_phone,
    contact_company, contact_role, entity_type, entity_id, 'merged'
  FROM source_data;

  GET DIAGNOSTICS v_count = ROW_COUNT;
  UPDATE contact_lists SET contact_count = v_count WHERE id = v_new_list_id;

  RETURN v_new_list_id;
END;
$$;


ALTER FUNCTION "public"."intersect_lists"("p_list_ids" "uuid"[], "p_new_name" "text", "p_list_type" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."intersect_lists"("p_list_ids" "uuid"[], "p_new_name" "text", "p_list_type" "text") IS 'Create a new list with only members in ALL specified lists; members tagged added_by=merged';



CREATE OR REPLACE FUNCTION "public"."invalidate_buyer_recommendation_cache"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  IF (TG_OP = 'INSERT' OR TG_OP = 'DELETE') THEN
    UPDATE buyer_recommendation_cache SET expires_at = NOW() WHERE expires_at > NOW();
  ELSIF (TG_OP = 'UPDATE') THEN
    IF (
      OLD.target_services    IS DISTINCT FROM NEW.target_services OR
      OLD.target_industries  IS DISTINCT FROM NEW.target_industries OR
      OLD.industry_vertical  IS DISTINCT FROM NEW.industry_vertical OR
      OLD.target_geographies IS DISTINCT FROM NEW.target_geographies OR
      OLD.geographic_footprint IS DISTINCT FROM NEW.geographic_footprint OR
      OLD.target_ebitda_min  IS DISTINCT FROM NEW.target_ebitda_min OR
      OLD.target_ebitda_max  IS DISTINCT FROM NEW.target_ebitda_max OR
      OLD.has_fee_agreement  IS DISTINCT FROM NEW.has_fee_agreement OR
      OLD.acquisition_appetite IS DISTINCT FROM NEW.acquisition_appetite OR
      OLD.total_acquisitions IS DISTINCT FROM NEW.total_acquisitions OR
      OLD.thesis_summary     IS DISTINCT FROM NEW.thesis_summary OR
      OLD.hq_state           IS DISTINCT FROM NEW.hq_state OR
      OLD.archived           IS DISTINCT FROM NEW.archived
    ) THEN
      UPDATE buyer_recommendation_cache SET expires_at = NOW() WHERE expires_at > NOW();
    END IF;
  END IF;
  RETURN COALESCE(NEW, OLD);
END;
$$;


ALTER FUNCTION "public"."invalidate_buyer_recommendation_cache"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."invalidate_cache_on_universe_change"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  UPDATE buyer_recommendation_cache SET expires_at = now()
  WHERE listing_id = COALESCE(NEW.listing_id, OLD.listing_id);
  RETURN COALESCE(NEW, OLD);
END;
$$;


ALTER FUNCTION "public"."invalidate_cache_on_universe_change"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."invalidate_recommendation_cache_on_listing_change"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  IF OLD.industry IS DISTINCT FROM NEW.industry
    OR OLD.category IS DISTINCT FROM NEW.category
    OR OLD.categories IS DISTINCT FROM NEW.categories
    OR OLD.address_state IS DISTINCT FROM NEW.address_state
    OR OLD.geographic_states IS DISTINCT FROM NEW.geographic_states
    OR OLD.executive_summary IS DISTINCT FROM NEW.executive_summary
  THEN
    UPDATE buyer_recommendation_cache
    SET expires_at = now()
    WHERE listing_id = NEW.id;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."invalidate_recommendation_cache_on_listing_change"() OWNER TO "postgres";


