    AND TRIM(website) <> ''
    AND website NOT LIKE 'unknown-%.placeholder'
    AND website NOT LIKE '%.unknown'
    AND LOWER(TRIM(website)) NOT IN ('n/a', 'none', 'unknown', 'na', 'null', '-')
