CREATE OR REPLACE FUNCTION "public"."log_nda_email"("target_user_id" "uuid", "recipient_email" "text", "admin_notes" "text" DEFAULT NULL::"text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  admin_profile RECORD;
  admin_user_id uuid;
BEGIN
  -- Get current authenticated user ID
  admin_user_id := auth.uid();
  
  -- Check if user is authenticated
  IF admin_user_id IS NULL THEN
    RAISE EXCEPTION 'User not authenticated';
  END IF;
  
  -- Get admin information
  SELECT email, first_name, last_name 
  INTO admin_profile 
  FROM public.profiles 
  WHERE id = admin_user_id;
  
  -- Update the profile to mark email as sent
  UPDATE public.profiles 
  SET 
    nda_email_sent = TRUE,
    nda_email_sent_at = NOW(),
    updated_at = NOW()
  WHERE id = target_user_id;
  
  -- Log the email
  INSERT INTO public.nda_logs (
    user_id, 
    admin_id, 
    action_type, 
    email_sent_to,
    admin_email,
    admin_name,
    notes,
    metadata
  ) VALUES (
    target_user_id,
    admin_user_id,
    'sent',
    recipient_email,
    admin_profile.email,
    COALESCE(admin_profile.first_name || ' ' || admin_profile.last_name, admin_profile.email),
    admin_notes,
    jsonb_build_object('email_sent', true, 'sent_at', NOW())
  );
  
  RETURN TRUE;
END;
$$;


ALTER FUNCTION "public"."log_nda_email"("target_user_id" "uuid", "recipient_email" "text", "admin_notes" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."log_portal_recommendation_event"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_event_type TEXT;
BEGIN
  IF TG_OP = 'INSERT' THEN
    INSERT INTO public.portal_recommendation_events (
      recommendation_id, portal_org_id, listing_id,
      event_type, new_status, new_score, actor_id
    ) VALUES (
      NEW.id, NEW.portal_org_id, NEW.listing_id,
      'created', NEW.status, NEW.match_score, NEW.reviewed_by
    );
    RETURN NEW;
  END IF;

  IF TG_OP = 'UPDATE' THEN
    -- Status change events
    IF NEW.status IS DISTINCT FROM OLD.status THEN
      v_event_type := CASE
        WHEN NEW.status = 'approved' THEN 'approved'
        WHEN NEW.status = 'pushed'   THEN 'pushed'
        WHEN NEW.status = 'dismissed' THEN 'dismissed'
        WHEN NEW.status = 'stale'    THEN 'stale'
        WHEN NEW.status = 'pending'  THEN 'reactivated'
        ELSE 'score_updated'
      END;
      INSERT INTO public.portal_recommendation_events (
        recommendation_id, portal_org_id, listing_id,
        event_type, previous_status, new_status,
        previous_score, new_score, actor_id,
        metadata
      ) VALUES (
        NEW.id, NEW.portal_org_id, NEW.listing_id,
        v_event_type, OLD.status, NEW.status,
        OLD.match_score, NEW.match_score, NEW.reviewed_by,
        jsonb_build_object(
          'dismiss_reason', NEW.dismiss_reason,
          'push_id',        NEW.push_id
        )
      );
    -- Score-only change (no status transition)
    ELSIF NEW.match_score IS DISTINCT FROM OLD.match_score THEN
      INSERT INTO public.portal_recommendation_events (
        recommendation_id, portal_org_id, listing_id,
        event_type, previous_score, new_score
      ) VALUES (
        NEW.id, NEW.portal_org_id, NEW.listing_id,
        'score_updated', OLD.match_score, NEW.match_score
      );
    END IF;
    RETURN NEW;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."log_portal_recommendation_event"() OWNER TO "postgres";


