CREATE OR REPLACE FUNCTION "public"."log_task_completion_to_deal"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_listing_id uuid;
BEGIN
  -- Resolve deal_pipeline.id → listing_id.
  -- For frontend-created tasks, entity_id already holds the listing UUID;
  -- for DB-trigger-created tasks, deal_id holds deal_pipeline.id.
  -- We look up via deal_pipeline when deal_id is set, otherwise fall back to
  -- entity_id (which for entity_type='deal' tasks is the listing UUID).
  IF NEW.deal_id IS NOT NULL THEN
    SELECT listing_id INTO v_listing_id
    FROM public.deal_pipeline
    WHERE id = NEW.deal_id;
  END IF;

  IF v_listing_id IS NULL AND NEW.entity_type IN ('deal', 'listing') THEN
    v_listing_id := NEW.entity_id;
  END IF;

  IF v_listing_id IS NULL THEN
    RETURN NEW;
  END IF;

  IF NEW.status = 'completed' AND OLD.status != 'completed' THEN
    PERFORM public.log_deal_activity(
      v_listing_id,
      'task_completed',
      format('Task completed: %s', NEW.title),
      NEW.completion_notes,
      NEW.assignee_id,
      jsonb_build_object(
        'task_id', NEW.id,
        'task_type', NEW.task_type,
        'completed_at', NEW.completed_at
      )
    );
  END IF;

  IF NEW.status = 'overdue' AND OLD.status != 'overdue' THEN
    PERFORM public.log_deal_activity(
      v_listing_id,
      'task_overdue',
      format('Task overdue: %s', NEW.title),
      NULL,
      NEW.assignee_id,
      jsonb_build_object('task_id', NEW.id, 'due_date', NEW.due_date)
    );
  END IF;

  IF NEW.status = 'snoozed' AND OLD.status != 'snoozed' THEN
    PERFORM public.log_deal_activity(
      v_listing_id,
      'task_snoozed',
      format('Task snoozed: %s', NEW.title),
      NULL,
      NEW.assignee_id,
      jsonb_build_object('task_id', NEW.id, 'snoozed_until', NEW.snoozed_until)
    );
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."log_task_completion_to_deal"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."log_trigger_error"("p_trigger_name" "text", "p_source_table" "text", "p_source_row_id" "text", "p_error_code" "text", "p_error_message" "text", "p_context" "jsonb" DEFAULT NULL::"jsonb") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  DELETE FROM public.trigger_error_log
   WHERE occurred_at < now() - INTERVAL '7 days';
  INSERT INTO public.trigger_error_log (
    trigger_name, source_table, source_row_id, error_code, error_message, context
  ) VALUES (
    p_trigger_name, p_source_table, p_source_row_id, p_error_code, p_error_message, p_context
  );
EXCEPTION WHEN OTHERS THEN
  NULL;
END;
$$;


ALTER FUNCTION "public"."log_trigger_error"("p_trigger_name" "text", "p_source_table" "text", "p_source_row_id" "text", "p_error_code" "text", "p_error_message" "text", "p_context" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."manage_user_role"("target_email" "text", "new_role" "text", "reason" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  owner_email TEXT;
BEGIN
  -- C-8 FIX: Read owner email from app_settings instead of hardcoding
  SELECT value::TEXT INTO owner_email FROM public.app_settings WHERE key = 'platform_owner_email';
  -- Strip JSON quotes if present
  owner_email := TRIM(BOTH '"' FROM owner_email);

  IF owner_email IS NULL THEN
    RAISE EXCEPTION 'Platform owner email not configured in app_settings';
  END IF;

  -- Prevent changing the owner's role away from owner
  IF target_email = owner_email AND new_role != 'owner' THEN
    RAISE EXCEPTION 'Cannot change the owner role of the platform owner. Update platform_owner_email in app_settings to transfer ownership.';
  END IF;

  -- Prevent assigning owner role to non-owner
  IF new_role = 'owner' AND target_email != owner_email THEN
    RAISE EXCEPTION 'Only the configured platform owner (%) can have the owner role. Update platform_owner_email in app_settings first.', owner_email;
  END IF;

  -- Update the role (use subquery to handle potential duplicates)
  UPDATE public.user_roles
  SET role = new_role, reason = manage_user_role.reason, granted_at = NOW()
  WHERE user_id = (SELECT id FROM auth.users WHERE email = target_email);

  IF NOT FOUND THEN
    INSERT INTO public.user_roles (user_id, role, reason)
    SELECT id, new_role, manage_user_role.reason
    FROM auth.users WHERE email = target_email;
  END IF;
END;
$$;


ALTER FUNCTION "public"."manage_user_role"("target_email" "text", "new_role" "text", "reason" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."map_agreement_status_to_deal"("p_status" "text") RETURNS "text"
    LANGUAGE "sql" IMMUTABLE
    AS $$
  SELECT CASE p_status
    WHEN 'signed' THEN 'signed'
    WHEN 'sent' THEN 'sent'
    WHEN 'declined' THEN 'declined'
    WHEN 'expired' THEN 'declined'
    WHEN 'redlined' THEN 'sent'
    WHEN 'not_started' THEN 'not_sent'
    ELSE 'not_sent'
  END;
$$;


