CREATE OR REPLACE FUNCTION "public"."mirror_rbc_to_contacts"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Mirror INSERT on remarketing_buyer_contacts → contacts (if not already present)
  INSERT INTO public.contacts (
    first_name,
    last_name,
    email,
    phone,
    linkedin_url,
    title,
    contact_type,
    remarketing_buyer_id,
    is_primary_at_firm,
    source,
    archived
  )
  VALUES (
    COALESCE(split_part(NEW.name, ' ', 1), NEW.name),
    CASE WHEN position(' ' in NEW.name) > 0 THEN substring(NEW.name from position(' ' in NEW.name) + 1) ELSE '' END,
    NEW.email,
    NEW.phone,
    NEW.linkedin_url,
    NEW.role,
    'buyer',
    NEW.buyer_id,
    COALESCE(NEW.is_primary, false),
    'legacy_mirror',
    false
  )
  ON CONFLICT DO NOTHING;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."mirror_rbc_to_contacts"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."move_deal_stage"("deal_id" "uuid", "new_stage_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  admin_user uuid;
  old_stage_id uuid;
  from_stage_name text;
  to_stage_name text;
BEGIN
  -- Ensure authenticated admin
  SELECT auth.uid() INTO admin_user;
  IF admin_user IS NULL THEN
    RAISE EXCEPTION 'User not authenticated';
  END IF;

  IF NOT is_admin(admin_user) THEN
    RAISE EXCEPTION 'Only admins can move deals';
  END IF;

  -- Get current stage
  SELECT d.stage_id INTO old_stage_id
  FROM public.deals d
  WHERE d.id = move_deal_stage.deal_id;

  IF old_stage_id IS NULL THEN
    RAISE EXCEPTION 'Deal not found or has no stage';
  END IF;

  -- Update deal stage atomically
  UPDATE public.deals
  SET stage_id = new_stage_id,
      stage_entered_at = NOW(),
      updated_at = NOW()
  WHERE id = move_deal_stage.deal_id;

  -- Resolve stage names for logging
  SELECT name INTO from_stage_name FROM public.deal_stages WHERE id = old_stage_id;
  SELECT name INTO to_stage_name FROM public.deal_stages WHERE id = new_stage_id;

  -- Log activity
  INSERT INTO public.deal_activities (
    deal_id,
    admin_id,
    activity_type,
    title,
    description,
    metadata
  ) VALUES (
    move_deal_stage.deal_id,
    admin_user,
    'stage_change',
    COALESCE('Moved to ' || to_stage_name, 'Moved to new stage'),
    CASE 
      WHEN from_stage_name IS NULL THEN 'Deal moved to ' || COALESCE(to_stage_name,'new stage')
      ELSE 'Deal moved from "' || from_stage_name || '" to "' || COALESCE(to_stage_name,'new stage') || '"'
    END,
    jsonb_build_object(
      'from_stage', from_stage_name,
      'to_stage', to_stage_name,
      'from_stage_id', old_stage_id,
      'to_stage_id', new_stage_id
    )
  );

  RETURN TRUE;
END;
$$;


ALTER FUNCTION "public"."move_deal_stage"("deal_id" "uuid", "new_stage_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."move_deal_stage_with_ownership"("p_deal_id" "uuid", "p_new_stage_id" "uuid", "p_current_admin_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_deal_record RECORD;
  v_new_stage_record RECORD;
  v_old_stage_name text;
  v_new_stage_name text;
  v_should_assign_owner boolean := false;
  v_different_owner boolean := false;
  v_previous_owner_id uuid;
  v_previous_owner_name text;
  v_current_admin_name text;
  v_admin_exists boolean;
  v_listing_website text;
  v_result jsonb;
BEGIN
  IF p_current_admin_id IS NULL THEN
    RAISE EXCEPTION 'move_deal_stage_with_ownership requires a non-null current admin id';
  END IF;

  SELECT EXISTS (SELECT 1 FROM public.profiles WHERE id = p_current_admin_id)
  INTO v_admin_exists;
  IF NOT v_admin_exists THEN
    RAISE EXCEPTION 'Unknown admin id: %', p_current_admin_id;
  END IF;

  SELECT * INTO v_deal_record FROM public.deal_pipeline WHERE id = p_deal_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Deal not found: %', p_deal_id;
  END IF;

  SELECT name INTO v_old_stage_name FROM public.deal_stages WHERE id = v_deal_record.stage_id;
  SELECT * INTO v_new_stage_record FROM public.deal_stages WHERE id = p_new_stage_id;
  v_new_stage_name := v_new_stage_record.name;

  IF v_new_stage_record.stage_type = 'active' THEN
    SELECT website INTO v_listing_website
    FROM public.listings
    WHERE id = v_deal_record.listing_id;

    IF NOT public.is_valid_company_website(v_listing_website) THEN
      RAISE EXCEPTION 'Cannot move deal to active stage: the company listing does not have a valid website/domain. Please add a real company website before moving this deal.';
    END IF;
  END IF;

  IF v_old_stage_name = 'New Inquiry' AND v_deal_record.assigned_to IS NULL THEN
    v_should_assign_owner := true;
  END IF;

  IF v_deal_record.assigned_to IS NOT NULL
     AND v_deal_record.assigned_to != p_current_admin_id THEN
    v_different_owner := true;
    v_previous_owner_id := v_deal_record.assigned_to;

    SELECT COALESCE(first_name || ' ' || last_name, email, 'Unknown Admin')
      INTO v_previous_owner_name
    FROM public.profiles
    WHERE id = v_previous_owner_id;

    SELECT COALESCE(first_name || ' ' || last_name, email, 'Unknown Admin')
      INTO v_current_admin_name
    FROM public.profiles
    WHERE id = p_current_admin_id;
  END IF;

  UPDATE public.deal_pipeline
  SET
    stage_id = p_new_stage_id,
    stage_entered_at = now(),
    updated_at = now(),
    assigned_to = CASE
      WHEN v_should_assign_owner THEN p_current_admin_id
      ELSE assigned_to
    END,
    owner_assigned_at = CASE
      WHEN v_should_assign_owner THEN now()
      ELSE owner_assigned_at
    END,
    owner_assigned_by = CASE
      WHEN v_should_assign_owner THEN p_current_admin_id
      ELSE owner_assigned_by
    END
  WHERE id = p_deal_id;

  v_result := jsonb_build_object(
    'success', true,
    'old_stage_name', v_old_stage_name,
    'new_stage_name', v_new_stage_name,
    'new_stage_type', v_new_stage_record.stage_type,
    'owner_assigned', v_should_assign_owner,
    'different_owner_warning', v_different_owner,
    'previous_owner_id', v_previous_owner_id,
    'previous_owner_name', v_previous_owner_name
  );

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."move_deal_stage_with_ownership"("p_deal_id" "uuid", "p_new_stage_id" "uuid", "p_current_admin_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."normalize_company_name"("name" "text") RETURNS "text"
    LANGUAGE "sql" IMMUTABLE
    SET "search_path" TO 'public'
    AS $$
  SELECT lower(regexp_replace(name, '[^a-zA-Z0-9]', '', 'g'));
$$;


ALTER FUNCTION "public"."normalize_company_name"("name" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."normalize_domain"("url" "text") RETURNS "text"
    LANGUAGE "sql" IMMUTABLE
    AS $$
  SELECT CASE
    WHEN url IS NULL OR trim(url) = '' OR trim(url) = '<UNKNOWN>' THEN NULL
    ELSE
      rtrim(
        split_part(
          split_part(
            regexp_replace(
              regexp_replace(
                -- If the input contains '@', extract only the domain part after '@'
                CASE
                  WHEN position('@' in lower(trim(url))) > 0
                  THEN split_part(lower(trim(url)), '@', 2)
                  ELSE lower(trim(url))
                END,
                '^[a-z]+://', ''
              ),
              '^www\.', ''
            ),
            '/', 1
          ),
          ':', 1
        ),
        '.'
      )
  END
$$;


ALTER FUNCTION "public"."normalize_domain"("url" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."normalize_domain"("url" "text") IS 'Normalizes URLs to comparable domain format. Returns NULL for: NULL input, empty string, or placeholder values (<UNKNOWN>, UNKNOWN, N/A, TBD, PENDING, NONE, NULL). Strips protocol, www, path, and port. Lowercases result. Used for domain-based deduplication via unique indexes.';



CREATE OR REPLACE FUNCTION "public"."normalize_email"("e" "text") RETURNS "text"
    LANGUAGE "sql" IMMUTABLE
    AS $$
  SELECT CASE WHEN e IS NULL OR TRIM(e) = '' THEN NULL ELSE LOWER(TRIM(e)) END;
$$;


ALTER FUNCTION "public"."normalize_email"("e" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."normalize_linkedin_url"("url" "text") RETURNS "text"
    LANGUAGE "sql" IMMUTABLE STRICT PARALLEL SAFE
    AS $_$
  SELECT NULLIF(
    -- 6. Strip trailing slashes
    rtrim(
      -- 5. Strip leading www.
      regexp_replace(
        -- 4. Strip protocol (https:// or http://)
        regexp_replace(
          -- 3. Strip fragment (# and everything after)
          regexp_replace(
            -- 2. Strip query string (? and everything after)
            regexp_replace(
              -- 1. Trim whitespace and lowercase
              btrim(lower(url)),
              '\?.*$', ''
            ),
            '#.*$', ''
          ),
          '^https?://', ''
        ),
        '^www\.', ''
      ),
      '/'
    ),
    -- Return NULL if all transforms produce an empty string
    ''
  )
$_$;


ALTER FUNCTION "public"."normalize_linkedin_url"("url" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."normalize_linkedin_url"("url" "text") IS 'Normalize a LinkedIn URL to canonical form (no protocol, no www, no trailing slash, no query string, lowercase). Mirrors normalizeLinkedInUrl() in _shared/outreach-match.ts — both functions must produce identical output. Used for dedup matching and will back a generated column + unique index in a subsequent migration.';



CREATE OR REPLACE FUNCTION "public"."normalize_name"("n" "text") RETURNS "text"
    LANGUAGE "plpgsql" IMMUTABLE
    AS $_$
DECLARE
  result TEXT;
BEGIN
  IF n IS NULL OR TRIM(n) = '' THEN RETURN NULL; END IF;
  result := LOWER(TRIM(n));
  result := REGEXP_REPLACE(result, '\s+(inc|llc|ltd|corp|co|company|group|holdings|partners|lp|gp|lllp|pllc|pc|pa)\.?\s*$', '', 'g');
  result := REGEXP_REPLACE(result, '[^a-z0-9\s]', '', 'g');
  result := REGEXP_REPLACE(result, '\s+', ' ', 'g');
  RETURN TRIM(result);
END;
$_$;


ALTER FUNCTION "public"."normalize_name"("n" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."normalize_phone_lookup"("value" "text") RETURNS "text"
    LANGUAGE "sql" IMMUTABLE
    SET "search_path" TO 'public'
    AS $$
  select case
    when value is null or btrim(value) = '' then null
    else
      case
        when left(regexp_replace(value, '[^0-9]', '', 'g'), 1) = '1'
         and length(regexp_replace(value, '[^0-9]', '', 'g')) = 11
          then right(regexp_replace(value, '[^0-9]', '', 'g'), 10)
        else regexp_replace(value, '[^0-9]', '', 'g')
      end
  end
$$;


ALTER FUNCTION "public"."normalize_phone_lookup"("value" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."normalize_state_name"("state_name" "text") RETURNS "text"
    LANGUAGE "sql" IMMUTABLE
    SET "search_path" TO 'public'
    AS $$
  SELECT CASE lower(trim(state_name))
    WHEN 'alabama' THEN 'AL' WHEN 'alaska' THEN 'AK' WHEN 'arizona' THEN 'AZ' WHEN 'arkansas' THEN 'AR'
    WHEN 'california' THEN 'CA' WHEN 'colorado' THEN 'CO' WHEN 'connecticut' THEN 'CT' WHEN 'delaware' THEN 'DE'
    WHEN 'florida' THEN 'FL' WHEN 'georgia' THEN 'GA' WHEN 'hawaii' THEN 'HI' WHEN 'idaho' THEN 'ID'
    WHEN 'illinois' THEN 'IL' WHEN 'indiana' THEN 'IN' WHEN 'iowa' THEN 'IA' WHEN 'kansas' THEN 'KS'
    WHEN 'kentucky' THEN 'KY' WHEN 'louisiana' THEN 'LA' WHEN 'maine' THEN 'ME' WHEN 'maryland' THEN 'MD'
    WHEN 'massachusetts' THEN 'MA' WHEN 'michigan' THEN 'MI' WHEN 'minnesota' THEN 'MN' WHEN 'mississippi' THEN 'MS'
    WHEN 'missouri' THEN 'MO' WHEN 'montana' THEN 'MT' WHEN 'nebraska' THEN 'NE' WHEN 'nevada' THEN 'NV'
    WHEN 'new hampshire' THEN 'NH' WHEN 'new jersey' THEN 'NJ' WHEN 'new mexico' THEN 'NM' WHEN 'new york' THEN 'NY'
    WHEN 'north carolina' THEN 'NC' WHEN 'north dakota' THEN 'ND' WHEN 'ohio' THEN 'OH' WHEN 'oklahoma' THEN 'OK'
    WHEN 'oregon' THEN 'OR' WHEN 'pennsylvania' THEN 'PA' WHEN 'rhode island' THEN 'RI' WHEN 'south carolina' THEN 'SC'
    WHEN 'south dakota' THEN 'SD' WHEN 'tennessee' THEN 'TN' WHEN 'texas' THEN 'TX' WHEN 'utah' THEN 'UT'
    WHEN 'vermont' THEN 'VT' WHEN 'virginia' THEN 'VA' WHEN 'washington' THEN 'WA' WHEN 'west virginia' THEN 'WV'
    WHEN 'wisconsin' THEN 'WI' WHEN 'wyoming' THEN 'WY' WHEN 'district of columbia' THEN 'DC'
    ELSE upper(trim(state_name))
  END
$$;


ALTER FUNCTION "public"."normalize_state_name"("state_name" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."notify_admin_on_buyer_message"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  -- Only fire for messages from buyer side.
  IF NEW.sender_type <> 'portal_user' THEN
    RETURN NEW;
  END IF;

  INSERT INTO public.portal_activity_log (
    portal_org_id,
    actor_type,
    actor_id,
    action,
    push_id,
    metadata,
    created_at
  )
  VALUES (
    NEW.portal_org_id,
    'portal_user',
    NEW.sender_id,
    'buyer_message_sent',
    NEW.push_id,
    jsonb_build_object(
      'preview', LEFT(COALESCE(NEW.message, ''), 200),
      'sender_name', NEW.sender_name
    ),
    now()
  );

  -- Broadcast for any listener (future: websocket push to admin dashboard).
  PERFORM pg_notify(
    'portal_buyer_message',
    json_build_object(
      'push_id', NEW.push_id,
      'portal_org_id', NEW.portal_org_id,
      'message_id', NEW.id
    )::text
  );

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."notify_admin_on_buyer_message"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."notify_buyers_on_document_upload"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Insert a notification for every marketplace user who has data_room access to this deal
  INSERT INTO public.user_notifications (user_id, notification_type, title, message, metadata)
  SELECT
    dra.marketplace_user_id,
    'document_uploaded',
    'New Document Available',
    'A new document "' || NEW.file_name || '" has been added to the data room.',
    jsonb_build_object(
      'deal_id', NEW.deal_id,
      'document_id', NEW.id,
      'folder_name', NEW.folder_name,
      'file_name', NEW.file_name
    )
  FROM data_room_access dra
  WHERE dra.deal_id = NEW.deal_id
    AND dra.can_view_data_room = true
    AND dra.marketplace_user_id IS NOT NULL
    AND dra.revoked_at IS NULL;

  RETURN NEW;
END;
$$;


