      'Your deal has moved to: ' || COALESCE(stage_name, 'a new stage'),
      jsonb_build_object(
        'listing_id', NEW.listing_id,
        'stage_id', NEW.pipeline_stage_id,
        'stage_name', stage_name
      )
    );
  END IF;
  RETURN NEW;
END;
