CREATE OR REPLACE FUNCTION "public"."notify_user_on_status_change"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF OLD.status IS DISTINCT FROM NEW.status AND NEW.user_id IS NOT NULL THEN
    INSERT INTO public.user_notifications (
      user_id,
      connection_request_id,
      notification_type,
      title,
      message,
      metadata
    )
    VALUES (
      NEW.user_id,
      NEW.id,
      'status_changed',
      CASE
        WHEN NEW.status = 'approved' THEN 'Connection Request Approved'
        WHEN NEW.status = 'rejected' THEN 'Connection Request Declined'
        WHEN NEW.status = 'on_hold' THEN 'Connection Request On Hold'
        ELSE 'Connection Request Updated'
      END,
      CASE
        WHEN NEW.status = 'approved' THEN 'Great news! Your connection request has been approved.'
        WHEN NEW.status = 'rejected' THEN 'Your connection request was declined. Continue exploring other opportunities.'
        WHEN NEW.status = 'on_hold' THEN 'Your connection request is currently on hold pending review.'
        ELSE 'Your connection request status has been updated.'
      END,
      jsonb_build_object(
        'listing_id', NEW.listing_id,
        'old_status', OLD.status,
        'new_status', NEW.status
      )
    );
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."notify_user_on_status_change"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."portal_responses_for_user"("p_push_id" "uuid") RETURNS TABLE("id" "uuid", "push_id" "uuid", "responded_by" "uuid", "response_type" "text", "notes" "text", "internal_notes" "text", "created_at" timestamp with time zone)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
  SELECT
    r.id,
    r.push_id,
    r.responded_by,
    r.response_type,
    r.notes,
    CASE WHEN EXISTS (
      SELECT 1 FROM public.profiles WHERE id = auth.uid() AND is_admin = true
    )
      THEN r.internal_notes
      ELSE NULL
    END AS internal_notes,
    r.created_at
  FROM public.portal_deal_responses r
  WHERE r.push_id = p_push_id
  ORDER BY r.created_at DESC;
$$;


