CREATE OR REPLACE FUNCTION "public"."queue_portal_message_notification"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_deal_headline text;
  v_user record;
BEGIN
  -- Only queue notifications for admin-sent messages
  IF NEW.sender_type != 'admin' THEN
    RETURN NEW;
  END IF;

  -- Get deal headline from snapshot
  SELECT (deal_snapshot->>'headline')::text INTO v_deal_headline
  FROM portal_deal_pushes
  WHERE id = NEW.push_id;

  -- Queue a notification row for each active portal user (the processor cron will send emails)
  FOR v_user IN 
    SELECT id, email, name 
    FROM portal_users 
    WHERE portal_org_id = NEW.portal_org_id 
      AND is_active = true 
      AND email IS NOT NULL
  LOOP
    INSERT INTO portal_notifications (
      portal_user_id,
      portal_org_id,
      push_id,
      type,
      channel,
      subject,
      body,
      sent_at
    ) VALUES (
      v_user.id,
      NEW.portal_org_id,
      NEW.push_id,
      'message',
      'email',
      'New message about ' || COALESCE(v_deal_headline, 'a deal'),
      COALESCE(NEW.sender_name, 'Your advisor') || ' sent you a message: ' || LEFT(NEW.message, 200),
      NULL  -- queued, not yet sent
    );
  END LOOP;

  RETURN NEW;
END;
$$;


