CREATE OR REPLACE FUNCTION "public"."refresh_contact_call_rollup"("p_contact_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF p_contact_id IS NULL THEN RETURN; END IF;

  UPDATE public.contacts c SET
    total_call_attempts = sub.attempts,
    total_calls_connected = sub.connected,
    total_call_duration_seconds = sub.duration,
    last_call_attempt_at = sub.last_attempt,
    last_call_connected_at = sub.last_connected,
    last_disposition_code = sub.last_disp_code,
    last_disposition_label = sub.last_disp_label,
    last_disposition_date = sub.last_disp_date,
    phoneburner_last_sync_at = now(),
    updated_at = now()
  FROM (
    SELECT
      COUNT(*) FILTER (WHERE activity_type IN ('call_completed','call_attempt'))         AS attempts,
      COUNT(*) FILTER (WHERE activity_type='call_completed'
                         AND call_connected = TRUE)                                       AS connected,
      COALESCE(SUM(call_duration_seconds)
        FILTER (WHERE activity_type='call_completed'), 0)::INT                            AS duration,
      MAX(call_started_at)   FILTER (WHERE activity_type IN ('call_completed','call_attempt'))
                                                                                          AS last_attempt,
      MAX(call_connected_at) FILTER (WHERE activity_type='call_completed'
                                      AND call_connected = TRUE)                         AS last_connected,
      (ARRAY_AGG(disposition_code  ORDER BY disposition_set_at DESC NULLS LAST)
         FILTER (WHERE disposition_code IS NOT NULL))[1]                                  AS last_disp_code,
      (ARRAY_AGG(disposition_label ORDER BY disposition_set_at DESC NULLS LAST)
         FILTER (WHERE disposition_label IS NOT NULL))[1]                                 AS last_disp_label,
      MAX(disposition_set_at)                                                             AS last_disp_date
    FROM public.contact_activities
    WHERE contact_id = p_contact_id
      AND activity_type IN ('call_completed','call_attempt')
  ) sub
  WHERE c.id = p_contact_id;
END;
$$;


