COMMENT ON FUNCTION "public"."refresh_contact_call_rollup"("p_contact_id" "uuid") IS 'Recomputes contacts.last_call_* and last_disposition_* rollup columns from the full contact_activities history for a single contact. Called from trg_contact_activities_call_rollup. Idempotent.';



