CREATE OR REPLACE FUNCTION "public"."remarketing_scores_append_snapshot"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Only snapshot meaningful changes
  IF TG_OP = 'INSERT'
     OR (NEW.composite_score IS DISTINCT FROM OLD.composite_score)
     OR (NEW.tier              IS DISTINCT FROM OLD.tier)
  THEN
    INSERT INTO public.score_snapshots (
      listing_id,
      buyer_id,
      universe_id,
      composite_score,
      geography_score,
      size_score,
      service_score,
      owner_goals_score,
      tier,
      trigger_type,
      scoring_version,
      scored_at
    ) VALUES (
      NEW.listing_id,
      NEW.buyer_id,
      NEW.universe_id,
      NEW.composite_score,
      NEW.geography_score,
      NEW.size_score,
      NEW.service_score,
      NEW.owner_goals_score,
      NEW.tier,
      CASE WHEN TG_OP = 'INSERT' THEN 'auto' ELSE 'recalculation' END,
      'trigger-v1',
      NOW()
    );
  END IF;
  RETURN NEW;
END;
$$;


