CREATE OR REPLACE FUNCTION "public"."rematch_orphaned_activities"() RETURNS TABLE("activities_matched" bigint, "outlook_matched" bigint, "smartlead_matched" bigint, "heyreach_matched" bigint)
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_activities bigint := 0;
  v_outlook bigint := 0;
  v_smartlead bigint := 0;
  v_heyreach bigint := 0;
BEGIN
  -- Match contact_activities by email
  WITH matched AS (
    UPDATE contact_activities ca
    SET contact_id = c.id
    FROM contacts c
    WHERE ca.contact_id IS NULL
      AND ca.contact_email IS NOT NULL
      AND lower(ca.contact_email) = lower(c.email)
    RETURNING ca.id
  )
  SELECT count(*) INTO v_activities FROM matched;

  -- Match by listing main_contact_email
  WITH matched AS (
    UPDATE contact_activities ca
    SET contact_id = c.id
    FROM listings l
    JOIN contacts c ON lower(c.email) = lower(l.main_contact_email)
    WHERE ca.contact_id IS NULL
      AND ca.listing_id IS NOT NULL
      AND ca.listing_id = l.id
      AND l.main_contact_email IS NOT NULL
    RETURNING ca.id
  )
  SELECT v_activities + count(*) INTO v_activities FROM matched;

  -- Promote outlook_unmatched_emails where contact now exists
  WITH matched AS (
    UPDATE outlook_unmatched_emails oue
    SET matched_at = now()
    FROM contacts c
    WHERE oue.matched_at IS NULL
      AND lower(c.email) = ANY(SELECT lower(unnest(oue.participant_emails)))
    RETURNING oue.id
  )
  SELECT count(*) INTO v_outlook FROM matched;

  RETURN QUERY SELECT v_activities, v_outlook, v_smartlead, v_heyreach;
END;
$$;


ALTER FUNCTION "public"."rematch_orphaned_activities"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rematch_unmatched_outlook_emails"("p_contact_ids" "uuid"[] DEFAULT NULL::"uuid"[]) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_materialized INTEGER := 0;
  v_promoted_msg_ids TEXT[];
BEGIN
  -- Materialize matched queue rows into `email_messages`. Each unmatched
  -- queue row fans out to one `email_messages` row per matched contact
  -- (a single thread can involve multiple contacts in our CRM).
  WITH target_contacts AS (
    SELECT c.id, LOWER(c.email) AS email
      FROM public.contacts c
     WHERE c.email IS NOT NULL
       AND c.archived = false
       AND (p_contact_ids IS NULL OR c.id = ANY(p_contact_ids))
  ),
  candidates AS (
    SELECT
      ue.*,
      tc.id AS matched_contact_id
    FROM public.outlook_unmatched_emails ue
    JOIN target_contacts tc
      ON tc.email = ANY(ue.participant_emails)
   WHERE ue.matched_at IS NULL
  ),
  inserted AS (
    INSERT INTO public.email_messages (
      microsoft_message_id,
      microsoft_conversation_id,
      contact_id,
      deal_id,
      sourceco_user_id,
      direction,
      from_address,
      to_addresses,
      cc_addresses,
      bcc_addresses,
      subject,
      body_html,
      body_text,
      sent_at,
      has_attachments,
      attachment_metadata
    )
    SELECT
      c.microsoft_message_id,
      c.microsoft_conversation_id,
      c.matched_contact_id,
      (
        SELECT dp.id
          FROM public.deal_pipeline dp
         WHERE dp.deleted_at IS NULL
           AND (
             dp.buyer_contact_id  = c.matched_contact_id
             OR dp.seller_contact_id = c.matched_contact_id
           )
         ORDER BY dp.updated_at DESC NULLS LAST
         LIMIT 1
      ),
      c.sourceco_user_id,
      c.direction,
      c.from_address,
      c.to_addresses,
      c.cc_addresses,
      '{}',
      c.subject,
      c.body_html,
      COALESCE(c.body_text, c.body_preview),
      c.sent_at,
      c.has_attachments,
      c.attachment_metadata
    FROM candidates c
    ON CONFLICT (microsoft_message_id, contact_id) DO NOTHING
    RETURNING microsoft_message_id
  )
  SELECT COUNT(*), COALESCE(ARRAY_AGG(DISTINCT microsoft_message_id), '{}')
    INTO v_materialized, v_promoted_msg_ids
    FROM inserted;

  -- Mark the queue rows whose messages were successfully promoted so the
  -- next rematch pass skips them.
  IF v_promoted_msg_ids IS NOT NULL AND array_length(v_promoted_msg_ids, 1) > 0 THEN
    UPDATE public.outlook_unmatched_emails ue
       SET matched_at = now(),
           match_attempt_count = ue.match_attempt_count + 1
     WHERE ue.matched_at IS NULL
       AND ue.microsoft_message_id = ANY(v_promoted_msg_ids);
  END IF;

  RETURN v_materialized;
END;
$$;


ALTER FUNCTION "public"."rematch_unmatched_outlook_emails"("p_contact_ids" "uuid"[]) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."reset_all_admin_notifications"() RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NOT public.is_admin(auth.uid()) THEN
    RAISE EXCEPTION 'Access denied: admin role required';
  END IF;

  UPDATE admin_view_state
  SET last_viewed_at = NOW(), updated_at = NOW();
END;
$$;


