CREATE OR REPLACE FUNCTION "public"."resolve_canonical_buyer_id"("p_buyer_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  cur UUID := p_buyer_id;
  next_id UUID;
  depth INT := 0;
  visited UUID[] := ARRAY[]::UUID[];
BEGIN
  IF p_buyer_id IS NULL THEN RETURN NULL; END IF;

  LOOP
    IF depth > 10 THEN RETURN cur; END IF;          -- safety cap
    IF cur = ANY(visited) THEN RETURN cur; END IF;   -- cycle guard
    visited := visited || cur;

    SELECT merged_into_id INTO next_id
    FROM public.buyers
    WHERE id = cur;

    IF next_id IS NULL THEN RETURN cur; END IF;
    cur := next_id;
    depth := depth + 1;
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."resolve_canonical_buyer_id"("p_buyer_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."resolve_canonical_buyer_id"("p_buyer_id" "uuid") IS 'Walks buyers.merged_into_id chain. Returns the live survivor id (or input id if not merged). Cycle-safe and depth-capped.';



CREATE OR REPLACE FUNCTION "public"."resolve_canonical_profile_id"("p_profile_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  cur UUID := p_profile_id;
  next_id UUID;
  depth INT := 0;
  visited UUID[] := ARRAY[]::UUID[];
BEGIN
  IF p_profile_id IS NULL THEN RETURN NULL; END IF;

  LOOP
    IF depth > 10 THEN RETURN cur; END IF;            -- safety cap
    IF cur = ANY(visited) THEN RETURN cur; END IF;    -- cycle guard
    visited := visited || cur;

    SELECT merged_into_profile_id INTO next_id
    FROM public.profiles
    WHERE id = cur;

    IF next_id IS NULL THEN RETURN cur; END IF;
    cur := next_id;
    depth := depth + 1;
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."resolve_canonical_profile_id"("p_profile_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."resolve_canonical_profile_id"("p_profile_id" "uuid") IS 'Walks profiles.merged_into_profile_id chain. Returns the live canonical id (or input id if not merged, or NULL for NULL input). Cycle-safe, depth-capped at 10. Mirrors resolve_canonical_buyer_id (20260801000037).';



CREATE OR REPLACE FUNCTION "public"."resolve_contact_agreement_status"("p_contact_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_contact contacts%ROWTYPE;
  v_firm    firm_agreements%ROWTYPE;
  v_profile profiles%ROWTYPE;
  v_firm_nda BOOLEAN;
  v_firm_fee BOOLEAN;
  v_individual_nda BOOLEAN;
  v_individual_fee BOOLEAN;
BEGIN
  SELECT * INTO v_contact FROM contacts WHERE id = p_contact_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'Contact not found');
  END IF;

  v_firm_nda := false;
  v_firm_fee := false;

  IF v_contact.firm_id IS NOT NULL THEN
    SELECT * INTO v_firm FROM firm_agreements WHERE id = v_contact.firm_id;
    IF FOUND THEN
      v_firm_nda := COALESCE(v_firm.nda_status = 'signed', false)
                    AND (v_firm.nda_expires_at IS NULL OR v_firm.nda_expires_at > now());
      v_firm_fee := COALESCE(v_firm.fee_agreement_status = 'signed', false)
                    AND (v_firm.fee_agreement_expires_at IS NULL OR v_firm.fee_agreement_expires_at > now());
    END IF;
  END IF;

  v_individual_nda := COALESCE(v_contact.nda_signed, false);
  v_individual_fee := COALESCE(v_contact.fee_agreement_signed, false);

  IF v_contact.profile_id IS NOT NULL THEN
    SELECT * INTO v_profile FROM profiles WHERE id = v_contact.profile_id;
    IF FOUND THEN
      v_individual_nda := COALESCE(v_profile.nda_signed, v_contact.nda_signed, false);
      v_individual_fee := COALESCE(v_profile.fee_agreement_signed, v_contact.fee_agreement_signed, false);
    END IF;
  END IF;

  RETURN jsonb_build_object(
    'contact_id', p_contact_id,
    'contact_name', TRIM(v_contact.first_name || ' ' || v_contact.last_name),
    'firm_id', v_contact.firm_id,
    'firm_name', v_firm.primary_company_name,
    'firm_nda', v_firm_nda,
    'firm_nda_status', v_firm.nda_status,
    'firm_nda_at', v_firm.nda_signed_at,
    'firm_fee', v_firm_fee,
    'firm_fee_status', v_firm.fee_agreement_status,
    'firm_fee_at', v_firm.fee_agreement_signed_at,
    'individual_nda', v_individual_nda,
    'individual_nda_at', COALESCE(v_profile.nda_signed_at, v_contact.nda_signed_at),
    'individual_fee', v_individual_fee,
    'individual_fee_at', COALESCE(v_profile.fee_agreement_signed_at, v_contact.fee_agreement_signed_at),
    'effective_nda', v_firm_nda OR v_individual_nda,
    'effective_fee', v_firm_fee OR v_individual_fee
  );
END;
$$;


ALTER FUNCTION "public"."resolve_contact_agreement_status"("p_contact_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."resolve_contact_identity"("p_email" "text" DEFAULT NULL::"text", "p_linkedin_url" "text" DEFAULT NULL::"text", "p_phone" "text" DEFAULT NULL::"text", "p_firm_id" "uuid" DEFAULT NULL::"uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_contact_id UUID;
BEGIN
  -- 1. email match
  IF p_email IS NOT NULL AND trim(p_email) <> '' THEN
    SELECT id INTO v_contact_id
    FROM public.contacts
    WHERE lower(email) = lower(trim(p_email))
      AND deleted_at IS NULL
      AND merged_into_id IS NULL
      AND archived = false
    ORDER BY created_at ASC
    LIMIT 1;

    IF v_contact_id IS NOT NULL THEN
      RETURN v_contact_id;
    END IF;
  END IF;

  -- 2. linkedin_url match
  IF p_linkedin_url IS NOT NULL AND trim(p_linkedin_url) <> '' THEN
    SELECT id INTO v_contact_id
    FROM public.contacts
    WHERE lower(linkedin_url) = lower(trim(p_linkedin_url))
      AND deleted_at IS NULL
      AND merged_into_id IS NULL
      AND archived = false
    ORDER BY created_at ASC
    LIMIT 1;

    IF v_contact_id IS NOT NULL THEN
      RETURN v_contact_id;
    END IF;
  END IF;

  -- 3. phone + firm_id tuple
  IF p_phone IS NOT NULL AND trim(p_phone) <> '' AND p_firm_id IS NOT NULL THEN
    SELECT id INTO v_contact_id
    FROM public.contacts
    WHERE lower(phone) = lower(trim(p_phone))
      AND firm_id = p_firm_id
      AND deleted_at IS NULL
      AND merged_into_id IS NULL
      AND archived = false
    ORDER BY created_at ASC
    LIMIT 1;

    IF v_contact_id IS NOT NULL THEN
      RETURN v_contact_id;
    END IF;
  END IF;

  RETURN NULL;
END;
$$;


ALTER FUNCTION "public"."resolve_contact_identity"("p_email" "text", "p_linkedin_url" "text", "p_phone" "text", "p_firm_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."resolve_contact_list_member_contact_id"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  -- Only resolve if contact_id is not already set and we have an email
  IF NEW.contact_id IS NULL AND NEW.contact_email IS NOT NULL THEN
    SELECT c.id INTO NEW.contact_id
    FROM contacts c
    WHERE lower(c.email) = lower(NEW.contact_email)
      AND c.archived = false
    ORDER BY c.updated_at DESC
    LIMIT 1;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."resolve_contact_list_member_contact_id"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."resolve_phone_activity_link_by_phone"("p_phone" "text", "p_name" "text" DEFAULT NULL::"text", "p_email" "text" DEFAULT NULL::"text") RETURNS TABLE("contact_id" "uuid", "listing_id" "uuid", "remarketing_buyer_id" "uuid", "contact_email" "text", "match_source" "text")
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_phone TEXT := public.normalize_phone_lookup(p_phone);
BEGIN
  IF v_phone IS NULL THEN RETURN; END IF;

  RETURN QUERY
  WITH contact_match AS (
    SELECT
      c.id AS contact_id,
      c.listing_id,
      c.remarketing_buyer_id,
      c.email AS contact_email,
      'contact'::text AS match_source,
      (
        CASE WHEN p_email IS NOT NULL AND c.email IS NOT NULL AND lower(c.email) = lower(p_email) THEN 100 ELSE 0 END +
        CASE WHEN p_name IS NOT NULL AND lower(trim(concat_ws(' ', c.first_name, c.last_name))) = lower(trim(p_name)) THEN 20 ELSE 0 END +
        CASE WHEN c.listing_id IS NOT NULL THEN 5 ELSE 0 END +
        CASE WHEN c.remarketing_buyer_id IS NOT NULL THEN 5 ELSE 0 END
      ) AS score
    FROM public.contacts c
    WHERE coalesce(c.archived, false) = false
      AND public.normalize_phone_lookup(c.phone) = v_phone
  ),
  listing_match AS (
    SELECT
      NULL::uuid AS contact_id,
      l.id AS listing_id,
      NULL::uuid AS remarketing_buyer_id,
      l.main_contact_email AS contact_email,
      'listing'::text AS match_source,
      (
        CASE WHEN p_email IS NOT NULL AND l.main_contact_email IS NOT NULL AND lower(l.main_contact_email) = lower(p_email) THEN 100 ELSE 0 END +
        CASE WHEN p_name IS NOT NULL AND l.main_contact_name IS NOT NULL AND lower(trim(l.main_contact_name)) = lower(trim(p_name)) THEN 20 ELSE 0 END
      ) AS score
    FROM public.listings l
    WHERE public.normalize_phone_lookup(l.main_contact_phone) = v_phone
  ),
  buyer_match AS (
    -- NEW: match a PhoneBurner call to a buyer by primary or additional phone.
    SELECT
      NULL::uuid AS contact_id,
      NULL::uuid AS listing_id,
      b.id AS remarketing_buyer_id,
      NULL::text AS contact_email,
      'buyer'::text AS match_source,
      (
        CASE WHEN p_name IS NOT NULL AND lower(trim(b.company_name)) = lower(trim(p_name)) THEN 20 ELSE 0 END +
        3  -- small base to rank above pure phone-without-context matches
      ) AS score
    FROM public.buyers b
    WHERE coalesce(b.archived, false) = false
      AND b.deleted_at IS NULL
      AND (
        public.normalize_phone_lookup(b.phone) = v_phone
        OR EXISTS (
          SELECT 1 FROM unnest(coalesce(b.additional_phones, ARRAY[]::text[])) AS ap
          WHERE public.normalize_phone_lookup(ap) = v_phone
        )
      )
  ),
  ranked AS (
    SELECT * FROM contact_match
    UNION ALL
    SELECT * FROM listing_match
    UNION ALL
    SELECT * FROM buyer_match
  )
  SELECT r.contact_id, r.listing_id, r.remarketing_buyer_id, r.contact_email, r.match_source
  FROM ranked r
  ORDER BY r.score DESC, r.contact_id NULLS LAST, r.listing_id NULLS LAST
  LIMIT 1;
END;
$$;


ALTER FUNCTION "public"."resolve_phone_activity_link_by_phone"("p_phone" "text", "p_name" "text", "p_email" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."resolve_portal_access"("p_slug" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_org_id uuid;
  v_org_name text;
  v_org_slug text;
  v_welcome_message text;
  v_user_id uuid;
  v_portal_user jsonb;
BEGIN
  v_user_id := auth.uid();
  IF v_user_id IS NULL THEN
    RETURN NULL;
  END IF;

  SELECT id, name, portal_slug, welcome_message
    INTO v_org_id, v_org_name, v_org_slug, v_welcome_message
    FROM portal_organizations
   WHERE portal_slug = p_slug
     AND deleted_at IS NULL
   LIMIT 1;

  IF v_org_id IS NULL THEN
    RETURN NULL;
  END IF;

  SELECT jsonb_build_object(
    'id', pu.id,
    'portal_org_id', pu.portal_org_id,
    'profile_id', pu.profile_id,
    'contact_id', pu.contact_id,
    'role', pu.role,
    'email', pu.email,
    'name', pu.name,
    'is_active', pu.is_active,
    'last_login_at', pu.last_login_at,
    'invite_sent_at', pu.invite_sent_at,
    'invite_accepted_at', pu.invite_accepted_at,
    'created_at', pu.created_at,
    'updated_at', pu.updated_at,
    'portal_org', jsonb_build_object(
      'id', v_org_id,
      'name', v_org_name,
      'portal_slug', v_org_slug,
      'welcome_message', v_welcome_message
    )
  )
  INTO v_portal_user
  FROM portal_users pu
  WHERE pu.portal_org_id = v_org_id
    AND pu.profile_id = v_user_id
    AND pu.is_active = true
  LIMIT 1;

  IF v_portal_user IS NOT NULL THEN
    RETURN v_portal_user;
  END IF;

  IF EXISTS (
    SELECT 1 FROM user_roles
    WHERE user_roles.user_id = v_user_id
      AND role IN ('admin', 'owner', 'moderator')
  ) OR EXISTS (
    SELECT 1 FROM profiles
    WHERE id = v_user_id
      AND is_admin = true
  ) THEN
    RETURN jsonb_build_object(
      'id', 'admin-preview-' || v_user_id::text,
      'portal_org_id', v_org_id,
      'profile_id', v_user_id,
      'contact_id', null,
      'role', 'admin',
      'email', '',
      'name', 'Admin Preview',
      'is_active', true,
      'last_login_at', null,
      'invite_sent_at', null,
      'invite_accepted_at', null,
      'created_at', now(),
      'updated_at', now(),
      'portal_org', jsonb_build_object(
        'id', v_org_id,
        'name', v_org_name,
        'portal_slug', v_org_slug,
        'welcome_message', v_welcome_message
      )
    );
  END IF;

  RETURN NULL;
END;
$$;


ALTER FUNCTION "public"."resolve_portal_access"("p_slug" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."resolve_user_firm_id"("p_user_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_firm_id uuid;
  v_email_domain text;
  v_normalized_company text;
  v_generic_domains text[] := ARRAY[
    'gmail.com','googlemail.com','yahoo.com','hotmail.com','outlook.com',
    'icloud.com','me.com','mac.com','aol.com','live.com','msn.com',
    'mail.com','zoho.com','yandex.com','gmx.com','gmx.net',
    'protonmail.com','proton.me','pm.me','fastmail.com','tutanota.com',
    'hey.com','comcast.net','att.net','sbcglobal.net','verizon.net',
    'cox.net','bellsouth.net','rocketmail.com','ymail.com',
    'yahoo.com.au','hotmail.se','inbox.com'
  ];
BEGIN
  -- Get user's email domain and normalized company
  SELECT
    split_part(email, '@', 2),
    normalize_company_name(COALESCE(company, ''))
  INTO v_email_domain, v_normalized_company
  FROM profiles
  WHERE id = p_user_id;

  -- Priority 1: firm_members entry where firm's email_domain matches user's email domain
  -- (skip for generic/free email domains)
  IF v_email_domain IS NOT NULL AND v_email_domain <> ALL(v_generic_domains) THEN
    SELECT fm.firm_id INTO v_firm_id
    FROM firm_members fm
    JOIN firm_agreements fa ON fa.id = fm.firm_id
    WHERE fm.user_id = p_user_id
      AND fa.email_domain = v_email_domain
    ORDER BY fm.added_at DESC
    LIMIT 1;

    IF v_firm_id IS NOT NULL THEN
      RETURN v_firm_id;
    END IF;

    -- Also check if any firm matches the domain even without firm_members
    SELECT fa.id INTO v_firm_id
    FROM firm_agreements fa
    WHERE fa.email_domain = v_email_domain
    LIMIT 1;

    IF v_firm_id IS NOT NULL THEN
      RETURN v_firm_id;
    END IF;
  END IF;

  -- Priority 2: firm_members entry where firm's normalized name matches user's company
  IF v_normalized_company IS NOT NULL AND v_normalized_company != '' THEN
    SELECT fm.firm_id INTO v_firm_id
    FROM firm_members fm
    JOIN firm_agreements fa ON fa.id = fm.firm_id
    WHERE fm.user_id = p_user_id
      AND fa.normalized_company_name = v_normalized_company
    ORDER BY fm.added_at DESC
    LIMIT 1;

    IF v_firm_id IS NOT NULL THEN
      RETURN v_firm_id;
    END IF;
  END IF;

  -- Priority 3: Most recent firm_members entry (fallback)
  SELECT firm_id INTO v_firm_id
  FROM firm_members
  WHERE user_id = p_user_id
  ORDER BY added_at DESC
  LIMIT 1;

  RETURN v_firm_id;
END;
$$;


ALTER FUNCTION "public"."resolve_user_firm_id"("p_user_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."resolve_user_firm_id"("p_user_id" "uuid") IS 'Deterministic firm resolver. Priority: 1) email domain match, 2) company name match, 3) most recent membership. Never reads connection_requests to avoid circular dependency with sync_connection_request_firm trigger.';



CREATE OR REPLACE FUNCTION "public"."restore_deal"("deal_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Check if the calling user is an admin
  IF NOT public.is_admin(auth.uid()) THEN
    RAISE EXCEPTION 'Only admins can restore deals';
  END IF;
  
  -- Restore the deal by clearing deleted_at timestamp
  UPDATE public.deals 
  SET 
    deleted_at = NULL,
    updated_at = NOW(),
    metadata = COALESCE(metadata, '{}'::jsonb) || jsonb_build_object(
      'restored_by', auth.uid(),
      'restored_at', NOW()::text
    )
  WHERE id = deal_id AND deleted_at IS NOT NULL;
  
  -- Log the restoration activity
  IF FOUND THEN
    INSERT INTO public.deal_activities (
      deal_id,
      admin_id,
      activity_type,
      title,
      description
    ) VALUES (
      deal_id,
      auth.uid(),
      'deal_restored',
      'Deal Restored',
      'Deal was restored from deleted status'
    );
  END IF;
  
  RETURN FOUND;
END;
$$;


ALTER FUNCTION "public"."restore_deal"("deal_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."restore_deal"("deal_id" "uuid") IS 'Restore a soft-deleted deal (admin only)';



CREATE OR REPLACE FUNCTION "public"."restore_listing"("p_listing_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NOT public.is_admin(auth.uid()) THEN
    RAISE EXCEPTION 'Only admins can restore listings';
  END IF;

  UPDATE public.listings
  SET
    remarketing_status = 'active',
    archive_reason = NULL,
    updated_at = now()
  WHERE id = p_listing_id
    AND remarketing_status = 'archived';

  RETURN FOUND;
END;
$$;


ALTER FUNCTION "public"."restore_listing"("p_listing_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."restore_listing"("p_listing_id" "uuid") IS 'Restore a previously archived listing (remarketing_status=''archived'') to active status and clear its archive_reason. Admin-only.';



CREATE OR REPLACE FUNCTION "public"."restore_soft_deleted"("p_table_name" "text", "p_record_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
BEGIN
  -- Auth guard: admin-only
  IF NOT public.is_admin(auth.uid()) THEN
    RAISE EXCEPTION 'Access denied: admin role required';
  END IF;

  EXECUTE format(
    'UPDATE %I SET deleted_at = NULL WHERE id = $1',
    p_table_name
  ) USING p_record_id;

  RETURN FOUND;
END;
$_$;


ALTER FUNCTION "public"."restore_soft_deleted"("p_table_name" "text", "p_record_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rewrite_merged_buyer_fk"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  canonical UUID;
BEGIN
  IF NEW.remarketing_buyer_id IS NULL THEN RETURN NEW; END IF;

  canonical := public.resolve_canonical_buyer_id(NEW.remarketing_buyer_id);
  IF canonical IS NOT NULL AND canonical <> NEW.remarketing_buyer_id THEN
    RAISE NOTICE 'rewrite_merged_buyer_fk: % → % (merge-chain resolved)',
      NEW.remarketing_buyer_id, canonical;
    NEW.remarketing_buyer_id := canonical;
  END IF;

  RETURN NEW;
END;
$$;


