CREATE OR REPLACE FUNCTION "public"."safe_trigger_deal_alerts"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  listing_json JSONB;
  matching_alerts RECORD;
  supabase_url TEXT;
  service_key TEXT;
BEGIN
  -- Only process for INSERT operations on active listings
  IF TG_OP = 'INSERT' AND NEW.status = 'active' THEN
    BEGIN
      -- Resolve Supabase URL and service role key for edge function call
      supabase_url := COALESCE(
        current_setting('app.settings.supabase_url', true),
        current_setting('app.supabase_url', true)
      );
      service_key := COALESCE(
        current_setting('app.settings.service_role_key', true),
        current_setting('app.supabase_service_role_key', true)
      );

      -- If we can't resolve credentials, log and skip (don't break listing creation)
      IF supabase_url IS NULL OR service_key IS NULL THEN
        RAISE WARNING 'Deal alerts trigger: missing supabase_url or service_role_key settings';
        RETURN NEW;
      END IF;

      -- Safely convert listing to JSON with error handling
      listing_json := jsonb_build_object(
        'id', NEW.id,
        'title', NEW.title,
        'category', NEW.category,
        'categories', COALESCE(array_to_json(NEW.categories), '[]'::json),
        'location', NEW.location,
        'revenue', NEW.revenue,
        'ebitda', NEW.ebitda,
        'description', NEW.description,
        'tags', COALESCE(array_to_json(NEW.tags), '[]'::json),
        'status', NEW.status,
        'created_at', NEW.created_at,
        'updated_at', NEW.updated_at
      );

      -- Find matching alerts and send notifications
      FOR matching_alerts IN
        SELECT * FROM public.match_deal_alerts_with_listing(listing_json)
      LOOP
        -- Only send instant alerts immediately
        IF matching_alerts.alert_frequency = 'instant' THEN
          -- Log the delivery attempt
          INSERT INTO public.alert_delivery_logs (alert_id, listing_id, user_id, delivery_status)
          VALUES (matching_alerts.alert_id, NEW.id, matching_alerts.user_id, 'pending');

          -- Call the edge function to send the email
          PERFORM net.http_post(
            url := supabase_url || '/functions/v1/send-deal-alert',
            headers := jsonb_build_object(
              'Content-Type', 'application/json',
              'Authorization', 'Bearer ' || service_key
            ),
            body := jsonb_build_object(
              'alert_id', matching_alerts.alert_id,
              'user_email', matching_alerts.user_email,
              'user_id', matching_alerts.user_id,
              'listing_id', NEW.id,
              'alert_name', matching_alerts.alert_name,
              'listing_data', listing_json
            )
          );
        END IF;
      END LOOP;

    EXCEPTION WHEN OTHERS THEN
      -- Log the error but don't fail the listing creation
      RAISE WARNING 'Deal alerts trigger failed for listing %: %', NEW.id, SQLERRM;
    END;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."safe_trigger_deal_alerts"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."save_extended_profile"("p_user_id" "uuid", "p_data" "jsonb") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  UPDATE profiles SET
    ideal_target_description = COALESCE(p_data->>'ideal_target_description', ideal_target_description),
    business_categories = CASE WHEN p_data ? 'business_categories' THEN p_data->'business_categories' ELSE business_categories END,
    target_locations = CASE WHEN p_data ? 'target_locations' THEN p_data->'target_locations' ELSE target_locations END,
    revenue_range_min = COALESCE(p_data->>'revenue_range_min', revenue_range_min),
    revenue_range_max = COALESCE(p_data->>'revenue_range_max', revenue_range_max),
    specific_business_search = COALESCE(p_data->>'specific_business_search', specific_business_search),
    target_deal_size_min = COALESCE(NULLIF(p_data->>'target_deal_size_min', '')::numeric, target_deal_size_min),
    target_deal_size_max = COALESCE(NULLIF(p_data->>'target_deal_size_max', '')::numeric, target_deal_size_max),
    estimated_revenue = COALESCE(p_data->>'estimated_revenue', estimated_revenue),
    fund_size = COALESCE(p_data->>'fund_size', fund_size),
    investment_size = CASE WHEN p_data ? 'investment_size' THEN p_data->'investment_size' ELSE investment_size END,
    aum = COALESCE(p_data->>'aum', aum),
    is_funded = COALESCE(p_data->>'is_funded', is_funded),
    funded_by = COALESCE(p_data->>'funded_by', funded_by),
    target_company_size = COALESCE(p_data->>'target_company_size', target_company_size),
    funding_source = COALESCE(p_data->>'funding_source', funding_source),
    needs_loan = COALESCE(p_data->>'needs_loan', needs_loan),
    ideal_target = COALESCE(p_data->>'ideal_target', ideal_target),
    deploying_capital_now = COALESCE(p_data->>'deploying_capital_now', deploying_capital_now),
    owning_business_unit = COALESCE(p_data->>'owning_business_unit', owning_business_unit),
    deal_size_band = COALESCE(p_data->>'deal_size_band', deal_size_band),
    buyer_org_url = COALESCE(p_data->>'buyer_org_url', buyer_org_url),
    integration_plan = CASE WHEN p_data ? 'integration_plan' THEN p_data->'integration_plan' ELSE integration_plan END,
    corpdev_intent = COALESCE(p_data->>'corpdev_intent', corpdev_intent),
    discretion_type = COALESCE(p_data->>'discretion_type', discretion_type),
    committed_equity_band = COALESCE(p_data->>'committed_equity_band', committed_equity_band),
    equity_source = CASE WHEN p_data ? 'equity_source' THEN p_data->'equity_source' ELSE equity_source END,
    deployment_timing = COALESCE(p_data->>'deployment_timing', deployment_timing),
    geographic_focus = CASE WHEN p_data ? 'geographic_focus' THEN p_data->'geographic_focus' ELSE geographic_focus END,
    industry_expertise = CASE WHEN p_data ? 'industry_expertise' THEN p_data->'industry_expertise' ELSE industry_expertise END,
    deal_structure_preference = COALESCE(p_data->>'deal_structure_preference', deal_structure_preference),
    permanent_capital = COALESCE((p_data->>'permanent_capital')::boolean, permanent_capital),
    operating_company_targets = CASE WHEN p_data ? 'operating_company_targets' THEN p_data->'operating_company_targets' ELSE operating_company_targets END,
    flex_subxm_ebitda = COALESCE((p_data->>'flex_subxm_ebitda')::boolean, flex_subxm_ebitda),
    search_type = COALESCE(p_data->>'search_type', search_type),
    acq_equity_band = COALESCE(p_data->>'acq_equity_band', acq_equity_band),
    financing_plan = CASE WHEN p_data ? 'financing_plan' THEN p_data->'financing_plan' ELSE financing_plan END,
    search_stage = COALESCE(p_data->>'search_stage', search_stage),
    flex_sub2m_ebitda = COALESCE((p_data->>'flex_sub2m_ebitda')::boolean, flex_sub2m_ebitda),
    on_behalf_of_buyer = COALESCE(p_data->>'on_behalf_of_buyer', on_behalf_of_buyer),
    buyer_role = COALESCE(p_data->>'buyer_role', buyer_role),
    owner_timeline = COALESCE(p_data->>'owner_timeline', owner_timeline),
    owner_intent = COALESCE(p_data->>'owner_intent', owner_intent),
    uses_bank_finance = COALESCE(p_data->>'uses_bank_finance', uses_bank_finance),
    max_equity_today_band = COALESCE(p_data->>'max_equity_today_band', max_equity_today_band),
    mandate_blurb = COALESCE(p_data->>'mandate_blurb', mandate_blurb),
    portfolio_company_addon = COALESCE(p_data->>'portfolio_company_addon', portfolio_company_addon),
    backers_summary = COALESCE(p_data->>'backers_summary', backers_summary),
    anchor_investors_summary = COALESCE(p_data->>'anchor_investors_summary', anchor_investors_summary),
    deal_intent = COALESCE(p_data->>'deal_intent', deal_intent),
    exclusions = CASE WHEN p_data ? 'exclusions' THEN p_data->'exclusions' ELSE exclusions END,
    include_keywords = CASE WHEN p_data ? 'include_keywords' THEN p_data->'include_keywords' ELSE include_keywords END,
    referral_source = COALESCE(p_data->>'referral_source', referral_source),
    referral_source_detail = COALESCE(p_data->>'referral_source_detail', referral_source_detail),
    deal_sourcing_methods = CASE WHEN p_data ? 'deal_sourcing_methods' THEN p_data->'deal_sourcing_methods' ELSE deal_sourcing_methods END,
    target_acquisition_volume = COALESCE(p_data->>'target_acquisition_volume', target_acquisition_volume),
    updated_at = now()
  WHERE id = p_user_id;

EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'save_extended_profile failed for user %: %', p_user_id, SQLERRM;
END;
$$;


ALTER FUNCTION "public"."save_extended_profile"("p_user_id" "uuid", "p_data" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."save_primary_seller_contact"("p_listing_id" "uuid", "p_name" "text", "p_email" "text", "p_phone" "text", "p_mobile_phone_2" "text" DEFAULT NULL::"text", "p_mobile_phone_3" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_contact_id UUID;
  v_first_name TEXT;
  v_last_name  TEXT;
  v_trimmed_name TEXT := NULLIF(TRIM(p_name), '');
  v_trimmed_email TEXT := NULLIF(TRIM(lower(p_email)), '');
BEGIN
  IF p_listing_id IS NULL THEN
    RAISE EXCEPTION 'save_primary_seller_contact: p_listing_id is required';
  END IF;

  -- 1. Find an existing seller contact for this listing. Prefer the one
  --    flagged as primary; otherwise fall back to the oldest non-archived
  --    seller contact so we don't create a duplicate when the sync trigger's
  --    ON CONFLICT DO NOTHING left the flag un-set.
  SELECT id
  INTO v_contact_id
  FROM public.contacts
  WHERE listing_id = p_listing_id
    AND contact_type = 'seller'
    AND archived = false
  ORDER BY is_primary_seller_contact DESC, created_at ASC
  LIMIT 1;

  -- 2a. Create the contact if none exists yet. Split the name on the first
  --     whitespace; if the name is empty, fall back to 'Unknown'.
  IF v_contact_id IS NULL THEN
    v_first_name := COALESCE(
      NULLIF(TRIM(split_part(COALESCE(v_trimmed_name, ''), ' ', 1)), ''),
      'Unknown'
    );
    v_last_name := CASE
      WHEN v_trimmed_name IS NOT NULL AND position(' ' IN v_trimmed_name) > 0
      THEN TRIM(substring(v_trimmed_name FROM position(' ' IN v_trimmed_name) + 1))
      ELSE ''
    END;

    INSERT INTO public.contacts (
      first_name, last_name, email, phone,
      contact_type, listing_id, is_primary_seller_contact,
      mobile_phone_1, mobile_phone_2, mobile_phone_3,
      phone_source, source
    ) VALUES (
      v_first_name,
      v_last_name,
      v_trimmed_email,
      NULLIF(TRIM(p_phone), ''),
      'seller',
      p_listing_id,
      true,
      NULLIF(TRIM(p_phone), ''),
      NULLIF(TRIM(p_mobile_phone_2), ''),
      NULLIF(TRIM(p_mobile_phone_3), ''),
      'manual',
      'deal_detail_edit'
    )
    RETURNING id INTO v_contact_id;

  -- 2b. Otherwise update the existing contact. CASE WHEN distinguishes
  --     NULL (keep existing) from '' (explicit clear) so the UI can remove
  --     a phone number by clearing the input.
  ELSE
    UPDATE public.contacts
    SET
      first_name = CASE
        WHEN v_trimmed_name IS NOT NULL
        THEN COALESCE(NULLIF(TRIM(split_part(v_trimmed_name, ' ', 1)), ''), first_name)
        ELSE first_name
      END,
      last_name = CASE
        WHEN v_trimmed_name IS NOT NULL AND position(' ' IN v_trimmed_name) > 0
        THEN TRIM(substring(v_trimmed_name FROM position(' ' IN v_trimmed_name) + 1))
        WHEN v_trimmed_name IS NOT NULL
        THEN ''
        ELSE last_name
      END,
      email = CASE
        WHEN p_email IS NOT NULL THEN v_trimmed_email
        ELSE email
      END,
      phone = CASE
        WHEN p_phone IS NOT NULL THEN NULLIF(TRIM(p_phone), '')
        ELSE phone
      END,
      mobile_phone_1 = CASE
        WHEN p_phone IS NOT NULL THEN NULLIF(TRIM(p_phone), '')
        ELSE mobile_phone_1
      END,
      mobile_phone_2 = CASE
        WHEN p_mobile_phone_2 IS NOT NULL THEN NULLIF(TRIM(p_mobile_phone_2), '')
        ELSE mobile_phone_2
      END,
      mobile_phone_3 = CASE
        WHEN p_mobile_phone_3 IS NOT NULL THEN NULLIF(TRIM(p_mobile_phone_3), '')
        ELSE mobile_phone_3
      END,
      is_primary_seller_contact = true,
      phone_source = 'manual',
      updated_at = now()
    WHERE id = v_contact_id;
  END IF;

  RETURN v_contact_id;
END;
$$;


ALTER FUNCTION "public"."save_primary_seller_contact"("p_listing_id" "uuid", "p_name" "text", "p_email" "text", "p_phone" "text", "p_mobile_phone_2" "text", "p_mobile_phone_3" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."save_primary_seller_contact"("p_listing_id" "uuid", "p_name" "text", "p_email" "text", "p_phone" "text", "p_mobile_phone_2" "text", "p_mobile_phone_3" "text") IS 'Upserts the primary seller contact for a listing and writes mobile_phone_1/2/3 in a single SECURITY DEFINER call. Sets is_primary_seller_contact=true so future reads resolve the same row. Pass NULL to keep a phone, '''' to clear it.';



CREATE OR REPLACE FUNCTION "public"."search_all_transcripts"("p_query" "text", "p_limit" integer DEFAULT 25) RETURNS TABLE("source_table" "text", "source_id" "uuid", "buyer_id" "uuid", "listing_id" "uuid", "snippet" "text", "rank" real, "matched_at" timestamp with time zone)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  WITH q AS (
    SELECT websearch_to_tsquery('english', p_query) AS tsq
  )
  (
    SELECT
      'buyer_transcripts'::text          AS source_table,
      bt.id                              AS source_id,
      bt.buyer_id                        AS buyer_id,
      NULL::uuid                         AS listing_id,
      ts_headline('english',
                  LEFT(COALESCE(bt.transcript_text, ''), 2000),
                  (SELECT tsq FROM q),
                  'MaxFragments=2, MaxWords=25, MinWords=10')  AS snippet,
      ts_rank(to_tsvector('english', COALESCE(bt.transcript_text, '')),
              (SELECT tsq FROM q))       AS rank,
      bt.call_date                       AS matched_at
    FROM public.buyer_transcripts bt, q
    WHERE to_tsvector('english', COALESCE(bt.transcript_text, '')) @@ q.tsq
  )
  UNION ALL
  (
    SELECT
      'deal_transcripts', dt.id, NULL::uuid, dt.listing_id,
      ts_headline('english',
                  LEFT(COALESCE(dt.transcript_text, ''), 2000),
                  (SELECT tsq FROM q),
                  'MaxFragments=2, MaxWords=25, MinWords=10'),
      ts_rank(to_tsvector('english', COALESCE(dt.transcript_text, '')),
              (SELECT tsq FROM q)),
      dt.call_date
    FROM public.deal_transcripts dt, q
    WHERE to_tsvector('english', COALESCE(dt.transcript_text, '')) @@ q.tsq
  )
  UNION ALL
  (
    SELECT
      'contact_activities', ca.id, ca.remarketing_buyer_id, ca.listing_id,
      ts_headline('english',
                  LEFT(COALESCE(ca.call_transcript, ''), 2000),
                  (SELECT tsq FROM q),
                  'MaxFragments=2, MaxWords=25, MinWords=10'),
      ts_rank(to_tsvector('english', COALESCE(ca.call_transcript, '')),
              (SELECT tsq FROM q)),
      ca.call_started_at
    FROM public.contact_activities ca, q
    WHERE to_tsvector('english', COALESCE(ca.call_transcript, '')) @@ q.tsq
  )
  ORDER BY rank DESC, matched_at DESC NULLS LAST
  LIMIT COALESCE(p_limit, 25);
$$;


ALTER FUNCTION "public"."search_all_transcripts"("p_query" "text", "p_limit" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."search_all_transcripts"("p_query" "text", "p_limit" integer) IS 'Unified full-text search across buyer_transcripts, deal_transcripts, and contact_activities. Returns ranked snippets with ts_headline. Usage: SELECT * FROM search_all_transcripts(''hvac texas'', 20);';



CREATE OR REPLACE FUNCTION "public"."search_buyers_by_similarity"("search_name" "text", "min_similarity" double precision DEFAULT 0.70) RETURNS TABLE("id" "uuid", "company_name" "text", "score" double precision)
    LANGUAGE "sql" STABLE
    AS $$
  SELECT
    b.id,
    b.company_name,
    similarity(LOWER(b.company_name), LOWER(search_name))::FLOAT AS score
  FROM public.buyers b
  WHERE b.archived = false
    AND similarity(LOWER(b.company_name), LOWER(search_name)) > min_similarity
  ORDER BY score DESC
  LIMIT 5;
$$;


ALTER FUNCTION "public"."search_buyers_by_similarity"("search_name" "text", "min_similarity" double precision) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."search_buyers_in_radius"("p_center_lat" double precision, "p_center_lng" double precision, "p_radius_miles" double precision, "p_limit" integer DEFAULT 500) RETURNS TABLE("buyer_id" "uuid", "distance_miles" double precision)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT
    b.id AS buyer_id,
    public.haversine_miles(p_center_lat, p_center_lng, b.latitude, b.longitude) AS distance_miles
  FROM public.buyers b
  WHERE b.latitude IS NOT NULL
    AND b.longitude IS NOT NULL
    AND b.geocoding_status = 'success'
    -- Bounding-box prefilter: ~69 miles per degree of latitude at US latitudes.
    -- Avoids computing haversine for rows obviously out of range.
    AND b.latitude  BETWEEN p_center_lat - (p_radius_miles / 69.0) AND p_center_lat + (p_radius_miles / 69.0)
    AND b.longitude BETWEEN p_center_lng - (p_radius_miles / 55.0) AND p_center_lng + (p_radius_miles / 55.0)
    AND public.haversine_miles(p_center_lat, p_center_lng, b.latitude, b.longitude) <= p_radius_miles
  ORDER BY distance_miles ASC
  LIMIT p_limit;
$$;


ALTER FUNCTION "public"."search_buyers_in_radius"("p_center_lat" double precision, "p_center_lng" double precision, "p_radius_miles" double precision, "p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."search_listings"("search_query" "text", "filter_status" "text" DEFAULT 'active'::"text", "filter_category" "text" DEFAULT NULL::"text", "filter_location" "text" DEFAULT NULL::"text", "filter_revenue_min" numeric DEFAULT NULL::numeric, "filter_revenue_max" numeric DEFAULT NULL::numeric, "filter_ebitda_min" numeric DEFAULT NULL::numeric, "filter_ebitda_max" numeric DEFAULT NULL::numeric, "page_offset" integer DEFAULT 0, "page_limit" integer DEFAULT 20) RETURNS TABLE("id" "uuid", "title" "text", "description" "text", "description_html" "text", "hero_description" "text", "category" "text", "categories" "text"[], "acquisition_type" "text", "location" "text", "revenue" numeric, "ebitda" numeric, "tags" "text"[], "image_url" "text", "status" "text", "status_tag" "text", "visible_to_buyer_types" "text"[], "created_at" timestamp with time zone, "updated_at" timestamp with time zone, "full_time_employees" integer, "part_time_employees" integer, "custom_metric_label" "text", "custom_metric_value" "text", "custom_metric_subtitle" "text", "metric_3_type" "text", "metric_3_custom_label" "text", "metric_3_custom_value" "text", "metric_3_custom_subtitle" "text", "metric_4_type" "text", "metric_4_custom_label" "text", "metric_4_custom_value" "text", "metric_4_custom_subtitle" "text", "revenue_metric_subtitle" "text", "ebitda_metric_subtitle" "text", "owner_notes" "text", "rank" real, "total_count" bigint)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  tsq tsquery;
  total bigint;
BEGIN
  tsq := websearch_to_tsquery('english', search_query);

  SELECT count(*) INTO total
  FROM public.listings l
  WHERE l.fts @@ tsq
    AND l.status = filter_status
    AND l.deleted_at IS NULL
    AND l.is_internal_deal = false
    AND (filter_category IS NULL OR l.category = filter_category OR l.categories @> ARRAY[filter_category])
    AND (filter_location IS NULL OR l.location = filter_location)
    AND (filter_revenue_min IS NULL OR l.revenue >= filter_revenue_min)
    AND (filter_revenue_max IS NULL OR l.revenue <= filter_revenue_max)
    AND (filter_ebitda_min IS NULL OR l.ebitda >= filter_ebitda_min)
    AND (filter_ebitda_max IS NULL OR l.ebitda <= filter_ebitda_max);

  RETURN QUERY
  SELECT
    l.id, l.title, l.description, l.description_html, l.hero_description,
    l.category, l.categories, l.acquisition_type, l.location,
    l.revenue, l.ebitda, l.tags, l.image_url, l.status, l.status_tag,
    l.visible_to_buyer_types, l.created_at, l.updated_at,
    l.full_time_employees, l.part_time_employees,
    l.custom_metric_label, l.custom_metric_value, l.custom_metric_subtitle,
    l.metric_3_type, l.metric_3_custom_label, l.metric_3_custom_value, l.metric_3_custom_subtitle,
    l.metric_4_type, l.metric_4_custom_label, l.metric_4_custom_value, l.metric_4_custom_subtitle,
    l.revenue_metric_subtitle, l.ebitda_metric_subtitle, l.owner_notes,
    ts_rank_cd(l.fts, tsq) AS rank,
    total AS total_count
  FROM public.listings l
  WHERE l.fts @@ tsq
    AND l.status = filter_status
    AND l.deleted_at IS NULL
    AND l.is_internal_deal = false
    AND (filter_category IS NULL OR l.category = filter_category OR l.categories @> ARRAY[filter_category])
    AND (filter_location IS NULL OR l.location = filter_location)
    AND (filter_revenue_min IS NULL OR l.revenue >= filter_revenue_min)
    AND (filter_revenue_max IS NULL OR l.revenue <= filter_revenue_max)
    AND (filter_ebitda_min IS NULL OR l.ebitda >= filter_ebitda_min)
    AND (filter_ebitda_max IS NULL OR l.ebitda <= filter_ebitda_max)
  ORDER BY ts_rank_cd(l.fts, tsq) DESC, l.created_at DESC
  OFFSET page_offset
  LIMIT page_limit;
END;
$$;


ALTER FUNCTION "public"."search_listings"("search_query" "text", "filter_status" "text", "filter_category" "text", "filter_location" "text", "filter_revenue_min" numeric, "filter_revenue_max" numeric, "filter_ebitda_min" numeric, "filter_ebitda_max" numeric, "page_offset" integer, "page_limit" integer) OWNER TO "postgres";


