CREATE OR REPLACE FUNCTION "public"."search_transcripts_semantic"("query_embedding" "extensions"."vector", "match_threshold" double precision DEFAULT 0.7, "match_count" integer DEFAULT 10, "p_buyer_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("id" "uuid", "source_type" "text", "buyer_id" "uuid", "title" "text", "transcript_snippet" "text", "similarity" double precision, "call_date" timestamp with time zone, "created_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    bt.id,
    'buyer_transcript'::text as source_type,
    bt.buyer_id,
    bt.title,
    LEFT(bt.transcript_text, 500) as transcript_snippet,
    1 - (bt.embedding <=> query_embedding) as similarity,
    bt.call_date::timestamptz,
    bt.created_at
  FROM buyer_transcripts bt
  WHERE bt.embedding IS NOT NULL
    AND 1 - (bt.embedding <=> query_embedding) > match_threshold
    AND (p_buyer_id IS NULL OR bt.buyer_id = p_buyer_id)
  
  UNION ALL
  
  SELECT 
    dt.id,
    'deal_transcript'::text as source_type,
    NULL::uuid as buyer_id,
    dt.title,
    LEFT(dt.transcript_text, 500) as transcript_snippet,
    1 - (dt.embedding <=> query_embedding) as similarity,
    dt.call_date::timestamptz,
    dt.created_at
  FROM deal_transcripts dt
  WHERE dt.embedding IS NOT NULL
    AND 1 - (dt.embedding <=> query_embedding) > match_threshold
  
  ORDER BY similarity DESC
  LIMIT match_count;
END;
$$;


ALTER FUNCTION "public"."search_transcripts_semantic"("query_embedding" "extensions"."vector", "match_threshold" double precision, "match_count" integer, "p_buyer_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."set_contact_email_domain"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_domain TEXT;
BEGIN
  IF NEW.email IS NULL OR NEW.email = '' THEN
    NEW.email_domain := NULL;
    RETURN NEW;
  END IF;
  v_domain := lower(trim(split_part(NEW.email, '@', 2)));
  IF v_domain IS NULL OR v_domain = '' THEN
    NEW.email_domain := NULL;
    RETURN NEW;
  END IF;
  IF EXISTS (SELECT 1 FROM public.generic_email_domains WHERE domain = v_domain) THEN
    NEW.email_domain := NULL;
  ELSE
    NEW.email_domain := v_domain;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."set_contact_email_domain"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."set_portal_user_deactivated_at"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  IF OLD.is_active = true AND NEW.is_active = false THEN
    NEW.deactivated_at := now();
  ELSIF OLD.is_active = false AND NEW.is_active = true THEN
    NEW.deactivated_at := NULL;
  END IF;
  RETURN NEW;
END;
$$;


