CREATE OR REPLACE FUNCTION "public"."soft_delete_deal"("deal_id" "uuid", "deletion_reason" "text" DEFAULT NULL::"text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Check if the calling user is an admin
  IF NOT public.is_admin(auth.uid()) THEN
    RAISE EXCEPTION 'Only admins can delete deals';
  END IF;
  
  -- Soft delete the deal by setting deleted_at timestamp
  UPDATE public.deals 
  SET 
    deleted_at = NOW(),
    updated_at = NOW(),
    metadata = COALESCE(metadata, '{}'::jsonb) || jsonb_build_object(
      'deleted_by', auth.uid(),
      'deletion_reason', deletion_reason,
      'deleted_at_iso', NOW()::text
    )
  WHERE id = deal_id AND deleted_at IS NULL;
  
  -- Log the deletion activity
  IF FOUND THEN
    INSERT INTO public.deal_activities (
      deal_id,
      admin_id,
      activity_type,
      title,
      description,
      metadata
    ) VALUES (
      deal_id,
      auth.uid(),
      'deal_deleted',
      'Deal Deleted',
      COALESCE('Reason: ' || deletion_reason, 'Deal was deleted'),
      jsonb_build_object('deletion_reason', deletion_reason)
    );
  END IF;
  
  RETURN FOUND;
END;
$$;


ALTER FUNCTION "public"."soft_delete_deal"("deal_id" "uuid", "deletion_reason" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."soft_delete_deal"("deal_id" "uuid", "deletion_reason" "text") IS 'Soft delete a deal (admin only) with optional reason';



