CREATE OR REPLACE FUNCTION "public"."subtract_lists"("p_primary_id" "uuid", "p_exclude_ids" "uuid"[], "p_new_name" "text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_new_list_id uuid;
  v_count int;
  v_list_type text;
BEGIN
  IF NOT is_admin(auth.uid()) THEN
    RAISE EXCEPTION 'Only admins can subtract lists';
  END IF;

  SELECT list_type INTO v_list_type FROM contact_lists WHERE id = p_primary_id;

  INSERT INTO contact_lists (name, list_type, created_by, contact_count)
  VALUES (p_new_name, COALESCE(v_list_type, 'mixed'), auth.uid(), 0)
  RETURNING id INTO v_new_list_id;

  INSERT INTO contact_list_members (list_id, contact_email, contact_name, contact_phone,
    contact_company, contact_role, entity_type, entity_id, added_by)
  SELECT v_new_list_id, m.contact_email, m.contact_name, m.contact_phone,
    m.contact_company, m.contact_role, m.entity_type, m.entity_id, 'merged'
  FROM contact_list_members m
  WHERE m.list_id = p_primary_id AND m.removed_at IS NULL
    AND m.contact_email NOT IN (
      SELECT ex.contact_email
      FROM contact_list_members ex
      WHERE ex.list_id = ANY(p_exclude_ids) AND ex.removed_at IS NULL
    );

  GET DIAGNOSTICS v_count = ROW_COUNT;
  UPDATE contact_lists SET contact_count = v_count WHERE id = v_new_list_id;

  RETURN v_new_list_id;
END;
$$;


ALTER FUNCTION "public"."subtract_lists"("p_primary_id" "uuid", "p_exclude_ids" "uuid"[], "p_new_name" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."subtract_lists"("p_primary_id" "uuid", "p_exclude_ids" "uuid"[], "p_new_name" "text") IS 'Create a new list from primary minus exclude lists; members tagged added_by=merged';



CREATE OR REPLACE FUNCTION "public"."sync_agreement_status_from_booleans"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Sync nda_status when nda_signed boolean changes
  IF OLD.nda_signed IS DISTINCT FROM NEW.nda_signed THEN
    IF NEW.nda_signed = true AND NEW.nda_status != 'signed' THEN
      NEW.nda_status := 'signed';
    ELSIF NEW.nda_signed = false AND NEW.nda_status = 'signed' THEN
      NEW.nda_status := 'not_started';
    END IF;
  END IF;

  -- Sync fee_agreement_status when fee_agreement_signed boolean changes
  IF OLD.fee_agreement_signed IS DISTINCT FROM NEW.fee_agreement_signed THEN
    IF NEW.fee_agreement_signed = true AND NEW.fee_agreement_status != 'signed' THEN
      NEW.fee_agreement_status := 'signed';
    ELSIF NEW.fee_agreement_signed = false AND NEW.fee_agreement_status = 'signed' THEN
      NEW.fee_agreement_status := 'not_started';
    END IF;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."sync_agreement_status_from_booleans"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."sync_buyer_score_to_remarketing"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  -- When buyer scoring fields change on profiles, sync to remarketing_buyers
  IF NEW.remarketing_buyer_id IS NOT NULL AND (
    NEW.buyer_quality_score IS DISTINCT FROM OLD.buyer_quality_score OR
    NEW.buyer_tier IS DISTINCT FROM OLD.buyer_tier OR
    NEW.admin_tier_override IS DISTINCT FROM OLD.admin_tier_override OR
    NEW.admin_override_note IS DISTINCT FROM OLD.admin_override_note OR
    NEW.platform_signal_detected IS DISTINCT FROM OLD.platform_signal_detected
  ) THEN
    UPDATE public.remarketing_buyers
    SET
      buyer_quality_score = NEW.buyer_quality_score,
      buyer_quality_score_last_calculated = NEW.buyer_quality_score_last_calculated::timestamptz,
      buyer_tier = NEW.buyer_tier,
      admin_tier_override = NEW.admin_tier_override,
      admin_override_note = NEW.admin_override_note,
      platform_signal_detected = COALESCE(NEW.platform_signal_detected, false),
      platform_signal_source = NEW.platform_signal_source,
      updated_at = now()
    WHERE id = NEW.remarketing_buyer_id;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."sync_buyer_score_to_remarketing"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."sync_buyer_target_geographies"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF TG_OP = 'UPDATE' AND NEW.target_geographies IS NOT DISTINCT FROM OLD.target_geographies THEN
    RETURN NEW;
  END IF;

  DELETE FROM public.buyer_target_geographies btg
  WHERE btg.buyer_id = NEW.id
    AND btg.geography_code NOT IN (
      SELECT UPPER(TRIM(g))
      FROM unnest(COALESCE(NEW.target_geographies, '{}'::TEXT[])) AS g
      WHERE g IS NOT NULL AND TRIM(g) <> ''
    );

  INSERT INTO public.buyer_target_geographies (buyer_id, geography_code)
  SELECT DISTINCT NEW.id, UPPER(TRIM(geo))
  FROM unnest(COALESCE(NEW.target_geographies, '{}'::TEXT[])) AS geo
  WHERE geo IS NOT NULL AND TRIM(geo) <> ''
  ON CONFLICT (buyer_id, geography_code) DO NOTHING;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."sync_buyer_target_geographies"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."sync_buyer_target_industries"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF TG_OP = 'UPDATE' AND NEW.target_industries IS NOT DISTINCT FROM OLD.target_industries THEN
    RETURN NEW;
  END IF;

  DELETE FROM public.buyer_target_industries bti
  WHERE bti.buyer_id = NEW.id
    AND NOT EXISTS (
      SELECT 1 FROM public.industries i
      WHERE i.id = bti.industry_id
        AND i.normalized_name = ANY (
          SELECT public.normalize_name(ind)
          FROM unnest(COALESCE(NEW.target_industries, '{}'::TEXT[])) AS ind
          WHERE ind IS NOT NULL AND TRIM(ind) <> ''
        )
    );

  INSERT INTO public.buyer_target_industries (buyer_id, industry_id)
  SELECT DISTINCT NEW.id, i.id
  FROM unnest(COALESCE(NEW.target_industries, '{}'::TEXT[])) AS ind
  JOIN public.industries i
    ON i.normalized_name = public.normalize_name(ind)
   AND i.archived = false
  WHERE ind IS NOT NULL AND TRIM(ind) <> ''
  ON CONFLICT (buyer_id, industry_id) DO NOTHING;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."sync_buyer_target_industries"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."sync_buyer_universe_membership"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- INSERT: create membership if universe_id set and buyer not soft-deleted
  IF TG_OP = 'INSERT' THEN
    IF NEW.universe_id IS NOT NULL AND NEW.deleted_at IS NULL THEN
      BEGIN
        INSERT INTO public.buyer_universe_memberships
          (buyer_id, universe_id, status, source, added_at, created_at)
        VALUES (
          NEW.id,
          NEW.universe_id,
          CASE WHEN COALESCE(NEW.archived, false) THEN 'archived' ELSE 'active' END,
          'sync_trigger',
          COALESCE(NEW.created_at, now()),
          COALESCE(NEW.created_at, now())
        )
        ON CONFLICT (buyer_id, universe_id) WHERE deleted_at IS NULL DO NOTHING;
      EXCEPTION WHEN OTHERS THEN
        RAISE NOTICE 'sync_buyer_universe_membership INSERT non-fatal: %', SQLERRM;
      END;
    END IF;
    RETURN NEW;
  END IF;

  -- UPDATE: handle universe_id changes + soft-delete transitions
  IF TG_OP = 'UPDATE' THEN
    BEGIN
      -- universe_id changed: soft-delete old membership, insert new
      IF NEW.universe_id IS DISTINCT FROM OLD.universe_id THEN
        IF OLD.universe_id IS NOT NULL THEN
          UPDATE public.buyer_universe_memberships
          SET deleted_at = now(), updated_at = now()
          WHERE buyer_id = OLD.id
            AND universe_id = OLD.universe_id
            AND deleted_at IS NULL;
        END IF;
        IF NEW.universe_id IS NOT NULL AND NEW.deleted_at IS NULL THEN
          INSERT INTO public.buyer_universe_memberships
            (buyer_id, universe_id, status, source, added_at, created_at)
          VALUES (
            NEW.id, NEW.universe_id,
            CASE WHEN COALESCE(NEW.archived, false) THEN 'archived' ELSE 'active' END,
            'sync_trigger', now(), now()
          )
          ON CONFLICT (buyer_id, universe_id) WHERE deleted_at IS NULL DO NOTHING;
        END IF;
      END IF;

      -- Soft-delete transition: archive or soft-delete memberships
      IF NEW.deleted_at IS DISTINCT FROM OLD.deleted_at THEN
        IF NEW.deleted_at IS NOT NULL THEN
          UPDATE public.buyer_universe_memberships
          SET deleted_at = NEW.deleted_at, updated_at = now()
          WHERE buyer_id = NEW.id AND deleted_at IS NULL;
        END IF;
      END IF;

      -- Archived flag transition: sync status
      IF NEW.archived IS DISTINCT FROM OLD.archived THEN
        UPDATE public.buyer_universe_memberships
        SET status = CASE WHEN COALESCE(NEW.archived, false) THEN 'archived' ELSE 'active' END,
            updated_at = now()
        WHERE buyer_id = NEW.id AND deleted_at IS NULL;
      END IF;
    EXCEPTION WHEN OTHERS THEN
      RAISE NOTICE 'sync_buyer_universe_membership UPDATE non-fatal: %', SQLERRM;
    END;
    RETURN NEW;
  END IF;

  -- DELETE: junction FK has ON DELETE CASCADE, handled automatically
  RETURN COALESCE(NEW, OLD);
END;
$$;


ALTER FUNCTION "public"."sync_buyer_universe_membership"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."sync_connection_request_firm_after"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_lead_email TEXT;
  v_lead_name TEXT;
  v_lead_company TEXT;
BEGIN
  IF NEW.firm_id IS NOT NULL AND NEW.user_id IS NULL AND COALESCE(NEW.lead_email) IS NOT NULL THEN
    v_lead_email := NEW.lead_email;
    v_lead_name := NEW.lead_name;
    v_lead_company := NEW.lead_company;

    -- If source_lead_id, get from inbound_leads
    IF NEW.source_lead_id IS NOT NULL THEN
      SELECT COALESCE(email, v_lead_email), COALESCE(name, v_lead_name), COALESCE(company_name, v_lead_company)
      INTO v_lead_email, v_lead_name, v_lead_company
      FROM inbound_leads WHERE id = NEW.source_lead_id;
    END IF;

    INSERT INTO firm_members (firm_id, member_type, lead_email, lead_name, lead_company, connection_request_id, inbound_lead_id, added_at)
    VALUES (NEW.firm_id, 'lead', v_lead_email, v_lead_name, v_lead_company, NEW.id, NEW.source_lead_id, NOW())
    ON CONFLICT (firm_id, lead_email) WHERE member_type = 'lead'
    DO UPDATE SET
      connection_request_id = COALESCE(EXCLUDED.connection_request_id, firm_members.connection_request_id),
      inbound_lead_id = COALESCE(EXCLUDED.inbound_lead_id, firm_members.inbound_lead_id),
      lead_name = COALESCE(EXCLUDED.lead_name, firm_members.lead_name),
      lead_company = COALESCE(EXCLUDED.lead_company, firm_members.lead_company),
      updated_at = NOW();

    UPDATE firm_agreements
    SET member_count = (SELECT COUNT(*) FROM firm_members WHERE firm_id = NEW.firm_id), updated_at = NOW()
    WHERE id = NEW.firm_id;
  END IF;

  RETURN NULL;
END;
$$;


ALTER FUNCTION "public"."sync_connection_request_firm_after"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."sync_connection_request_firm_before"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_firm_id UUID;
  v_firm_record RECORD;
  v_email_domain TEXT;
  v_normalized_company TEXT;
  v_generic_domains TEXT[] := ARRAY[
    'gmail.com','googlemail.com','yahoo.com','yahoo.com.au','hotmail.com','hotmail.se',
    'outlook.com','aol.com','icloud.com','me.com','mac.com','live.com','msn.com',
    'mail.com','zoho.com','yandex.com','gmx.com','gmx.net','inbox.com',
    'rocketmail.com','ymail.com','protonmail.com','proton.me','pm.me',
    'fastmail.com','tutanota.com','hey.com','comcast.net','att.net',
    'sbcglobal.net','verizon.net','cox.net','charter.net','earthlink.net',
    'optonline.net','frontier.com','windstream.net','mediacombb.net','bellsouth.net',
    'webxio.pro','leabro.com','coursora.com'
  ];
BEGIN
  -- If firm_id already set, skip resolution
  IF NEW.firm_id IS NOT NULL THEN
    v_firm_id := NEW.firm_id;
  ELSIF NEW.user_id IS NOT NULL THEN
    v_firm_id := resolve_user_firm_id(NEW.user_id);
    NEW.firm_id := v_firm_id;
  ELSIF NEW.source_lead_id IS NOT NULL THEN
    SELECT firm_id INTO v_firm_id FROM inbound_leads WHERE id = NEW.source_lead_id;
    NEW.firm_id := v_firm_id;
  ELSIF NEW.lead_company IS NOT NULL OR NEW.lead_email IS NOT NULL THEN
    -- Extract domain
    IF NEW.lead_email IS NOT NULL THEN
      v_email_domain := extract_domain(NEW.lead_email);
    END IF;
    IF NEW.lead_company IS NOT NULL THEN
      v_normalized_company := normalize_company_name(NEW.lead_company);
    END IF;

    -- PRIORITY 1: Domain match (non-generic only)
    IF v_email_domain IS NOT NULL AND v_email_domain <> '' AND v_email_domain <> ALL(v_generic_domains) THEN
      SELECT id INTO v_firm_id FROM firm_agreements
      WHERE email_domain = v_email_domain
      LIMIT 1;
    END IF;

    -- PRIORITY 2: Normalized company name match (only if domain didn't match)
    IF v_firm_id IS NULL AND v_normalized_company IS NOT NULL AND v_normalized_company <> '' THEN
      SELECT id INTO v_firm_id FROM firm_agreements
      WHERE normalized_company_name = v_normalized_company
      LIMIT 1;
    END IF;

    -- PRIORITY 3: Create new firm if no match found
    IF v_firm_id IS NULL AND (v_normalized_company IS NOT NULL OR v_email_domain IS NOT NULL) THEN
      INSERT INTO firm_agreements (
        primary_company_name, normalized_company_name, email_domain,
        member_count, created_at, updated_at
      ) VALUES (
        COALESCE(NEW.lead_company, v_email_domain),
        COALESCE(v_normalized_company, v_email_domain),
        CASE WHEN v_email_domain IS NOT NULL AND v_email_domain <> ALL(v_generic_domains) THEN v_email_domain ELSE NULL END,
        0, NOW(), NOW()
      )
      RETURNING id INTO v_firm_id;
    END IF;

    NEW.firm_id := v_firm_id;
  END IF;

  -- Inherit agreement status from firm
  IF NEW.firm_id IS NOT NULL THEN
    SELECT * INTO v_firm_record FROM firm_agreements WHERE id = NEW.firm_id;
    IF v_firm_record.fee_agreement_signed AND NOT COALESCE(NEW.lead_fee_agreement_signed, FALSE) THEN
      NEW.lead_fee_agreement_signed := TRUE;
      NEW.lead_fee_agreement_signed_at := v_firm_record.fee_agreement_signed_at;
    END IF;
    IF v_firm_record.nda_signed AND NOT COALESCE(NEW.lead_nda_signed, FALSE) THEN
      NEW.lead_nda_signed := TRUE;
      NEW.lead_nda_signed_at := v_firm_record.nda_signed_at;
    END IF;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."sync_connection_request_firm_before"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."sync_fee_agreement_to_remarketing"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Only act when fee_agreement_signed actually changes
  IF OLD.fee_agreement_signed IS DISTINCT FROM NEW.fee_agreement_signed THEN
    IF NEW.fee_agreement_signed = true THEN
      -- Firm signed: mark all linked remarketing buyers as having fee agreement
      UPDATE public.remarketing_buyers
      SET
        has_fee_agreement = true,
        fee_agreement_source = 'marketplace_synced'
      WHERE marketplace_firm_id = NEW.id
        AND (has_fee_agreement IS NULL OR has_fee_agreement = false);

      -- Also propagate to platforms whose PE firm matches this firm's domain
      UPDATE public.remarketing_buyers
      SET
        has_fee_agreement = true,
        fee_agreement_source = 'pe_firm_inherited'
      WHERE pe_firm_website IS NOT NULL
        AND NEW.website_domain IS NOT NULL
        AND extract_domain(pe_firm_website) = NEW.website_domain
        AND (has_fee_agreement IS NULL OR has_fee_agreement = false);

    ELSE
      -- Firm unsigned: only remove marketplace_synced and pe_firm_inherited flags
      -- NEVER remove manual_override — those were set by an admin deliberately
      UPDATE public.remarketing_buyers
      SET
        has_fee_agreement = false,
        fee_agreement_source = NULL
      WHERE marketplace_firm_id = NEW.id
        AND fee_agreement_source IN ('marketplace_synced', 'pe_firm_inherited');

      -- Also remove inheritance from platforms
      UPDATE public.remarketing_buyers
      SET
        has_fee_agreement = false,
        fee_agreement_source = NULL
      WHERE pe_firm_website IS NOT NULL
        AND NEW.website_domain IS NOT NULL
        AND extract_domain(pe_firm_website) = NEW.website_domain
        AND fee_agreement_source = 'pe_firm_inherited';
    END IF;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."sync_fee_agreement_to_remarketing"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."sync_firm_agreement_to_downstream"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_deal_nda_status text;
  v_deal_fee_status text;
BEGIN
  IF (
    OLD.nda_signed IS DISTINCT FROM NEW.nda_signed OR
    OLD.nda_status IS DISTINCT FROM NEW.nda_status OR
    OLD.nda_signed_at IS DISTINCT FROM NEW.nda_signed_at OR
    OLD.fee_agreement_signed IS DISTINCT FROM NEW.fee_agreement_signed OR
    OLD.fee_agreement_status IS DISTINCT FROM NEW.fee_agreement_status OR
    OLD.fee_agreement_signed_at IS DISTINCT FROM NEW.fee_agreement_signed_at
  ) THEN
    -- Sync NDA fields to connection_requests
    UPDATE public.connection_requests
    SET
      lead_nda_signed = COALESCE(NEW.nda_signed, false),
      lead_nda_signed_at = NEW.nda_signed_at,
      lead_nda_signed_by = NEW.nda_signed_by,
      updated_at = now()
    WHERE firm_id = NEW.id
      AND (
        COALESCE(lead_nda_signed, false) IS DISTINCT FROM COALESCE(NEW.nda_signed, false)
        OR lead_nda_signed_at IS DISTINCT FROM NEW.nda_signed_at
      );

    -- Sync Fee Agreement fields to connection_requests
    UPDATE public.connection_requests
    SET
      lead_fee_agreement_signed = COALESCE(NEW.fee_agreement_signed, false),
      lead_fee_agreement_signed_at = NEW.fee_agreement_signed_at,
      lead_fee_agreement_signed_by = NEW.fee_agreement_signed_by,
      updated_at = now()
    WHERE firm_id = NEW.id
      AND (
        COALESCE(lead_fee_agreement_signed, false) IS DISTINCT FROM COALESCE(NEW.fee_agreement_signed, false)
        OR lead_fee_agreement_signed_at IS DISTINCT FROM NEW.fee_agreement_signed_at
      );

    -- Map statuses for deal_pipeline constraint compatibility
    v_deal_nda_status := public.map_agreement_status_to_deal(NEW.nda_status);
    v_deal_fee_status := public.map_agreement_status_to_deal(NEW.fee_agreement_status);

    -- Sync to deal_pipeline via connection_request_id
    UPDATE public.deal_pipeline dp
    SET
      nda_status = v_deal_nda_status,
      fee_agreement_status = v_deal_fee_status,
      updated_at = now()
    FROM public.connection_requests cr
    WHERE cr.firm_id = NEW.id
      AND dp.connection_request_id = cr.id
      AND (
        dp.nda_status IS DISTINCT FROM v_deal_nda_status
        OR dp.fee_agreement_status IS DISTINCT FROM v_deal_fee_status
      );
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."sync_firm_agreement_to_downstream"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."sync_followup_to_connection_requests"() RETURNS "trigger"
