BEGIN
  NEW.phone := COALESCE(
    NULLIF(NEW.mobile_phone_1, ''),
    NULLIF(NEW.mobile_phone_2, ''),
    NULLIF(NEW.mobile_phone_3, ''),
    NULLIF(NEW.office_phone,   ''),
