CREATE OR REPLACE FUNCTION "public"."sync_phoneburner_activity_to_buyer_transcript"("p_activity_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  act              public.contact_activities;
  resolved_buyer   UUID;
  new_transcript   UUID;
BEGIN
  SELECT * INTO act FROM public.contact_activities WHERE id = p_activity_id;
  IF NOT FOUND THEN RETURN NULL; END IF;

  IF act.activity_type <> 'call_completed' THEN RETURN NULL; END IF;
  IF act.call_transcript IS NULL OR LENGTH(act.call_transcript) < 200 THEN RETURN NULL; END IF;

  resolved_buyer := act.remarketing_buyer_id;
  IF resolved_buyer IS NULL AND act.contact_id IS NOT NULL THEN
    SELECT c.remarketing_buyer_id INTO resolved_buyer
    FROM public.contacts c WHERE c.id = act.contact_id;
  END IF;
  IF resolved_buyer IS NULL THEN RETURN NULL; END IF;

  IF EXISTS (SELECT 1 FROM public.buyer_transcripts
             WHERE source_activity_id = act.id) THEN
    RETURN NULL;
  END IF;

  INSERT INTO public.buyer_transcripts (
    buyer_id, transcript_text, title, call_date,
    duration_minutes, source, source_activity_id,
    extraction_status, linked_at, notes, phone_number
  ) VALUES (
    resolved_buyer,
    act.call_transcript,
    COALESCE(
      'PhoneBurner: ' || COALESCE(act.disposition_label,'') ||
      CASE WHEN act.contact_email IS NOT NULL
           THEN ' — ' || act.contact_email ELSE '' END,
      'PhoneBurner call'
    ),
    act.call_started_at,
    CASE WHEN act.call_duration_seconds IS NOT NULL
         THEN ROUND(act.call_duration_seconds / 60.0)::INT ELSE NULL END,
    'phoneburner',
    act.id,
    'pending',
    now(),
    NULLIF(act.disposition_notes, ''),
    act.phone_number
  )
  ON CONFLICT (source_activity_id) WHERE source_activity_id IS NOT NULL DO NOTHING
  RETURNING id INTO new_transcript;

  RETURN new_transcript;
END;
$$;


ALTER FUNCTION "public"."sync_phoneburner_activity_to_buyer_transcript"("p_activity_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."sync_phoneburner_activity_to_deal_transcript"("p_activity_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  act              public.contact_activities;
  resolved_listing UUID;
  resolved_contact UUID;
  new_transcript   UUID;
BEGIN
  SELECT * INTO act FROM public.contact_activities WHERE id = p_activity_id;
  IF NOT FOUND THEN RETURN NULL; END IF;

  IF act.activity_type <> 'call_completed' THEN RETURN NULL; END IF;
  IF act.call_transcript IS NULL OR LENGTH(act.call_transcript) < 200 THEN
    RETURN NULL;
  END IF;

  resolved_listing := act.listing_id;
  IF resolved_listing IS NULL THEN RETURN NULL; END IF;
  IF NOT EXISTS (SELECT 1 FROM public.listings WHERE id = resolved_listing) THEN
    RETURN NULL;
  END IF;

  resolved_contact := act.contact_id;

  IF EXISTS (
    SELECT 1 FROM public.deal_transcripts
    WHERE contact_activity_id = act.id
  ) THEN
    RETURN NULL;
  END IF;

  INSERT INTO public.deal_transcripts (
    listing_id,
    contact_id,
    contact_activity_id,
    phoneburner_call_id,
    transcript_text,
    source,
    extraction_status,
    duration_minutes,
    processed_at,
    phone_number
  ) VALUES (
    resolved_listing,
    resolved_contact,
    act.id,
    act.phoneburner_contact_id,
    act.call_transcript,
    'phoneburner',
    'pending',
    CASE WHEN act.call_duration_seconds IS NOT NULL
         THEN ROUND(act.call_duration_seconds / 60.0)::INT ELSE NULL END,
    act.call_started_at,
    act.phone_number
  )
  ON CONFLICT (contact_activity_id) WHERE contact_activity_id IS NOT NULL DO NOTHING
  RETURNING id INTO new_transcript;

  RETURN new_transcript;
END;
$$;


ALTER FUNCTION "public"."sync_phoneburner_activity_to_deal_transcript"("p_activity_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."sync_phoneburner_activity_to_deal_transcript"("p_activity_id" "uuid") IS 'Lift a contact_activities row into deal_transcripts when it represents a seller call (listing_id resolved). Idempotent via unique index on contact_activity_id. Returns the new deal_transcripts.id or NULL.';



CREATE OR REPLACE FUNCTION "public"."sync_pipeline_close_to_introduction"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  new_stage_type TEXT;
BEGIN
  -- Only act when stage_id changes
  IF NEW.stage_id IS DISTINCT FROM OLD.stage_id AND NEW.buyer_introduction_id IS NOT NULL THEN
    SELECT stage_type INTO new_stage_type
    FROM deal_stages WHERE id = NEW.stage_id;
    
    -- If deal moved to closed stage, update introduction status
    IF new_stage_type IN ('closed_won', 'closed_lost') THEN
      UPDATE buyer_introductions
      SET introduction_status = 'deal_created',
          updated_at = now()
      WHERE id = NEW.buyer_introduction_id
        AND introduction_status = 'fit_and_interested';
    END IF;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."sync_pipeline_close_to_introduction"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."sync_primary_at_firm"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Only act when the row was just flipped to primary AND has a firm scope
  -- to be primary at. "Firm scope" is either marketplace firm_id (for
  -- federated rows) or remarketing_buyer_id (buyer-scoped rows that haven't
  -- been attached to a firm_agreement yet).
  IF NEW.is_primary_at_firm = true
     AND (NEW.firm_id IS NOT NULL OR NEW.remarketing_buyer_id IS NOT NULL)
     AND NEW.contact_type IN ('buyer', 'advisor', 'portal_user')
  THEN
    UPDATE public.contacts
    SET is_primary_at_firm = false,
        updated_at = now()
    WHERE id <> NEW.id
      AND contact_type = NEW.contact_type
      AND is_primary_at_firm = true
      AND deleted_at IS NULL
      AND merged_into_id IS NULL
      AND (
        -- Same firm (federated) OR same buyer org (unfederated)
        (NEW.firm_id IS NOT NULL AND firm_id = NEW.firm_id)
        OR (NEW.firm_id IS NULL
            AND NEW.remarketing_buyer_id IS NOT NULL
            AND remarketing_buyer_id = NEW.remarketing_buyer_id)
      );
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."sync_primary_at_firm"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."sync_primary_at_firm"() IS 'Enforces at most one is_primary_at_firm=true per (firm_id, contact_type) for buyer/advisor/portal_user rows. Mirrors sync_primary_seller_contact which does the same thing for contact_type=''seller''. Fires AFTER the write and flips other live primaries to false.';



CREATE OR REPLACE FUNCTION "public"."sync_primary_seller_contact"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NEW.is_primary_seller_contact = true AND NEW.listing_id IS NOT NULL THEN
    UPDATE public.contacts
    SET is_primary_seller_contact = false, updated_at = now()
    WHERE listing_id = NEW.listing_id
      AND id != NEW.id
      AND is_primary_seller_contact = true
      AND contact_type = 'seller';

    UPDATE public.listings
    SET
      main_contact_name = TRIM(NEW.first_name || ' ' || NEW.last_name),
      main_contact_email = NEW.email,
      main_contact_phone = NEW.phone,
      main_contact_title = NEW.title,
      updated_at = now()
    WHERE id = NEW.listing_id;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."sync_primary_seller_contact"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."sync_profile_documents_to_connection_request"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_profile RECORD;
BEGIN
  -- Only sync for marketplace requests (those with user_id)
  IF NEW.user_id IS NOT NULL THEN
    -- Get user's profile document statuses
    SELECT 
      nda_signed,
      nda_email_sent,
      nda_signed_at,
      nda_email_sent_at,
      fee_agreement_signed,
      fee_agreement_email_sent,
      fee_agreement_signed_at,
      fee_agreement_email_sent_at
    INTO v_profile
    FROM public.profiles
    WHERE id = NEW.user_id;
    
    -- If profile found, sync document statuses
    IF FOUND THEN
      NEW.lead_nda_signed := COALESCE(v_profile.nda_signed, false);
      NEW.lead_nda_email_sent := COALESCE(v_profile.nda_email_sent, false);
      NEW.lead_nda_signed_at := v_profile.nda_signed_at;
      NEW.lead_nda_email_sent_at := v_profile.nda_email_sent_at;
      NEW.lead_fee_agreement_signed := COALESCE(v_profile.fee_agreement_signed, false);
      NEW.lead_fee_agreement_email_sent := COALESCE(v_profile.fee_agreement_email_sent, false);
      NEW.lead_fee_agreement_signed_at := v_profile.fee_agreement_signed_at;
      NEW.lead_fee_agreement_email_sent_at := v_profile.fee_agreement_email_sent_at;
    END IF;
  END IF;
  
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."sync_profile_documents_to_connection_request"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."sync_source_deal_financials"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  -- Only sync when financial fields change on internal deals
  IF NEW.is_internal_deal = true AND (
    NEW.revenue IS DISTINCT FROM OLD.revenue OR
    NEW.ebitda IS DISTINCT FROM OLD.ebitda OR
    NEW.ebitda_margin IS DISTINCT FROM OLD.ebitda_margin
  ) THEN
    UPDATE public.listings
    SET
      revenue = COALESCE(NEW.revenue, revenue),
      ebitda = COALESCE(NEW.ebitda, ebitda),
      ebitda_margin = COALESCE(NEW.ebitda_margin, ebitda_margin),
      updated_at = NOW()
    WHERE source_deal_id = NEW.id
    AND is_internal_deal = false;
  END IF;

  RETURN NEW;
END;
$$;


