CREATE OR REPLACE FUNCTION "public"."tg_buyer_introductions_mark_stale"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_buyer_id uuid;
BEGIN
  IF NEW.contact_id IS NOT NULL THEN
    PERFORM public.mark_contact_summary_stale(NEW.contact_id);
    SELECT remarketing_buyer_id INTO v_buyer_id
      FROM public.contacts WHERE id = NEW.contact_id;
    IF v_buyer_id IS NOT NULL THEN
      PERFORM public.mark_buyer_summary_stale(v_buyer_id);
    END IF;
  END IF;
  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'tg_buyer_introductions_mark_stale failed on %: % / %',
    NEW.id, SQLSTATE, SQLERRM;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."tg_buyer_introductions_mark_stale"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."tg_buyer_transcripts_mark_stale"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NEW.buyer_id IS NOT NULL THEN
    PERFORM public.mark_buyer_summary_stale(NEW.buyer_id);
    UPDATE public.contacts
       SET last_interaction_summary_stale = true
     WHERE remarketing_buyer_id = NEW.buyer_id
       AND archived = false
       AND last_interaction_summary_stale = false;
  END IF;
  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'tg_buyer_transcripts_mark_stale failed on %: % / %',
    NEW.id, SQLSTATE, SQLERRM;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."tg_buyer_transcripts_mark_stale"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."tg_connection_requests_mirror_identity"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_buyer_id uuid;
BEGIN
  v_buyer_id := public.upsert_buyer_from_connection_request(
    NEW.user_id,
    NEW.lead_email,
    coalesce(NEW.lead_company, NEW.lead_company_name),
    NEW.lead_website
  );

  PERFORM public.upsert_contact_from_connection_request(
    NEW.user_id,
    NEW.lead_email,
    NEW.lead_name,
    NEW.lead_first_name,
    NEW.lead_last_name,
    coalesce(NEW.lead_phone, NEW.lead_mobile),
    NEW.lead_title,
    NEW.lead_linkedin_url,
    v_buyer_id
  );

  RETURN NEW;
EXCEPTION
  -- Never let identity mirroring fail the inquiry write. The inquiry is
  -- the source of truth; the mirror rows are a convenience index.
  WHEN OTHERS THEN
    RAISE WARNING 'connection_requests identity mirror failed for cr %: % / %',
      NEW.id, SQLSTATE, SQLERRM;
    RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."tg_connection_requests_mirror_identity"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."tg_connection_requests_mirror_identity"() IS 'Trigger wrapper that calls upsert_buyer_from_connection_request + upsert_contact_from_connection_request on every connection_requests insert/update. Swallows errors so mirror failure never blocks the inquiry write itself.';



CREATE OR REPLACE FUNCTION "public"."tg_contact_activities_mark_stale"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_buyer_id uuid;
BEGIN
  IF NEW.contact_id IS NOT NULL THEN
    PERFORM public.mark_contact_summary_stale(NEW.contact_id);
    SELECT remarketing_buyer_id INTO v_buyer_id
      FROM public.contacts WHERE id = NEW.contact_id;
  END IF;

  -- Prefer the denormalised FK on the activity row if it's set.
  IF NEW.remarketing_buyer_id IS NOT NULL THEN
    v_buyer_id := NEW.remarketing_buyer_id;
  END IF;

  IF v_buyer_id IS NOT NULL THEN
    PERFORM public.mark_buyer_summary_stale(v_buyer_id);
  END IF;

  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'tg_contact_activities_mark_stale failed on %: % / %',
    NEW.id, SQLSTATE, SQLERRM;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."tg_contact_activities_mark_stale"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."tg_contact_list_members_mirror_contact"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_contact_id uuid;
BEGIN
  BEGIN
    -- If the BEFORE-resolver already linked a contact, and we're on an
    -- INSERT, nothing to do.
    IF TG_OP = 'INSERT' AND NEW.contact_id IS NOT NULL THEN
      RETURN NEW;
    END IF;

    v_contact_id := public.upsert_contact_from_list_member(
      NEW.contact_email,
      NEW.contact_name,
      NEW.contact_phone,
      NEW.contact_company,
      NEW.contact_role,
      NEW.entity_type,
      NEW.entity_id
    );

    -- Write back — only if we resolved and the column isn't already set
    -- to that id (prevents infinite trigger recursion).
    IF v_contact_id IS NOT NULL
       AND (NEW.contact_id IS NULL OR NEW.contact_id <> v_contact_id) THEN
      UPDATE public.contact_list_members
         SET contact_id = v_contact_id
       WHERE id = NEW.id
         AND (contact_id IS NULL OR contact_id <> v_contact_id);
    END IF;

    RETURN NEW;
  EXCEPTION
    -- Never let contact mirroring fail the list_member write.
    WHEN OTHERS THEN
      RAISE WARNING 'contact_list_members contact mirror failed for clm %: % / %',
        NEW.id, SQLSTATE, SQLERRM;
      RETURN NEW;
  END;
END;
$$;


ALTER FUNCTION "public"."tg_contact_list_members_mirror_contact"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."tg_contact_list_members_mirror_contact"() IS 'AFTER-INSERT/UPDATE trigger wrapper. Calls upsert_contact_from_list_member and writes the resulting contact_id back onto the list-member row. Swallows all errors — list-member inserts must never fail because of the contact mirror.';



