CREATE OR REPLACE FUNCTION "public"."track_portal_login"("p_slug" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid;
  v_org_id uuid;
BEGIN
  v_user_id := auth.uid();
  IF v_user_id IS NULL THEN RETURN; END IF;

  SELECT po.id INTO v_org_id
  FROM portal_organizations po
  WHERE po.portal_slug = p_slug AND po.deleted_at IS NULL
  LIMIT 1;

  IF v_org_id IS NULL THEN RETURN; END IF;

  UPDATE portal_users
  SET
    last_login_at = now(),
    invite_accepted_at = COALESCE(invite_accepted_at, now()),
    updated_at = now()
  WHERE portal_org_id = v_org_id
    AND profile_id = v_user_id
    AND is_active = true;
END;
$$;


ALTER FUNCTION "public"."track_portal_login"("p_slug" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."trg_contact_activities_call_rollup"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_new_contact UUID := COALESCE(NEW.contact_id, NULL);
  v_old_contact UUID := CASE WHEN TG_OP = 'UPDATE' THEN OLD.contact_id ELSE NULL END;
BEGIN
  -- Fire for the new contact (if any)
  IF v_new_contact IS NOT NULL THEN
    BEGIN
      PERFORM public.refresh_contact_call_rollup(v_new_contact);
    EXCEPTION WHEN OTHERS THEN
      RAISE WARNING 'refresh_contact_call_rollup failed for % — %', v_new_contact, SQLERRM;
    END;
  END IF;

  -- If UPDATE rewrote contact_id, refresh the old contact too so its rollup
  -- reflects the loss of this activity row.
  IF v_old_contact IS NOT NULL AND v_old_contact IS DISTINCT FROM v_new_contact THEN
    BEGIN
      PERFORM public.refresh_contact_call_rollup(v_old_contact);
    EXCEPTION WHEN OTHERS THEN
      RAISE WARNING 'refresh_contact_call_rollup failed for % — %', v_old_contact, SQLERRM;
    END;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."trg_contact_activities_call_rollup"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."trg_contact_activities_rollup"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  BEGIN
    IF TG_OP = 'DELETE' THEN
      PERFORM public.refresh_contact_call_rollup(OLD.contact_id);
      RETURN OLD;
    END IF;

    -- INSERT / UPDATE
    PERFORM public.refresh_contact_call_rollup(NEW.contact_id);

    -- If contact_id changed during UPDATE, refresh the old contact too
    IF TG_OP = 'UPDATE' AND NEW.contact_id IS DISTINCT FROM OLD.contact_id THEN
      PERFORM public.refresh_contact_call_rollup(OLD.contact_id);
    END IF;

    RETURN NEW;
  EXCEPTION WHEN OTHERS THEN
    RAISE NOTICE 'trg_contact_activities_rollup non-fatal: %', SQLERRM;
    RETURN COALESCE(NEW, OLD);
  END;
END;
$$;


ALTER FUNCTION "public"."trg_contact_activities_rollup"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."trg_contact_dnc_propagate"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  -- Fire when do_not_call transitions false/NULL -> true.
  IF NEW.do_not_call = TRUE
     AND (OLD.do_not_call IS DISTINCT FROM TRUE) THEN
    BEGIN
      PERFORM public.propagate_dnc_local(NEW.id);
    EXCEPTION WHEN OTHERS THEN
      RAISE WARNING 'propagate_dnc_local failed for % — %', NEW.id, SQLERRM;
    END;

    BEGIN
      INSERT INTO dnc_propagation_queue (contact_id, contact_email, linkedin_url)
      VALUES (NEW.id, NEW.email, NEW.linkedin_url);
    EXCEPTION WHEN OTHERS THEN
      RAISE WARNING 'dnc_propagation_queue insert failed for % — %', NEW.id, SQLERRM;
    END;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."trg_contact_dnc_propagate"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."trg_contacts_rematch_activities"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  UPDATE contact_activities
  SET contact_id = NEW.id
  WHERE contact_id IS NULL
    AND contact_email IS NOT NULL
    AND lower(contact_email) = lower(NEW.email);

  UPDATE outlook_unmatched_emails
  SET matched_at = now()
  WHERE matched_at IS NULL
    AND lower(NEW.email) = ANY(SELECT lower(unnest(participant_emails)));

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."trg_contacts_rematch_activities"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."trg_email_messages_log_activity"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_activity_type text;
  v_title text;
  v_to_display text;
  v_direction text;
BEGIN
  -- Cast the email_direction enum to text so we can compare without
  -- hard-coding a schema-qualified type reference.
  v_direction := NEW.direction::text;

  IF v_direction = 'outbound' THEN
    v_activity_type := 'email_sent';
    v_to_display := NULLIF(array_to_string(NEW.to_addresses, ', '), '');
    v_title := format('Email sent to %s', COALESCE(left(v_to_display, 200), '(no recipients)'));
  ELSE
    v_activity_type := 'email_received';
    v_title := format('Email from %s', COALESCE(NEW.from_address, '(unknown sender)'));
  END IF;

  INSERT INTO public.deal_activities (
    deal_id,
    admin_id,
    activity_type,
    title,
    description,
    metadata
  ) VALUES (
    NEW.deal_id,
    NULL,
    v_activity_type,
    v_title,
    COALESCE(NEW.subject, '(No subject)'),
    jsonb_build_object(
      'email_message_id', NEW.microsoft_message_id,
      'direction', v_direction,
      'from_address', NEW.from_address,
      'to_addresses', NEW.to_addresses,
      'subject', NEW.subject,
      'has_attachments', NEW.has_attachments,
      'contact_id', NEW.contact_id,
      'body_preview', left(COALESCE(NEW.body_text, NEW.body_html, ''), 300)
    )
  );

  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  -- Activity logging failures must not roll back the email insert itself
  -- (matches the pre-trigger edge-function behavior where the RPC was
  -- wrapped in a try/catch that only logged to console).
  RAISE NOTICE 'trg_email_messages_log_activity failed for email %: %',
    NEW.microsoft_message_id, SQLERRM;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."trg_email_messages_log_activity"() OWNER TO "postgres";


