CREATE OR REPLACE FUNCTION "public"."trg_feedback_to_signal"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  w NUMERIC;
  half_life INTEGER := 180;
BEGIN
  -- Map feedback action to event weight. Magnitudes deliberately small on
  -- first pass; calibration refines them.
  w := CASE NEW.action
         WHEN 'accepted' THEN 0.10
         WHEN 'rejected' THEN -0.08
         ELSE 0
       END;

  IF w = 0 THEN
    RETURN NEW;
  END IF;

  BEGIN
    INSERT INTO public.buyer_signal_events
      (buyer_id, listing_id, event_type, event_weight, decay_half_life_days,
       observed_at, metadata, source_table, source_row_id)
    VALUES
      (NEW.buyer_id, NEW.listing_id, NEW.action, w, half_life,
       COALESCE(NEW.created_at, now()),
       jsonb_build_object('reason_category', NEW.reason_category,
                          'niche_category',  NEW.niche_category),
       'buyer_discovery_feedback', NEW.id)
    ON CONFLICT (source_table, source_row_id, event_type) DO NOTHING;
  EXCEPTION WHEN OTHERS THEN
    -- Never break the source-table write. Log via RAISE NOTICE.
    RAISE NOTICE 'trg_feedback_to_signal failed for row %: %', NEW.id, SQLERRM;
  END;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."trg_feedback_to_signal"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."trg_intro_to_signal"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
DECLARE
  event_type_name TEXT;
  w NUMERIC;
  half_life INTEGER;
  buyer_id_resolved UUID;
BEGIN
  -- Only fire when status actually changes, or on INSERT
  IF TG_OP = 'UPDATE' AND NEW.introduction_status IS NOT DISTINCT FROM OLD.introduction_status THEN
    RETURN NEW;
  END IF;

  -- Map intro status to event
  SELECT
    CASE NEW.introduction_status
      WHEN 'introduced' THEN 'introduced'
      WHEN 'interested' THEN 'interested'
      ELSE NULL
    END
  INTO event_type_name;

  IF event_type_name IS NULL THEN
    RETURN NEW;
  END IF;

  w := CASE event_type_name
         WHEN 'introduced' THEN 0.05
         WHEN 'interested' THEN 0.20
         ELSE 0
       END;
  half_life := CASE event_type_name
                 WHEN 'interested' THEN 365   -- stays relevant longer
                 ELSE 180
               END;

  -- buyer_introductions may not carry a direct buyer_id; try contact_id → buyer link
  -- For now, use NULL if not available — the scorer can skip events without buyer_id.
  buyer_id_resolved := NULL;
  BEGIN
    -- best-effort: look up via contacts.remarketing_buyer_id if the join is
    -- available. (Column is named remarketing_buyer_id on prod, not buyer_id.)
    IF NEW.contact_id IS NOT NULL THEN
      EXECUTE 'SELECT remarketing_buyer_id FROM public.contacts WHERE id = $1 AND remarketing_buyer_id IS NOT NULL LIMIT 1'
        INTO buyer_id_resolved USING NEW.contact_id;
    END IF;
  EXCEPTION WHEN OTHERS THEN
    buyer_id_resolved := NULL;
  END;

  IF buyer_id_resolved IS NULL THEN
    -- Can't attribute — skip.
    RETURN NEW;
  END IF;

  BEGIN
    INSERT INTO public.buyer_signal_events
      (buyer_id, listing_id, event_type, event_weight, decay_half_life_days,
       observed_at, metadata, source_table, source_row_id)
    VALUES
      (buyer_id_resolved, NEW.listing_id, event_type_name, w, half_life,
       COALESCE(NEW.introduction_date, NEW.created_at, now()),
       jsonb_build_object('introduction_status', NEW.introduction_status,
                          'buyer_firm_name',     NEW.buyer_firm_name),
       'buyer_introductions', NEW.id)
    ON CONFLICT (source_table, source_row_id, event_type) DO NOTHING;
  EXCEPTION WHEN OTHERS THEN
    RAISE NOTICE 'trg_intro_to_signal failed for row %: %', NEW.id, SQLERRM;
  END;

  RETURN NEW;
END;
$_$;


ALTER FUNCTION "public"."trg_intro_to_signal"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."trg_link_transcripts_from_buyer"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  matched_deal_id UUID;
BEGIN
  -- Skip if we have nothing to match on or are already linked.
  IF NEW.fireflies_transcript_id IS NULL THEN RETURN NEW; END IF;
  IF NEW.deal_transcript_id IS NOT NULL THEN RETURN NEW; END IF;

  BEGIN
    SELECT id INTO matched_deal_id
      FROM public.deal_transcripts
     WHERE fireflies_transcript_id = NEW.fireflies_transcript_id
     LIMIT 1;

    IF matched_deal_id IS NULL THEN
      RETURN NEW;
    END IF;

    -- Point our side at the deal row.
    UPDATE public.buyer_transcripts
       SET deal_transcript_id = matched_deal_id
     WHERE id = NEW.id
       AND deal_transcript_id IS NULL;

    -- Point the deal row back at us, but only if it has no pointer yet
    -- (multi-buyer meetings: keep the first-linked buyer as the
    -- deal-side convenience pointer).
    UPDATE public.deal_transcripts
       SET buyer_transcript_id = NEW.id
     WHERE id = matched_deal_id
       AND buyer_transcript_id IS NULL;

  EXCEPTION WHEN OTHERS THEN
    RAISE NOTICE 'trg_link_transcripts_from_buyer non-fatal: %', SQLERRM;
  END;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."trg_link_transcripts_from_buyer"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."trg_link_transcripts_from_buyer"() IS 'Cross-side linker: when a buyer_transcripts row gets a fireflies_transcript_id, look up the matching deal_transcripts row and set both FKs. Idempotent; only fires when our FK is NULL.';



CREATE OR REPLACE FUNCTION "public"."trg_link_transcripts_from_deal"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  latest_buyer_id UUID;
BEGIN
  IF NEW.fireflies_transcript_id IS NULL THEN RETURN NEW; END IF;
  IF NEW.buyer_transcript_id IS NOT NULL THEN RETURN NEW; END IF;

  BEGIN
    -- Pick the most recent buyer_transcripts row for the deal-side
    -- scalar pointer. Tiebreak: linked_at DESC, created_at DESC, id DESC.
    SELECT id INTO latest_buyer_id
      FROM public.buyer_transcripts
     WHERE fireflies_transcript_id = NEW.fireflies_transcript_id
     ORDER BY linked_at DESC NULLS LAST,
              created_at DESC NULLS LAST,
              id DESC
     LIMIT 1;

    IF latest_buyer_id IS NULL THEN
      RETURN NEW;
    END IF;

    -- Point every buyer row for this meeting at the deal row.
    UPDATE public.buyer_transcripts
       SET deal_transcript_id = NEW.id
     WHERE fireflies_transcript_id = NEW.fireflies_transcript_id
       AND deal_transcript_id IS NULL;

    -- Point the deal row at the freshest buyer row.
    UPDATE public.deal_transcripts
       SET buyer_transcript_id = latest_buyer_id
     WHERE id = NEW.id
       AND buyer_transcript_id IS NULL;

  EXCEPTION WHEN OTHERS THEN
    RAISE NOTICE 'trg_link_transcripts_from_deal non-fatal: %', SQLERRM;
  END;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."trg_link_transcripts_from_deal"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."trg_link_transcripts_from_deal"() IS 'Cross-side linker: when a deal_transcripts row gets a fireflies_transcript_id, find all buyer_transcripts rows that share it and cross-link. Idempotent; only fires when our FK is NULL.';



CREATE OR REPLACE FUNCTION "public"."trg_outlook_unmatched_auto_create"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_email TEXT;
BEGIN
  IF NEW.participant_emails IS NULL OR array_length(NEW.participant_emails, 1) IS NULL THEN RETURN NEW; END IF;
  FOREACH v_email IN ARRAY NEW.participant_emails LOOP
    BEGIN
      PERFORM public.auto_create_contact_from_email(v_email, 'outlook_auto_detected');
    EXCEPTION WHEN OTHERS THEN
      PERFORM public.log_trigger_error(
        'trg_outlook_unmatched_auto_create', 'outlook_unmatched_emails',
        NEW.id::text, SQLSTATE, SQLERRM,
        jsonb_build_object('email', v_email));
    END;
  END LOOP;
  RETURN NEW;
END;
$$;


