CREATE OR REPLACE FUNCTION "public"."trg_outreach_to_signal"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  event_type_name TEXT;
  w NUMERIC;
  half_life INTEGER := 365;
BEGIN
  IF TG_OP = 'UPDATE' AND NEW.outcome IS NOT DISTINCT FROM OLD.outcome THEN
    RETURN NEW;
  END IF;

  event_type_name := CASE NEW.outcome
    WHEN 'won' THEN 'won'
    WHEN 'lost' THEN 'lost'
    ELSE NULL
  END;

  IF event_type_name IS NULL OR NEW.buyer_id IS NULL THEN
    RETURN NEW;
  END IF;

  w := CASE event_type_name WHEN 'won' THEN 0.35 WHEN 'lost' THEN -0.05 ELSE 0 END;

  BEGIN
    INSERT INTO public.buyer_signal_events
      (buyer_id, listing_id, event_type, event_weight, decay_half_life_days,
       observed_at, metadata, source_table, source_row_id)
    VALUES
      (NEW.buyer_id, NEW.listing_id, event_type_name, w, half_life,
       COALESCE(NEW.contacted_at, now()),
       jsonb_build_object('outcome', NEW.outcome, 'outcome_notes', NEW.outcome_notes),
       'outreach_records', NEW.id)
    ON CONFLICT (source_table, source_row_id, event_type) DO NOTHING;
  EXCEPTION WHEN OTHERS THEN
    RAISE NOTICE 'trg_outreach_to_signal failed for row %: %', NEW.id, SQLERRM;
  END;

  RETURN NEW;
END;
$$;


