CREATE OR REPLACE FUNCTION "public"."trigger_standup_meeting_sync"() RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_result JSONB;
  v_request_id BIGINT;
  v_supabase_url TEXT;
  v_service_key TEXT;
BEGIN
  v_supabase_url := current_setting('app.settings.supabase_url', true);
  v_service_key := current_setting('app.settings.service_role_key', true);

  IF v_supabase_url IS NULL OR v_service_key IS NULL THEN
    v_result := jsonb_build_object(
      'success', false,
      'error', 'Supabase URL or service key not configured.',
      'timestamp', NOW()
    );
    INSERT INTO public.cron_job_logs (job_name, result, created_at)
    VALUES ('sync_standup_meetings', v_result, NOW());
    RETURN v_result;
  END IF;

  SELECT net.http_post(
    url := v_supabase_url || '/functions/v1/sync-standup-meetings',
    headers := jsonb_build_object(
      'Authorization', 'Bearer ' || v_service_key,
      'Content-Type', 'application/json'
    ),
    body := jsonb_build_object('lookback_hours', 48)
  ) INTO v_request_id;

  v_result := jsonb_build_object(
    'success', true,
    'request_id', v_request_id,
    'timestamp', NOW()
  );

  INSERT INTO public.cron_job_logs (job_name, result, created_at)
  VALUES ('sync_standup_meetings', v_result, NOW());

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."trigger_standup_meeting_sync"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."try_acquire_queue_processor_lock"("p_queue_name" "text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  lock_id bigint;
BEGIN
  -- Generate a deterministic lock ID from the queue name using hashtext.
  -- hashtext returns a 32-bit int; we cast to bigint for pg_try_advisory_lock.
  lock_id := hashtext('queue_processor:' || p_queue_name)::bigint;

  -- Try to acquire a session-level advisory lock (non-blocking).
  -- Returns true if acquired, false if another session already holds it.
  RETURN pg_try_advisory_lock(lock_id);
END;
$$;


ALTER FUNCTION "public"."try_acquire_queue_processor_lock"("p_queue_name" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."update_agreement_status"("p_firm_agreement_id" "uuid", "p_field" "text", "p_new_status" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_old_status      text;
  v_old_fee_signed  boolean;
  v_new_fee_signed  boolean;
  v_website_domain  text;
  v_agreement_type  text;
BEGIN
  IF p_field NOT IN ('nda_status', 'fee_agreement_status') THEN
    RAISE EXCEPTION 'update_agreement_status: invalid field "%". Must be nda_status or fee_agreement_status.', p_field;
  END IF;

  v_agreement_type := CASE
    WHEN p_field = 'nda_status' THEN 'nda'
    WHEN p_field = 'fee_agreement_status' THEN 'fee_agreement'
  END;

  IF p_field = 'nda_status' THEN
    SELECT fa.nda_status
      INTO v_old_status
      FROM public.firm_agreements fa
     WHERE fa.id = p_firm_agreement_id;
  ELSE
    SELECT fa.fee_agreement_status, fa.fee_agreement_signed, fa.website_domain
      INTO v_old_status, v_old_fee_signed, v_website_domain
      FROM public.firm_agreements fa
     WHERE fa.id = p_firm_agreement_id;
  END IF;

  IF v_old_status IS NULL AND NOT FOUND THEN
    RAISE EXCEPTION 'update_agreement_status: firm_agreement not found: %', p_firm_agreement_id;
  END IF;

  -- UPDATE with boolean sync
  IF p_field = 'nda_status' THEN
    UPDATE public.firm_agreements
       SET nda_status = p_new_status,
           nda_signed = (p_new_status = 'signed'),
           nda_signed_at = CASE
             WHEN p_new_status = 'signed' AND nda_signed_at IS NULL THEN now()
             ELSE nda_signed_at
           END,
           updated_at = now()
     WHERE id = p_firm_agreement_id;
  ELSE
    UPDATE public.firm_agreements
       SET fee_agreement_status = p_new_status,
           fee_agreement_signed = (p_new_status = 'signed'),
           fee_agreement_signed_at = CASE
             WHEN p_new_status = 'signed' AND fee_agreement_signed_at IS NULL THEN now()
             ELSE fee_agreement_signed_at
           END,
           updated_at = now()
     WHERE id = p_firm_agreement_id;
  END IF;

  -- Audit log
  IF v_old_status IS DISTINCT FROM p_new_status THEN
    INSERT INTO public.agreement_audit_log (
      firm_id,
      agreement_type,
      old_status,
      new_status,
      changed_by,
      metadata
    ) VALUES (
      p_firm_agreement_id,
      v_agreement_type,
      v_old_status,
      p_new_status,
      auth.uid(),
      jsonb_build_object('via_rpc', true)
    );
  END IF;

  -- Sync fee_agreement_status to remarketing_buyers
  IF p_field = 'fee_agreement_status' THEN

    IF v_website_domain IS NULL THEN
      SELECT fa.website_domain
        INTO v_website_domain
        FROM public.firm_agreements fa
       WHERE fa.id = p_firm_agreement_id;
    END IF;

    v_new_fee_signed := (p_new_status = 'signed');
    v_old_fee_signed := COALESCE(v_old_fee_signed, false);

    IF p_new_status = 'signed' AND v_old_status IS DISTINCT FROM 'signed' THEN

      UPDATE public.remarketing_buyers
         SET has_fee_agreement   = true,
             fee_agreement_source = 'marketplace_synced'
       WHERE marketplace_firm_id = p_firm_agreement_id
         AND (has_fee_agreement IS NULL OR has_fee_agreement = false);

      IF v_website_domain IS NOT NULL THEN
        UPDATE public.remarketing_buyers
           SET has_fee_agreement   = true,
               fee_agreement_source = 'pe_firm_inherited'
         WHERE pe_firm_website IS NOT NULL
           AND extract_domain(pe_firm_website) = v_website_domain
           AND (has_fee_agreement IS NULL OR has_fee_agreement = false);
      END IF;

    ELSIF v_old_status = 'signed' AND p_new_status IS DISTINCT FROM 'signed' THEN

      UPDATE public.remarketing_buyers
         SET has_fee_agreement   = false,
             fee_agreement_source = NULL
       WHERE marketplace_firm_id = p_firm_agreement_id
         AND fee_agreement_source IN ('marketplace_synced', 'pe_firm_inherited');

      IF v_website_domain IS NOT NULL THEN
        UPDATE public.remarketing_buyers
           SET has_fee_agreement   = false,
               fee_agreement_source = NULL
         WHERE pe_firm_website IS NOT NULL
           AND extract_domain(pe_firm_website) = v_website_domain
           AND fee_agreement_source = 'pe_firm_inherited';
      END IF;

    END IF;

  END IF;

END;
$$;


ALTER FUNCTION "public"."update_agreement_status"("p_firm_agreement_id" "uuid", "p_field" "text", "p_new_status" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."update_agreement_status"("p_firm_agreement_id" "uuid", "p_field" "text", "p_new_status" "text") IS 'Phase 4 RPC: Replaces the agreement trigger chain on firm_agreements. Updates the status, writes to agreement_audit_log, and syncs fee_agreement changes to remarketing_buyers in one explicit call.';



CREATE OR REPLACE FUNCTION "public"."update_agreement_via_user"("p_user_id" "uuid", "p_agreement_type" "text", "p_action" "text", "p_admin_notes" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_firm_id uuid;
  v_firm_name text;
  v_user_email text;
  v_user_name text;
  v_user_company text;
  v_email_domain text;
  v_admin_id uuid;
BEGIN
  -- Verify caller is admin
  IF NOT public.is_admin() THEN
    RAISE EXCEPTION 'Unauthorized: admin access required';
  END IF;

  v_admin_id := auth.uid();

  -- Get user info
  SELECT email, 
         COALESCE(first_name || ' ' || last_name, first_name, last_name, email),
         company
  INTO v_user_email, v_user_name, v_user_company
  FROM profiles
  WHERE id = p_user_id;

  IF v_user_email IS NULL THEN
    RAISE EXCEPTION 'User not found: %', p_user_id;
  END IF;

  -- Extract email domain
  v_email_domain := split_part(v_user_email, '@', 2);

  -- 1. Try to find firm via firm_members
  SELECT fm.firm_id, fa.primary_company_name
  INTO v_firm_id, v_firm_name
  FROM firm_members fm
  JOIN firm_agreements fa ON fa.id = fm.firm_id
  WHERE fm.user_id = p_user_id
  LIMIT 1;

  -- 2. If not found, try email domain match
  IF v_firm_id IS NULL AND v_email_domain IS NOT NULL THEN
    SELECT fa.id, fa.primary_company_name
    INTO v_firm_id, v_firm_name
    FROM firm_agreements fa
    WHERE fa.email_domain = v_email_domain
       OR fa.website_domain = v_email_domain
    LIMIT 1;
    
    -- Also check firm_domain_aliases
    IF v_firm_id IS NULL THEN
      SELECT fa.id, fa.primary_company_name
      INTO v_firm_id, v_firm_name
      FROM firm_domain_aliases fda
      JOIN firm_agreements fa ON fa.id = fda.firm_id
      WHERE fda.domain = v_email_domain
      LIMIT 1;
    END IF;

    -- If found by domain, create firm_members link
    IF v_firm_id IS NOT NULL THEN
      INSERT INTO firm_members (firm_id, user_id, member_type, added_by)
      VALUES (v_firm_id, p_user_id, 'auto_domain_match', v_admin_id)
      ON CONFLICT DO NOTHING;
    END IF;
  END IF;

  -- 3. If still no firm, create one from user's company name
  IF v_firm_id IS NULL THEN
    v_firm_name := COALESCE(v_user_company, v_email_domain, 'Unknown Firm');
    
    INSERT INTO firm_agreements (
      primary_company_name,
      normalized_company_name,
      email_domain
    ) VALUES (
      v_firm_name,
      lower(trim(regexp_replace(v_firm_name, '[^a-zA-Z0-9]', '', 'g'))),
      v_email_domain
    )
    RETURNING id INTO v_firm_id;

    -- Link user to new firm
    INSERT INTO firm_members (firm_id, user_id, member_type, is_primary_contact, added_by)
    VALUES (v_firm_id, p_user_id, 'auto_created', true, v_admin_id);
  END IF;

  -- Now update the firm_agreements record based on action + type
  IF p_agreement_type = 'nda' THEN
    CASE p_action
      WHEN 'sign' THEN
        UPDATE firm_agreements SET
          nda_signed = true,
          nda_signed_at = now(),
          nda_signed_by = p_user_id,
          nda_signed_by_name = v_user_name,
          nda_status = 'signed',
          updated_at = now()
        WHERE id = v_firm_id;
      WHEN 'unsign' THEN
        UPDATE firm_agreements SET
          nda_signed = false,
          nda_signed_at = NULL,
          nda_signed_by = NULL,
          nda_signed_by_name = NULL,
          nda_status = 'not_started',
          updated_at = now()
        WHERE id = v_firm_id;
      WHEN 'email_sent' THEN
        UPDATE firm_agreements SET
          nda_email_sent = true,
          nda_email_sent_at = now(),
          nda_email_sent_by = v_admin_id,
          nda_status = CASE WHEN nda_status IS NULL OR nda_status = 'not_started' THEN 'sent' ELSE nda_status END,
          updated_at = now()
        WHERE id = v_firm_id;
      WHEN 'email_unsent' THEN
        UPDATE firm_agreements SET
          nda_email_sent = false,
          nda_email_sent_at = NULL,
          nda_email_sent_by = NULL,
          updated_at = now()
        WHERE id = v_firm_id;
    END CASE;
  ELSIF p_agreement_type = 'fee_agreement' THEN
    CASE p_action
      WHEN 'sign' THEN
        UPDATE firm_agreements SET
          fee_agreement_signed = true,
          fee_agreement_signed_at = now(),
          fee_agreement_signed_by = p_user_id,
          fee_agreement_signed_by_name = v_user_name,
          fee_agreement_status = 'signed',
          updated_at = now()
        WHERE id = v_firm_id;
      WHEN 'unsign' THEN
        UPDATE firm_agreements SET
          fee_agreement_signed = false,
          fee_agreement_signed_at = NULL,
          fee_agreement_signed_by = NULL,
          fee_agreement_signed_by_name = NULL,
          fee_agreement_status = 'not_started',
          updated_at = now()
        WHERE id = v_firm_id;
      WHEN 'email_sent' THEN
        UPDATE firm_agreements SET
          fee_agreement_email_sent = true,
          fee_agreement_email_sent_at = now(),
          fee_agreement_email_sent_by = v_admin_id,
          fee_agreement_status = CASE WHEN fee_agreement_status IS NULL OR fee_agreement_status = 'not_started' THEN 'sent' ELSE fee_agreement_status END,
          updated_at = now()
        WHERE id = v_firm_id;
      WHEN 'email_unsent' THEN
        UPDATE firm_agreements SET
          fee_agreement_email_sent = false,
          fee_agreement_email_sent_at = NULL,
          fee_agreement_email_sent_by = NULL,
          updated_at = now()
        WHERE id = v_firm_id;
    END CASE;
  END IF;

  -- Also keep profile in sync for backward compatibility
  IF p_agreement_type = 'nda' THEN
    IF p_action = 'sign' THEN
      UPDATE profiles SET nda_signed = true, nda_signed_at = now() WHERE id = p_user_id;
    ELSIF p_action = 'unsign' THEN
      UPDATE profiles SET nda_signed = false, nda_signed_at = NULL WHERE id = p_user_id;
    ELSIF p_action = 'email_sent' THEN
      UPDATE profiles SET nda_email_sent = true, nda_email_sent_at = now() WHERE id = p_user_id;
    ELSIF p_action = 'email_unsent' THEN
      UPDATE profiles SET nda_email_sent = false, nda_email_sent_at = NULL WHERE id = p_user_id;
    END IF;
  ELSIF p_agreement_type = 'fee_agreement' THEN
    IF p_action = 'sign' THEN
      UPDATE profiles SET fee_agreement_signed = true, fee_agreement_signed_at = now() WHERE id = p_user_id;
    ELSIF p_action = 'unsign' THEN
      UPDATE profiles SET fee_agreement_signed = false, fee_agreement_signed_at = NULL WHERE id = p_user_id;
    ELSIF p_action = 'email_sent' THEN
      UPDATE profiles SET fee_agreement_email_sent = true, fee_agreement_email_sent_at = now() WHERE id = p_user_id;
    ELSIF p_action = 'email_unsent' THEN
      UPDATE profiles SET fee_agreement_email_sent = false, fee_agreement_email_sent_at = NULL WHERE id = p_user_id;
    END IF;
  END IF;

  -- Log to audit
  INSERT INTO agreement_audit_log (
    firm_id, agreement_type, new_status, old_status, 
    changed_by, notes
  ) VALUES (
    v_firm_id,
    p_agreement_type,
    p_action,
    NULL,
    v_admin_id,
    COALESCE(p_admin_notes, 'Updated via user toggle for ' || v_user_name)
  );

  RETURN jsonb_build_object(
    'success', true,
    'firm_id', v_firm_id,
    'firm_name', v_firm_name,
    'action', p_action,
    'agreement_type', p_agreement_type,
    'user_name', v_user_name
  );
END;
$$;


ALTER FUNCTION "public"."update_agreement_via_user"("p_user_id" "uuid", "p_agreement_type" "text", "p_action" "text", "p_admin_notes" "text") OWNER TO "postgres";


