CREATE OR REPLACE FUNCTION "public"."update_contact_last_contacted_via_activity"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
  IF NEW.contact_id IS NOT NULL THEN
    UPDATE public.contacts
    SET last_contacted_at = COALESCE(NEW.call_started_at, NEW.created_at)
    WHERE id = NEW.contact_id
      AND (
        last_contacted_at IS NULL
        OR last_contacted_at < COALESCE(NEW.call_started_at, NEW.created_at)
      );
  END IF;
  RETURN NEW;
END;
$$;


