CREATE OR REPLACE FUNCTION "public"."update_deal_owner"("p_deal_id" "uuid", "p_assigned_to" "uuid", "p_actor_id" "uuid" DEFAULT NULL::"uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_actor_id uuid;
  v_old_owner uuid;
  v_listing_id uuid;
  v_primary_owner uuid;
  v_stage_name text;
  v_old_owner_name text;
  v_result jsonb;
BEGIN
  -- Always use the authenticated caller. p_actor_id is kept as a parameter for
  -- compatibility with the current client but is intentionally NOT honoured —
  -- see migration comment above.
  v_actor_id := auth.uid();
  IF v_actor_id IS NULL THEN
    RAISE EXCEPTION 'update_deal_owner requires an authenticated caller';
  END IF;

  SELECT assigned_to, listing_id INTO v_old_owner, v_listing_id
  FROM public.deal_pipeline
  WHERE id = p_deal_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Deal not found: %', p_deal_id;
  END IF;

  SELECT primary_owner_id INTO v_primary_owner
  FROM public.listings
  WHERE id = v_listing_id;

  IF NOT (
    public.is_admin(v_actor_id)
    OR v_actor_id = v_old_owner
    OR v_actor_id = v_primary_owner
  ) THEN
    RAISE EXCEPTION 'Only admins, current owners, or listing primary owners can update deal ownership';
  END IF;

  IF v_old_owner IS NOT NULL AND v_old_owner IS DISTINCT FROM p_assigned_to THEN
    SELECT first_name || ' ' || last_name INTO v_old_owner_name
    FROM public.profiles
    WHERE id = v_old_owner;
  END IF;

  UPDATE public.deal_pipeline
  SET
    assigned_to = p_assigned_to,
    owner_assigned_at = CASE WHEN p_assigned_to IS NULL THEN NULL ELSE now() END,
    owner_assigned_by = CASE WHEN p_assigned_to IS NULL THEN NULL ELSE v_actor_id END,
    updated_at = now()
  WHERE id = p_deal_id;

  SELECT name INTO v_stage_name
  FROM public.deal_stages ds
  JOIN public.deal_pipeline dp ON dp.stage_id = ds.id
  WHERE dp.id = p_deal_id;

  v_result := jsonb_build_object(
    'owner_changed', v_old_owner IS DISTINCT FROM p_assigned_to,
    'previous_owner_id', v_old_owner,
    'previous_owner_name', v_old_owner_name,
    'stage_name', v_stage_name
  );

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."update_deal_owner"("p_deal_id" "uuid", "p_assigned_to" "uuid", "p_actor_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."update_deal_owner"("p_deal_id" "uuid", "p_assigned_to" "uuid", "p_actor_id" "uuid") IS 'Reassigns a deal owner. The p_actor_id parameter is accepted for backward compatibility but is IGNORED — auth.uid() is always used to prevent permission escalation via SECURITY DEFINER.';



CREATE OR REPLACE FUNCTION "public"."update_deal_stage_timestamp"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Update stage_entered_at when stage changes
  IF OLD.stage_id IS DISTINCT FROM NEW.stage_id THEN
    NEW.stage_entered_at = NOW();
    
    -- Log stage change activity
    INSERT INTO public.deal_activities (
      deal_id, admin_id, activity_type, title, description, metadata
    ) VALUES (
      NEW.id,
      auth.uid(),
      'stage_change',
      'Stage changed',
      CASE 
        WHEN OLD.stage_id IS NULL THEN 'Deal created'
        ELSE 'Moved to new stage'
      END,
      jsonb_build_object(
        'previous_stage_id', OLD.stage_id,
        'new_stage_id', NEW.stage_id,
        'changed_at', NOW()
      )
    );
  END IF;
  
  NEW.updated_at = NOW();
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."update_deal_stage_timestamp"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."update_email_messages_deal_id"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NEW.buyer_contact_id IS DISTINCT FROM OLD.buyer_contact_id THEN
    IF OLD.buyer_contact_id IS NOT NULL THEN
      UPDATE public.email_messages
         SET deal_id = NULL
       WHERE contact_id = OLD.buyer_contact_id
         AND deal_id = OLD.id;
    END IF;

    IF NEW.buyer_contact_id IS NOT NULL THEN
      UPDATE public.email_messages
         SET deal_id = NEW.id
       WHERE contact_id = NEW.buyer_contact_id
         AND deal_id IS NULL;
    END IF;
  END IF;

  IF NEW.seller_contact_id IS DISTINCT FROM OLD.seller_contact_id THEN
    IF OLD.seller_contact_id IS NOT NULL THEN
      UPDATE public.email_messages
         SET deal_id = NULL
       WHERE contact_id = OLD.seller_contact_id
         AND deal_id = OLD.id;
    END IF;

    IF NEW.seller_contact_id IS NOT NULL THEN
      UPDATE public.email_messages
         SET deal_id = NEW.id
       WHERE contact_id = NEW.seller_contact_id
         AND deal_id IS NULL;
    END IF;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."update_email_messages_deal_id"() OWNER TO "postgres";


