CREATE OR REPLACE FUNCTION "public"."update_fee_agreement_email_status"("target_user_id" "uuid", "is_sent" boolean, "admin_notes" "text" DEFAULT NULL::"text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  UPDATE public.profiles SET 
    fee_agreement_email_sent = is_sent,
    fee_agreement_email_sent_at = CASE WHEN is_sent THEN NOW() ELSE NULL END,
    updated_at = NOW()
  WHERE id = target_user_id;

  UPDATE public.connection_requests SET 
    lead_fee_agreement_email_sent = is_sent,
    lead_fee_agreement_email_sent_at = CASE WHEN is_sent THEN NOW() ELSE NULL END,
    lead_fee_agreement_email_sent_by = CASE WHEN is_sent THEN auth.uid() ELSE NULL END,
    updated_at = NOW()
  WHERE user_id = target_user_id;

  UPDATE public.deals SET 
    fee_agreement_status = CASE WHEN is_sent THEN 'sent'::text ELSE 'not_sent'::text END,
    updated_at = NOW()
  WHERE connection_request_id IN (
    SELECT id FROM public.connection_requests WHERE user_id = target_user_id
  );

  INSERT INTO public.fee_agreement_logs (user_id, admin_id, action_type, notes, metadata)
  VALUES (target_user_id, auth.uid(),
    CASE WHEN is_sent THEN 'sent' ELSE 'revoked' END,
    admin_notes, jsonb_build_object('manual_update', true, 'email_sent', is_sent));
  RETURN FOUND;
END; $$;


