CREATE OR REPLACE FUNCTION "public"."update_journey_milestone"("p_visitor_id" "text", "p_milestone_key" "text", "p_milestone_time" timestamp with time zone DEFAULT "now"()) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  UPDATE public.user_journeys
  SET 
    milestones = jsonb_set(
      COALESCE(milestones, '{}'::jsonb),
      ARRAY[p_milestone_key],
      to_jsonb(p_milestone_time::text)
    ),
    journey_stage = CASE 
      WHEN p_milestone_key = 'first_connection_at' THEN 'converted'
      WHEN p_milestone_key IN ('nda_signed_at', 'fee_agreement_at') THEN 'qualified'
      WHEN p_milestone_key = 'signup_at' THEN 'registered'
      ELSE journey_stage
    END,
    updated_at = NOW()
  WHERE visitor_id = p_visitor_id;
END;
$$;


ALTER FUNCTION "public"."update_journey_milestone"("p_visitor_id" "text", "p_milestone_key" "text", "p_milestone_time" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."update_lead_conversion_tracking"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- If this connection request is created from a lead, update the lead's conversion tracking
  IF NEW.source_lead_id IS NOT NULL THEN
    UPDATE public.inbound_leads 
    SET 
      converted_to_request_id = NEW.id,
      converted_at = NEW.created_at,
      converted_by = NEW.converted_by,
      status = 'converted'
    WHERE id = NEW.source_lead_id;
  END IF;
  
  RETURN NEW;
END;
$$;


