CREATE OR REPLACE FUNCTION "public"."update_lead_fee_agreement_email_status"("p_request_id" "uuid", "p_value" boolean) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_state text;
  v_admin_id uuid;
  v_deal_id uuid;
  v_user_id uuid;
BEGIN
  v_admin_id := auth.uid();
  IF v_admin_id IS NULL THEN
    RAISE EXCEPTION 'User not authenticated';
  END IF;

  v_state := CASE WHEN p_value THEN 'sent' ELSE 'not_sent' END;

  UPDATE public.connection_requests
  SET 
    lead_fee_agreement_email_sent = p_value,
    lead_fee_agreement_email_sent_at = CASE WHEN p_value THEN NOW() ELSE NULL END,
    lead_fee_agreement_email_sent_by = CASE WHEN p_value THEN v_admin_id ELSE NULL END,
    updated_at = NOW()
  WHERE id = p_request_id
  RETURNING user_id INTO v_user_id;

  IF v_user_id IS NOT NULL THEN
    UPDATE public.profiles
    SET 
      fee_agreement_email_sent = p_value,
      fee_agreement_email_sent_at = CASE WHEN p_value THEN NOW() ELSE NULL END,
      updated_at = NOW()
    WHERE id = v_user_id;
  END IF;

  SELECT id INTO v_deal_id FROM public.deals WHERE connection_request_id = p_request_id LIMIT 1;

  IF v_deal_id IS NOT NULL THEN
    UPDATE public.deals
    SET 
      fee_agreement_status = v_state,
      updated_at = NOW()
    WHERE id = v_deal_id;

    INSERT INTO public.deal_activities (deal_id, admin_id, activity_type, title, description, metadata)
    VALUES (
      v_deal_id,
      v_admin_id,
      'fee_agreement_email_sent',
      'Fee Agreement Email Status Changed',
      CASE WHEN p_value THEN 'Fee Agreement email marked as sent' ELSE 'Fee Agreement email status cleared' END,
      jsonb_build_object('email_sent', p_value, 'sent_by_admin', v_admin_id)
    );
  END IF;

  RETURN FOUND;
END;
$$;


ALTER FUNCTION "public"."update_lead_fee_agreement_email_status"("p_request_id" "uuid", "p_value" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."update_lead_fee_agreement_email_status"("request_id" "uuid", "is_sent" boolean, "admin_notes" "text" DEFAULT NULL::"text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  admin_user_id uuid;
  admin_is_admin boolean;
BEGIN
  -- Get current authenticated user ID
  admin_user_id := auth.uid();
  
  -- Check if user is authenticated
  IF admin_user_id IS NULL THEN
    RAISE EXCEPTION 'User not authenticated';
  END IF;
  
  -- Check if the calling user is an admin
  SELECT is_admin INTO admin_is_admin 
  FROM public.profiles 
  WHERE id = admin_user_id;
  
  IF NOT COALESCE(admin_is_admin, false) THEN
    RAISE EXCEPTION 'Only admins can update lead fee agreement email status';
  END IF;
  
  -- Update the connection request
  UPDATE public.connection_requests 
  SET 
    lead_fee_agreement_email_sent = is_sent,
    lead_fee_agreement_email_sent_at = CASE 
      WHEN is_sent THEN NOW() 
      ELSE NULL 
    END,
    updated_at = NOW()
  WHERE id = request_id;
  
  RETURN FOUND;
END;
$$;


ALTER FUNCTION "public"."update_lead_fee_agreement_email_status"("request_id" "uuid", "is_sent" boolean, "admin_notes" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."update_lead_fee_agreement_status"("p_request_id" "uuid", "p_value" boolean) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_firm_id uuid;
  v_deal_id uuid;
BEGIN
  -- Get firm_id and deal_id from connection request
  SELECT firm_id, deal_id INTO v_firm_id, v_deal_id
  FROM connection_requests
  WHERE id = p_request_id;

  -- Update firm_agreements
  IF v_firm_id IS NOT NULL THEN
    UPDATE firm_agreements
    SET fee_agreement_signed = p_value,
        fee_agreement_signed_at = CASE WHEN p_value THEN now() ELSE NULL END,
        fee_agreement_status = CASE WHEN p_value THEN 'signed' ELSE 'not_started' END,
        updated_at = now()
    WHERE id = v_firm_id;
  END IF;

  -- Update deal_pipeline
  IF v_deal_id IS NOT NULL THEN
    UPDATE deal_pipeline
    SET fee_agreement_status = CASE WHEN p_value THEN 'signed' ELSE 'not_started' END,
        updated_at = now()
    WHERE id = v_deal_id;
  END IF;

  -- Update connection_requests (Bug Fix: this was missing)
  UPDATE connection_requests
  SET lead_fee_agreement_signed = p_value,
      lead_fee_agreement_signed_at = CASE WHEN p_value THEN now() ELSE NULL END,
      updated_at = now()
  WHERE id = p_request_id;
END;
$$;


ALTER FUNCTION "public"."update_lead_fee_agreement_status"("p_request_id" "uuid", "p_value" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."update_lead_nda_email_status"("p_request_id" "uuid", "p_value" boolean) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_state text;
  v_admin_id uuid;
  v_deal_id uuid;
  v_user_id uuid;
BEGIN
  v_admin_id := auth.uid();
  IF v_admin_id IS NULL THEN
    RAISE EXCEPTION 'User not authenticated';
  END IF;

  v_state := CASE WHEN p_value THEN 'sent' ELSE 'not_sent' END;

  UPDATE public.connection_requests
  SET 
    lead_nda_email_sent = p_value,
    lead_nda_email_sent_at = CASE WHEN p_value THEN NOW() ELSE NULL END,
    lead_nda_email_sent_by = CASE WHEN p_value THEN v_admin_id ELSE NULL END,
    updated_at = NOW()
  WHERE id = p_request_id
  RETURNING user_id INTO v_user_id;

  IF v_user_id IS NOT NULL THEN
    UPDATE public.profiles
    SET 
      nda_email_sent = p_value,
      nda_email_sent_at = CASE WHEN p_value THEN NOW() ELSE NULL END,
      updated_at = NOW()
    WHERE id = v_user_id;
  END IF;

  SELECT id INTO v_deal_id FROM public.deals WHERE connection_request_id = p_request_id LIMIT 1;

  IF v_deal_id IS NOT NULL THEN
    UPDATE public.deals
    SET 
      nda_status = v_state,
      updated_at = NOW()
    WHERE id = v_deal_id;

    INSERT INTO public.deal_activities (deal_id, admin_id, activity_type, title, description, metadata)
    VALUES (
      v_deal_id,
      v_admin_id,
      'nda_email_sent',
      'NDA Email Status Changed',
      CASE WHEN p_value THEN 'NDA email marked as sent' ELSE 'NDA email status cleared' END,
      jsonb_build_object('email_sent', p_value, 'sent_by_admin', v_admin_id)
    );
  END IF;

  RETURN FOUND;
END;
$$;


