CREATE OR REPLACE FUNCTION "public"."update_nda_firm_status"("p_firm_id" "uuid", "p_is_signed" boolean, "p_signed_by_user_id" "uuid" DEFAULT NULL::"uuid", "p_signed_by_name" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_member_record RECORD;
BEGIN
  IF NOT is_admin(auth.uid()) THEN
    RAISE EXCEPTION 'Only admins can update firm NDA status';
  END IF;

  UPDATE public.firm_agreements
  SET
    nda_signed = p_is_signed,
    nda_signed_at = CASE WHEN p_is_signed THEN NOW() ELSE NULL END,
    nda_signed_by = p_signed_by_user_id,
    nda_signed_by_name = p_signed_by_name,
    updated_at = NOW()
  WHERE id = p_firm_id;

  FOR v_member_record IN
    SELECT fm.user_id
    FROM public.firm_members fm
    WHERE fm.firm_id = p_firm_id
  LOOP
    UPDATE public.profiles
    SET
      nda_signed = p_is_signed,
      nda_signed_at = CASE WHEN p_is_signed THEN NOW() ELSE NULL END,
      updated_at = NOW()
    WHERE id = v_member_record.user_id;

    UPDATE public.connection_requests
    SET
      lead_nda_signed = p_is_signed,
      lead_nda_signed_at = CASE WHEN p_is_signed THEN NOW() ELSE NULL END,
      lead_nda_signed_by = CASE WHEN p_is_signed THEN p_signed_by_user_id ELSE NULL END,
      updated_at = NOW()
    WHERE user_id = v_member_record.user_id;

    UPDATE public.deal_pipeline
    SET
      nda_status = CASE WHEN p_is_signed THEN 'signed'::text ELSE 'not_sent'::text END,
      updated_at = NOW()
    WHERE connection_request_id IN (
      SELECT id FROM public.connection_requests WHERE user_id = v_member_record.user_id
    );
  END LOOP;

  INSERT INTO public.nda_logs (user_id, admin_id, firm_id, action_type, notes, metadata)
  VALUES (
    COALESCE(p_signed_by_user_id, auth.uid()),
    auth.uid(),
    p_firm_id,
    CASE WHEN p_is_signed THEN 'signed' ELSE 'revoked' END,
    CASE
      WHEN p_is_signed AND p_signed_by_name IS NOT NULL THEN 'NDA marked as signed by ' || p_signed_by_name || ' for entire firm'
      WHEN p_is_signed THEN 'NDA marked as signed for entire firm'
      ELSE 'NDA revoked for entire firm'
    END,
    jsonb_build_object('firm_wide_update', true, 'signed_by_user_id', p_signed_by_user_id, 'signed_by_name', p_signed_by_name)
  );
END;
$$;


ALTER FUNCTION "public"."update_nda_firm_status"("p_firm_id" "uuid", "p_is_signed" boolean, "p_signed_by_user_id" "uuid", "p_signed_by_name" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."update_nda_firm_status"("p_firm_id" "uuid", "p_is_signed" boolean, "p_signed_by_user_id" "uuid" DEFAULT NULL::"uuid", "p_signed_at" timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  caller_id uuid;
  caller_is_admin boolean;
BEGIN
  caller_id := auth.uid();
  IF caller_id IS NULL THEN
    RAISE EXCEPTION 'User not authenticated';
  END IF;

  SELECT is_admin INTO caller_is_admin FROM public.profiles WHERE id = caller_id;
  IF NOT COALESCE(caller_is_admin, false) THEN
    RAISE EXCEPTION 'Only admins can update firm NDAs';
  END IF;

  UPDATE public.firm_agreements
  SET
    nda_signed = p_is_signed,
    nda_signed_by = CASE WHEN p_is_signed THEN p_signed_by_user_id ELSE NULL END,
    nda_signed_at = CASE WHEN p_is_signed THEN COALESCE(p_signed_at, NOW()) ELSE NULL END,
    updated_at = NOW()
  WHERE id = p_firm_id;

  UPDATE public.profiles
  SET
    nda_signed = p_is_signed,
    nda_signed_at = CASE WHEN p_is_signed THEN COALESCE(p_signed_at, NOW()) ELSE NULL END,
    updated_at = NOW()
  WHERE id IN (
    SELECT user_id FROM public.firm_members WHERE firm_id = p_firm_id AND user_id IS NOT NULL
  );

  UPDATE public.connection_requests
  SET
    lead_nda_signed = p_is_signed,
    lead_nda_signed_at = CASE WHEN p_is_signed THEN COALESCE(p_signed_at, NOW()) ELSE NULL END,
    lead_nda_signed_by = CASE WHEN p_is_signed THEN p_signed_by_user_id ELSE NULL END,
    updated_at = NOW()
  WHERE firm_id = p_firm_id;

  UPDATE public.deal_pipeline
  SET
    nda_status = CASE WHEN p_is_signed THEN 'signed'::text ELSE 'not_sent'::text END,
    updated_at = NOW()
  WHERE connection_request_id IN (
    SELECT id FROM public.connection_requests WHERE firm_id = p_firm_id
  );

  RETURN FOUND;
END;
$$;


ALTER FUNCTION "public"."update_nda_firm_status"("p_firm_id" "uuid", "p_is_signed" boolean, "p_signed_by_user_id" "uuid", "p_signed_at" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."update_nda_firm_status_with_notes"("p_firm_id" "uuid", "p_is_signed" boolean, "p_signed_by_user_id" "uuid" DEFAULT NULL::"uuid", "p_signed_by_name" "text" DEFAULT NULL::"text", "p_admin_notes" "text" DEFAULT NULL::"text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_admin_id UUID;
  v_member_record RECORD;
BEGIN
  v_admin_id := auth.uid();
  
  IF v_admin_id IS NULL THEN
    RAISE EXCEPTION 'User not authenticated';
  END IF;
  
  IF NOT is_admin(v_admin_id) THEN
    RAISE EXCEPTION 'Only admins can update firm NDA status';
  END IF;
  
  -- Update firm_agreements table
  UPDATE public.firm_agreements
  SET 
    nda_signed = p_is_signed,
    nda_signed_at = CASE WHEN p_is_signed THEN NOW() ELSE NULL END,
    nda_signed_by = CASE WHEN p_is_signed THEN COALESCE(p_signed_by_user_id, v_admin_id) ELSE NULL END,
    nda_signed_by_name = CASE WHEN p_is_signed THEN p_signed_by_name ELSE NULL END,
    updated_at = NOW()
  WHERE id = p_firm_id;
  
  -- Cascade to all firm members' profiles
  FOR v_member_record IN 
    SELECT user_id FROM public.firm_members WHERE firm_id = p_firm_id
  LOOP
    UPDATE public.profiles
    SET 
      nda_signed = p_is_signed,
      nda_signed_at = CASE WHEN p_is_signed THEN NOW() ELSE NULL END,
      updated_at = NOW()
    WHERE id = v_member_record.user_id;
    
    -- Cascade to all connection_requests for this user
    UPDATE public.connection_requests
    SET 
      lead_nda_signed = p_is_signed,
      lead_nda_signed_at = CASE WHEN p_is_signed THEN NOW() ELSE NULL END,
      lead_nda_signed_by = CASE WHEN p_is_signed THEN COALESCE(p_signed_by_user_id, v_admin_id) ELSE NULL END,
      updated_at = NOW()
    WHERE user_id = v_member_record.user_id;
    
    -- Cascade to all deals for this user (via connection_requests)
    UPDATE public.deals
    SET 
      nda_status = CASE 
        WHEN p_is_signed THEN 'signed'::text
        ELSE 'not_sent'::text
      END,
      updated_at = NOW()
    WHERE connection_request_id IN (
      SELECT id FROM public.connection_requests WHERE user_id = v_member_record.user_id
    );
  END LOOP;
  
  -- Log the action WITH firm_id
  INSERT INTO public.nda_logs (
    user_id,
    admin_id,
    firm_id,
    action_type,
    notes,
    metadata
  )
  SELECT 
    v_member_record.user_id,
    v_admin_id,
    p_firm_id,
    CASE WHEN p_is_signed THEN 'signed' ELSE 'revoked' END,
    p_admin_notes,
    jsonb_build_object(
      'firm_update', true,
      'firm_id', p_firm_id,
      'signed_by_name', p_signed_by_name,
      'signed_by_user_id', p_signed_by_user_id
    )
  FROM public.firm_members v_member_record
  WHERE v_member_record.firm_id = p_firm_id;
  
  RETURN TRUE;
END;
$$;


ALTER FUNCTION "public"."update_nda_firm_status_with_notes"("p_firm_id" "uuid", "p_is_signed" boolean, "p_signed_by_user_id" "uuid", "p_signed_by_name" "text", "p_admin_notes" "text") OWNER TO "postgres";


