CREATE OR REPLACE FUNCTION "public"."upsert_alignment_scoring_queue"("p_universe_id" "uuid", "p_buyer_id" "uuid", "p_score_type" "text", "p_status" "text" DEFAULT 'pending'::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  INSERT INTO remarketing_scoring_queue (universe_id, buyer_id, score_type, status, created_at, updated_at)
  VALUES (p_universe_id, p_buyer_id, p_score_type, p_status, now(), now())
  ON CONFLICT (universe_id, buyer_id, score_type) WHERE buyer_id IS NOT NULL
  DO UPDATE SET
    status = CASE 
      WHEN remarketing_scoring_queue.status IN ('pending', 'processing') THEN remarketing_scoring_queue.status
      ELSE EXCLUDED.status
    END,
    updated_at = now();
END;
$$;


ALTER FUNCTION "public"."upsert_alignment_scoring_queue"("p_universe_id" "uuid", "p_buyer_id" "uuid", "p_score_type" "text", "p_status" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."upsert_buyer_contact"("p_first_name" "text", "p_last_name" "text", "p_email" "text" DEFAULT NULL::"text", "p_phone" "text" DEFAULT NULL::"text", "p_title" "text" DEFAULT NULL::"text", "p_linkedin_url" "text" DEFAULT NULL::"text", "p_is_primary_at_firm" boolean DEFAULT false, "p_remarketing_buyer_id" "uuid" DEFAULT NULL::"uuid", "p_firm_id" "uuid" DEFAULT NULL::"uuid", "p_source" "text" DEFAULT 'remarketing_manual'::"text", "p_mobile_phone_1" "text" DEFAULT NULL::"text", "p_mobile_phone_2" "text" DEFAULT NULL::"text", "p_mobile_phone_3" "text" DEFAULT NULL::"text", "p_office_phone" "text" DEFAULT NULL::"text", "p_phone_source" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_email TEXT := NULLIF(TRIM(lower(p_email)), '');
  v_linkedin TEXT := NULLIF(TRIM(p_linkedin_url), '');
  v_contact_id UUID;
  v_existing_buyer UUID;
BEGIN
  -- 0a. Cross-buyer email collision guard. If this email already lives on
  -- a LIVE buyer-type contact tied to a DIFFERENT remarketing_buyer_id,
  -- the caller is about to silently lose their intent (the contact ends
  -- up on the other buyer). Raise with a categorised SQLSTATE so the UI
  -- can render a human-actionable message instead of a silent "added".
  IF v_email IS NOT NULL AND p_remarketing_buyer_id IS NOT NULL THEN
    SELECT remarketing_buyer_id
      INTO v_existing_buyer
    FROM public.contacts
    WHERE lower(email) = v_email
      AND contact_type = 'buyer'
      AND deleted_at IS NULL
      AND merged_into_id IS NULL
      AND archived = false
      AND remarketing_buyer_id IS NOT NULL
      AND remarketing_buyer_id <> p_remarketing_buyer_id
    ORDER BY created_at ASC
    LIMIT 1;

    IF v_existing_buyer IS NOT NULL THEN
      RAISE EXCEPTION 'Contact with email % is already attached to buyer %',
        v_email, v_existing_buyer
        USING ERRCODE = 'P0001',
              HINT = 'Open that buyer and edit the contact there, '
                     'or merge the two buyer orgs first.';
    END IF;
  END IF;

  -- 0b. LinkedIn resolution — unchanged from 20260727000000.
  IF v_linkedin IS NOT NULL THEN
    SELECT id
    INTO v_contact_id
    FROM public.contacts
    WHERE lower(linkedin_url) = lower(v_linkedin)
      AND deleted_at IS NULL
      AND merged_into_id IS NULL
    ORDER BY created_at ASC
    LIMIT 1;

    IF v_contact_id IS NOT NULL THEN
      UPDATE public.contacts
      SET
        first_name           = COALESCE(NULLIF(TRIM(p_first_name), ''), first_name),
        last_name            = COALESCE(p_last_name, last_name),
        email                = COALESCE(email, v_email),
        phone                = COALESCE(phone, NULLIF(TRIM(p_phone), '')),
        title                = COALESCE(title, NULLIF(TRIM(p_title), '')),
        remarketing_buyer_id = COALESCE(remarketing_buyer_id, p_remarketing_buyer_id),
        firm_id              = COALESCE(firm_id, p_firm_id),
        is_primary_at_firm   = is_primary_at_firm OR p_is_primary_at_firm,
        mobile_phone_1       = COALESCE(mobile_phone_1, NULLIF(TRIM(p_mobile_phone_1), '')),
        mobile_phone_2       = COALESCE(mobile_phone_2, NULLIF(TRIM(p_mobile_phone_2), '')),
        mobile_phone_3       = COALESCE(mobile_phone_3, NULLIF(TRIM(p_mobile_phone_3), '')),
        office_phone         = COALESCE(office_phone, NULLIF(TRIM(p_office_phone), '')),
        phone_source         = COALESCE(phone_source, NULLIF(TRIM(p_phone_source), '')),
        archived             = false,
        updated_at           = now()
      WHERE id = v_contact_id;

      RETURN v_contact_id;
    END IF;
  END IF;

  IF v_email IS NOT NULL THEN
    INSERT INTO public.contacts
      (first_name, last_name, email, phone, title, linkedin_url,
       is_primary_at_firm, contact_type, remarketing_buyer_id, firm_id, source,
       mobile_phone_1, mobile_phone_2, mobile_phone_3, office_phone, phone_source)
    VALUES
      (p_first_name, p_last_name, v_email,
       NULLIF(TRIM(p_phone), ''),
       NULLIF(TRIM(p_title), ''),
       v_linkedin,
       p_is_primary_at_firm, 'buyer', p_remarketing_buyer_id, p_firm_id, p_source,
       NULLIF(TRIM(p_mobile_phone_1), ''),
       NULLIF(TRIM(p_mobile_phone_2), ''),
       NULLIF(TRIM(p_mobile_phone_3), ''),
       NULLIF(TRIM(p_office_phone), ''),
       NULLIF(TRIM(p_phone_source), ''))
    ON CONFLICT (lower(email))
      WHERE contact_type = 'buyer' AND email IS NOT NULL AND archived = false
    DO UPDATE SET
      first_name           = EXCLUDED.first_name,
      last_name            = EXCLUDED.last_name,
      remarketing_buyer_id = COALESCE(contacts.remarketing_buyer_id, EXCLUDED.remarketing_buyer_id),
      firm_id              = COALESCE(contacts.firm_id, EXCLUDED.firm_id),
      is_primary_at_firm   = contacts.is_primary_at_firm OR EXCLUDED.is_primary_at_firm,
      phone                = COALESCE(EXCLUDED.phone, contacts.phone),
      linkedin_url         = COALESCE(EXCLUDED.linkedin_url, contacts.linkedin_url),
      title                = COALESCE(EXCLUDED.title, contacts.title),
      mobile_phone_1       = COALESCE(EXCLUDED.mobile_phone_1, contacts.mobile_phone_1),
      mobile_phone_2       = COALESCE(EXCLUDED.mobile_phone_2, contacts.mobile_phone_2),
      mobile_phone_3       = COALESCE(EXCLUDED.mobile_phone_3, contacts.mobile_phone_3),
      office_phone         = COALESCE(EXCLUDED.office_phone, contacts.office_phone),
      phone_source         = COALESCE(EXCLUDED.phone_source, contacts.phone_source),
      updated_at           = now()
    RETURNING id INTO v_contact_id;

  ELSIF p_remarketing_buyer_id IS NOT NULL THEN
    INSERT INTO public.contacts
      (first_name, last_name, email, phone, title, linkedin_url,
       is_primary_at_firm, contact_type, remarketing_buyer_id, firm_id, source,
       mobile_phone_1, mobile_phone_2, mobile_phone_3, office_phone, phone_source)
    VALUES
      (p_first_name, p_last_name, NULL,
       NULLIF(TRIM(p_phone), ''),
       NULLIF(TRIM(p_title), ''),
       v_linkedin,
       p_is_primary_at_firm, 'buyer', p_remarketing_buyer_id, p_firm_id, p_source,
       NULLIF(TRIM(p_mobile_phone_1), ''),
       NULLIF(TRIM(p_mobile_phone_2), ''),
       NULLIF(TRIM(p_mobile_phone_3), ''),
       NULLIF(TRIM(p_office_phone), ''),
       NULLIF(TRIM(p_phone_source), ''))
    ON CONFLICT (lower(trim(first_name)), lower(trim(last_name)), remarketing_buyer_id)
      WHERE contact_type = 'buyer' AND email IS NULL
        AND remarketing_buyer_id IS NOT NULL AND archived = false
    DO UPDATE SET
      firm_id            = COALESCE(contacts.firm_id, EXCLUDED.firm_id),
      is_primary_at_firm = contacts.is_primary_at_firm OR EXCLUDED.is_primary_at_firm,
      phone              = COALESCE(EXCLUDED.phone, contacts.phone),
      linkedin_url       = COALESCE(EXCLUDED.linkedin_url, contacts.linkedin_url),
      title              = COALESCE(EXCLUDED.title, contacts.title),
      mobile_phone_1     = COALESCE(EXCLUDED.mobile_phone_1, contacts.mobile_phone_1),
      mobile_phone_2     = COALESCE(EXCLUDED.mobile_phone_2, contacts.mobile_phone_2),
      mobile_phone_3     = COALESCE(EXCLUDED.mobile_phone_3, contacts.mobile_phone_3),
      office_phone       = COALESCE(EXCLUDED.office_phone, contacts.office_phone),
      phone_source       = COALESCE(EXCLUDED.phone_source, contacts.phone_source),
      updated_at         = now()
    RETURNING id INTO v_contact_id;

  ELSE
    INSERT INTO public.contacts
      (first_name, last_name, email, phone, title, linkedin_url,
       is_primary_at_firm, contact_type, remarketing_buyer_id, firm_id, source,
       mobile_phone_1, mobile_phone_2, mobile_phone_3, office_phone, phone_source)
    VALUES
      (p_first_name, p_last_name, NULL,
       NULLIF(TRIM(p_phone), ''),
       NULLIF(TRIM(p_title), ''),
       v_linkedin,
       p_is_primary_at_firm, 'buyer', NULL, p_firm_id, p_source,
       NULLIF(TRIM(p_mobile_phone_1), ''),
       NULLIF(TRIM(p_mobile_phone_2), ''),
       NULLIF(TRIM(p_mobile_phone_3), ''),
       NULLIF(TRIM(p_office_phone), ''),
       NULLIF(TRIM(p_phone_source), ''))
    ON CONFLICT (lower(trim(first_name)), lower(trim(last_name)))
      WHERE contact_type = 'buyer' AND email IS NULL
        AND remarketing_buyer_id IS NULL AND archived = false
    DO UPDATE SET
      firm_id            = COALESCE(contacts.firm_id, EXCLUDED.firm_id),
      is_primary_at_firm = contacts.is_primary_at_firm OR EXCLUDED.is_primary_at_firm,
      phone              = COALESCE(EXCLUDED.phone, contacts.phone),
      linkedin_url       = COALESCE(EXCLUDED.linkedin_url, contacts.linkedin_url),
      title              = COALESCE(EXCLUDED.title, contacts.title),
      mobile_phone_1     = COALESCE(EXCLUDED.mobile_phone_1, contacts.mobile_phone_1),
      mobile_phone_2     = COALESCE(EXCLUDED.mobile_phone_2, contacts.mobile_phone_2),
      mobile_phone_3     = COALESCE(EXCLUDED.mobile_phone_3, contacts.mobile_phone_3),
      office_phone       = COALESCE(EXCLUDED.office_phone, contacts.office_phone),
      phone_source       = COALESCE(EXCLUDED.phone_source, contacts.phone_source),
      updated_at         = now()
    RETURNING id INTO v_contact_id;
  END IF;

  RETURN v_contact_id;
END;
$$;


ALTER FUNCTION "public"."upsert_buyer_contact"("p_first_name" "text", "p_last_name" "text", "p_email" "text", "p_phone" "text", "p_title" "text", "p_linkedin_url" "text", "p_is_primary_at_firm" boolean, "p_remarketing_buyer_id" "uuid", "p_firm_id" "uuid", "p_source" "text", "p_mobile_phone_1" "text", "p_mobile_phone_2" "text", "p_mobile_phone_3" "text", "p_office_phone" "text", "p_phone_source" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."upsert_buyer_contact"("p_first_name" "text", "p_last_name" "text", "p_email" "text", "p_phone" "text", "p_title" "text", "p_linkedin_url" "text", "p_is_primary_at_firm" boolean, "p_remarketing_buyer_id" "uuid", "p_firm_id" "uuid", "p_source" "text", "p_mobile_phone_1" "text", "p_mobile_phone_2" "text", "p_mobile_phone_3" "text", "p_office_phone" "text", "p_phone_source" "text") IS 'Upserts a buyer-type contact. Resolution order: (1) LinkedIn URL exact match on live rows, (2) email via idx_contacts_buyer_email_unique, (3) (name, remarketing_buyer_id) via idx_contacts_buyer_name_rmkt_unique, (4) name via idx_contacts_buyer_name_only_unique. LinkedIn check runs first because its unique index is independent of contact_type and email presence — missing that path caused every Add Contact save to fail with a generic "Failed to add contact" toast whenever the LinkedIn URL was already live on any row (enrichment, auto-discovery, etc.).';



CREATE OR REPLACE FUNCTION "public"."upsert_buyer_from_connection_request"("p_user_id" "uuid", "p_lead_email" "text", "p_lead_company" "text", "p_lead_website" "text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_profile_website   text;
  v_profile_company   text;
  v_candidate_website text;
  v_normalized_domain text;
  v_company_name      text;
  v_existing_id       uuid;
  v_new_id            uuid;
BEGIN
  IF p_user_id IS NOT NULL THEN
    SELECT website, company
      INTO v_profile_website, v_profile_company
      FROM public.profiles
     WHERE id = p_user_id;
  END IF;

  -- Priority: profile.website > lead_website > lead_email domain.
  v_candidate_website := coalesce(
    nullif(trim(v_profile_website), ''),
    nullif(trim(p_lead_website),   ''),
    nullif(trim(p_lead_email),     '')
  );

  v_normalized_domain := public.normalize_domain(v_candidate_website);

  IF v_normalized_domain IS NULL OR v_normalized_domain = '' THEN
    RETURN NULL;
  END IF;

  IF public.is_free_email_domain(v_normalized_domain) THEN
    RETURN NULL;
  END IF;

  -- Reuse any existing active buyer sharing this domain. extract_domain
  -- mirrors idx_buyers_unique_domain so this matches the dedup key.
  SELECT id INTO v_existing_id
    FROM public.buyers
   WHERE archived = false
     AND company_website IS NOT NULL
     AND public.extract_domain(company_website) = public.extract_domain(v_normalized_domain)
   LIMIT 1;

  IF v_existing_id IS NOT NULL THEN
    RETURN v_existing_id;
  END IF;

  -- buyers.company_name is NOT NULL; fall back through name sources.
  v_company_name := coalesce(
    nullif(trim(p_lead_company),     ''),
    nullif(trim(v_profile_company),  ''),
    v_normalized_domain
  );

  INSERT INTO public.buyers (company_name, company_website)
  VALUES (v_company_name, v_normalized_domain)
  ON CONFLICT DO NOTHING
  RETURNING id INTO v_new_id;

  -- Race: another trigger could have inserted the same domain between
  -- our existence check and the insert. Re-read the winner if so.
  IF v_new_id IS NULL THEN
    SELECT id INTO v_new_id
      FROM public.buyers
     WHERE archived = false
       AND public.extract_domain(company_website) = public.extract_domain(v_normalized_domain)
     LIMIT 1;
  END IF;

  RETURN v_new_id;
END;
$$;


ALTER FUNCTION "public"."upsert_buyer_from_connection_request"("p_user_id" "uuid", "p_lead_email" "text", "p_lead_company" "text", "p_lead_website" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."upsert_buyer_from_connection_request"("p_user_id" "uuid", "p_lead_email" "text", "p_lead_company" "text", "p_lead_website" "text") IS 'Mirrors the inquirer''s company into the buyers table so it appears in All Buyers search. Dedups on extract_domain(company_website). Returns the buyer id, or NULL if no usable company domain can be derived.';



CREATE OR REPLACE FUNCTION "public"."upsert_contact_from_connection_request"("p_user_id" "uuid", "p_lead_email" "text", "p_lead_name" "text", "p_lead_first" "text", "p_lead_last" "text", "p_lead_phone" "text", "p_lead_title" "text", "p_lead_linkedin" "text", "p_buyer_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_profile_first   text;
  v_profile_last    text;
  v_profile_phone   text;
  v_profile_title   text;
  v_profile_linked  text;
  v_first           text;
  v_last            text;
  v_email           text;
  v_phone           text;
  v_title           text;
  v_linkedin        text;
  v_split_at        int;
  v_name_raw        text;
  v_existing_id     uuid;
  v_new_id          uuid;
BEGIN
  v_email := nullif(trim(lower(p_lead_email)), '');

  -- No email → we can't dedup, and buyer contacts are keyed on email. Skip.
  IF v_email IS NULL THEN
    RETURN NULL;
  END IF;

  IF p_user_id IS NOT NULL THEN
    SELECT p.first_name, p.last_name, p.phone_number, NULL::text, p.linkedin_url
      INTO v_profile_first, v_profile_last, v_profile_phone, v_profile_title, v_profile_linked
      FROM public.profiles p
     WHERE p.id = p_user_id;
  END IF;

  -- Names: prefer the split lead_first/lead_last columns, then profile,
  -- then a last-space split of lead_name.
  v_first := coalesce(
    nullif(trim(p_lead_first),    ''),
    nullif(trim(v_profile_first), '')
  );
  v_last := coalesce(
    nullif(trim(p_lead_last),    ''),
    nullif(trim(v_profile_last), '')
  );

  IF v_first IS NULL THEN
    v_name_raw := nullif(trim(p_lead_name), '');
    IF v_name_raw IS NOT NULL THEN
      v_split_at := length(v_name_raw) - position(' ' in reverse(v_name_raw));
      IF v_split_at > 0 AND v_split_at < length(v_name_raw) THEN
        v_first := trim(substring(v_name_raw from 1 for v_split_at));
        v_last  := coalesce(v_last, trim(substring(v_name_raw from v_split_at + 1)));
      ELSE
        v_first := v_name_raw;
      END IF;
    END IF;
  END IF;

  -- contacts.first_name is NOT NULL; use the email local-part as a last
  -- resort rather than storing 'Unknown', which is harder to triage.
  IF v_first IS NULL OR v_first = '' THEN
    v_first := split_part(v_email, '@', 1);
  END IF;

  v_phone    := coalesce(nullif(trim(p_lead_phone), ''),    v_profile_phone);
  v_title    := coalesce(nullif(trim(p_lead_title), ''),    v_profile_title);
  v_linkedin := coalesce(nullif(trim(p_lead_linkedin), ''), v_profile_linked);

  -- Match the existing buyer contact by email (partial unique index key).
  SELECT id INTO v_existing_id
    FROM public.contacts
   WHERE contact_type = 'buyer'
     AND archived = false
     AND email IS NOT NULL
     AND lower(email) = v_email
   LIMIT 1;

  IF v_existing_id IS NOT NULL THEN
    -- Backfill FKs + any missing fields on the existing contact. We never
    -- overwrite a non-null value, so admin edits stick.
    UPDATE public.contacts
       SET remarketing_buyer_id = coalesce(remarketing_buyer_id, p_buyer_id),
           profile_id           = coalesce(profile_id,           p_user_id),
           phone                = coalesce(phone,                v_phone),
           title                = coalesce(title,                v_title),
           linkedin_url         = coalesce(linkedin_url,         v_linkedin),
           updated_at           = now()
     WHERE id = v_existing_id;
    RETURN v_existing_id;
  END IF;

  INSERT INTO public.contacts (
    first_name,
    last_name,
    email,
    phone,
    title,
    linkedin_url,
    contact_type,
    remarketing_buyer_id,
    profile_id,
    source
  )
  VALUES (
    v_first,
    coalesce(v_last, ''),
    v_email,
    v_phone,
    v_title,
    v_linkedin,
    'buyer',
    p_buyer_id,
    p_user_id,
    'marketplace_inquiry'
  )
  ON CONFLICT DO NOTHING
  RETURNING id INTO v_new_id;

  -- Race: another trigger may have inserted the same email.
  IF v_new_id IS NULL THEN
    SELECT id INTO v_new_id
      FROM public.contacts
     WHERE contact_type = 'buyer'
       AND archived = false
       AND email IS NOT NULL
       AND lower(email) = v_email
     LIMIT 1;
  END IF;

  RETURN v_new_id;
END;
$$;


ALTER FUNCTION "public"."upsert_contact_from_connection_request"("p_user_id" "uuid", "p_lead_email" "text", "p_lead_name" "text", "p_lead_first" "text", "p_lead_last" "text", "p_lead_phone" "text", "p_lead_title" "text", "p_lead_linkedin" "text", "p_buyer_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."upsert_contact_from_connection_request"("p_user_id" "uuid", "p_lead_email" "text", "p_lead_name" "text", "p_lead_first" "text", "p_lead_last" "text", "p_lead_phone" "text", "p_lead_title" "text", "p_lead_linkedin" "text", "p_buyer_id" "uuid") IS 'Mirrors the inquirer''s contact info into the contacts table (type=buyer) so the approval flow can link deal_pipeline.buyer_contact_id, and so the unified contacts system has a record of every marketplace inquiry. Dedups on lower(email). Returns the contact id, or NULL if no email is available (email is the canonical buyer-contact key).';



CREATE OR REPLACE FUNCTION "public"."upsert_contact_from_list_member"("p_email" "text", "p_name" "text", "p_phone" "text", "p_company" "text", "p_role" "text", "p_entity_type" "text", "p_entity_id" "text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_email           text;
  v_phone           text;
  v_title           text;
  v_first           text;
  v_last            text;
  v_name_raw        text;
  v_split_at        int;
  v_listing_id      uuid;
  v_contact_type    text;
  v_existing_id     uuid;
  v_new_id          uuid;
BEGIN
  v_email := nullif(trim(lower(p_email)), '');

  -- No email → can't dedup, can't upsert.
  IF v_email IS NULL THEN
    RETURN NULL;
  END IF;

  v_phone := nullif(trim(p_phone), '');
  v_title := nullif(trim(p_role), '');

  -- Split name into first/last. contacts.first_name is NOT NULL; fall back
  -- to the email local-part rather than 'Unknown' so triage is easier.
  v_name_raw := nullif(trim(p_name), '');
  IF v_name_raw IS NOT NULL THEN
    v_split_at := length(v_name_raw) - position(' ' in reverse(v_name_raw));
    IF v_split_at > 0 AND v_split_at < length(v_name_raw) THEN
      v_first := trim(substring(v_name_raw from 1 for v_split_at));
      v_last  := trim(substring(v_name_raw from v_split_at + 1));
    ELSE
      v_first := v_name_raw;
    END IF;
  END IF;
  IF v_first IS NULL OR v_first = '' THEN
    v_first := split_part(v_email, '@', 1);
  END IF;

  -- Resolve listing_id if entity_type='listing' and the id parses as a real
  -- UUID that actually matches an existing listing. Any failure (bad cast,
  -- missing row) demotes the contact to buyer-flavour rather than breaking
  -- the trigger.
  IF lower(coalesce(p_entity_type, '')) = 'listing' AND p_entity_id IS NOT NULL THEN
    BEGIN
      v_listing_id := p_entity_id::uuid;
      IF NOT EXISTS (SELECT 1 FROM public.listings WHERE id = v_listing_id) THEN
        v_listing_id := NULL;
      END IF;
    EXCEPTION WHEN invalid_text_representation THEN
      v_listing_id := NULL;
    END;
  END IF;

  IF v_listing_id IS NOT NULL THEN
    v_contact_type := 'seller';
  ELSE
    v_contact_type := 'buyer';
  END IF;

  -- Seller-flavour dedup: (lower(email), listing_id) is the partial unique
  -- index key. Match within the listing scope.
  IF v_contact_type = 'seller' THEN
    SELECT id INTO v_existing_id
      FROM public.contacts
     WHERE contact_type = 'seller'
       AND archived = false
       AND email IS NOT NULL
       AND lower(email) = v_email
       AND listing_id = v_listing_id
     LIMIT 1;
  ELSE
    -- Buyer-flavour dedup: lower(email) is globally unique among buyer contacts.
    SELECT id INTO v_existing_id
      FROM public.contacts
     WHERE contact_type = 'buyer'
       AND archived = false
       AND email IS NOT NULL
       AND lower(email) = v_email
     LIMIT 1;
  END IF;

  IF v_existing_id IS NOT NULL THEN
    -- Backfill missing fields on the existing contact. Never overwrite a
    -- non-null value, so admin edits stick. listing_id is intentionally
    -- NOT overwritten even when v_listing_id is set — see header note.
    UPDATE public.contacts
       SET phone      = coalesce(phone, v_phone),
           title      = coalesce(title, v_title),
           updated_at = now()
     WHERE id = v_existing_id;
    RETURN v_existing_id;
  END IF;

  INSERT INTO public.contacts (
    first_name,
    last_name,
    email,
    phone,
    title,
    contact_type,
    listing_id,
    source
  )
  VALUES (
    v_first,
    coalesce(v_last, ''),
    v_email,
    v_phone,
    v_title,
    v_contact_type,
    v_listing_id,
    'contact_list_member_auto'
  )
  ON CONFLICT DO NOTHING
  RETURNING id INTO v_new_id;

  -- Race: another trigger could have inserted the same email while we were
  -- checking. Re-read the winner if so.
  IF v_new_id IS NULL THEN
    IF v_contact_type = 'seller' THEN
      SELECT id INTO v_new_id
        FROM public.contacts
       WHERE contact_type = 'seller'
         AND archived = false
         AND email IS NOT NULL
         AND lower(email) = v_email
         AND listing_id = v_listing_id
       LIMIT 1;
    ELSE
      SELECT id INTO v_new_id
        FROM public.contacts
       WHERE contact_type = 'buyer'
         AND archived = false
         AND email IS NOT NULL
         AND lower(email) = v_email
       LIMIT 1;
    END IF;
  END IF;

  RETURN v_new_id;
END;
$$;


ALTER FUNCTION "public"."upsert_contact_from_list_member"("p_email" "text", "p_name" "text", "p_phone" "text", "p_company" "text", "p_role" "text", "p_entity_type" "text", "p_entity_id" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."upsert_contact_from_list_member"("p_email" "text", "p_name" "text", "p_phone" "text", "p_company" "text", "p_role" "text", "p_entity_type" "text", "p_entity_id" "text") IS 'Upserts a contacts row from a contact_list_members entry. Seller flavour when entity_type=listing and entity_id resolves to a real listing; buyer flavour otherwise. Tag: source=contact_list_member_auto. Returns the contact id, or NULL if no email is present. Mirrors upsert_contact_from_connection_request (migration 60) for cold-lead dialers.';



CREATE OR REPLACE FUNCTION "public"."upsert_deal_scoring_queue"("p_universe_id" "uuid", "p_listing_id" "uuid", "p_score_type" "text", "p_status" "text" DEFAULT 'pending'::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  INSERT INTO remarketing_scoring_queue (universe_id, listing_id, score_type, status, created_at, updated_at)
  VALUES (p_universe_id, p_listing_id, p_score_type, p_status, now(), now())
  ON CONFLICT (universe_id, listing_id, score_type) WHERE listing_id IS NOT NULL
  DO UPDATE SET
    status = CASE 
      WHEN remarketing_scoring_queue.status IN ('pending', 'processing') THEN remarketing_scoring_queue.status
      ELSE EXCLUDED.status
    END,
    updated_at = now();
END;
$$;


ALTER FUNCTION "public"."upsert_deal_scoring_queue"("p_universe_id" "uuid", "p_listing_id" "uuid", "p_score_type" "text", "p_status" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."upsert_enrichment_job"("p_job_type" "text", "p_total_records" integer, "p_triggered_by" "uuid" DEFAULT NULL::"uuid", "p_source" "text" DEFAULT 'manual'::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_job_id UUID;
BEGIN
  INSERT INTO enrichment_jobs (job_type, status, total_records, triggered_by, source, started_at)
  VALUES (p_job_type, 'processing', p_total_records, p_triggered_by, p_source, NOW())
  RETURNING id INTO v_job_id;

  RETURN v_job_id;
END;
$$;


ALTER FUNCTION "public"."upsert_enrichment_job"("p_job_type" "text", "p_total_records" integer, "p_triggered_by" "uuid", "p_source" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."validate_connection_request_transition"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  ok BOOLEAN;
BEGIN
  -- Always log the attempt, even if we're about to reject.
  -- Logging is best-effort and isolated from the main validation so it
  -- can't silently suppress a real problem.

  IF TG_OP = 'INSERT' THEN
    -- New row: any allowed status that's in the "entry" set is fine.
    IF NEW.status NOT IN ('pending', 'under_review', 'approved',
                          'rejected', 'on_hold', 'withdrawn', 'expired') THEN
      BEGIN
        INSERT INTO public.connection_request_status_log
          (connection_request_id, old_status, new_status, changed_by,
           reason, transition_ok)
        VALUES (NEW.id, NULL, NEW.status, NULL,
                'INSERT with disallowed status', FALSE);
      EXCEPTION WHEN OTHERS THEN NULL;
      END;
      RAISE EXCEPTION 'connection_requests.status=% is not a valid status', NEW.status;
    END IF;

    BEGIN
      INSERT INTO public.connection_request_status_log
        (connection_request_id, old_status, new_status, reason)
      VALUES (NEW.id, NULL, NEW.status, 'INSERT');
    EXCEPTION WHEN OTHERS THEN NULL;
    END;

    RETURN NEW;
  END IF;

  -- UPDATE path
  IF NEW.status IS NOT DISTINCT FROM OLD.status THEN
    RETURN NEW;
  END IF;

  -- Transition matrix: old_status → set of legal new statuses
  ok := CASE OLD.status
    WHEN 'pending'      THEN NEW.status IN ('under_review','approved','rejected','on_hold','withdrawn','expired')
    WHEN 'under_review' THEN NEW.status IN ('approved','rejected','on_hold','pending','withdrawn','expired')
    WHEN 'on_hold'      THEN NEW.status IN ('under_review','approved','rejected','withdrawn','expired')
    WHEN 'approved'     THEN NEW.status IN ('withdrawn')           -- once approved, only withdraw
    WHEN 'rejected'     THEN NEW.status IN ('under_review')        -- re-open allowed
    WHEN 'withdrawn'    THEN FALSE                                 -- terminal
    WHEN 'expired'      THEN NEW.status IN ('under_review','pending') -- can revive
    ELSE                     TRUE                                  -- unknown old status: don't block
  END;

  BEGIN
    INSERT INTO public.connection_request_status_log
      (connection_request_id, old_status, new_status, reason, transition_ok)
    VALUES (NEW.id, OLD.status, NEW.status,
            CASE WHEN ok THEN 'valid transition'
                 ELSE 'invalid transition blocked by state-machine' END,
            ok);
  EXCEPTION WHEN OTHERS THEN NULL;
  END;

  IF NOT ok THEN
    RAISE EXCEPTION 'Invalid connection_requests status transition: % → % (request id %)',
      OLD.status, NEW.status, OLD.id;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."validate_connection_request_transition"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."validate_firm_email_domain"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  IF NEW.email_domain IS NOT NULL AND NEW.email_domain LIKE '%@%' THEN
    -- Auto-fix: extract domain part
    NEW.email_domain := split_part(NEW.email_domain, '@', 2);
    -- If result is generic, null it out
    IF NEW.email_domain = ANY(ARRAY['gmail.com', 'yahoo.com', 'hotmail.com', 'outlook.com', 'icloud.com', 'aol.com', 'mail.com', 'protonmail.com']) THEN
      NEW.email_domain := NULL;
    END IF;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."validate_firm_email_domain"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."validate_linkedin_url"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Allow NULL (no LinkedIn URL known) or a valid LinkedIn profile/company/school
  -- URL, including country-specific subdomains (ca., uk., sg., ch., etc.).
  -- Silently NULLs values that are non-empty but don't match the whitelist.
  -- Emits RAISE NOTICE with contact_id and source so ops can trace the ingestion
  -- path producing garbage values.
  --
  -- TODO: Forward-protection at the database layer is best-effort. The
  -- authoritative validation lives in the UI input layer. This trigger prevents
  -- a repeat of the 'n/a' / '0' / bare-domain / /feed contamination seen in
  -- the Step 3a audit, but callers should validate before insert.
  IF NEW.linkedin_url IS NOT NULL
     AND NEW.linkedin_url <> ''
     AND normalize_linkedin_url(NEW.linkedin_url) NOT SIMILAR TO
         '([a-z]{2}\.)?linkedin\.com/(in|company|school)/%'
  THEN
    RAISE NOTICE
      'contacts.linkedin_url cleaned: rejected non-LinkedIn value ''%'' for contact_id=%, source=%. Set to NULL.',
      NEW.linkedin_url, NEW.id, NEW.source;
    NEW.linkedin_url := NULL;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."validate_linkedin_url"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."validate_listing_data"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $_$
BEGIN
  -- CapTarget-sourced rows skip validation entirely — they're imported
  -- without revenue / ebitda / long descriptions by design.
  IF NEW.deal_source = 'captarget' THEN
    RETURN NEW;
  END IF;

  -- Revenue: between $1K and $1B. Only re-validate when revenue itself
  -- changes (or on INSERT, where OLD is NULL).
  IF TG_OP = 'INSERT' OR NEW.revenue IS DISTINCT FROM OLD.revenue THEN
    IF NEW.revenue IS NOT NULL
       AND (NEW.revenue < 1000 OR NEW.revenue > 1000000000) THEN
      RAISE EXCEPTION 'Revenue must be between $1,000 and $1,000,000,000';
    END IF;
  END IF;

  -- EBITDA / revenue ratio. Re-validate when either side of the ratio
  -- changes, or on INSERT.
  IF TG_OP = 'INSERT'
     OR NEW.revenue IS DISTINCT FROM OLD.revenue
     OR NEW.ebitda  IS DISTINCT FROM OLD.ebitda THEN
    IF NEW.revenue IS NOT NULL
       AND NEW.ebitda IS NOT NULL
       AND NEW.ebitda > NEW.revenue * 2 THEN
      RAISE EXCEPTION 'EBITDA cannot exceed 200%% of revenue';
    END IF;
  END IF;

  -- Title length: 5..200 chars. Only re-validate on actual title change
  -- or on INSERT.
  IF TG_OP = 'INSERT' OR NEW.title IS DISTINCT FROM OLD.title THEN
    IF NEW.title IS NOT NULL
       AND (LENGTH(NEW.title) < 5 OR LENGTH(NEW.title) > 200) THEN
      RAISE EXCEPTION 'Title must be between 5 and 200 characters';
    END IF;
  END IF;

  -- Description length: 20..5000 chars. Only re-validate on actual
  -- description change or on INSERT.
  IF TG_OP = 'INSERT' OR NEW.description IS DISTINCT FROM OLD.description THEN
    IF NEW.description IS NOT NULL
       AND (LENGTH(NEW.description) < 20 OR LENGTH(NEW.description) > 5000) THEN
      RAISE EXCEPTION 'Description must be between 20 and 5000 characters';
    END IF;
  END IF;

  RETURN NEW;
END;
$_$;


ALTER FUNCTION "public"."validate_listing_data"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."validate_listing_data"() IS 'BEFORE INSERT OR UPDATE trigger on listings. Validates revenue/ebitda/title/description only for fields that are actually being changed, so status-only updates (archive, not_a_fit, soft-delete) do not re-validate unrelated legacy columns. CapTarget-sourced rows are exempted.';



CREATE OR REPLACE FUNCTION "public"."validate_marketplace_publishing"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- If trying to publish to marketplace (is_internal_deal = false)
  -- and the listing looks like a research deal, require hero_description
  IF NEW.is_internal_deal = false THEN
    -- If website is populated but no hero_description, it's likely a research deal
    -- that shouldn't be on the marketplace
    IF (NEW.website IS NOT NULL AND NEW.website != '') 
       AND (NEW.hero_description IS NULL OR NEW.hero_description = '') THEN
      -- Allow it but log a warning (we don't want to hard-block admin workflow)
      -- Instead, we rely on the default being true and explicit admin action
      RAISE WARNING 'Publishing listing % to marketplace without hero_description despite having website field', NEW.id;
    END IF;
  END IF;
  
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."validate_marketplace_publishing"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."validate_task_entity_reference"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  ref_exists boolean;
BEGIN
  -- Primary entity
  IF NEW.entity_id IS NOT NULL AND NEW.entity_type IS NOT NULL THEN
    CASE NEW.entity_type
      WHEN 'listing' THEN
        SELECT EXISTS(SELECT 1 FROM public.listings WHERE id = NEW.entity_id) INTO ref_exists;
      WHEN 'deal' THEN
        SELECT EXISTS(SELECT 1 FROM public.deals WHERE id = NEW.entity_id) INTO ref_exists;
      WHEN 'buyer' THEN
        SELECT EXISTS(SELECT 1 FROM public.buyers WHERE id = NEW.entity_id) INTO ref_exists;
      WHEN 'contact' THEN
        SELECT EXISTS(SELECT 1 FROM public.contacts WHERE id = NEW.entity_id) INTO ref_exists;
      WHEN 'buyer_universe' THEN
        SELECT EXISTS(SELECT 1 FROM public.buyer_universes WHERE id = NEW.entity_id) INTO ref_exists;
      ELSE
        ref_exists := true;  -- unknown entity_type; CHECK constraint will reject
    END CASE;

    IF NOT ref_exists THEN
      RAISE EXCEPTION
        'daily_standup_tasks.entity_id % does not exist in % table',
        NEW.entity_id, NEW.entity_type
        USING ERRCODE = 'foreign_key_violation';
    END IF;
  END IF;

  -- Secondary entity (optional)
  IF NEW.secondary_entity_id IS NOT NULL AND NEW.secondary_entity_type IS NOT NULL THEN
    CASE NEW.secondary_entity_type
      WHEN 'listing' THEN
        SELECT EXISTS(SELECT 1 FROM public.listings WHERE id = NEW.secondary_entity_id) INTO ref_exists;
      WHEN 'deal' THEN
        SELECT EXISTS(SELECT 1 FROM public.deals WHERE id = NEW.secondary_entity_id) INTO ref_exists;
      WHEN 'buyer' THEN
        SELECT EXISTS(SELECT 1 FROM public.buyers WHERE id = NEW.secondary_entity_id) INTO ref_exists;
      WHEN 'contact' THEN
        SELECT EXISTS(SELECT 1 FROM public.contacts WHERE id = NEW.secondary_entity_id) INTO ref_exists;
      WHEN 'buyer_universe' THEN
        SELECT EXISTS(SELECT 1 FROM public.buyer_universes WHERE id = NEW.secondary_entity_id) INTO ref_exists;
      ELSE
        ref_exists := true;
    END CASE;

    IF NOT ref_exists THEN
      RAISE EXCEPTION
        'daily_standup_tasks.secondary_entity_id % does not exist in % table',
        NEW.secondary_entity_id, NEW.secondary_entity_type
        USING ERRCODE = 'foreign_key_violation';
    END IF;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."validate_task_entity_reference"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."valuation_lead_quarantine_reason"("_website" "text", "_business_name" "text", "_full_name" "text", "_revenue" numeric, "_ebitda" numeric) RETURNS "text"
    LANGUAGE "plpgsql" IMMUTABLE
    SET "search_path" TO 'public'
    AS $_$
DECLARE
  w text := lower(coalesce(trim(_website), ''));
  b text := lower(coalesce(trim(_business_name), ''));
  n text := lower(coalesce(trim(_full_name), ''));
BEGIN
  -- Strip protocol + www for matching
  w := regexp_replace(w, '^[a-z]{3,6}://', '');
  w := regexp_replace(w, '^www\.', '');

  -- ── WEBSITE checks ─────────────────────────────────────────
  IF w <> '' THEN
    -- Search engines / social / marketplaces posing as a website
    IF w ~ '^(google|facebook|fb|yelp|instagram|linkedin|youtube|youtu\.be|tiktok|amazon|bing|duckduckgo|yahoo|baidu|twitter|x\.com|pinterest|reddit|snapchat|whatsapp|telegram|wechat|wikipedia)\.' THEN
      RETURN 'invalid_website';
    END IF;
    IF w LIKE 'play.google.com%' OR w LIKE 'apps.apple.com%' OR w LIKE 'm.facebook.com%' THEN
      RETURN 'invalid_website';
    END IF;
    -- Whitespace is never valid in a domain
    IF w ~ '\s' THEN
      RETURN 'invalid_website';
    END IF;
    -- Must contain a dot
    IF position('.' in w) = 0 THEN
      RETURN 'invalid_website';
    END IF;
    -- Obvious placeholders
    IF w IN ('no.com', 'none.com', 'test.com', 'example.com', 'example.org', 'example.net', 'noemail.com', 'nowebsite.com', 'na.com') THEN
      RETURN 'invalid_website';
    END IF;
    IF w ~ '^(test|no|none|na|n/a|tbd|tba|blah|asdf|xxx)\.' THEN
      RETURN 'invalid_website';
    END IF;
    -- Comma instead of dot ("blahblah,com") and other malformed
    IF w ~ ',' THEN
      RETURN 'invalid_website';
    END IF;
  END IF;

  -- ── BUSINESS NAME / FULL NAME checks ──────────────────────
  IF b IN ('test', 'testing', 'theoretical', 'asdf', 'blah', 'blahblah', 'na', 'n/a', 'none', 'tbd', 'xxx') THEN
    RETURN 'invalid_business';
  END IF;
  IF b LIKE 'theoretical%' OR b LIKE 'test %' OR b LIKE '% test' OR b = 'my auto shop' OR b = 'my shop' OR b = 'mymechanic' OR b = 'kcc' THEN
    RETURN 'invalid_business';
  END IF;
  IF n IN ('test', 'testing', 'asdf', 'blah') THEN
    RETURN 'invalid_business';
  END IF;

  -- ── FINANCIAL sanity checks ────────────────────────────────
  -- Revenue impossibly large (> $100B)
  IF _revenue IS NOT NULL AND _revenue > 100000000000 THEN
    RETURN 'invalid_financials';
  END IF;
  -- Both revenue and ebitda exactly 0 (no real business signal)
  IF coalesce(_revenue, 0) = 0 AND coalesce(_ebitda, 0) = 0 THEN
    RETURN 'invalid_financials';
  END IF;
  -- Revenue = 1 / ebitda = 1 (joke values)
  IF _revenue IS NOT NULL AND _revenue > 0 AND _revenue < 100 THEN
    RETURN 'invalid_financials';
  END IF;

  RETURN NULL;
END;
$_$;


ALTER FUNCTION "public"."valuation_lead_quarantine_reason"("_website" "text", "_business_name" "text", "_full_name" "text", "_revenue" numeric, "_ebitda" numeric) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."valuation_leads_dedup_check"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  existing_id uuid;
BEGIN
  -- Skip dedup if email is null or empty
  IF NEW.email IS NULL OR TRIM(NEW.email) = '' THEN
    RETURN NEW;
  END IF;

  -- Find existing record with same email (case-insensitive)
  SELECT id INTO existing_id
  FROM public.valuation_leads
  WHERE LOWER(TRIM(email)) = LOWER(TRIM(NEW.email))
    AND id != COALESCE(NEW.id, '00000000-0000-0000-0000-000000000000'::uuid)
    AND excluded = false
  ORDER BY created_at DESC
  LIMIT 1;

  IF existing_id IS NOT NULL THEN
    -- Update existing record with newer financial data
    UPDATE public.valuation_leads
    SET
      revenue = COALESCE(NEW.revenue, revenue),
      ebitda = COALESCE(NEW.ebitda, ebitda),
      valuation_low = COALESCE(NEW.valuation_low, valuation_low),
      valuation_mid = COALESCE(NEW.valuation_mid, valuation_mid),
      valuation_high = COALESCE(NEW.valuation_high, valuation_high),
      updated_at = NOW()
    WHERE id = existing_id;
    RETURN NULL; -- Cancel the INSERT
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."valuation_leads_dedup_check"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."write_outreach_event_from_buyer_transcript"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NEW.buyer_id IS NULL THEN RETURN NEW; END IF;
  BEGIN
    INSERT INTO public.outreach_events
      (event_type, channel, buyer_id, subject, summary,
       duration_seconds, occurred_at, source_table, source_row_id, source_external_id, metadata)
    VALUES
      ('meeting', COALESCE(NEW.source, 'fireflies'), NEW.buyer_id,
       NEW.title,
       COALESCE(NEW.summary, LEFT(NEW.transcript_text, 240)),
       NEW.duration_minutes * 60,
       COALESCE(NEW.call_date, NEW.created_at, now()),
       'buyer_transcripts', NEW.id, NEW.fireflies_transcript_id,
       jsonb_build_object('extraction_status', NEW.extraction_status));
  EXCEPTION WHEN OTHERS THEN
    RAISE NOTICE 'write_outreach_event_from_buyer_transcript non-fatal: %', SQLERRM;
  END;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."write_outreach_event_from_buyer_transcript"() OWNER TO "postgres";


