       actor_user_id, actor_name, actor_email,
       subject, summary, duration_seconds, occurred_at,
       source_table, source_row_id, source_external_id)
    VALUES
      ('call', COALESCE(NEW.source_system, 'phoneburner'), NEW.call_direction,
       NEW.remarketing_buyer_id, NEW.contact_id, NEW.listing_id,
       NEW.user_id, NEW.user_name, NEW.user_email,
       COALESCE(NEW.disposition_label, NEW.call_outcome),
       COALESCE(NEW.ai_summary, LEFT(NEW.call_transcript, 240), NEW.contact_notes),
       NEW.call_duration_seconds, COALESCE(NEW.call_started_at, NEW.created_at, now()),
       'contact_activities', NEW.id, NEW.phoneburner_call_id);
  EXCEPTION WHEN OTHERS THEN
    RAISE NOTICE 'write_outreach_event_from_contact_activity non-fatal: %', SQLERRM;
  END;
  RETURN NEW;
END;
$$;


