CREATE OR REPLACE FUNCTION "public"."write_signal_from_outreach_event"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  weight          NUMERIC;
  signal_type     TEXT;
BEGIN
  IF NEW.buyer_id IS NULL THEN RETURN NEW; END IF;

  -- Map (event_type, channel, direction, duration) → signal
  IF NEW.event_type = 'call' THEN
    IF NEW.duration_seconds IS NOT NULL AND NEW.duration_seconds > 30 THEN
      signal_type := 'called_connected';
      weight := 0.05;
    ELSE
      signal_type := 'called_no_answer';
      weight := 0.01;
    END IF;
  ELSIF NEW.event_type = 'meeting' THEN
    signal_type := 'meeting';
    weight := 0.12;
  ELSIF NEW.event_type = 'email' THEN
    IF NEW.direction = 'outbound' THEN
      signal_type := 'emailed_outbound';
      weight := 0.02;
    ELSIF NEW.direction = 'inbound' THEN
      signal_type := 'emailed_reply';
      weight := 0.08;
    ELSE
      signal_type := 'emailed';
      weight := 0.02;
    END IF;
  ELSE
    RETURN NEW;
  END IF;

  BEGIN
    INSERT INTO public.buyer_signal_events
      (buyer_id, listing_id, event_type, event_weight, decay_half_life_days,
       observed_at, source_table, source_row_id, metadata)
    VALUES
      (NEW.buyer_id, NEW.listing_id, signal_type, weight, 90,
       NEW.occurred_at, NEW.source_table, NEW.source_row_id,
       jsonb_build_object('channel', NEW.channel, 'direction', NEW.direction));
  EXCEPTION WHEN OTHERS THEN
    RAISE NOTICE 'write_signal_from_outreach_event non-fatal: %', SQLERRM;
  END;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."write_signal_from_outreach_event"() OWNER TO "postgres";


