    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "buyer_id" "uuid" NOT NULL,
    "listing_id" "uuid",
    "event_type" "text" NOT NULL,
    "event_weight" numeric NOT NULL,
    "decay_half_life_days" integer DEFAULT 180 NOT NULL,
    "observed_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "metadata" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "source_table" "text",
    "source_row_id" "uuid",
    CONSTRAINT "buyer_signal_events_decay_half_life_days_check" CHECK (("decay_half_life_days" > 0)),
    CONSTRAINT "buyer_signal_events_event_type_check" CHECK (("event_type" = ANY (ARRAY['accepted'::"text", 'rejected'::"text", 'introduced'::"text", 'interested'::"text", 'replied'::"text", 'won'::"text", 'lost'::"text", 'fee_agreement_signed'::"text", 'transcript_positive'::"text", 'transcript_negative'::"text", 'enriched'::"text", 'called_connected'::"text", 'called_no_answer'::"text", 'meeting'::"text", 'emailed_outbound'::"text", 'emailed_reply'::"text", 'emailed'::"text"])))
);


ALTER TABLE "public"."buyer_signal_events" OWNER TO "postgres";


COMMENT ON TABLE "public"."buyer_signal_events" IS 'Event log for buyer-side signals that feed the scoring relationship term. Write-only append log; read via materialized view buyer_current_signal.';



CREATE MATERIALIZED VIEW "public"."buyer_current_signal" AS
 SELECT "buyer_signal_events"."buyer_id",
    ("sum"((("buyer_signal_events"."event_weight")::double precision * "exp"((((- "ln"((2)::double precision)) * (EXTRACT(epoch FROM ("now"() - "buyer_signal_events"."observed_at")))::double precision) / (("buyer_signal_events"."decay_half_life_days" * 86400))::double precision)))))::numeric(10,4) AS "current_signal_score",
    "count"(*) FILTER (WHERE ("buyer_signal_events"."event_type" = ANY (ARRAY['interested'::"text", 'replied'::"text", 'won'::"text"]))) AS "positive_events",
    "count"(*) FILTER (WHERE ("buyer_signal_events"."event_type" = 'rejected'::"text")) AS "rejection_events",
    "max"("buyer_signal_events"."observed_at") FILTER (WHERE ("buyer_signal_events"."event_type" = ANY (ARRAY['interested'::"text", 'replied'::"text", 'won'::"text"]))) AS "last_positive_at",
    "max"("buyer_signal_events"."observed_at") FILTER (WHERE ("buyer_signal_events"."event_type" = 'rejected'::"text")) AS "last_rejection_at",
    "count"(*) AS "total_events",
    "max"("buyer_signal_events"."observed_at") AS "last_event_at"
   FROM "public"."buyer_signal_events"
  GROUP BY "buyer_signal_events"."buyer_id"
  WITH NO DATA;


ALTER TABLE "public"."buyer_current_signal" OWNER TO "postgres";


COMMENT ON MATERIALIZED VIEW "public"."buyer_current_signal" IS 'Per-buyer decay-weighted current signal score. Refresh CONCURRENTLY every 15-60 min via pg_cron or scheduled function.';



