COMMENT ON COLUMN "public"."buyer_introductions"."deleted_at" IS 'Soft-delete timestamp. NULL = live row. Set by application code. Do not rely on this alone yet — existing archived columns may still gate visibility.';



CREATE OR REPLACE VIEW "public"."buyer_introduction_summary" WITH ("security_invoker"='true') AS
 SELECT "l"."id" AS "listing_id",
    "l"."title" AS "company_name",
    "count"(
        CASE
            WHEN ("bi"."introduction_status" = 'need_to_show_deal'::"text") THEN 1
            ELSE NULL::integer
        END) AS "need_to_show_deal",
    "count"(
        CASE
            WHEN ("bi"."introduction_status" = 'outreach_initiated'::"text") THEN 1
            ELSE NULL::integer
        END) AS "pending_introductions",
    "count"(
        CASE
            WHEN ("bi"."introduction_status" = 'meeting_scheduled'::"text") THEN 1
            ELSE NULL::integer
        END) AS "meetings_scheduled",
    "count"(
        CASE
            WHEN ("bi"."introduction_status" = 'fit_and_interested'::"text") THEN 1
            ELSE NULL::integer
        END) AS "fit_and_interested_buyers",
    "count"(
        CASE
            WHEN ("bi"."introduction_status" = 'not_a_fit'::"text") THEN 1
            ELSE NULL::integer
        END) AS "not_a_fit_buyers",
    "count"(*) AS "total_tracked_buyers"
   FROM ("public"."listings" "l"
     LEFT JOIN "public"."buyer_introductions" "bi" ON (("l"."id" = "bi"."listing_id")))
  WHERE ("l"."deleted_at" IS NULL)
  GROUP BY "l"."id", "l"."title"
  ORDER BY "l"."title";


