CREATE MATERIALIZED VIEW "public"."buyer_stats" AS
 SELECT "b"."id" AS "buyer_id",
    "count"(DISTINCT "bi"."id") FILTER (WHERE ("bi"."introduction_status" = 'introduced'::"text")) AS "times_introduced",
    "count"(DISTINCT "bi"."id") FILTER (WHERE ("bi"."introduction_status" = 'interested'::"text")) AS "times_replied",
    "count"(DISTINCT "orr"."id") FILTER (WHERE ("orr"."outcome" = 'won'::"text")) AS "times_won",
    "count"(DISTINCT "orr"."id") FILTER (WHERE ("orr"."outcome" = 'lost'::"text")) AS "times_lost",
    ( SELECT "count"(*) AS "count"
           FROM "public"."buyer_transcripts" "bt"
          WHERE ("bt"."buyer_id" = "b"."id")) AS "transcript_count",
    ( SELECT "max"("bt"."created_at") AS "max"
           FROM "public"."buyer_transcripts" "bt"
          WHERE ("bt"."buyer_id" = "b"."id")) AS "last_transcript_at",
    "bcs"."current_signal_score",
    "bcs"."last_positive_at",
    "bcs"."last_rejection_at",
    "now"() AS "refreshed_at"
   FROM ((("public"."buyers" "b"
     LEFT JOIN "public"."outreach_records" "orr" ON (("orr"."buyer_id" = "b"."id")))
     LEFT JOIN "public"."buyer_introductions" "bi" ON (("bi"."contact_id" IN ( SELECT "c"."id"
           FROM "public"."contacts" "c"
          WHERE ("c"."remarketing_buyer_id" = "b"."id")))))
     LEFT JOIN "public"."buyer_current_signal" "bcs" ON (("bcs"."buyer_id" = "b"."id")))
  WHERE ("b"."archived" = false)
  GROUP BY "b"."id", "bcs"."current_signal_score", "bcs"."last_positive_at", "bcs"."last_rejection_at"
  WITH NO DATA;


ALTER TABLE "public"."buyer_stats" OWNER TO "postgres";


COMMENT ON MATERIALIZED VIEW "public"."buyer_stats" IS 'Single source of truth for per-buyer lifetime counts + current signal score.';



