    "generation_source" "text",
    "escalated_at" timestamp with time zone,
    "escalation_level" integer DEFAULT 0,
    "completion_notes" "text",
    "source_timestamp_seconds" integer,
    "task_category" "text" DEFAULT 'deal_task'::"text",
    "carry_count" integer DEFAULT 0,
    CONSTRAINT "daily_standup_tasks_extraction_confidence_check" CHECK (("extraction_confidence" = ANY (ARRAY['high'::"text", 'medium'::"text", 'low'::"text"]))),
    CONSTRAINT "daily_standup_tasks_status_check" CHECK (("status" = ANY (ARRAY['pending_approval'::"text", 'pending'::"text", 'in_progress'::"text", 'completed'::"text", 'overdue'::"text", 'snoozed'::"text", 'cancelled'::"text", 'listing_closed'::"text"]))),
    CONSTRAINT "dst_task_type_check" CHECK (("task_type" = ANY (ARRAY['contact_owner'::"text", 'build_buyer_universe'::"text", 'follow_up_with_buyer'::"text", 'send_materials'::"text", 'update_pipeline'::"text", 'schedule_call'::"text", 'nda_execution'::"text", 'ioi_loi_process'::"text", 'due_diligence'::"text", 'buyer_qualification'::"text", 'seller_relationship'::"text", 'buyer_ic_followup'::"text", 'other'::"text", 'call'::"text", 'email'::"text", 'find_buyers'::"text", 'contact_buyers'::"text"])))
);


ALTER TABLE "public"."daily_standup_tasks" OWNER TO "postgres";


COMMENT ON COLUMN "public"."daily_standup_tasks"."status" IS 'Task lifecycle. Values:

  pending_approval — AI-extracted task awaiting a human to approve before it
                     becomes a real assignment. See extract-standup-tasks.
  pending          — active, not yet started. Default for manual creation.
  in_progress      — active, assignee has marked it started.
  snoozed          — temporarily hidden until snoozed_until; the
                     check-overdue-tasks cron (hourly) wakes it back to
                     pending/in_progress when the timer elapses.
  overdue          — past due_date and still active. Flipped by
                     check-overdue-tasks. escalation_level + escalated_at
                     are the escalation state.
  completed        — finished. Triggers auto_recur_completed_task (if
                     recurrence_rule is set) and log_task_completion_to_deal
                     (writes to deal_activities).
  cancelled        — user-initiated dismissal. Never auto-set.
  listing_closed   — auto-applied by check-overdue-tasks when the
                     underlying deal in deal_pipeline transitions to
                     closed/lost/archived. Distinct from cancelled so
                     analytics can separate "user gave up" from "deal died".';



COMMENT ON COLUMN "public"."daily_standup_tasks"."source_timestamp_seconds" IS 'Parsed seconds offset of the moment in the meeting transcript where this task was mentioned. Used to jump to that point in the Fireflies recording.';



COMMENT ON COLUMN "public"."daily_standup_tasks"."task_category" IS 'High-level category: deal_task | platform_task | operations_task. Set by AI extractor; tasks with non-deal_task category are forced to pending_approval.';



COMMENT ON COLUMN "public"."daily_standup_tasks"."carry_count" IS 'How many prior standups this incomplete task has been carried forward from. Increments each time carryOverIncompleteTasks rolls it to a new meeting.';



