COMMENT ON COLUMN "public"."deal_transcripts"."transcript_text" IS 'Full transcript text. Empty for Fireflies transcripts until fetched on-demand, then cached here.';



COMMENT ON COLUMN "public"."deal_transcripts"."source" IS 'Transcript source: fireflies, phoneburner, upload, link, manual';



COMMENT ON COLUMN "public"."deal_transcripts"."fireflies_transcript_id" IS 'Fireflies transcript ID - primary key from Fireflies API (e.g., "transcript_abc123")';



COMMENT ON COLUMN "public"."deal_transcripts"."fireflies_meeting_id" IS 'Fireflies meeting ID - can have multiple transcripts per meeting';



COMMENT ON COLUMN "public"."deal_transcripts"."participants" IS 'JSONB array of participant objects from Fireflies (includes name, email, etc.)';



COMMENT ON COLUMN "public"."deal_transcripts"."meeting_attendees" IS 'Simple text array of participant emails for easy filtering';



COMMENT ON COLUMN "public"."deal_transcripts"."duration_minutes" IS 'Call duration in minutes (derived from Fireflies duration_seconds)';



COMMENT ON COLUMN "public"."deal_transcripts"."auto_linked" IS 'True if automatically linked via participant email match, false if manually uploaded';



COMMENT ON COLUMN "public"."deal_transcripts"."has_content" IS 'False when Fireflies marked meeting as silent/skipped with no transcript captured. These are displayed with a warning label.';



COMMENT ON COLUMN "public"."deal_transcripts"."match_type" IS 'How this transcript was matched to the deal: email (direct participant match), domain (matched by company domain), keyword (fallback matched by company name in content)';



COMMENT ON COLUMN "public"."deal_transcripts"."external_participants" IS 'JSONB array of {name, email} for non-internal participants (excludes @sourcecodeals.com and @captarget.com addresses)';



COMMENT ON COLUMN "public"."deal_transcripts"."phoneburner_call_id" IS 'PhoneBurner call ID for deduplication';



COMMENT ON COLUMN "public"."deal_transcripts"."recording_url" IS 'URL to the call recording (PhoneBurner or other source)';



COMMENT ON COLUMN "public"."deal_transcripts"."contact_activity_id" IS 'Link to contact_activities row for PhoneBurner calls';



COMMENT ON COLUMN "public"."deal_transcripts"."contact_id" IS 'Seller contact who was on the call / in the meeting. Resolved by the seller-side PhoneBurner sync trigger via contact_activity_id → contact_activities.contact_id, or by bulk-sync-all-fireflies when a Fireflies participant email matches a contacts row. Nullable — older rows and company-name-only matches have no contact attribution.';



COMMENT ON COLUMN "public"."deal_transcripts"."phone_number" IS 'Dialed phone number for this call. Surfaces the primary matching key on orphan/unlinked surfaces without requiring a join through contact_activities.';



COMMENT ON COLUMN "public"."deal_transcripts"."buyer_transcript_id" IS 'Cross-side link: ONE of the buyer_transcripts rows for the same Fireflies meeting (shared fireflies_transcript_id). A joint meeting with N buyers produces N buyer_transcripts rows but ONE deal_transcripts row — this column holds the most-recently-linked buyer row as a convenience pointer. To enumerate ALL buyers on a meeting, query buyer_transcripts WHERE deal_transcript_id = <this.id>.';



