CREATE OR REPLACE VIEW "public"."introduced_and_passed_buyers" WITH ("security_invoker"='true') AS
 SELECT "bi"."id",
    "bi"."buyer_name",
    "bi"."buyer_firm_name",
    "bi"."company_name",
    "bi"."introduction_date",
    "bi"."introduced_by",
    "bi"."passed_date",
    "bi"."passed_reason",
    "bi"."buyer_feedback",
    "bi"."next_step",
    "bi"."expected_next_step_date",
    "bi"."listing_id",
        CASE
            WHEN ("bi"."introduction_status" = 'fit_and_interested'::"text") THEN 'Fit & Interested'::"text"
            WHEN ("bi"."introduction_status" = 'not_a_fit'::"text") THEN 'Not a Fit'::"text"
            ELSE NULL::"text"
        END AS "stage",
    (CURRENT_DATE - "bi"."introduction_date") AS "days_since_introduction"
   FROM "public"."buyer_introductions" "bi"
  WHERE (("bi"."introduction_status" = ANY (ARRAY['fit_and_interested'::"text", 'not_a_fit'::"text"])) AND ("bi"."archived_at" IS NULL))
  ORDER BY
        CASE
            WHEN ("bi"."introduction_status" = 'fit_and_interested'::"text") THEN 0
            ELSE 1
        END, "bi"."updated_at" DESC NULLS LAST;


