CREATE MATERIALIZED VIEW "public"."listing_stats" AS
 SELECT "l"."id" AS "listing_id",
    "count"(DISTINCT "rud"."universe_id") FILTER (WHERE ("rud"."status" = 'active'::"text")) AS "universe_count",
    "count"(DISTINCT "bdf"."buyer_id") FILTER (WHERE ("bdf"."action" = 'accepted'::"text")) AS "accepted_buyer_count",
    "count"(DISTINCT "bdf"."buyer_id") FILTER (WHERE ("bdf"."action" = 'rejected'::"text")) AS "rejected_buyer_count",
    "count"(DISTINCT "bi"."id") FILTER (WHERE ("bi"."introduction_status" = 'introduced'::"text")) AS "introduced_count",
    "count"(DISTINCT "bi"."id") FILTER (WHERE ("bi"."introduction_status" = 'interested'::"text")) AS "interested_count",
    "count"(DISTINCT "bi"."id") FILTER (WHERE ("bi"."introduction_status" = 'passed'::"text")) AS "passed_count",
    "count"(DISTINCT "orr"."id") FILTER (WHERE ("orr"."outcome" = 'won'::"text")) AS "won_count",
    "count"(DISTINCT "orr"."id") FILTER (WHERE ("orr"."outcome" = 'lost'::"text")) AS "lost_count",
    "now"() AS "refreshed_at"
   FROM (((("public"."listings" "l"
     LEFT JOIN "public"."remarketing_universe_deals" "rud" ON (("rud"."listing_id" = "l"."id")))
     LEFT JOIN "public"."buyer_discovery_feedback" "bdf" ON (("bdf"."listing_id" = "l"."id")))
     LEFT JOIN "public"."buyer_introductions" "bi" ON (("bi"."listing_id" = "l"."id")))
     LEFT JOIN "public"."outreach_records" "orr" ON (("orr"."listing_id" = "l"."id")))
  WHERE ("l"."deleted_at" IS NULL)
  GROUP BY "l"."id"
  WITH NO DATA;


ALTER TABLE "public"."listing_stats" OWNER TO "postgres";


COMMENT ON MATERIALIZED VIEW "public"."listing_stats" IS 'Single source of truth for per-listing pipeline counts. Used by the deal matching page stat cards.';



