CREATE OR REPLACE VIEW "public"."phantom_phone_buyers" AS
 SELECT "b"."id" AS "buyer_id",
    "b"."company_name",
    "b"."pe_firm_name",
    "b"."buyer_type",
    "b"."universe_id",
    "b"."ai_seeded",
    "b"."ai_seeded_from_deal_id",
    "b"."phone",
    "b"."additional_phones",
    "b"."company_website",
    "b"."created_at",
    "b"."updated_at"
   FROM "public"."buyers" "b"
  WHERE (("regexp_replace"(COALESCE("b"."phone", ''::"text"), '\D'::"text", ''::"text", 'g'::"text") ~~ '%8003918892%'::"text") OR ("regexp_replace"(COALESCE("b"."company_website", ''::"text"), '\D'::"text", ''::"text", 'g'::"text") ~~ '%8003918892%'::"text") OR (EXISTS ( SELECT 1
           FROM "unnest"(COALESCE("b"."additional_phones", ARRAY[]::"text"[])) "ap"("val")
          WHERE ("regexp_replace"(COALESCE("ap"."val", ''::"text"), '\D'::"text", ''::"text", 'g'::"text") ~~ '%8003918892%'::"text"))));


ALTER TABLE "public"."phantom_phone_buyers" OWNER TO "postgres";


COMMENT ON VIEW "public"."phantom_phone_buyers" IS 'Ticket 16 diagnostic — buyers whose phone, additional_phones, or company_website embeds the phantom number.';



CREATE OR REPLACE VIEW "public"."phantom_phone_contacts" AS
 SELECT "c"."id" AS "contact_id",
