    "c"."source" AS "contact_source",
    "c"."contact_type",
    "c"."firm_id",
    "c"."listing_id",
    "c"."remarketing_buyer_id",
    "c"."created_at",
    "c"."updated_at",
    ARRAY['phone'::"text"] AS "phantom_slots"
   FROM "public"."contacts" "c"
  WHERE ("regexp_replace"(COALESCE("c"."phone", ''::"text"), '\D'::"text", ''::"text", 'g'::"text") ~~ '%8003918892%'::"text");


ALTER TABLE "public"."phantom_phone_contacts" OWNER TO "postgres";


COMMENT ON VIEW "public"."phantom_phone_contacts" IS 'Ticket 16 diagnostic — lists every contacts row carrying (800) 391-8892 in the phone field. Group-by contact_source to identify the writer. Does not mutate data; cleanup_phantom_phone(false) is the separate wipe path.';



