CREATE OR REPLACE VIEW "public"."phoneburner_phantom_contacts" AS
 SELECT DISTINCT ((("w"."payload" -> 'body'::"text") -> 'contact'::"text") ->> 'primary_email'::"text") AS "pb_email",
    ((("w"."payload" -> 'body'::"text") -> 'contact'::"text") ->> 'first_name'::"text") AS "pb_first_name",
    ((("w"."payload" -> 'body'::"text") -> 'contact'::"text") ->> 'last_name'::"text") AS "pb_last_name",
    ((("w"."payload" -> 'body'::"text") -> 'contact'::"text") ->> 'id'::"text") AS "pb_contact_id",
    ((("w"."payload" -> 'body'::"text") -> 'custom_data'::"text") ->> 'request_id'::"text") AS "source_request_id",
    ((("w"."payload" -> 'body'::"text") -> 'custom_data'::"text") ->> 'entity_type'::"text") AS "source_entity_type",
    ((("w"."payload" -> 'body'::"text") -> 'custom_data'::"text") ->> 'session_name'::"text") AS "pb_session_name",
    "min"("w"."created_at") AS "first_seen",
    "max"("w"."created_at") AS "last_seen",
    "count"(*) AS "webhook_hits",
    ("array_agg"(((("w"."payload" -> 'body'::"text") -> 'contact'::"text") -> 'phones'::"text") ORDER BY "w"."created_at" DESC))[1] AS "latest_phones_array"
   FROM "public"."phoneburner_webhooks_log" "w"
  WHERE ((((("w"."payload" -> 'body'::"text") -> 'contact'::"text") -> 'phones'::"text") @> '[{"number": "8003918892"}]'::"jsonb") OR (((("w"."payload" -> 'body'::"text") -> 'contact'::"text") -> 'phones'::"text") @> '[{"number": "18003918892"}]'::"jsonb") OR (((("w"."payload" -> 'body'::"text") -> 'contact'::"text") ->> 'phone'::"text") ~~ '%8003918892%'::"text"))
  GROUP BY ((("w"."payload" -> 'body'::"text") -> 'contact'::"text") ->> 'primary_email'::"text"), ((("w"."payload" -> 'body'::"text") -> 'contact'::"text") ->> 'first_name'::"text"), ((("w"."payload" -> 'body'::"text") -> 'contact'::"text") ->> 'last_name'::"text"), ((("w"."payload" -> 'body'::"text") -> 'contact'::"text") ->> 'id'::"text"), ((("w"."payload" -> 'body'::"text") -> 'custom_data'::"text") ->> 'request_id'::"text"), ((("w"."payload" -> 'body'::"text") -> 'custom_data'::"text") ->> 'entity_type'::"text"), ((("w"."payload" -> 'body'::"text") -> 'custom_data'::"text") ->> 'session_name'::"text");


ALTER TABLE "public"."phoneburner_phantom_contacts" OWNER TO "postgres";


COMMENT ON VIEW "public"."phoneburner_phantom_contacts" IS 'Ticket 16 — PhoneBurner-side phantom detection. Lists distinct contacts in PhoneBurner that have (800) 391-8892 stored as one of their phones, based on webhook payloads. Cross-reference pb_email against public.contacts to find the matching SourceCo record; then re-push via phoneburner-push-contacts to overwrite PhoneBurner''s stale phones array, OR edit the contact in PhoneBurner''s dialer UI directly.';



