CREATE OR REPLACE VIEW "public"."portal_pass_reason_summary" WITH ("security_invoker"='true') AS
 SELECT "p"."portal_org_id",
    "r"."pass_reason_category",
    "count"(*) AS "pass_count",
    "max"("r"."created_at") AS "most_recent_at"
   FROM ("public"."portal_deal_responses" "r"
     JOIN "public"."portal_deal_pushes" "p" ON (("r"."push_id" = "p"."id")))
  WHERE (("r"."response_type" = 'pass'::"text") AND ("r"."pass_reason_category" IS NOT NULL))
  GROUP BY "p"."portal_org_id", "r"."pass_reason_category";


