    "pass_category" "text",
    "human_override_score" numeric,
    "scored_by" "uuid",
    "scored_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "acquisition_score" numeric,
    "portfolio_score" numeric,
    "business_model_score" numeric,
    "thesis_bonus" numeric DEFAULT 0,
    "hidden_from_deal" boolean DEFAULT false,
    "rejection_category" "text",
    "rejection_reason" "text",
    "rejection_notes" "text",
    "rejected_at" timestamp with time zone,
    "last_viewed_at" timestamp with time zone,
    "deal_snapshot" "jsonb",
    "size_multiplier" numeric DEFAULT 1.0,
    "service_multiplier" numeric DEFAULT 1.0,
    "geography_mode_factor" numeric DEFAULT 1.0,
    "thesis_alignment_bonus" integer DEFAULT 0,
    "data_quality_bonus" integer DEFAULT 0,
    "kpi_bonus" integer DEFAULT 0,
    "custom_bonus" integer DEFAULT 0,
    "learning_penalty" integer DEFAULT 0,
    "is_disqualified" boolean DEFAULT false,
    "disqualification_reason" "text",
    "needs_review" boolean DEFAULT false,
    CONSTRAINT "remarketing_scores_status_check" CHECK (("status" = ANY (ARRAY['pending'::"text", 'approved'::"text", 'passed'::"text", 'hidden'::"text"]))),
    CONSTRAINT "remarketing_scores_tier_check" CHECK ((("tier" IS NULL) OR ("tier" = ANY (ARRAY['A'::"text", 'B'::"text", 'C'::"text", 'D'::"text", 'F'::"text"]))))
);


ALTER TABLE "public"."remarketing_scores" OWNER TO "postgres";


COMMENT ON COLUMN "public"."remarketing_scores"."scored_at" IS 'Timestamp when this score was last calculated';



COMMENT ON COLUMN "public"."remarketing_scores"."last_viewed_at" IS 'Timestamp when this score was last viewed/expanded by an admin';



COMMENT ON COLUMN "public"."remarketing_scores"."deal_snapshot" IS 'Snapshot of deal data at scoring time for change detection';



COMMENT ON COLUMN "public"."remarketing_scores"."size_multiplier" IS 'Gate 1: Size multiplier (0.0-1.0) applied to entire composite. Wrong size = dead deal.';



COMMENT ON COLUMN "public"."remarketing_scores"."service_multiplier" IS 'Gate 2: Service multiplier (0.0-1.0) applied to entire composite. Wrong services = dead deal.';



COMMENT ON COLUMN "public"."remarketing_scores"."geography_mode_factor" IS 'Geography weight adjustment factor: critical=1.0, preferred=0.6, minimal=0.25';



COMMENT ON COLUMN "public"."remarketing_scores"."thesis_alignment_bonus" IS 'AI-scored thesis-deal alignment bonus (0-20 pts). Only fires when buyer has thesis >50 chars.';



COMMENT ON COLUMN "public"."remarketing_scores"."data_quality_bonus" IS 'Deterministic data quality reward (0-10 pts). Based on completeness of buyer profile.';



COMMENT ON COLUMN "public"."remarketing_scores"."learning_penalty" IS 'Penalty from buyer_learning_history patterns (0 to -25 pts).';



COMMENT ON COLUMN "public"."remarketing_scores"."is_disqualified" IS 'True when a hard disqualification rule fires (size too big/small, excluded service, geo exclusion).';



COMMENT ON COLUMN "public"."remarketing_scores"."needs_review" IS 'True when score 50-65 with low confidence, or data_completeness=Low.';



