CREATE MATERIALIZED VIEW "public"."universe_stats" AS
 SELECT "u"."id" AS "universe_id",
    "u"."name" AS "universe_name",
    "u"."archived" AS "is_archived",
    "count"(DISTINCT "b"."id") FILTER (WHERE ("b"."archived" = false)) AS "buyer_count",
    "count"(DISTINCT "b"."id") FILTER (WHERE (("b"."archived" = false) AND ("b"."data_last_updated" IS NOT NULL) AND ("b"."data_last_updated" > ("now"() - '1 year'::interval)))) AS "buyer_fresh_count",
    "count"(DISTINCT "b"."id") FILTER (WHERE (("b"."archived" = false) AND (EXISTS ( SELECT 1
           FROM "public"."buyer_transcripts" "bt"
          WHERE ("bt"."buyer_id" = "b"."id"))))) AS "buyer_with_transcripts_count",
    "count"(DISTINCT "b"."id") FILTER (WHERE (("b"."archived" = false) AND ("b"."has_fee_agreement" = true))) AS "fee_agreement_count",
    "count"(DISTINCT "rud"."listing_id") FILTER (WHERE ("rud"."status" = 'active'::"text")) AS "deal_count",
    "now"() AS "refreshed_at"
   FROM (("public"."buyer_universes" "u"
     LEFT JOIN "public"."buyers" "b" ON (("b"."universe_id" = "u"."id")))
     LEFT JOIN "public"."remarketing_universe_deals" "rud" ON (("rud"."universe_id" = "u"."id")))
  GROUP BY "u"."id", "u"."name", "u"."archived"
  WITH NO DATA;


ALTER TABLE "public"."universe_stats" OWNER TO "postgres";


COMMENT ON MATERIALIZED VIEW "public"."universe_stats" IS 'Single source of truth for per-universe counts. Now covers archived + non-archived universes; consumers filter via is_archived.';



