CREATE OR REPLACE VIEW "public"."v_campaign_outreach_stats" WITH ("security_invoker"='true') AS
 SELECT 'smartlead'::"text" AS "channel",
    "sm"."smartlead_campaign_id" AS "external_campaign_id",
    "sc"."name" AS "campaign_name",
    "sc"."status" AS "campaign_status",
    "count"(DISTINCT "sm"."contact_id") AS "unique_contacts",
    "count"(*) FILTER (WHERE ("sm"."event_type" = 'sent'::"text")) AS "sent",
    "count"(*) FILTER (WHERE ("sm"."event_type" = 'opened'::"text")) AS "opened",
    "count"(*) FILTER (WHERE ("sm"."event_type" = 'clicked'::"text")) AS "clicked",
    "count"(*) FILTER (WHERE ("sm"."event_type" = 'replied'::"text")) AS "replied",
    "count"(*) FILTER (WHERE ("sm"."event_type" = 'bounced'::"text")) AS "bounced",
    "count"(*) FILTER (WHERE ("sm"."event_type" = 'unsubscribed'::"text")) AS "unsubscribed",
    "round"(((100.0 * (NULLIF("count"(DISTINCT "sm"."contact_id") FILTER (WHERE ("sm"."event_type" = 'replied'::"text")), 0))::numeric) / (NULLIF("count"(DISTINCT "sm"."contact_id") FILTER (WHERE ("sm"."event_type" = 'sent'::"text")), 0))::numeric), 2) AS "reply_rate_pct",
    "min"("sm"."sent_at") AS "first_activity_at",
    "max"("sm"."sent_at") AS "last_activity_at"
   FROM ("public"."smartlead_messages" "sm"
     LEFT JOIN "public"."smartlead_campaigns" "sc" ON (("sc"."smartlead_campaign_id" = "sm"."smartlead_campaign_id")))
  GROUP BY "sm"."smartlead_campaign_id", "sc"."name", "sc"."status"
UNION ALL
 SELECT 'heyreach'::"text" AS "channel",
    "hm"."heyreach_campaign_id" AS "external_campaign_id",
    "hc"."name" AS "campaign_name",
    "hc"."status" AS "campaign_status",
    "count"(DISTINCT "hm"."contact_id") AS "unique_contacts",
    "count"(*) FILTER (WHERE ("hm"."event_type" = 'connection_request_sent'::"text")) AS "sent",
    NULL::bigint AS "opened",
    NULL::bigint AS "clicked",
    "count"(*) FILTER (WHERE ("hm"."event_type" = ANY (ARRAY['lead_replied'::"text", 'message_received'::"text", 'inmail_received'::"text"]))) AS "replied",
    NULL::bigint AS "bounced",
    NULL::bigint AS "unsubscribed",
    "round"(((100.0 * (NULLIF("count"(*) FILTER (WHERE ("hm"."event_type" = 'connection_request_accepted'::"text")), 0))::numeric) / (NULLIF("count"(*) FILTER (WHERE ("hm"."event_type" = 'connection_request_sent'::"text")), 0))::numeric), 2) AS "reply_rate_pct",
    "min"("hm"."sent_at") AS "first_activity_at",
    "max"("hm"."sent_at") AS "last_activity_at"
   FROM ("public"."heyreach_messages" "hm"
     LEFT JOIN "public"."heyreach_campaigns" "hc" ON (("hc"."heyreach_campaign_id" = "hm"."heyreach_campaign_id")))
  GROUP BY "hm"."heyreach_campaign_id", "hc"."name", "hc"."status";


ALTER TABLE "public"."v_campaign_outreach_stats" OWNER TO "postgres";


COMMENT ON VIEW "public"."v_campaign_outreach_stats" IS 'Per-campaign performance leaderboard across both channels. For HeyReach rows, reply_rate_pct is actually connect-acceptance rate (no real email open/click semantics on LinkedIn).';



CREATE OR REPLACE VIEW "public"."v_contact_outreach_summary" WITH ("security_invoker"='true') AS
 WITH "smartlead_agg" AS (
         SELECT "smartlead_messages"."contact_id",
            "count"(*) FILTER (WHERE ("smartlead_messages"."direction" = 'outbound'::"text")) AS "sl_outbound",
            "count"(*) FILTER (WHERE ("smartlead_messages"."direction" = 'inbound'::"text")) AS "sl_inbound",
            "count"(*) FILTER (WHERE ("smartlead_messages"."event_type" = 'sent'::"text")) AS "sl_sent",
            "count"(*) FILTER (WHERE ("smartlead_messages"."event_type" = 'opened'::"text")) AS "sl_opened",
            "count"(*) FILTER (WHERE ("smartlead_messages"."event_type" = 'clicked'::"text")) AS "sl_clicked",
            "count"(*) FILTER (WHERE ("smartlead_messages"."event_type" = 'replied'::"text")) AS "sl_replied",
            "count"(*) FILTER (WHERE ("smartlead_messages"."event_type" = 'bounced'::"text")) AS "sl_bounced",
            "min"("smartlead_messages"."sent_at") AS "sl_first_touch_at",
            "max"("smartlead_messages"."sent_at") AS "sl_last_touch_at"
           FROM "public"."smartlead_messages"
          GROUP BY "smartlead_messages"."contact_id"
        ), "heyreach_agg" AS (
         SELECT "heyreach_messages"."contact_id",
            "count"(*) FILTER (WHERE ("heyreach_messages"."direction" = 'outbound'::"text")) AS "hr_outbound",
            "count"(*) FILTER (WHERE ("heyreach_messages"."direction" = 'inbound'::"text")) AS "hr_inbound",
            "count"(*) FILTER (WHERE ("heyreach_messages"."event_type" = 'connection_request_sent'::"text")) AS "hr_connects_sent",
            "count"(*) FILTER (WHERE ("heyreach_messages"."event_type" = 'connection_request_accepted'::"text")) AS "hr_connects_accepted",
            "count"(*) FILTER (WHERE ("heyreach_messages"."event_type" = 'message_sent'::"text")) AS "hr_messages_sent",
            "count"(*) FILTER (WHERE ("heyreach_messages"."event_type" = ANY (ARRAY['lead_replied'::"text", 'message_received'::"text", 'inmail_received'::"text"]))) AS "hr_replies",
            "min"("heyreach_messages"."sent_at") AS "hr_first_touch_at",
            "max"("heyreach_messages"."sent_at") AS "hr_last_touch_at"
           FROM "public"."heyreach_messages"
          GROUP BY "heyreach_messages"."contact_id"
        )
 SELECT "c"."id" AS "contact_id",
    "c"."contact_type",
    "c"."first_name",
    "c"."last_name",
    "c"."email",
    "c"."linkedin_url",
    "c"."remarketing_buyer_id",
    "c"."listing_id",
    "c"."archived",
    COALESCE("sl"."sl_outbound", (0)::bigint) AS "smartlead_outbound_events",
    COALESCE("sl"."sl_inbound", (0)::bigint) AS "smartlead_inbound_events",
    COALESCE("sl"."sl_sent", (0)::bigint) AS "smartlead_sent",
    COALESCE("sl"."sl_opened", (0)::bigint) AS "smartlead_opened",
    COALESCE("sl"."sl_clicked", (0)::bigint) AS "smartlead_clicked",
    COALESCE("sl"."sl_replied", (0)::bigint) AS "smartlead_replied",
    COALESCE("sl"."sl_bounced", (0)::bigint) AS "smartlead_bounced",
    "sl"."sl_first_touch_at" AS "smartlead_first_touch_at",
    "sl"."sl_last_touch_at" AS "smartlead_last_touch_at",
    COALESCE("hr"."hr_outbound", (0)::bigint) AS "heyreach_outbound_events",
    COALESCE("hr"."hr_inbound", (0)::bigint) AS "heyreach_inbound_events",
    COALESCE("hr"."hr_connects_sent", (0)::bigint) AS "heyreach_connects_sent",
    COALESCE("hr"."hr_connects_accepted", (0)::bigint) AS "heyreach_connects_accepted",
    COALESCE("hr"."hr_messages_sent", (0)::bigint) AS "heyreach_messages_sent",
    COALESCE("hr"."hr_replies", (0)::bigint) AS "heyreach_replies",
    "hr"."hr_first_touch_at" AS "heyreach_first_touch_at",
    "hr"."hr_last_touch_at" AS "heyreach_last_touch_at",
    (COALESCE("sl"."sl_outbound", (0)::bigint) + COALESCE("hr"."hr_outbound", (0)::bigint)) AS "total_outbound_events",
    (COALESCE("sl"."sl_inbound", (0)::bigint) + COALESCE("hr"."hr_inbound", (0)::bigint)) AS "total_inbound_events",
    (COALESCE("sl"."sl_replied", (0)::bigint) + COALESCE("hr"."hr_replies", (0)::bigint)) AS "total_replies",
    LEAST(COALESCE("sl"."sl_first_touch_at", 'infinity'::timestamp with time zone), COALESCE("hr"."hr_first_touch_at", 'infinity'::timestamp with time zone)) AS "first_touch_at",
    GREATEST(COALESCE("sl"."sl_last_touch_at", '-infinity'::timestamp with time zone), COALESCE("hr"."hr_last_touch_at", '-infinity'::timestamp with time zone)) AS "last_touch_at"
   FROM (("public"."contacts" "c"
     LEFT JOIN "smartlead_agg" "sl" ON (("sl"."contact_id" = "c"."id")))
     LEFT JOIN "heyreach_agg" "hr" ON (("hr"."contact_id" = "c"."id")));


ALTER TABLE "public"."v_contact_outreach_summary" OWNER TO "postgres";


COMMENT ON VIEW "public"."v_contact_outreach_summary" IS 'One row per contact with aggregate SmartLead + HeyReach outreach counts and first/last touch timestamps. Use for stale-contact filters and per-contact engagement summaries.';



CREATE OR REPLACE VIEW "public"."v_deals_exceeding_sla" WITH ("security_invoker"='true') AS
 SELECT "dp"."id",
    "dp"."title",
    "dp"."created_at",
    "dp"."first_reviewed_at",
    "dp"."review_sla_hours",
    (EXTRACT(epoch FROM (COALESCE("dp"."first_reviewed_at", "now"()) - "dp"."created_at")) / (3600)::numeric) AS "hours_since_creation",
        CASE
            WHEN (("dp"."first_reviewed_at" IS NULL) AND ((EXTRACT(epoch FROM ("now"() - "dp"."created_at")) / (3600)::numeric) > ("dp"."review_sla_hours")::numeric)) THEN true
            ELSE false
        END AS "sla_breached"
   FROM "public"."deal_pipeline" "dp"
  WHERE ("dp"."deleted_at" IS NULL);


ALTER TABLE "public"."v_deals_exceeding_sla" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_duplicate_buyers" WITH ("security_invoker"='true') AS
 SELECT "public"."extract_domain"("b"."company_website") AS "domain",
    "count"(*) AS "duplicate_count",
    "array_agg"("b"."id" ORDER BY "b"."created_at") AS "buyer_ids",
    "array_agg"("b"."company_name" ORDER BY "b"."created_at") AS "company_names",
    "array_agg"("b"."company_website" ORDER BY "b"."created_at") AS "websites",
    "array_agg"("b"."created_at" ORDER BY "b"."created_at") AS "created_ats",
    "min"("b"."created_at") AS "first_created_at"
   FROM "public"."buyers" "b"
  WHERE (("b"."archived" = false) AND ("b"."company_website" IS NOT NULL) AND (TRIM(BOTH FROM "b"."company_website") <> ''::"text"))
  GROUP BY ("public"."extract_domain"("b"."company_website"))
 HAVING ("count"(*) > 1)
  ORDER BY ("count"(*)) DESC, ("min"("b"."created_at"));


ALTER TABLE "public"."v_duplicate_buyers" OWNER TO "postgres";


COMMENT ON VIEW "public"."v_duplicate_buyers" IS 'Shows active buyers sharing the same website domain. Should always be empty once the idx_buyers_unique_domain index is in place. Query periodically to detect regressions from direct DB writes or triggers.';



