CREATE POLICY "Admin full access to valuation_leads" ON "public"."valuation_leads" USING ((EXISTS ( SELECT 1
   FROM "public"."profiles"
  WHERE (("profiles"."id" = "auth"."uid"()) AND ("profiles"."is_admin" = true)))));



CREATE POLICY "Admin team can read contact backfill queue" ON "public"."contact_backfill_queue" FOR SELECT USING ("public"."is_admin"("auth"."uid"()));



CREATE POLICY "Admin team can read contact backfill runs" ON "public"."contact_backfill_runs" FOR SELECT USING ("public"."is_admin"("auth"."uid"()));



CREATE POLICY "Admin users can view captarget sync exclusions" ON "public"."captarget_sync_exclusions" FOR SELECT TO "authenticated" USING ("public"."is_admin"("auth"."uid"()));



CREATE POLICY "Admin users can view captarget sync logs" ON "public"."captarget_sync_log" FOR SELECT TO "authenticated" USING ("public"."is_admin"("auth"."uid"()));



CREATE POLICY "Admins can create deal comments" ON "public"."deal_comments" FOR INSERT WITH CHECK (("public"."is_admin"("auth"."uid"()) AND ("auth"."uid"() = "admin_id")));



CREATE POLICY "Admins can create invite links" ON "public"."invite_links" FOR INSERT TO "authenticated" WITH CHECK (("public"."has_role"("auth"."uid"(), 'admin'::"public"."app_role") OR "public"."has_role"("auth"."uid"(), 'owner'::"public"."app_role")));



